async function buildSecretReadinessReport(walk: WalkResult): Promise<SecretReadinessReport> {
  const sourceFiles = await secretSourceFiles(walk);
  const secretSurfaces = secretSurfaceRows(walk, sourceFiles);
  const configSignals = secretConfigSignals(sourceFiles);
  const scanTargets = secretScanTargets(sourceFiles, walk);
  const reportingSignals = secretReportingSignals(sourceFiles);
  const preventionSignals = secretPreventionSignals(sourceFiles);
  const advancedSignals = secretAdvancedSignals(sourceFiles);
  const hasConfig = configSignals.some((item) => ["gitleaks-config", "extend-default", "custom-rule"].includes(item.signal));
  const hasGitScan = scanTargets.some((item) => item.target === "git-history" && item.readiness === "ready");
  const hasDirScan = scanTargets.some((item) => item.target === "working-tree" && item.readiness === "ready");
  const hasPrevention = preventionSignals.some((item) => ["pre-commit", "staged", "github-action", "ci"].includes(item.signal) && item.readiness === "ready");
  const hasReport = reportingSignals.some((item) => ["json", "sarif", "report-path"].includes(item.signal) && item.readiness === "ready");
  const hasRedaction = reportingSignals.some((item) => item.signal === "redaction" && item.readiness === "ready");
  const hasBaseline = reportingSignals.some((item) => item.signal === "baseline" && item.readiness === "ready");
  const hasAllowlist = configSignals.some((item) => ["allowlist", "gitleaksignore", "allow-comment"].includes(item.signal));

  const riskQueue: SecretReadinessReport["riskQueue"] = [];
  if (!hasGitScan && !hasDirScan) {
    riskQueue.push({
      priority: "high",
      action: "Add a Gitleaks git or dir scan target before claiming secret scanning coverage.",
      why: "Gitleaks separates git-history scanning from working-tree file scanning, and each catches different leak surfaces.",
      relatedHref: "html/secret-readiness.html"
    });
  }
  if (!hasPrevention) {
    riskQueue.push({
      priority: "high",
      action: "Run secret scanning before commits or in CI.",
      why: "A report-only scanner catches leaks late; pre-commit, staged, and CI gates reduce the chance of publishing credentials.",
      relatedHref: "html/secret-readiness.html"
    });
  }
  if (secretSurfaces.length > 0 && !hasConfig) {
    riskQueue.push({
      priority: "medium",
      action: "Add a .gitleaks.toml config or explicit config path for project-specific rules and false-positive handling.",
      why: "Secret-shaped paths exist, so default rules may need project-specific allowlists or custom rule tuning.",
      relatedHref: "html/secret-readiness.html"
    });
  }
  if (!hasReport) {
    riskQueue.push({
      priority: "medium",
      action: "Emit machine-readable secret scan reports such as JSON or SARIF.",
      why: "Auditable release gates need a durable report path rather than transient terminal output.",
      relatedHref: "html/secret-readiness.html"
    });
  }
  if (!hasRedaction) {
    riskQueue.push({
      priority: "medium",
      action: "Use --redact when showing findings in logs.",
      why: "Secret scanners can accidentally reprint credentials unless output is redacted.",
      relatedHref: "html/secret-readiness.html"
    });
  }
  if (!hasBaseline && secretSurfaces.length > 0) {
    riskQueue.push({
      priority: "low",
      action: "Create a baseline before enforcing on a repository with existing findings.",
      why: "Gitleaks baselines let teams separate old accepted findings from new leaks.",
      relatedHref: "html/secret-readiness.html"
    });
  }
  if (!hasAllowlist && hasConfig) {
    riskQueue.push({
      priority: "low",
      action: "Document allowlists or .gitleaksignore fingerprints for intentional test fixtures.",
      why: "False-positive handling should be reviewable and narrow instead of disabling broad scan coverage.",
      relatedHref: "html/secret-readiness.html"
    });
  }
  riskQueue.push({
    priority: "low",
    action: "Run Gitleaks in the original repository before treating this static report as secret-scan approval.",
    why: "RepoTutor does not inspect excluded secret-like file contents or traverse full git history.",
    relatedHref: "html/secret-readiness.html"
  });

  return {
    summary: `Gitleaks식 secret readiness report: scan target ${scanTargets.length}개, secret surface ${secretSurfaces.length}개, config signal ${configSignals.length}개, prevention signal ${preventionSignals.length}개를 정적 분석으로 정리했습니다.`,
    sourcePattern: "Gitleaks git dir stdin baseline config rules allowlists redaction report formats pre-commit staged secret scanning",
    scanTargets,
    secretSurfaces,
    configSignals,
    reportingSignals,
    preventionSignals,
    advancedSignals,
    riskQueue: riskQueue.sort((a, b) => ({ high: 0, medium: 1, low: 2 }[a.priority] - { high: 0, medium: 1, low: 2 }[b.priority])),
    recommendedCommands: [
      { command: "gitleaks git --redact --report-format sarif --report-path gitleaks.sarif .", purpose: "Scan git history and write a redacted SARIF report for code-scanning systems." },
      { command: "gitleaks dir --redact --report-format json --report-path gitleaks.json .", purpose: "Scan the current working tree and write durable JSON findings." },
      { command: "gitleaks git --baseline-path gitleaks-report.json --report-path findings.json .", purpose: "Filter known findings through a baseline and report only new issues." },
      { command: "gitleaks git --pre-commit --redact --staged --verbose", purpose: "Run a staged pre-commit scan before local commits." },
      { command: "gitleaks git --config .gitleaks.toml --redact .", purpose: "Run with project-specific rules, entropy thresholds, and allowlists." }
    ],
    learnerNextSteps: [
      "git-history scan과 working-tree scan은 다릅니다. 둘 중 무엇을 커버하는지 먼저 확인하세요.",
      "secret-shaped path는 내용이 안전 필터로 제외될 수 있으므로 원본 repo에서 실제 scanner를 다시 실행하세요.",
      "baseline, allowlist, gitleaks:allow는 누락을 숨길 수 있으므로 좁은 scope와 fingerprint 중심으로 검토하세요.",
      "로그나 CI summary에 findings를 노출할 때는 반드시 redaction과 report artifact 경로를 확인하세요."
    ]
  };
}

type SecretSourceFile = {
  filePath: string;
  text: string;
  sourceHref: string;
};

async function secretSourceFiles(walk: WalkResult): Promise<SecretSourceFile[]> {
  const files: SecretSourceFile[] = [];
  for (const file of walk.files) {
    if (!file.isTextCandidate || !secretInspectablePath(file.relPath)) continue;
    const text = await readTextIfSafe(file.absPath, 200_000);
    if (!text) continue;
    if (!secretPathSignal(file.relPath) && !secretContentSignal(text)) continue;
    files.push({ filePath: file.relPath, text, sourceHref: `source/${encodedPath(file.relPath)}` });
    if (files.length >= 200) break;
  }
  return files;
}

function secretInspectablePath(filePath: string): boolean {
  const base = path.basename(filePath);
  return /^(package\.json|\.gitleaks\.toml|gitleaks\.toml|\.gitleaksignore|\.pre-commit-config\.ya?ml|pre-commit-config\.ya?ml|\.pre-commit-hooks\.ya?ml|README\.md|SECURITY\.md)$/i.test(base)
    || /^\.github\/workflows\/.+\.ya?ml$/i.test(filePath)
    || /\.(toml|ya?ml|json|md|js|ts|tsx|sh|env|example|sample)$/i.test(filePath);
}

function secretPathSignal(filePath: string): boolean {
  return /(gitleaks|secret|secrets|credential|credentials|token|tokens|password|passwd|apikey|api-key|\.env|pre-commit|security|sarif)/i.test(filePath);
}

function secretContentSignal(text: string): boolean {
  return /(gitleaks|secret scanning|detect secrets|hardcoded secrets|baseline-path|gitleaksignore|gitleaks:allow|allowlists?|secretGroup|entropy|report-format|report-path|redact|pre-commit|--staged|SARIF|GITLEAKS_CONFIG|GITLEAKS_CONFIG_TOML|max-decode-depth|max-archive-depth)/i.test(text);
}

function secretSurfaceRows(walk: WalkResult, sourceFiles: SecretSourceFile[]): SecretReadinessReport["secretSurfaces"] {
  const ignored = walk.secretCandidatePaths.map((filePath): SecretReadinessReport["secretSurfaces"][number] => ({
    filePath,
    surfaceType: "ignored-secret-candidate",
    readiness: "partial",
    evidence: `${filePath} matched RepoTutor secret-like path filters and was excluded from copied source content.`,
    sourceHref: "html/secret-readiness.html"
  }));
  const detected = sourceFiles
    .filter((source) => secretSurfaceType(source.filePath) !== "unknown")
    .map((source): SecretReadinessReport["secretSurfaces"][number] => {
      const surfaceType = secretSurfaceType(source.filePath);
      return {
        filePath: source.filePath,
        surfaceType,
        readiness: surfaceType === "unknown" ? "partial" : "ready",
        evidence: `${source.filePath} is a secret-scanning surface candidate by path or config role.`,
        sourceHref: source.sourceHref
      };
    });
  const rows = [...ignored, ...detected];
  return rows.slice(0, 120);
}

function secretSurfaceType(filePath: string): SecretReadinessReport["secretSurfaces"][number]["surfaceType"] {
  const base = path.basename(filePath).toLowerCase();
  if (/^\.env|\.env\.|env\.|\.env$/.test(base)) return "env-file";
  if (/\.(pem|key|p12|pfx|crt|cer|jks)$/i.test(base)) return "key-file";
  if (/(credential|credentials|secrets?)\.(json|ya?ml|toml|ini|conf)$/i.test(base) || /(credential|credentials|secrets?)\//i.test(filePath)) return "credential-config";
  if (/(token|apikey|api-key|password|passwd)/i.test(filePath)) return "token-path";
  return "unknown";
}

function secretConfigSignals(sourceFiles: SecretSourceFile[]): SecretReadinessReport["configSignals"] {
  const rows: SecretReadinessReport["configSignals"] = [];
  for (const source of sourceFiles) {
    for (const signal of secretConfigSignalTypes(source.filePath, source.text)) {
      rows.push({
        filePath: source.filePath,
        signal,
        readiness: signal === "unknown" ? "partial" : "ready",
        evidence: secretConfigSignalEvidence(source.filePath, signal),
        sourceHref: source.sourceHref
      });
    }
  }
  return rows.slice(0, 140);
}

function secretConfigSignalTypes(filePath: string, text: string): SecretReadinessReport["configSignals"][number]["signal"][] {
  const signals = new Set<SecretReadinessReport["configSignals"][number]["signal"]>();
  if (/\.gitleaks\.toml$|gitleaks\.toml$/i.test(filePath) || /GITLEAKS_CONFIG|GITLEAKS_CONFIG_TOML/i.test(text)) signals.add("gitleaks-config");
  if (/\[extend\]|useDefault|disabledRules|path\s*=.*gitleaks/i.test(text)) signals.add("extend-default");
  if (/\[\[rules\]\]|id\s*=|description\s*=|regex\s*=|path\s*=/i.test(text)) signals.add("custom-rule");
  if (/entropy\s*=/i.test(text)) signals.add("entropy");
  if (/secretGroup\s*=/i.test(text)) signals.add("secret-group");
  if (/keywords\s*=/i.test(text)) signals.add("keywords");
  if (/allowlists?|targetRules|stopwords|regexTarget/i.test(text)) signals.add("allowlist");
  if (/\.gitleaksignore$/i.test(filePath) || /Fingerprint|gitleaksignore/i.test(text)) signals.add("gitleaksignore");
  if (/gitleaks:allow/i.test(text)) signals.add("allow-comment");
  if (signals.size === 0 && secretContentSignal(text)) signals.add("unknown");
  return [...signals];
}

function secretConfigSignalEvidence(filePath: string, signal: SecretReadinessReport["configSignals"][number]["signal"]): string {
  if (signal === "gitleaks-config") return `${filePath} provides or references Gitleaks configuration.`;
  if (signal === "extend-default") return `${filePath} config extends default or shared Gitleaks rules.`;
  if (signal === "custom-rule") return `${filePath} contains custom rule metadata or regex evidence.`;
  if (signal === "entropy") return `${filePath} config references entropy thresholds.`;
  if (signal === "secret-group") return `${filePath} config references secretGroup extraction.`;
  if (signal === "keywords") return `${filePath} config references keyword prefilters.`;
  if (signal === "allowlist") return `${filePath} config references allowlist criteria.`;
  if (signal === "gitleaksignore") return `${filePath} references finding fingerprint ignore workflow.`;
  if (signal === "allow-comment") return `${filePath} references inline gitleaks:allow suppression.`;
  return `${filePath} contains secret-scanning configuration evidence.`;
}

function secretScanTargets(sourceFiles: SecretSourceFile[], walk: WalkResult): SecretReadinessReport["scanTargets"] {
  const specs: Array<{ target: SecretReadinessReport["scanTargets"][number]["target"]; pattern: RegExp; evidence: string }> = [
    { target: "git-history", pattern: /gitleaks\s+(git|detect)|git log -p|log-opts/i, evidence: "git history scan evidence was detected." },
    { target: "working-tree", pattern: /gitleaks\s+(dir|files|directory)|scan directories|scan files/i, evidence: "directory or file scan evidence was detected." },
    { target: "stdin", pattern: /gitleaks\s+stdin|detect secrets from stdin/i, evidence: "stdin scan evidence was detected." },
    { target: "pre-commit", pattern: /pre-commit|--pre-commit|\.pre-commit-config/i, evidence: "pre-commit scan evidence was detected." },
    { target: "archive", pattern: /max-archive-depth|archive scanning|zip|tarball/i, evidence: "archive scan evidence was detected." },
    { target: "config", pattern: /\.gitleaks\.toml|--config|GITLEAKS_CONFIG/i, evidence: "config-driven scan evidence was detected." }
  ];
  return specs.map((spec) => {
    const match = sourceFiles.find((source) => spec.pattern.test(source.text) || spec.pattern.test(source.filePath));
    const hasSurface = walk.files.some((file) => file.isTextCandidate) || walk.secretCandidatePaths.length > 0;
    return {
      target: spec.target,
      readiness: match ? "ready" : hasSurface ? "external" : "missing",
      evidence: match ? `${match.filePath} ${spec.evidence}` : `${spec.target} scan target evidence was not detected.`,
      relatedHref: match?.sourceHref ?? "html/secret-readiness.html"
    };
  });
}

function secretReportingSignals(sourceFiles: SecretSourceFile[]): SecretReadinessReport["reportingSignals"] {
  const specs: Array<{ signal: SecretReadinessReport["reportingSignals"][number]["signal"]; pattern: RegExp; evidence: string }> = [
    { signal: "json", pattern: /report-format\s+(json|.*json)|--report-format[=\s]+json/i, evidence: "JSON report output evidence was detected." },
    { signal: "csv", pattern: /report-format\s+(csv|.*csv)|--report-format[=\s]+csv/i, evidence: "CSV report output evidence was detected." },
    { signal: "junit", pattern: /report-format\s+(junit|.*junit)|--report-format[=\s]+junit/i, evidence: "JUnit report output evidence was detected." },
    { signal: "sarif", pattern: /sarif|--report-format[=\s]+sarif/i, evidence: "SARIF report output evidence was detected." },
    { signal: "template", pattern: /--report-template|report format template|\.tmpl/i, evidence: "custom template report evidence was detected." },
    { signal: "report-path", pattern: /--report-path|report-path|gitleaks-report\.json|findings\.json/i, evidence: "durable report path evidence was detected." },
    { signal: "baseline", pattern: /--baseline-path|baseline-path|baseline/i, evidence: "baseline report evidence was detected." },
    { signal: "fingerprint", pattern: /Fingerprint|fingerprint/i, evidence: "finding fingerprint evidence was detected." },
    { signal: "redaction", pattern: /--redact|redact/i, evidence: "redacted output evidence was detected." }
  ];
  return specs.map((spec) => secretReadinessFromSpecs(sourceFiles, spec, "reporting"));
}

function secretPreventionSignals(sourceFiles: SecretSourceFile[]): SecretReadinessReport["preventionSignals"] {
  const specs: Array<{ signal: SecretReadinessReport["preventionSignals"][number]["signal"]; pattern: RegExp; evidence: string }> = [
    { signal: "pre-commit", pattern: /pre-commit|\.pre-commit-config|\.pre-commit-hooks/i, evidence: "pre-commit hook evidence was detected." },
    { signal: "staged", pattern: /--staged|staged/i, evidence: "staged diff scan evidence was detected." },
    { signal: "git-hook", pattern: /\.git\/hooks|git hooks?|pre-commit\.py/i, evidence: "git hook installation evidence was detected." },
    { signal: "github-action", pattern: /gitleaks-action|uses:\s*gitleaks|github action/i, evidence: "GitHub Action scanner evidence was detected." },
    { signal: "ci", pattern: /^\.github\/workflows\//i, evidence: "CI workflow can host secret scanning." },
    { signal: "exit-code", pattern: /--exit-code|exit-code/i, evidence: "scanner failure exit code evidence was detected." },
    { signal: "protect-legacy", pattern: /gitleaks\s+protect|protect command/i, evidence: "legacy protect command evidence was detected." }
  ];
  return specs.map((spec) => secretReadinessFromSpecs(sourceFiles, spec, "prevention"));
}

function secretAdvancedSignals(sourceFiles: SecretSourceFile[]): SecretReadinessReport["advancedSignals"] {
  const specs: Array<{ signal: SecretReadinessReport["advancedSignals"][number]["signal"]; pattern: RegExp; evidence: string }> = [
    { signal: "decode-depth", pattern: /--max-decode-depth|max-decode-depth|decoded:/i, evidence: "recursive decoding evidence was detected." },
    { signal: "archive-depth", pattern: /--max-archive-depth|max-archive-depth|archive scanning/i, evidence: "archive traversal evidence was detected." },
    { signal: "diagnostics", pattern: /--diagnostics|diagnostics-dir|pprof|cpu,mem,trace/i, evidence: "diagnostics evidence was detected." },
    { signal: "enable-rule", pattern: /--enable-rule|enable-rule/i, evidence: "rule selection evidence was detected." },
    { signal: "log-opts", pattern: /--log-opts|log-opts|git log -p/i, evidence: "git log option evidence was detected." },
    { signal: "timeout", pattern: /--timeout|timeout/i, evidence: "scanner timeout control evidence was detected." }
  ];
  return specs.map((spec) => secretReadinessFromSpecs(sourceFiles, spec, "advanced"));
}

function secretReadinessFromSpecs<T extends string>(
  sourceFiles: SecretSourceFile[],
  spec: { signal: T; pattern: RegExp; evidence: string },
  label: string
): { signal: T; readiness: "ready" | "partial" | "missing" | "external"; evidence: string; relatedHref: string } {
  const match = sourceFiles.find((source) => spec.pattern.test(source.text) || spec.pattern.test(source.filePath));
  return {
    signal: spec.signal,
    readiness: match ? "ready" : sourceFiles.length > 0 ? "external" : "missing",
    evidence: match ? `${match.filePath} ${spec.evidence}` : `${spec.signal} ${label} evidence was not detected.`,
    relatedHref: match?.sourceHref ?? "html/secret-readiness.html"
  };
}

async function buildSecretManagementReadinessReport(walk: WalkResult): Promise<SecretManagementReadinessReport> {
  const sourceFiles = await secretManagementSourceFiles(walk);
  const secretManagementSetups = secretManagementSetupRows(sourceFiles);
  const platformSignals = secretManagementPlatformSignals(sourceFiles);
  const authSignals = secretManagementAuthSignals(sourceFiles);
  const storageSignals = secretManagementStorageSignals(sourceFiles);
  const deliverySignals = secretManagementDeliverySignals(sourceFiles);
  const governanceSignals = secretManagementGovernanceSignals(sourceFiles);
  const packageSignals = secretManagementPackageSignals(sourceFiles);
  const hasPlatform = platformSignals.some((item) => item.readiness === "ready" && item.signal !== "custom");
  const hasAuth = authSignals.some((item) => item.readiness === "ready");
  const hasPolicy = governanceSignals.some((item) => ["policy", "rbac"].includes(item.signal) && item.readiness === "ready");
  const hasDelivery = deliverySignals.some((item) => item.readiness === "ready");
  const hasRotationOrLease = governanceSignals.some((item) => ["rotation", "lease"].includes(item.signal) && item.readiness === "ready")
    || secretManagementSetups.some((item) => item.rotationCount > 0 || item.leaseCount > 0);
  const hasAudit = governanceSignals.some((item) => item.signal === "audit-log" && item.readiness === "ready")
    || secretManagementSetups.some((item) => item.auditCount > 0);
  const hasEncryption = storageSignals.some((item) => ["transit", "certificate"].includes(item.signal) && item.readiness === "ready")
    || secretManagementSetups.some((item) => item.encryptionCount > 0);

  const riskQueue: SecretManagementReadinessReport["riskQueue"] = [];
  if (!hasPlatform) {
    riskQueue.push({
      priority: "high",
      action: "Identify the runtime secret-management platform before treating secrets as operationally managed.",
      why: "Secret scanning can catch leaks, but production operation also needs a system of record such as Vault, Infisical, Doppler, SOPS, or Kubernetes secret controllers.",
      relatedHref: "html/secret-management-readiness.html"
    });
  }
  if (hasPlatform && (!hasAuth || !hasPolicy)) {
    riskQueue.push({
      priority: "high",
      action: "Pair the secret-management platform with explicit auth methods and policy or RBAC controls.",
      why: "A configured platform without auth and authorization evidence can still expose broad tokens or unmanaged access paths.",
      relatedHref: "html/secret-management-readiness.html"
    });
  }
  if (hasPlatform && !hasDelivery) {
    riskQueue.push({
      priority: "medium",
      action: "Document how applications receive secrets at runtime.",
      why: "Operators need to know whether secrets are injected through CLI wrappers, agents, Kubernetes operators, sync controllers, CI/CD, or SDK/API calls.",
      relatedHref: "html/secret-management-readiness.html"
    });
  }
  if (hasPlatform && !hasRotationOrLease) {
    riskQueue.push({
      priority: "medium",
      action: "Add rotation, TTL, lease, renew, or revoke evidence for secrets that should not be static.",
      why: "Managed secret systems are strongest when credentials expire or rotate instead of persisting indefinitely.",
      relatedHref: "html/secret-management-readiness.html"
    });
  }
  if (hasPlatform && !hasAudit) {
    riskQueue.push({
      priority: "low",
      action: "Expose audit logs or telemetry for secret access.",
      why: "Access logs make incident review and permission drift visible.",
      relatedHref: "html/secret-management-readiness.html"
    });
  }
  if (hasPlatform && !hasEncryption) {
    riskQueue.push({
      priority: "low",
      action: "Record encryption, KMS, SOPS, transit, PKI, or certificate-management evidence.",
      why: "Secret management often includes encryption workflows beyond simple key/value storage.",
      relatedHref: "html/secret-management-readiness.html"
    });
  }

  return {
    summary: `Secret-management readiness report: platform signal ${platformSignals.filter((item) => item.readiness === "ready").length}개, auth signal ${authSignals.filter((item) => item.readiness === "ready").length}개, delivery signal ${deliverySignals.filter((item) => item.readiness === "ready").length}개, governance signal ${governanceSignals.filter((item) => item.readiness === "ready").length}개를 정적 분석으로 정리했습니다.`,
    sourcePattern: "Secrets management readiness Vault Infisical Doppler SOPS Sealed Secrets External Secrets secret engines auth methods policies tokens leases rotation transit kv env injection sync Kubernetes operator agent CLI SDK API audit logs dynamic secrets",
    secretManagementSetups,
    platformSignals,
    authSignals,
    storageSignals,
    deliverySignals,
    governanceSignals,
    packageSignals,
    riskQueue: riskQueue.sort((a, b) => ({ high: 0, medium: 1, low: 2 }[a.priority] - { high: 0, medium: 1, low: 2 }[b.priority])),
    recommendedCommands: [
      { command: "rg \"Vault|VAULT_ADDR|vault kv|vault secrets|Infisical|infisical|Doppler|doppler run|doppler setup\" package.json src app docs .github", purpose: "Find platform-specific secret-management references across code, docs, and workflows." },
      { command: "rg \"auth method|AppRole|kubernetes auth|oidc|aws auth|gcp auth|azure auth|universal auth|token|policy|rbac\" src app docs infra config", purpose: "Review auth method and authorization evidence for secret-management access." },
      { command: "rg \"SOPS|\\.sops|SealedSecret|ExternalSecret|SecretStore|ClusterSecretStore|rotation|lease|audit log|transit|pki|dynamic secrets\" .", purpose: "Find encryption, Kubernetes sync, rotation, lease, and audit-log readiness signals." }
    ],
    learnerNextSteps: [
      "Secret scanning과 secret management를 분리해서 보세요. 스캐너는 유출 탐지이고, Vault/Infisical/Doppler/SOPS 계열은 운영·전달·회전 체계입니다.",
      "플랫폼 이름만 있으면 부족합니다. auth method, policy/RBAC, delivery path, audit log, rotation/lease 증거를 같이 확인하세요.",
      "Kubernetes에서는 ExternalSecret, SecretStore, ClusterSecretStore, SealedSecret이 실제 배포 경로와 연결되는지 추적하세요.",
      "RepoTutor는 설정을 실행하지 않습니다. 실제 플랫폼 CLI/API 검증은 원본 환경에서 별도 수행해야 합니다."
    ]
  };
}

type SecretManagementSourceFile = {
  filePath: string;
  text: string;
  sourceHref: string;
};

async function secretManagementSourceFiles(walk: WalkResult): Promise<SecretManagementSourceFile[]> {
  const files: SecretManagementSourceFile[] = [];
  for (const file of walk.files) {
    if (!file.isTextCandidate || !secretManagementInspectablePath(file.relPath)) continue;
    const text = await readTextIfSafe(file.absPath, 200_000);
    if (!text) continue;
    if (!secretManagementPathSignal(file.relPath) && !secretManagementContentSignal(text)) continue;
    files.push({ filePath: file.relPath, text, sourceHref: `source/${encodedPath(file.relPath)}` });
    if (files.length >= 220) break;
  }
  return files;
}

function secretManagementInspectablePath(filePath: string): boolean {
  const base = path.basename(filePath);
  return /^(package\.json|README\.md|SECURITY\.md|\.sops\.ya?ml|sops\.ya?ml|vault\.(hcl|json|ya?ml|toml)|infisical\.(json|ya?ml|toml)|doppler\.(json|ya?ml|toml))$/i.test(base)
    || /^\.github\/workflows\/.+\.ya?ml$/i.test(filePath)
    || /(vault|infisical|doppler|sops|sealed-?secret|external-?secret|secret-store|clustersecretstore|secrets?-management|secret-sync|pki|kms)/i.test(filePath)
    || /\.(hcl|toml|ya?ml|json|md|js|jsx|ts|tsx|mjs|cjs|go|py|rb|sh|env|example|sample)$/i.test(filePath);
}

function secretManagementPathSignal(filePath: string): boolean {
  return /(vault|infisical|doppler|sops|sealed-?secret|external-?secret|secret-store|clustersecretstore|secrets?-management|secret-sync|pki|kms|secret)/i.test(filePath);
}

function secretManagementContentSignal(text: string): boolean {
  return /(Vault|vault\s+(kv|secrets|auth|policy|login)|VAULT_ADDR|VAULT_TOKEN|Infisical|infisical|Doppler|doppler\s+(run|setup|login|secrets)|SOPS|\.sops|SealedSecret|ExternalSecret|SecretStore|ClusterSecretStore|secret engine|auth method|AppRole|transit|lease|rotation|audit log|dynamic secrets|env injection|secret sync|machine identity|Universal Auth|Kubernetes Operator|External Secrets)/i.test(text);
}

function secretManagementSetupRows(sourceFiles: SecretManagementSourceFile[]): SecretManagementReadinessReport["secretManagementSetups"] {
  return sourceFiles.map((source): SecretManagementReadinessReport["secretManagementSetups"][number] => {
    const authCount = countMatches(source.text, /(auth method|login|token|AppRole|Kubernetes Auth|kubernetes auth|OIDC|AWS Auth|GCP Auth|Azure Auth|Universal Auth|machine identity|service token)/gi);
    const engineCount = countMatches(source.text, /(secret engine|kv|transit|pki|database secrets|dynamic secrets|secret mount|vault secrets enable|certificates?)/gi);
    const policyCount = countMatches(source.text, /(policy|policies|rbac|role|permission|least privilege|access request|break glass)/gi);
    const injectionCount = countMatches(source.text, /(doppler run|infisical run|env injection|agent|sidecar|template|envFrom|secretRef|secrets\.inject)/gi);
    const rotationCount = countMatches(source.text, /(rotation|rotate|dynamic|TTL|lease|renew|revoke|expiry|expiration)/gi);
    const syncCount = countMatches(source.text, /(sync|Kubernetes Operator|ExternalSecret|SecretStore|ClusterSecretStore|SealedSecret|certificate sync)/gi);
    const auditCount = countMatches(source.text, /(audit|audit log|logs|telemetry|metrics|access log|event)/gi);
    const leaseCount = countMatches(source.text, /(lease|renew|revoke|ttl|token TTL|max_ttl)/gi);
    const encryptionCount = countMatches(source.text, /(transit|kms|SOPS|age|pgp|sealed secret|encryption as a service|encrypt|decrypt)/gi);
    const cliCount = countMatches(source.text, /(vault\s+(kv|login|secrets|auth|policy)|infisical\s+(run|login|secrets|export)|doppler\s+(run|setup|login|secrets)|sops\b)/gi);
    const filledBuckets = [authCount, engineCount, policyCount, injectionCount, rotationCount, syncCount, auditCount, leaseCount, encryptionCount, cliCount].filter((count) => count > 0).length;
    return {
      filePath: source.filePath,
      provider: secretManagementProvider(source),
      authCount,
      engineCount,
      policyCount,
      injectionCount,
      rotationCount,
      syncCount,
      auditCount,
      leaseCount,
      encryptionCount,
      cliCount,
      readiness: filledBuckets >= 4 ? "ready" : filledBuckets > 0 ? "partial" : "missing",
      evidence: `${source.filePath} contains secret-management platform, delivery, governance, or package evidence.`,
      sourceHref: source.sourceHref
    };
  }).slice(0, 140);
}

function secretManagementProvider(source: SecretManagementSourceFile): SecretManagementReadinessReport["secretManagementSetups"][number]["provider"] {
  const combined = `${source.filePath}\n${source.text}`;
  if (/Vault|VAULT_|vault\s+(kv|secrets|auth|policy|login)|node-vault/i.test(combined)) return "vault";
  if (/Infisical|@infisical\/sdk|infisical/i.test(combined)) return "infisical";
  if (/Doppler|doppler\s+(run|setup|login|secrets)/i.test(combined)) return "doppler";
  if (/\.sops|SOPS|\bsops\b|age|pgp/i.test(combined)) return "sops";
  if (/SealedSecret|sealed-?secrets?|kubeseal/i.test(combined)) return "sealed-secrets";
  if (/ExternalSecret|SecretStore|ClusterSecretStore|external-?secrets?/i.test(combined)) return "external-secrets";
  if (/secret management|secret sync|dynamic secrets|env injection/i.test(combined)) return "custom";
  return "unknown";
}

function secretManagementPlatformSignals(sourceFiles: SecretManagementSourceFile[]): SecretManagementReadinessReport["platformSignals"] {
  const specs: Array<{ signal: SecretManagementReadinessReport["platformSignals"][number]["signal"]; pattern: RegExp; evidence: string }> = [
    { signal: "vault", pattern: /Vault|VAULT_|vault\s+(kv|secrets|auth|policy|login)|node-vault/i, evidence: "Vault platform evidence was detected." },
    { signal: "infisical", pattern: /Infisical|@infisical\/sdk|infisical/i, evidence: "Infisical platform evidence was detected." },
    { signal: "doppler", pattern: /Doppler|doppler\s+(run|setup|login|secrets)/i, evidence: "Doppler platform evidence was detected." },
    { signal: "sops", pattern: /\.sops|SOPS|\bsops\b|age|pgp/i, evidence: "SOPS encrypted file workflow evidence was detected." },
    { signal: "sealed-secrets", pattern: /SealedSecret|sealed-?secrets?|kubeseal/i, evidence: "Sealed Secrets evidence was detected." },
    { signal: "external-secrets", pattern: /ExternalSecret|SecretStore|ClusterSecretStore|external-?secrets?/i, evidence: "External Secrets evidence was detected." },
    { signal: "custom", pattern: /secret management|secret sync|dynamic secrets|env injection/i, evidence: "Custom secret-management evidence was detected." }
  ];
  return specs.map((spec) => secretManagementSignalFromSpecs(sourceFiles, spec, "platform"));
}

function secretManagementAuthSignals(sourceFiles: SecretManagementSourceFile[]): SecretManagementReadinessReport["authSignals"] {
  const specs: Array<{ signal: SecretManagementReadinessReport["authSignals"][number]["signal"]; pattern: RegExp; evidence: string }> = [
    { signal: "token", pattern: /\btoken\b|VAULT_TOKEN|service token|personal token/i, evidence: "token auth evidence was detected." },
    { signal: "approle", pattern: /AppRole|approle|role_id|secret_id/i, evidence: "AppRole auth evidence was detected." },
    { signal: "kubernetes-auth", pattern: /Kubernetes Auth|kubernetes auth|auth\/kubernetes|serviceaccount|service account/i, evidence: "Kubernetes auth evidence was detected." },
    { signal: "oidc", pattern: /OIDC|OpenID Connect|JWT auth|auth\/jwt/i, evidence: "OIDC or JWT auth evidence was detected." },
    { signal: "aws-auth", pattern: /AWS Auth|aws auth|auth\/aws|IAM role|IAM auth/i, evidence: "AWS auth evidence was detected." },
    { signal: "gcp-auth", pattern: /GCP Auth|gcp auth|auth\/gcp|Google Cloud auth/i, evidence: "GCP auth evidence was detected." },
    { signal: "azure-auth", pattern: /Azure Auth|azure auth|auth\/azure|managed identity/i, evidence: "Azure auth evidence was detected." },
    { signal: "universal-auth", pattern: /Universal Auth|machine identity|client secret|client id/i, evidence: "Universal or machine identity auth evidence was detected." }
  ];
  return specs.map((spec) => secretManagementSignalFromSpecs(sourceFiles, spec, "auth"));
}

function secretManagementStorageSignals(sourceFiles: SecretManagementSourceFile[]): SecretManagementReadinessReport["storageSignals"] {
  const specs: Array<{ signal: SecretManagementReadinessReport["storageSignals"][number]["signal"]; pattern: RegExp; evidence: string }> = [
    { signal: "kv", pattern: /\bkv\b|key\/value|key-value|vault kv/i, evidence: "key/value secret storage evidence was detected." },
    { signal: "secret-engine", pattern: /secret engine|vault secrets enable|secret mount/i, evidence: "secret engine evidence was detected." },
    { signal: "dynamic-secrets", pattern: /dynamic secrets?|database credentials?|leased credentials?/i, evidence: "dynamic secret evidence was detected." },
    { signal: "pki", pattern: /\bpki\b|PKI|certificate authority/i, evidence: "PKI evidence was detected." },
    { signal: "transit", pattern: /transit|encryption as a service/i, evidence: "transit encryption evidence was detected." },
    { signal: "certificate", pattern: /certificates?|certificate sync|TLS cert/i, evidence: "certificate management evidence was detected." },
    { signal: "database-credentials", pattern: /database secrets?|database credentials?|db credentials?/i, evidence: "database credential evidence was detected." },
    { signal: "environment-config", pattern: /environment config|app config|env injection|doppler run|infisical run/i, evidence: "environment configuration evidence was detected." }
  ];
  return specs.map((spec) => secretManagementSignalFromSpecs(sourceFiles, spec, "storage"));
}

function secretManagementDeliverySignals(sourceFiles: SecretManagementSourceFile[]): SecretManagementReadinessReport["deliverySignals"] {
  const specs: Array<{ signal: SecretManagementReadinessReport["deliverySignals"][number]["signal"]; pattern: RegExp; evidence: string }> = [
    { signal: "env-injection", pattern: /env injection|environment injection|envFrom|secretRef|doppler run|infisical run/i, evidence: "environment injection evidence was detected." },
    { signal: "cli-run", pattern: /doppler run|infisical run|vault\s+(kv|login|secrets|auth|policy)|sops\b/i, evidence: "CLI runtime evidence was detected." },
    { signal: "agent", pattern: /agent|sidecar|vault agent|infisical agent|template/i, evidence: "agent or sidecar delivery evidence was detected." },
    { signal: "kubernetes-operator", pattern: /Kubernetes Operator|operator|ExternalSecret|SecretStore|ClusterSecretStore/i, evidence: "Kubernetes operator evidence was detected." },
    { signal: "sync", pattern: /sync|secret sync|certificate sync|ExternalSecret|SealedSecret/i, evidence: "secret sync evidence was detected." },
    { signal: "github-action", pattern: /GitHub Action|github action|uses:\s*.*(vault|infisical|doppler|sops|external-secrets)/i, evidence: "GitHub Action delivery evidence was detected." },
    { signal: "ci-cd", pattern: /CI\/CD|continuous integration|pipeline|workflow|gitlab-ci|circleci|jenkins/i, evidence: "CI/CD delivery evidence was detected." },
    { signal: "sdk-api", pattern: /SDK|API|@infisical\/sdk|node-vault|client\.secrets|vault client/i, evidence: "SDK/API access evidence was detected." }
  ];
  return specs.map((spec) => secretManagementSignalFromSpecs(sourceFiles, spec, "delivery"));
}

function secretManagementGovernanceSignals(sourceFiles: SecretManagementSourceFile[]): SecretManagementReadinessReport["governanceSignals"] {
  const specs: Array<{ signal: SecretManagementReadinessReport["governanceSignals"][number]["signal"]; pattern: RegExp; evidence: string }> = [
    { signal: "policy", pattern: /policy|policies|vault policy|least privilege/i, evidence: "policy evidence was detected." },
    { signal: "rbac", pattern: /rbac|role-based|role binding|permission|role:/i, evidence: "RBAC or role evidence was detected." },
    { signal: "audit-log", pattern: /audit log|audit|access log|telemetry|metrics/i, evidence: "audit log or telemetry evidence was detected." },
    { signal: "lease", pattern: /lease|renew|revoke|ttl|token TTL|max_ttl/i, evidence: "lease lifecycle evidence was detected." },
    { signal: "rotation", pattern: /rotation|rotate|expiry|expiration|dynamic secret/i, evidence: "rotation evidence was detected." },
    { signal: "versioning", pattern: /versioning|versions?|kv-v2|versioned secrets?/i, evidence: "versioning evidence was detected." },
    { signal: "access-request", pattern: /access request|approval|temporary access|privileged access/i, evidence: "access request evidence was detected." },
    { signal: "break-glass", pattern: /break glass|break-glass|emergency access/i, evidence: "break-glass evidence was detected." }
  ];
  return specs.map((spec) => secretManagementSignalFromSpecs(sourceFiles, spec, "governance"));
}

function secretManagementPackageSignals(sourceFiles: SecretManagementSourceFile[]): SecretManagementReadinessReport["packageSignals"] {
  const specs: Array<{ signal: SecretManagementReadinessReport["packageSignals"][number]["signal"]; pattern: RegExp; evidence: string }> = [
    { signal: "@infisical/sdk", pattern: /@infisical\/sdk/i, evidence: "@infisical/sdk dependency evidence was detected." },
    { signal: "infisical", pattern: /"infisical"|\binfisical\b/i, evidence: "Infisical package or CLI evidence was detected." },
    { signal: "vault", pattern: /"vault"|\bvault\b/i, evidence: "Vault package or CLI evidence was detected." },
    { signal: "node-vault", pattern: /node-vault/i, evidence: "node-vault dependency evidence was detected." },
    { signal: "doppler", pattern: /"doppler"|\bdoppler\b/i, evidence: "Doppler package or CLI evidence was detected." },
    { signal: "sops", pattern: /"sops"|\bsops\b|\.sops/i, evidence: "SOPS package or config evidence was detected." },
    { signal: "sealed-secrets", pattern: /sealed-?secrets?|kubeseal|SealedSecret/i, evidence: "Sealed Secrets package or manifest evidence was detected." },
    { signal: "external-secrets", pattern: /external-?secrets?|ExternalSecret|SecretStore|ClusterSecretStore/i, evidence: "External Secrets package or manifest evidence was detected." }
  ];
  return specs.map((spec) => secretManagementSignalFromSpecs(sourceFiles, spec, "package"));
}

function secretManagementSignalFromSpecs<T extends string>(
  sourceFiles: SecretManagementSourceFile[],
  spec: { signal: T; pattern: RegExp; evidence: string },
  label: string
): { signal: T; readiness: "ready" | "missing"; evidence: string; relatedHref: string } {
  const match = sourceFiles.find((source) => spec.pattern.test(source.text) || spec.pattern.test(source.filePath));
  return {
    signal: spec.signal,
    readiness: match ? "ready" : "missing",
    evidence: match ? `${match.filePath} ${spec.evidence}` : `${spec.signal} ${label} evidence was not detected.`,
    relatedHref: match?.sourceHref ?? "html/secret-management-readiness.html"
  };
}

async function buildContainerReadinessReport(walk: WalkResult): Promise<ContainerReadinessReport> {
  const sourceFiles = await containerSourceFiles(walk);
  const dockerfiles = containerDockerfiles(sourceFiles);
  const composeFiles = containerComposeFiles(sourceFiles);
  const configSignals = containerConfigSignals(sourceFiles);
  const instructionRisks = containerInstructionRisks(dockerfiles, configSignals);
  const labelPolicy = containerLabelPolicy(dockerfiles, configSignals, sourceFiles);
  const integrationSignals = containerIntegrationSignals(sourceFiles);
  const dockerfileRows = dockerfiles.map(({ text: _text, ...row }) => row);
  const hasDockerfile = dockerfiles.length > 0;
  const hasConfig = configSignals.some((item) => item.signal === "hadolint-config");
  const hasRegistryPolicy = configSignals.some((item) => item.signal === "trusted-registries");
  const hasLabelSchema = configSignals.some((item) => item.signal === "label-schema");
  const hasIntegration = integrationSignals.some((item) => ["pre-commit", "github-action", "gitlab-ci", "circleci", "jenkins"].includes(item.signal) && item.readiness === "ready");
  const hasMachineReport = integrationSignals.some((item) => ["sarif", "junit", "code-quality-report"].includes(item.signal) && item.readiness === "ready");
  const observedRisks = instructionRisks.filter((item) => item.readiness === "partial");

  const riskQueue: ContainerReadinessReport["riskQueue"] = [];
  if (!hasDockerfile) {
    riskQueue.push({
      priority: "medium",
      action: "Add a Dockerfile only if this project is meant to build container images.",
      why: "Container readiness is irrelevant for libraries without images, but runtime apps should make image build assumptions visible.",
      relatedHref: "html/container-readiness.html"
    });
  }
  if (hasDockerfile && !hasConfig) {
    riskQueue.push({
      priority: "high",
      action: "Add .hadolint.yaml to document failure thresholds, ignored rules, registries, and label policy.",
      why: "Hadolint supports project-level config; undocumented CLI flags make Dockerfile quality gates hard to reproduce.",
      relatedHref: "html/container-readiness.html"
    });
  }
  if (hasDockerfile && !hasIntegration) {
    riskQueue.push({
      priority: "high",
      action: "Run Hadolint in pre-commit or CI before container builds are published.",
      why: "Dockerfile linting is most useful before image build and release steps, not after a broken image reaches users.",
      relatedHref: "html/container-readiness.html"
    });
  }
  if (hasDockerfile && !hasRegistryPolicy) {
    riskQueue.push({
      priority: "medium",
      action: "Declare trustedRegistries or a trusted registry CLI policy.",
      why: "Hadolint can warn when FROM images come from registries outside the allowed list.",
      relatedHref: "html/container-readiness.html"
    });
  }
  if (hasDockerfile && !hasLabelSchema) {
    riskQueue.push({
      priority: "medium",
      action: "Define an image label schema for version, source, license, and documentation labels.",
      why: "Labels make built images traceable; Hadolint can enforce label formats such as semver, hash, url, email, and SPDX.",
      relatedHref: "html/container-readiness.html"
    });
  }
  if (observedRisks.length > 0) {
    riskQueue.push({
      priority: "medium",
      action: "Review observed Dockerfile risk patterns before building images.",
      why: `${observedRisks.length} Hadolint-style rule pattern(s) were detected in copied Dockerfile text.`,
      relatedHref: "html/container-readiness.html"
    });
  }
  if (hasDockerfile && !hasMachineReport) {
    riskQueue.push({
      priority: "low",
      action: "Emit SARIF, JUnit, or code-quality output for Dockerfile lint findings.",
      why: "Machine-readable lint reports can be attached to CI artifacts and code scanning systems.",
      relatedHref: "html/container-readiness.html"
    });
  }
  riskQueue.push({
    priority: "low",
    action: "Run Hadolint against the original source tree before treating this report as lint approval.",
    why: "RepoTutor records static readiness patterns only; it does not parse the Dockerfile AST, execute ShellCheck, build images, or verify registry access.",
    relatedHref: "html/container-readiness.html"
  });

  return {
    summary: `Hadolint식 container readiness report: Dockerfile ${dockerfiles.length}개, Compose file ${composeFiles.length}개, config signal ${configSignals.length}개, instruction check ${instructionRisks.length}개를 정적 분석으로 정리했습니다.`,
    sourcePattern: "Hadolint Dockerfile AST ShellCheck rules config ignored rules severity overrides trusted registries labels SARIF JUnit CI pre-commit",
    dockerfiles: dockerfileRows,
    composeFiles,
    configSignals,
    instructionRisks,
    labelPolicy,
    integrationSignals,
    riskQueue: riskQueue.sort((a, b) => ({ high: 0, medium: 1, low: 2 }[a.priority] - { high: 0, medium: 1, low: 2 }[b.priority])),
    recommendedCommands: [
      { command: "hadolint Dockerfile", purpose: "Lint the default Dockerfile with Hadolint best-practice and ShellCheck-backed rules." },
      { command: "hadolint --config .hadolint.yaml Dockerfile", purpose: "Run with project-specific ignored rules, severity overrides, trusted registries, and label schema." },
      { command: "hadolint --format sarif Dockerfile > hadolint.sarif", purpose: "Write SARIF output for code scanning or CI artifact review." },
      { command: "hadolint --failure-threshold warning Dockerfile", purpose: "Fail only when findings meet the configured minimum severity." },
      { command: "docker run --rm -i hadolint/hadolint < Dockerfile", purpose: "Run Hadolint via its container image without installing a local binary." }
    ],
    learnerNextSteps: [
      "Dockerfile이 없다면 이 프로젝트가 container image를 배포해야 하는지부터 확인하세요.",
      "FROM image tag, USER, package pinning, COPY/ADD, HEALTHCHECK, pipefail은 beginner가 image 품질을 이해하기 좋은 첫 점검 항목입니다.",
      ".hadolint.yaml의 ignored rule은 예외 사유가 좁고 문서화되어 있는지 확인하세요.",
      "RepoTutor는 Docker build나 registry 검증을 하지 않으므로 실제 배포 전 원본 repo에서 Hadolint를 실행하세요."
    ]
  };
}

type ContainerSourceFile = {
  filePath: string;
  text: string;
  sourceHref: string;
};

type ContainerDockerfile = ContainerReadinessReport["dockerfiles"][number] & {
  text: string;
};

async function containerSourceFiles(walk: WalkResult): Promise<ContainerSourceFile[]> {
  const files: ContainerSourceFile[] = [];
  for (const file of walk.files) {
    if (!file.isTextCandidate || !containerInspectablePath(file.relPath)) continue;
    const text = await readTextIfSafe(file.absPath, 240_000);
    if (!text) continue;
    if (!containerPathSignal(file.relPath) && !containerContentSignal(text)) continue;
    files.push({ filePath: file.relPath, text, sourceHref: `source/${encodedPath(file.relPath)}` });
    if (files.length >= 220) break;
  }
  return files;
}

function containerInspectablePath(filePath: string): boolean {
  const base = path.basename(filePath);
  return /^(Dockerfile|Containerfile|docker-compose\.ya?ml|compose\.ya?ml|\.hadolint\.ya?ml|hadolint\.ya?ml|\.pre-commit-config\.ya?ml|README\.md|SECURITY\.md)$/i.test(base)
    || /\.dockerfile$/i.test(base)
    || /^\.github\/workflows\/.+\.ya?ml$/i.test(filePath)
    || /\.(ya?ml|json|md|sh)$/i.test(filePath);
}

function containerPathSignal(filePath: string): boolean {
  return /(Dockerfile|Containerfile|docker-compose|compose\.ya?ml|hadolint|container|image|pre-commit|workflow|gitlab-ci|circleci|jenkins)/i.test(filePath);
}

function containerContentSignal(text: string): boolean {
  return /\b(FROM|RUN|COPY|ADD|USER|HEALTHCHECK|ENTRYPOINT|CMD|LABEL)\b|hadolint|Dockerfile|trustedRegistries|failure-threshold|label-schema|strict-labels|disable-ignore-pragma|gitlab_codeclimate|sarif|junit/i.test(text);
}

function containerDockerfiles(sourceFiles: ContainerSourceFile[]): ContainerDockerfile[] {
  return sourceFiles
    .filter((source) => /(^|\/)(Dockerfile|Containerfile)(\.[^/]*)?$|\.dockerfile$/i.test(source.filePath))
    .map((source) => {
      const baseImages = [...source.text.matchAll(/^FROM\s+(?:--platform=\S+\s+)?([^\s#]+)(?:\s+AS\s+\S+)?/gim)].map((match) => match[1] ?? "").filter(Boolean);
      const instructionKinds = [...new Set([...source.text.matchAll(/^\s*([A-Z][A-Z0-9_-]+)\b/gm)].map((match) => match[1] ?? "").filter(Boolean))];
      return {
        filePath: source.filePath,
        stageCount: baseImages.length,
        baseImages,
        instructionKinds,
        readiness: baseImages.length > 0 ? "ready" : "partial",
        evidence: baseImages.length > 0 ? `${source.filePath} defines ${baseImages.length} FROM stage(s).` : `${source.filePath} is Dockerfile-like but no FROM instruction was detected.`,
        sourceHref: source.sourceHref,
        text: source.text
      };
    });
}

function containerComposeFiles(sourceFiles: ContainerSourceFile[]): ContainerReadinessReport["composeFiles"] {
  return sourceFiles
    .filter((source) => /(^|\/)(docker-compose|compose)\.ya?ml$/i.test(source.filePath))
    .map((source) => {
      const servicesBlock = source.text.match(/(?:^|\n)services:\s*\n([\s\S]*?)(?:\n\S|\s*$)/i)?.[1] ?? "";
      const serviceCount = [...servicesBlock.matchAll(/^\s{2,}([A-Za-z0-9_.-]+):\s*(?:#.*)?$/gm)].length;
      return {
        filePath: source.filePath,
        serviceCount,
        readiness: serviceCount > 0 ? "ready" : "partial",
        evidence: serviceCount > 0 ? `${source.filePath} declares ${serviceCount} Compose service(s).` : `${source.filePath} is compose-like but service count could not be inferred statically.`,
        sourceHref: source.sourceHref
      };
    });
}

function containerConfigSignals(sourceFiles: ContainerSourceFile[]): ContainerReadinessReport["configSignals"] {
  const rows: ContainerReadinessReport["configSignals"] = [];
  for (const source of sourceFiles) {
    for (const signal of containerConfigSignalTypes(source.filePath, source.text)) {
      rows.push({
        filePath: source.filePath,
        signal,
        readiness: signal === "unknown" ? "partial" : "ready",
        evidence: containerConfigEvidence(source.filePath, signal),
        sourceHref: source.sourceHref
      });
    }
  }
  return rows.slice(0, 140);
}

function containerConfigSignalTypes(filePath: string, text: string): ContainerReadinessReport["configSignals"][number]["signal"][] {
  const signals = new Set<ContainerReadinessReport["configSignals"][number]["signal"]>();
  if (/\.hadolint\.ya?ml$|hadolint\.ya?ml$/i.test(filePath) || /hadolint\s+--config|HADOLINT_/i.test(text)) signals.add("hadolint-config");
  if (/ignored:\s*\[|ignored:\s*\n|--ignore\s+DL|HADOLINT_IGNORE|#\s*hadolint\s+(global\s+)?ignore=/i.test(text)) signals.add("ignored-rules");
  if (/override:\s*\n|--(error|warning|info|style)\s+DL|HADOLINT_OVERRIDE_/i.test(text)) signals.add("severity-override");
  if (/failure-threshold|HADOLINT_FAILURE_THRESHOLD/i.test(text)) signals.add("failure-threshold");
  if (/trustedRegistries|trusted-registry|HADOLINT_TRUSTED_REGISTRIES/i.test(text)) signals.add("trusted-registries");
  if (/label-schema|require-label|HADOLINT_REQUIRE_LABELS/i.test(text)) signals.add("label-schema");
  if (/strict-labels|HADOLINT_STRICT_LABELS/i.test(text)) signals.add("strict-labels");
  if (/disable-ignore-pragma|HADOLINT_DISABLE_IGNORE_PRAGMA/i.test(text)) signals.add("disable-ignore-pragma");
  if (/--format\s+(json|checkstyle|codeclimate|gitlab_codeclimate|gnu|codacy|sonarqube|sarif|junit)|HADOLINT_FORMAT|format:\s*(json|sarif|junit|codeclimate|gitlab_codeclimate)/i.test(text)) signals.add("output-format");
  if (signals.size === 0 && /hadolint/i.test(text)) signals.add("unknown");
  return [...signals];
}

function containerConfigEvidence(filePath: string, signal: ContainerReadinessReport["configSignals"][number]["signal"]): string {
  if (signal === "hadolint-config") return `${filePath} provides or references Hadolint configuration.`;
  if (signal === "ignored-rules") return `${filePath} references Hadolint ignored rules or inline/global ignores.`;
  if (signal === "severity-override") return `${filePath} references Hadolint severity overrides.`;
  if (signal === "failure-threshold") return `${filePath} references failure threshold behavior.`;
  if (signal === "trusted-registries") return `${filePath} references trusted registry policy.`;
  if (signal === "label-schema") return `${filePath} references image label schema policy.`;
  if (signal === "strict-labels") return `${filePath} references strict label enforcement.`;
  if (signal === "disable-ignore-pragma") return `${filePath} disables inline ignore pragmas.`;
  if (signal === "output-format") return `${filePath} references machine-readable Hadolint output format.`;
  return `${filePath} contains Hadolint-related configuration evidence.`;
}

function containerInstructionRisks(dockerfiles: ContainerDockerfile[], configSignals: ContainerReadinessReport["configSignals"]): ContainerReadinessReport["instructionRisks"] {
  const allText = dockerfiles.map((item) => item.text).join("\n");
  const allDockerfiles = dockerfiles.map((item) => item.filePath).join(", ") || "Dockerfile";
  const hasDockerfile = dockerfiles.length > 0;
  const hasTrustedRegistry = configSignals.some((item) => item.signal === "trusted-registries");
  const specs: Array<{ rule: ContainerReadinessReport["instructionRisks"][number]["rule"]; severity: ContainerReadinessReport["instructionRisks"][number]["severity"]; pattern: RegExp; missingEvidence: string; hitEvidence: string }> = [
    { rule: "DL3002", severity: "warning", pattern: /(^|\n)\s*USER\s+root\b/i, missingEvidence: "No explicit USER root instruction was detected.", hitEvidence: "USER root pattern was detected." },
    { rule: "DL3006", severity: "warning", pattern: /^FROM\s+(?:--platform=\S+\s+)?(?:[^\s:@]+\/)?[^\s:@]+(?:\s|$)/gim, missingEvidence: "All detected FROM images appear to include a tag, digest, or alias-only reference.", hitEvidence: "FROM image without explicit tag or digest may be present." },
    { rule: "DL3007", severity: "warning", pattern: /^FROM\s+.*:latest\b/gim, missingEvidence: "No FROM latest tag was detected.", hitEvidence: "FROM latest tag was detected." },
    { rule: "DL3008", severity: "warning", pattern: /RUN\s+.*apt-get\s+.*install(?![^&;\n]*=)[^|\n]*/i, missingEvidence: "No obvious unpinned apt-get install pattern was detected.", hitEvidence: "apt-get install without visible version pin may be present." },
    { rule: "DL3013", severity: "warning", pattern: /RUN\s+.*(?:pip|pip3|python\s+-m\s+pip)\s+install(?![^&;\n]*(==|~=|>=|<=|!=|<|>|-r|--requirement|\.[\s;&|]|\.whl|\.tar\.gz))[^|\n]*/i, missingEvidence: "No obvious unpinned pip install pattern was detected.", hitEvidence: "pip install without visible version pin or requirements file may be present." },
    { rule: "DL3016", severity: "warning", pattern: /RUN\s+.*npm\s+install\s+(?!(-g\s+)?[^&;\n]*@)[A-Za-z0-9@/_-]+/i, missingEvidence: "No obvious unpinned npm install pattern was detected.", hitEvidence: "npm install without visible version pin may be present." },
    { rule: "DL3018", severity: "warning", pattern: /RUN\s+.*apk\s+add(?![^&;\n]*=)[^|\n]*/i, missingEvidence: "No obvious unpinned apk add pattern was detected.", hitEvidence: "apk add without visible version pin may be present." },
    { rule: "DL3020", severity: "error", pattern: /^ADD\s+(?!.*\.(tar|tgz|tar\.gz|zip)\b)/gim, missingEvidence: "No ADD-for-plain-copy pattern was detected.", hitEvidence: "ADD is used where COPY may be clearer." },
    { rule: "DL3025", severity: "warning", pattern: /^(CMD|ENTRYPOINT)\s+(?!\[)/gim, missingEvidence: "CMD/ENTRYPOINT instructions appear to use JSON notation when present.", hitEvidence: "Shell-form CMD or ENTRYPOINT was detected." },
    { rule: "DL3026", severity: "error", pattern: /^FROM\s+(?!scratch\b|[A-Za-z0-9_.-]+(?:\s+AS\s+\S+)?$)/gim, missingEvidence: hasTrustedRegistry ? "Trusted registry policy is configured." : "No trusted registry policy was found for FROM image validation.", hitEvidence: "FROM image registry should be checked against trustedRegistries." },
    { rule: "DL3042", severity: "warning", pattern: /RUN\s+.*(?:pip|pip3|python\s+-m\s+pip)\s+install(?![^&;\n]*--no-cache-dir)/i, missingEvidence: "No pip install without --no-cache-dir was detected.", hitEvidence: "pip install without --no-cache-dir may cache packages in the image layer." },
    { rule: "DL3057", severity: "info", pattern: /^HEALTHCHECK\b/gim, missingEvidence: "HEALTHCHECK was not detected.", hitEvidence: "HEALTHCHECK instruction was detected." },
    { rule: "DL3059", severity: "info", pattern: /^RUN\b[\s\S]*\n\s*RUN\b/i, missingEvidence: "Multiple consecutive RUN instructions were not detected.", hitEvidence: "Multiple consecutive RUN instructions may be present." },
    { rule: "DL4006", severity: "warning", pattern: /^RUN\s+.*\|.*$/gim, missingEvidence: "RUN pipelines were not detected.", hitEvidence: "RUN pipeline detected; SHELL pipefail should be reviewed." },
    { rule: "SC", severity: "external", pattern: /^RUN\s+.*(\$\(|`|&&|\|\||;)/gim, missingEvidence: "No complex shell RUN instruction was detected.", hitEvidence: "Complex RUN shell text exists; Hadolint delegates Bash checks to ShellCheck." }
  ];

  return specs.map((spec) => {
    const matched = hasDockerfile && spec.pattern.test(allText);
    spec.pattern.lastIndex = 0;
    const readiness = !hasDockerfile ? "missing" : matched ? "partial" : spec.rule === "DL3026" && !hasTrustedRegistry ? "external" : spec.rule === "DL3057" && !matched ? "external" : "ready";
    return {
      rule: spec.rule,
      severity: spec.severity,
      readiness,
      evidence: !hasDockerfile ? "No Dockerfile target was detected." : matched ? `${allDockerfiles}: ${spec.hitEvidence}` : spec.missingEvidence,
      relatedHref: matched ? dockerfiles[0]?.sourceHref ?? "html/container-readiness.html" : "html/container-readiness.html"
    };
  });
}

function containerLabelPolicy(dockerfiles: ContainerDockerfile[], configSignals: ContainerReadinessReport["configSignals"], sourceFiles: ContainerSourceFile[]): ContainerReadinessReport["labelPolicy"] {
  const allText = dockerfiles.map((item) => item.text).join("\n");
  const labelSchemaFiles = configSignals.filter((item) => item.signal === "label-schema");
  const labelSchemaSources = sourceFiles.filter((source) => labelSchemaFiles.some((item) => item.filePath === source.filePath));
  const hasDockerfile = dockerfiles.length > 0;
  const labels: ContainerReadinessReport["labelPolicy"][number]["label"][] = ["author", "contact", "created", "version", "documentation", "git-revision", "license"];
  return labels.map((label) => {
    const labelPattern = new RegExp(`(?:LABEL\\s+[^\\n]*\\b${label}\\b|label-schema:[\\s\\S]*\\b${label}\\b|${label}:\\s*(?:text|email|rfc3339|semver|url|hash|spdx))`, "i");
    const matchedDockerfile = labelPattern.test(allText);
    const matchedConfig = labelSchemaSources.find((source) => labelPattern.test(source.text));
    return {
      label,
      readiness: matchedDockerfile || matchedConfig ? "ready" : hasDockerfile ? "external" : "missing",
      evidence: matchedDockerfile ? `Dockerfile LABEL or schema evidence includes ${label}.` : matchedConfig ? `Hadolint label-schema config should be checked for ${label}.` : `${label} image label policy was not detected.`,
      relatedHref: matchedDockerfile ? dockerfiles[0]?.sourceHref ?? "html/container-readiness.html" : matchedConfig?.sourceHref ?? "html/container-readiness.html"
    };
  });
}

function containerIntegrationSignals(sourceFiles: ContainerSourceFile[]): ContainerReadinessReport["integrationSignals"] {
  const specs: Array<{ signal: ContainerReadinessReport["integrationSignals"][number]["signal"]; pattern: RegExp; evidence: string }> = [
    { signal: "pre-commit", pattern: /pre-commit|hadolint-docker|types:\s*\["?dockerfile/i, evidence: "pre-commit Hadolint hook evidence was detected." },
    { signal: "github-action", pattern: /hadolint-action|uses:\s*hadolint|hadolint\/hadolint-action/i, evidence: "GitHub Actions Hadolint evidence was detected." },
    { signal: "gitlab-ci", pattern: /gitlab_codeclimate|\.gitlab-ci|reports:\s*codequality/i, evidence: "GitLab code quality integration evidence was detected." },
    { signal: "circleci", pattern: /circleci|docker\/hadolint|ignore-rules|trusted-registries/i, evidence: "CircleCI Hadolint integration evidence was detected." },
    { signal: "jenkins", pattern: /Jenkinsfile|jenkins|archiveArtifacts|recordIssues/i, evidence: "Jenkins Hadolint integration evidence was detected." },
    { signal: "editor", pattern: /vscode-hadolint|Hadolint extension|editor integration/i, evidence: "editor integration evidence was detected." },
    { signal: "code-quality-report", pattern: /gitlab_codeclimate|codeclimate|sonarqube|codacy|checkstyle/i, evidence: "code quality report format evidence was detected." },
    { signal: "sarif", pattern: /--format\s+sarif|format:\s*sarif|HADOLINT_FORMAT=sarif/i, evidence: "SARIF report evidence was detected." },
    { signal: "junit", pattern: /--format\s+junit|format:\s*junit|HADOLINT_FORMAT=junit/i, evidence: "JUnit report evidence was detected." }
  ];
  return specs.map((spec) => {
    const match = sourceFiles.find((source) => spec.pattern.test(source.text) || spec.pattern.test(source.filePath));
    return {
      signal: spec.signal,
      readiness: match ? "ready" : sourceFiles.length > 0 ? "external" : "missing",
      evidence: match ? `${match.filePath} ${spec.evidence}` : `${spec.signal} integration evidence was not detected.`,
      relatedHref: match?.sourceHref ?? "html/container-readiness.html"
    };
  });
}

async function buildContainerScanReadinessReport(walk: WalkResult): Promise<ContainerScanReadinessReport> {
  const sourceFiles = await containerScanSourceFiles(walk);
  const containerScanSetups = containerScanSetupsFromSources(sourceFiles);
  const targetSignals = containerScanTargetSignals(sourceFiles);
  const scannerSignals = containerScanScannerSignals(sourceFiles);
  const gateSignals = containerScanGateSignals(sourceFiles);
  const outputSignals = containerScanOutputSignals(sourceFiles);
  const policySignals = containerScanPolicySignals(sourceFiles);
  const registrySignals = containerScanRegistrySignals(sourceFiles);
  const ciSignals = containerScanCiSignals(sourceFiles);
  const packageSignals = containerScanPackageSignals(sourceFiles);

  const hasImageTarget = targetSignals.some((item) => item.signal === "image" && item.readiness === "ready")
    || containerScanSetups.some((item) => item.imageCount > 0);
  const hasScanner = scannerSignals.some((item) => ["trivy", "grype", "dockle"].includes(item.signal) && item.readiness === "ready");
  const hasGate = gateSignals.some((item) => ["exit-code", "severity", "fail-on", "exit-level"].includes(item.signal) && item.readiness === "ready");
  const hasOutput = outputSignals.some((item) => ["json", "sarif", "cyclonedx", "spdx", "artifact-upload"].includes(item.signal) && item.readiness === "ready")
    || containerScanSetups.some((item) => item.outputCount > 0);
  const hasPolicy = policySignals.some((item) => item.readiness === "ready")
    || containerScanSetups.some((item) => item.policyCount > 0);
  const hasCi = ciSignals.some((item) => item.readiness === "ready")
    || containerScanSetups.some((item) => item.ciCount > 0);

  const riskQueue: ContainerScanReadinessReport["riskQueue"] = [];
  if (!hasImageTarget && hasScanner) {
    riskQueue.push({
      priority: "high",
      action: "Declare the container image, tar archive, filesystem, or SBOM target that scanners review.",
      why: "Container scan tools need a concrete image-ref, tar input, filesystem path, or SBOM source before the gate is reproducible.",
      relatedHref: "html/container-scan-readiness.html"
    });
  }
  if (!hasScanner) {
    riskQueue.push({
      priority: "high",
      action: "Add a Trivy, Grype, or Dockle scan before relying on image security readiness.",
      why: "Dockerfile linting and dependency review do not prove the built image was scanned for package vulnerabilities, misconfigurations, secrets, licenses, or CIS checks.",
      relatedHref: "html/container-scan-readiness.html"
    });
  }
  if (hasScanner && !hasGate) {
    riskQueue.push({
      priority: "high",
      action: "Set failure thresholds such as exit-code, severity, fail-on, or Dockle exit-level.",
      why: "Container scanners can report findings without failing CI unless the gate is explicit.",
      relatedHref: "html/container-scan-readiness.html"
    });
  }
  if (hasScanner && !hasOutput) {
    riskQueue.push({
      priority: "medium",
      action: "Persist JSON, SARIF, CycloneDX, SPDX, table/template, GitHub, or artifact output.",
      why: "Machine-readable scan output lets reviewers inspect findings after CI and feed code scanning or SBOM workflows.",
      relatedHref: "html/container-scan-readiness.html"
    });
  }
  if (hasScanner && !hasPolicy) {
    riskQueue.push({
      priority: "medium",
      action: "Document ignore, VEX, offline DB, or suspicious-file acceptance policy.",
      why: "Suppression policy is the boundary between accepted findings and hidden image risk.",
      relatedHref: "html/container-scan-readiness.html"
    });
  }
  if (hasScanner && !hasCi) {
    riskQueue.push({
      priority: "medium",
      action: "Attach image scanning to the build or pull-request workflow.",
      why: "Image scans are most useful when they run on the exact image tag or digest produced by CI.",
      relatedHref: "html/container-scan-readiness.html"
    });
  }
  riskQueue.push({
    priority: "low",
    action: "Run Trivy, Grype, Dockle, Docker, registry, vulnerability DB, and SARIF upload commands only in an authorized local or CI environment.",
    why: "RepoTutor records static container-scan readiness only and never builds images, pulls registries, downloads scanner databases, starts Docker, or uploads SARIF.",
    relatedHref: "html/container-scan-readiness.html"
  });

  return {
    summary: `Container scan readiness report: setup ${containerScanSetups.length}개, target signal ${targetSignals.length}개, scanner signal ${scannerSignals.length}개, gate signal ${gateSignals.length}개, output signal ${outputSignals.length}개를 정적 분석으로 정리했습니다.`,
    sourcePattern: "Container scan readiness Trivy Grype Dockle image filesystem SBOM vulnerability misconfig secret license CIS exit-code severity ignore-unfixed only-fixed fail-on exit-level SARIF CycloneDX SPDX JSON VEX trivyignore grype ignore dockleignore registry token docker-host",
    containerScanSetups,
    targetSignals,
    scannerSignals,
    gateSignals,
    outputSignals,
    policySignals,
    registrySignals,
    ciSignals,
    packageSignals,
    riskQueue: riskQueue.sort((a, b) => ({ high: 0, medium: 1, low: 2 }[a.priority] - { high: 0, medium: 1, low: 2 }[b.priority])),
    recommendedCommands: [
      { command: "rg \"trivy image|aquasecurity/trivy-action|image-ref|--scanners|--severity|--exit-code|--ignore-unfixed|--format sarif|--format cyclonedx|--format spdx\" .", purpose: "Find Trivy image targets, scanners, severity gates, ignore policy, and machine-readable output." },
      { command: "rg \"grype |anchore/grype|sbom:|--fail-on|--only-fixed|--by-cve|--scope|\\.grype\\.ya?ml|GRYPE_\" .", purpose: "Find Grype image/filesystem/SBOM targets, fail gates, config, and environment policy." },
      { command: "rg \"dockle|goodwithtech/dockle-action|--exit-code|--exit-level|\\.dockleignore|DOCKLE_IGNORES|accept-key|sensitive-file|CIS-DI|DKL-DI\" .", purpose: "Find Dockle CIS/best-practice gates, ignores, suspicious-file policy, and CI action usage." },
      { command: "rg \"docker build|docker save|image-ref|registry-token|docker-host|podman-host|platform|upload-sarif|upload-artifact|security-events: write\" .github .", purpose: "Find image build/source, registry auth, SARIF upload, and artifact retention evidence." }
    ],
    learnerNextSteps: [
      "Start from Container Scan Readiness after Dockerfile readiness so the image target and scan gate are separate.",
      "Check whether scanners review vulnerabilities, misconfigurations, secrets, licenses, and CIS checkpoints rather than only one finding class.",
      "Review ignore and VEX policy before treating a clean scan as proof of acceptable image risk.",
      "RepoTutor does not build images, access registries, download DBs, or upload SARIF; run the commands in authorized CI before release."
    ]
  };
}

type ContainerScanSourceFile = {
  filePath: string;
  text: string;
  sourceHref: string;
};

async function containerScanSourceFiles(walk: WalkResult): Promise<ContainerScanSourceFile[]> {
  const files: ContainerScanSourceFile[] = [];
  for (const file of walk.files) {
    if (!file.isTextCandidate || !containerScanInspectablePath(file.relPath)) continue;
    const text = await readTextIfSafe(file.absPath, 240_000);
    if (!text) continue;
    if (!containerScanPathSignal(file.relPath) && !containerScanContentSignal(text)) continue;
    files.push({ filePath: file.relPath, text, sourceHref: `source/${encodedPath(file.relPath)}` });
    if (files.length >= 240) break;
  }
  return files;
}

function containerScanInspectablePath(filePath: string): boolean {
  const base = path.basename(filePath);
  return containerScanPathSignal(filePath)
    || filePath.startsWith(".github/workflows/")
    || /(^|\/)(README|docs?|security|containers?|images?|scripts?|workflows?)(\/|\.|-|_|$)/i.test(filePath)
    || /^(package\.json|Dockerfile|Containerfile|docker-compose\.ya?ml|compose\.ya?ml|\.trivyignore|trivy\.ya?ml|trivy\.toml|\.grype\.ya?ml|\.dockleignore|Makefile|Taskfile\.ya?ml|justfile)$/i.test(base)
    || /\.(ya?ml|json|toml|md|sh)$/i.test(filePath);
}

function containerScanPathSignal(filePath: string): boolean {
  const base = path.basename(filePath);
  return /(trivy|grype|dockle|container[-_ ]?scan|image[-_ ]?scan|vulnerability[-_ ]?scan|scan[-_ ]?image|sbom|sarif)/i.test(filePath)
    || /^(trivy\.ya?ml|trivy\.toml|\.trivyignore|\.grype\.ya?ml|\.dockleignore)$/i.test(base);
}

function containerScanContentSignal(text: string): boolean {
  return /(trivy image|aquasecurity\/trivy-action|grype\s+(?:sbom:|docker:|oci:|registry:|dir:|\.|[A-Za-z0-9_.:/@-]+)|anchore\/grype|dockle|goodwithtech\/dockle-action|--scanners|--severity|--exit-code|--ignore-unfixed|--only-fixed|--fail-on|--exit-level|--format\s+(?:json|sarif|cyclonedx|spdx)|CycloneDX|SPDX|SARIF|\.trivyignore|\.grype|\.dockleignore|CIS-DI|DKL-DI|docker build|image-ref|registry-token|security-events: write)/i.test(text);
}

function containerScanSetupsFromSources(sourceFiles: ContainerScanSourceFile[]): ContainerScanReadinessReport["containerScanSetups"] {
  const rows: ContainerScanReadinessReport["containerScanSetups"] = [];
  for (const source of sourceFiles) {
    const imageCount = countMatches(source.text, /(trivy image|image-ref|docker build|docker save|dockle\s+[\w${}/:.@-]+|grype\s+(?:docker:|oci:|registry:)?[\w${}/:.@-]+|container image|IMAGE_NAME|IMAGE_NAME|platform|image-src)/gi);
    const vulnerabilityCount = countMatches(source.text, /(vulnerabilit|CVE|GHSA|trivy image|grype|--scanners\s+vuln|Known vulnerabilities|vulnerability database)/gi);
    const misconfigCount = countMatches(source.text, /(misconfig|IaC|Dockerfile|Kubernetes|CIS-DI|DKL-DI|CIS Benchmark|dockle|--image-config-scanners|--misconfig-scanners)/gi);
    const secretCount = countMatches(source.text, /(secret|Sensitive information|credential|DOCKLE_ACCEPT|DOCKLE_REJECT|sensitive-file|CIS-DI-0010|--scanners.*secret)/gi);
    const licenseCount = countMatches(source.text, /(license|--scanners.*license|--ignored-licenses|license-full|SPDX)/gi);
    const sbomCount = countMatches(source.text, /(SBOM|CycloneDX|SPDX|spdx-json|syft|sbom:|--format\s+cyclonedx|--format\s+spdx)/gi);
    const policyCount = countMatches(source.text, /(\.trivyignore|trivyignore|\.grype|ignore:|\.dockleignore|DOCKLE_IGNORES|--ignore|--ignore-policy|--ignore-unfixed|--only-fixed|--offline-scan|--skip-db-update|VEX|--vex|accept-key|sensitive-file)/gi);
    const outputCount = countMatches(source.text, /(SARIF|sarif|json|CycloneDX|SPDX|spdx-json|table|template|github|--output|-o\s+|upload-artifact|upload-sarif|artifact)/gi);
    const ciCount = countMatches(source.text, /(\.github\/workflows|github actions|pull_request|permissions:|security-events: write|docker build|upload-artifact|upload-sarif|trivy-action|dockle-action|anchore\/scan-action)/gi);
    const totalSignals = imageCount + vulnerabilityCount + misconfigCount + secretCount + licenseCount + sbomCount + policyCount + outputCount + ciCount;
    if (totalSignals === 0 && !containerScanPathSignal(source.filePath)) continue;
    rows.push({
      filePath: source.filePath,
      tool: containerScanTool(source),
      imageCount,
      vulnerabilityCount,
      misconfigCount,
      secretCount,
      licenseCount,
      sbomCount,
      policyCount,
      outputCount,
      ciCount,
      readiness: totalSignals >= 6 ? "ready" : totalSignals > 0 ? "partial" : "missing",
      evidence: `${totalSignals} container-scan readiness signal(s) detected in this file.`,
      sourceHref: source.sourceHref
    });
  }
  return rows.sort((a, b) => {
    const bScore = b.imageCount + b.vulnerabilityCount + b.misconfigCount + b.secretCount + b.licenseCount + b.sbomCount + b.policyCount + b.outputCount + b.ciCount;
    const aScore = a.imageCount + a.vulnerabilityCount + a.misconfigCount + a.secretCount + a.licenseCount + a.sbomCount + a.policyCount + a.outputCount + a.ciCount;
    return bScore - aScore || a.filePath.localeCompare(b.filePath);
  }).slice(0, 70);
}

function containerScanTool(source: ContainerScanSourceFile): ContainerScanReadinessReport["containerScanSetups"][number]["tool"] {
  if (/package\.json$/i.test(source.filePath) || /scripts?["']?\s*:/.test(source.text)) return "package-script";
  if (/trivy/i.test(source.filePath) || /trivy image|aquasecurity\/trivy-action|aquasec\/trivy/i.test(source.text)) return "trivy";
  if (/grype/i.test(source.filePath) || /\bgrype\b|anchore\/grype/i.test(source.text)) return "grype";
  if (/dockle/i.test(source.filePath) || /\bdockle\b|goodwithtech\/dockle-action/i.test(source.text)) return "dockle";
  if (/\.github\/workflows/i.test(source.filePath)) return "github-actions";
  if (/README|docs?/i.test(source.filePath)) return "readme";
  return "unknown";
}

function containerScanTargetSignals(sourceFiles: ContainerScanSourceFile[]): ContainerScanReadinessReport["targetSignals"] {
  return containerScanSignalFromSpecs(sourceFiles, [
    { signal: "image", pattern: /trivy image|image-ref|dockle\s+[\w${}/:.@-]+|grype\s+(?:docker:|oci:|registry:)?[\w${}/:.@-]+|container image/i, evidence: "container image scan target evidence was detected." },
    { signal: "filesystem", pattern: /trivy fs|filesystem|grype\s+(?:dir:)?\.|grype\s+\.\/|scan source/i, evidence: "filesystem scan target evidence was detected." },
    { signal: "sbom", pattern: /SBOM|sbom:|CycloneDX|SPDX|syft/i, evidence: "SBOM scan target evidence was detected." },
    { signal: "dockerfile", pattern: /Dockerfile|Containerfile|--image-config-scanners|CIS-DI|DKL-DI/i, evidence: "Dockerfile or image config target evidence was detected." },
    { signal: "kubernetes", pattern: /trivy k8s|Kubernetes|k8s|helm|--misconfig-scanners/i, evidence: "Kubernetes scan target evidence was detected." },
    { signal: "tar-input", pattern: /docker save|--input|image\.tar|alpine\.tar/i, evidence: "image tar input evidence was detected." },
    { signal: "registry", pattern: /registry|image-ref|ghcr\.io|docker\.io|quay\.io|ECR|GCR|DOCKLE_AUTH_URL/i, evidence: "registry image target evidence was detected." }
  ], "target");
}

function containerScanScannerSignals(sourceFiles: ContainerScanSourceFile[]): ContainerScanReadinessReport["scannerSignals"] {
  return containerScanSignalFromSpecs(sourceFiles, [
    { signal: "trivy", pattern: /trivy image|aquasecurity\/trivy-action|aquasec\/trivy|\.trivyignore/i, evidence: "Trivy evidence was detected." },
    { signal: "grype", pattern: /\bgrype\b|anchore\/grype|\.grype\.ya?ml/i, evidence: "Grype evidence was detected." },
    { signal: "dockle", pattern: /\bdockle\b|goodwithtech\/dockle-action|\.dockleignore/i, evidence: "Dockle evidence was detected." },
    { signal: "vulnerability", pattern: /vulnerabilit|CVE|GHSA|--scanners\s+vuln|Known vulnerabilities/i, evidence: "vulnerability scan evidence was detected." },
    { signal: "misconfig", pattern: /misconfig|IaC|Dockerfile|Kubernetes|CIS-DI|DKL-DI|--image-config-scanners|--misconfig-scanners/i, evidence: "misconfiguration scan evidence was detected." },
    { signal: "secret", pattern: /secret|Sensitive information|credential|CIS-DI-0010|--scanners.*secret/i, evidence: "secret scan evidence was detected." },
    { signal: "license", pattern: /license|--scanners.*license|--ignored-licenses|license-full|SPDX/i, evidence: "license scan evidence was detected." },
    { signal: "cis-benchmark", pattern: /CIS Benchmark|CIS-DI|DKL-DI|checkpoint|dockle/i, evidence: "CIS/checkpoint evidence was detected." }
  ], "scanner");
}

function containerScanGateSignals(sourceFiles: ContainerScanSourceFile[]): ContainerScanReadinessReport["gateSignals"] {
  return containerScanSignalFromSpecs(sourceFiles, [
    { signal: "exit-code", pattern: /--exit-code|exit-code:\s*['"]?\d|exit_code/i, evidence: "exit-code gate evidence was detected." },
    { signal: "severity", pattern: /--severity|severity:\s*(CRITICAL|HIGH|MEDIUM|LOW|UNKNOWN)|HIGH,CRITICAL|warn|fatal/i, evidence: "severity gate evidence was detected." },
    { signal: "ignore-unfixed", pattern: /--ignore-unfixed|ignore-unfixed/i, evidence: "ignore-unfixed evidence was detected." },
    { signal: "only-fixed", pattern: /--only-fixed|only-fixed/i, evidence: "only-fixed evidence was detected." },
    { signal: "fail-on", pattern: /--fail-on|fail-on|fail-on-severity/i, evidence: "fail-on gate evidence was detected." },
    { signal: "exit-level", pattern: /--exit-level|exit-level:\s*(warn|fatal|info)/i, evidence: "Dockle exit-level evidence was detected." },
    { signal: "ignore-policy", pattern: /--ignore-policy|ignore-policy|\.trivyignore|\.grype|\.dockleignore|DOCKLE_IGNORES/i, evidence: "ignore policy evidence was detected." }
  ], "gate");
}

function containerScanOutputSignals(sourceFiles: ContainerScanSourceFile[]): ContainerScanReadinessReport["outputSignals"] {
  return containerScanSignalFromSpecs(sourceFiles, [
    { signal: "json", pattern: /--format\s+json|-f\s+json|format:\s*json|\.json\b/i, evidence: "JSON output evidence was detected." },
    { signal: "sarif", pattern: /--format\s+sarif|-f\s+sarif|format:\s*sarif|SARIF|upload-sarif/i, evidence: "SARIF output evidence was detected." },
    { signal: "cyclonedx", pattern: /--format\s+cyclonedx|CycloneDX|cyclonedx/i, evidence: "CycloneDX output evidence was detected." },
    { signal: "spdx", pattern: /--format\s+spdx|spdx-json|SPDX/i, evidence: "SPDX output evidence was detected." },
    { signal: "table", pattern: /--format\s+table|format:\s*table|\btable\b/i, evidence: "table output evidence was detected." },
    { signal: "template", pattern: /--format\s+template|template:|\.tpl\b/i, evidence: "template output evidence was detected." },
    { signal: "github", pattern: /--format\s+github|format:\s*github|github code scanning/i, evidence: "GitHub output evidence was detected." },
    { signal: "artifact-upload", pattern: /upload-artifact|actions\/upload-artifact|artifact/i, evidence: "artifact upload evidence was detected." }
  ], "output");
}

function containerScanPolicySignals(sourceFiles: ContainerScanSourceFile[]): ContainerScanReadinessReport["policySignals"] {
  return containerScanSignalFromSpecs(sourceFiles, [
    { signal: "trivyignore", pattern: /\.trivyignore|trivyignore|--ignorefile/i, evidence: "Trivy ignore evidence was detected." },
    { signal: "grype-ignore", pattern: /\.grype\.ya?ml|ignore:\s|ignoredMatches|GRYPE_IGNORE/i, evidence: "Grype ignore evidence was detected." },
    { signal: "dockleignore", pattern: /\.dockleignore|DOCKLE_IGNORES|--ignore\s+CIS|--ignore\s+DKL/i, evidence: "Dockle ignore evidence was detected." },
    { signal: "vex", pattern: /\bVEX\b|OpenVEX|--vex|vex:/i, evidence: "VEX evidence was detected." },
    { signal: "ignore-policy", pattern: /--ignore-policy|ignore-policy|Rego/i, evidence: "ignore policy evidence was detected." },
    { signal: "accept-key", pattern: /accept-key|DOCKLE_ACCEPT_KEYS|accept-file|DOCKLE_ACCEPT_FILES/i, evidence: "accepted suspicious key/file evidence was detected." },
    { signal: "sensitive-file", pattern: /sensitive-file|DOCKLE_REJECT_FILES|sensitive-word|DOCKLE_REJECT_FILE_EXTENSIONS/i, evidence: "sensitive file/key policy evidence was detected." },
    { signal: "offline-db", pattern: /--offline-scan|--skip-db-update|--download-db-only|db-repository|vulnerability database/i, evidence: "offline or database policy evidence was detected." }
  ], "policy");
}

function containerScanRegistrySignals(sourceFiles: ContainerScanSourceFile[]): ContainerScanReadinessReport["registrySignals"] {
  return containerScanSignalFromSpecs(sourceFiles, [
    { signal: "image-ref", pattern: /image-ref|IMAGE_NAME|container image|docker build.*-t|ghcr\.io|docker\.io|quay\.io/i, evidence: "image reference evidence was detected." },
    { signal: "registry-token", pattern: /registry-token|TRIVY_PASSWORD|TRIVY_USERNAME|DOCKLE_AUTH|docker\/login-action|password-stdin/i, evidence: "registry credential evidence was detected." },
    { signal: "docker-host", pattern: /docker-host|DOCKER_HOST|\/var\/run\/docker\.sock/i, evidence: "Docker host evidence was detected." },
    { signal: "podman", pattern: /podman|podman-host/i, evidence: "Podman evidence was detected." },
    { signal: "private-registry", pattern: /private registry|self hosted registry|registry\.example|DOCKLE_AUTH_URL|registry-token/i, evidence: "private registry evidence was detected." },
    { signal: "platform", pattern: /--platform|platform:\s|linux\/amd64|linux\/arm64/i, evidence: "platform selection evidence was detected." }
  ], "registry");
}

function containerScanCiSignals(sourceFiles: ContainerScanSourceFile[]): ContainerScanReadinessReport["ciSignals"] {
  return containerScanSignalFromSpecs(sourceFiles, [
    { signal: "github-actions", pattern: /\.github\/workflows|github actions|actions\/checkout/i, evidence: "GitHub Actions evidence was detected." },
    { signal: "pull-request", pattern: /pull_request|merge_request|pull request/i, evidence: "pull-request evidence was detected." },
    { signal: "docker-build", pattern: /docker build|buildx|docker\/build-push-action/i, evidence: "Docker build evidence was detected." },
    { signal: "artifact-upload", pattern: /upload-artifact|actions\/upload-artifact|artifact/i, evidence: "artifact upload evidence was detected." },
    { signal: "sarif-upload", pattern: /upload-sarif|security-events: write|sarif_file/i, evidence: "SARIF upload evidence was detected." },
    { signal: "permissions", pattern: /permissions:|contents: read|security-events: write/i, evidence: "workflow permission evidence was detected." }
  ], "CI");
}

function containerScanPackageSignals(sourceFiles: ContainerScanSourceFile[]): ContainerScanReadinessReport["packageSignals"] {
  return containerScanSignalFromSpecs(sourceFiles, [
    { signal: "trivy-action", pattern: /aquasecurity\/trivy-action|aquasec\/trivy|\btrivy\b/i, evidence: "Trivy package/action evidence was detected." },
    { signal: "grype", pattern: /anchore\/grype|\bgrype\b/i, evidence: "Grype package/tool evidence was detected." },
    { signal: "dockle-action", pattern: /goodwithtech\/dockle-action|\bdockle\b/i, evidence: "Dockle package/action evidence was detected." },
    { signal: "docker", pattern: /docker build|docker save|docker\/login-action|docker\/build-push-action|DOCKER_HOST/i, evidence: "Docker package/tool evidence was detected." },
    { signal: "syft", pattern: /\bsyft\b|anchore\/sbom-action|SBOM/i, evidence: "Syft/SBOM evidence was detected." }
  ], "package");
}

function containerScanSignalFromSpecs<const T extends readonly { signal: string; pattern: RegExp; evidence: string }[]>(
  sourceFiles: ContainerScanSourceFile[],
  specs: T,
  label: string
): Array<{ signal: T[number]["signal"]; readiness: "ready" | "missing" | "external"; evidence: string; relatedHref: string }> {
  return specs.map((spec) => {
    const match = sourceFiles.find((source) => spec.pattern.test(source.filePath) || spec.pattern.test(source.text));
    return {
      signal: spec.signal,
      readiness: match ? "ready" : sourceFiles.length > 0 ? "external" : "missing",
      evidence: match ? `${match.filePath} ${spec.evidence}` : `${label} ${spec.signal} evidence was not detected.`,
      relatedHref: match?.sourceHref ?? "html/container-scan-readiness.html"
    };
  });
}

async function buildCodeQualityReport(walk: WalkResult): Promise<CodeQualityReport> {
  const sourceFiles = await codeQualitySourceFiles(walk);
  const toolConfigs = codeQualityToolConfigs(sourceFiles);
  const formatterSignals = codeQualityFormatterSignals(sourceFiles);
  const linterSignals = codeQualityLinterSignals(sourceFiles);
  const assistSignals = codeQualityAssistSignals(sourceFiles);
  const ciSignals = codeQualityCiSignals(sourceFiles);
  const languageCoverage = codeQualityLanguageCoverage(walk, toolConfigs);
  const hasWebFiles = languageCoverage.some((item) => item.fileCount > 0 && item.language !== "unknown");
  const hasBiomeConfig = toolConfigs.some((item) => item.tool === "biome-config");
  const hasFormatter = formatterSignals.some((item) => ["formatter-enabled", "format-command"].includes(item.signal) && item.readiness === "ready");
  const hasLinter = linterSignals.some((item) => ["linter-enabled", "rule-groups", "recommended-rules"].includes(item.signal) && item.readiness === "ready");
  const hasAssist = assistSignals.some((item) => ["assist-enabled", "organize-imports"].includes(item.signal) && item.readiness === "ready");
  const hasCi = ciSignals.some((item) => ["biome-ci", "biome-check", "github-action", "gitlab-ci", "pre-commit"].includes(item.signal) && item.readiness === "ready");
  const hasReporter = ciSignals.some((item) => item.signal === "reporter" && item.readiness === "ready");

  const riskQueue: CodeQualityReport["riskQueue"] = [];
  if (hasWebFiles && !hasBiomeConfig) {
    riskQueue.push({
      priority: "high",
      action: "Add a biome.json or biome.jsonc config when this repo wants unified formatting and linting.",
      why: "Biome works with sane defaults, but a committed config makes formatter, linter, assist, file include, and VCS ignore behavior reproducible.",
      relatedHref: "html/code-quality.html"
    });
  }
  if (hasWebFiles && !hasFormatter) {
    riskQueue.push({
      priority: "high",
      action: "Add a formatter command such as biome format or biome check.",
      why: "Biome's formatter is a first-class quality gate for JavaScript, TypeScript, JSX, JSON, CSS, and GraphQL files.",
      relatedHref: "html/code-quality.html"
    });
  }
  if (hasWebFiles && !hasLinter) {
    riskQueue.push({
      priority: "high",
      action: "Add a linter command or enable linter rules in config.",
      why: "Biome lint diagnostics and safe fixes give learners a concrete path from source findings to code health improvements.",
      relatedHref: "html/code-quality.html"
    });
  }
  if (hasWebFiles && !hasAssist) {
    riskQueue.push({
      priority: "medium",
      action: "Consider enabling assist actions such as organizeImports.",
      why: "Biome can centralize import organization and source actions that otherwise drift between editor settings and ad hoc scripts.",
      relatedHref: "html/code-quality.html"
    });
  }
  if (hasWebFiles && !hasCi) {
    riskQueue.push({
      priority: "medium",
      action: "Run biome ci or biome check in CI before publishing generated learning artifacts.",
      why: "Local formatting and linting are useful, but CI makes the code-quality contract visible to every contributor.",
      relatedHref: "html/code-quality.html"
    });
  }
  if (hasWebFiles && !hasReporter) {
    riskQueue.push({
      priority: "low",
      action: "Choose a machine-readable or CI-friendly reporter when findings need review artifacts.",
      why: "Biome supports diagnostics/reporting workflows; RepoTutor should surface whether a repo has a durable quality report path.",
      relatedHref: "html/code-quality.html"
    });
  }
  riskQueue.push({
    priority: "low",
    action: "Run Biome against the original source tree before treating this report as quality approval.",
    why: "RepoTutor records static code-quality readiness only; it does not execute Biome, ESLint, Prettier, editor LSPs, or unsafe fixes.",
    relatedHref: "html/code-quality.html"
  });

  return {
    summary: `Biome식 code quality report: config ${toolConfigs.length}개, formatter signal ${formatterSignals.length}개, linter signal ${linterSignals.length}개, CI/editor signal ${ciSignals.length}개를 정적 분석으로 정리했습니다.`,
    sourcePattern: "Biome formatter linter check ci biome.json assist organize imports diagnostics reporter editor LSP VCS ignore safe fixes",
    toolConfigs,
    formatterSignals,
    linterSignals,
    assistSignals,
    ciSignals,
    languageCoverage,
    riskQueue: riskQueue.sort((a, b) => ({ high: 0, medium: 1, low: 2 }[a.priority] - { high: 0, medium: 1, low: 2 }[b.priority])),
    recommendedCommands: [
      { command: "npx @biomejs/biome check .", purpose: "Run formatter, linter, assist, and other enabled checks without writing changes." },
      { command: "npx @biomejs/biome check --write .", purpose: "Apply safe formatting, lint, and assist fixes where the project policy allows writes." },
      { command: "npx @biomejs/biome ci .", purpose: "Run the CI-oriented quality gate for all configured files." },
      { command: "npx @biomejs/biome format --write .", purpose: "Format supported web-language files." },
      { command: "npx @biomejs/biome lint --write .", purpose: "Run lint rules and apply safe fixes." }
    ],
    learnerNextSteps: [
      "package.json scripts, biome.json, editor settings, and CI workflows should agree on the same quality gate.",
      "Formatter readiness answers style drift; linter readiness answers code-health diagnostics; assist readiness answers import/source-action drift.",
      "If the repo already uses ESLint or Prettier, decide whether Biome complements, replaces, or intentionally stays out of that scope.",
      "RepoTutor does not run Biome, so use the recommended commands on the original source tree before claiming code-quality pass/fail."
    ]
  };
}

type CodeQualitySourceFile = {
  filePath: string;
  text: string;
  sourceHref: string;
};

async function codeQualitySourceFiles(walk: WalkResult): Promise<CodeQualitySourceFile[]> {
  const files: CodeQualitySourceFile[] = [];
  for (const file of walk.files) {
    if (!file.isTextCandidate || !codeQualityInspectablePath(file.relPath)) continue;
    const text = await readTextIfSafe(file.absPath, 180_000);
    if (!text) continue;
    if (!codeQualityPathSignal(file.relPath) && !codeQualityContentSignal(text)) continue;
    files.push({ filePath: file.relPath, text, sourceHref: `source/${encodedPath(file.relPath)}` });
    if (files.length >= 220) break;
  }
  return files;
}

function codeQualityInspectablePath(filePath: string): boolean {
  const base = path.basename(filePath);
  return /^(package\.json|biome\.jsonc?|\.biome\.jsonc?|\.editorconfig|\.prettierrc(\..*)?|prettier\.config\.[cm]?[jt]s|eslint\.config\.[cm]?[jt]s|\.eslintrc(\..*)?|\.pre-commit-config\.ya?ml)$/i.test(base)
    || /^\.github\/workflows\/.+\.ya?ml$/i.test(filePath)
    || /^\.vscode\/settings\.json$/i.test(filePath)
    || /^\.gitlab-ci\.ya?ml$/i.test(filePath)
    || /\.(json|jsonc|ya?ml|toml|md|[cm]?[jt]s)$/i.test(filePath);
}

function codeQualityPathSignal(filePath: string): boolean {
  return /(biome|eslint|prettier|lint|format|pre-commit|workflow|gitlab-ci|\.vscode|editorconfig)/i.test(filePath);
}

function codeQualityContentSignal(text: string): boolean {
  return /@biomejs\/biome|\bbiome\s+(format|lint|check|ci)\b|biome\.json|organizeImports|assist|formatter|linter|prettier|eslint|reporter|diagnostic|safe fix|unsafe/i.test(text);
}

function codeQualityToolConfigs(sourceFiles: CodeQualitySourceFile[]): CodeQualityReport["toolConfigs"] {
  const rows: CodeQualityReport["toolConfigs"] = [];
  for (const source of sourceFiles) {
    const base = path.basename(source.filePath).toLowerCase();
    const push = (tool: CodeQualityReport["toolConfigs"][number]["tool"], readiness: CodeQualityReport["toolConfigs"][number]["readiness"], evidence: string) => {
      rows.push({ filePath: source.filePath, tool, readiness, evidence, sourceHref: source.sourceHref });
    };
    if (/^\.?biome\.jsonc?$/.test(base)) push("biome-config", "ready", `${source.filePath} is a Biome project configuration file.`);
    if (/^package\.json$/.test(base) && /@biomejs\/biome|\bbiome\s+(format|lint|check|ci)\b/i.test(source.text)) push("package-script", "ready", `${source.filePath} references Biome dependency or commands.`);
    if (/^package\.json$/.test(base) && /\b(eslint|prettier)\b/i.test(source.text) && !/@biomejs\/biome|\bbiome\s+(format|lint|check|ci)\b/i.test(source.text)) push("package-script", "partial", `${source.filePath} references ESLint or Prettier scripts without Biome.`);
    if (/^(eslint\.config\.[cm]?[jt]s|\.eslintrc(\..*)?)$/i.test(base)) push("eslint-config", "partial", `${source.filePath} is an ESLint configuration file.`);
    if (/^(\.prettierrc(\..*)?|prettier\.config\.[cm]?[jt]s)$/i.test(base)) push("prettier-config", "partial", `${source.filePath} is a Prettier configuration file.`);
    if (/^(\.editorconfig|settings\.json)$/i.test(base) && /(format|biome|prettier|eslint|editor\.defaultFormatter)/i.test(source.text)) push("editor-config", "partial", `${source.filePath} contains editor formatting or linting configuration.`);
    if (rows.length < 140 && /biome/i.test(source.text) && !rows.some((item) => item.filePath === source.filePath)) push("unknown", "partial", `${source.filePath} contains Biome-related text.`);
  }
  return rows.slice(0, 140);
}

function codeQualityFormatterSignals(sourceFiles: CodeQualitySourceFile[]): CodeQualityReport["formatterSignals"] {
  const specs: Array<{ signal: CodeQualityReport["formatterSignals"][number]["signal"]; pattern: RegExp; evidence: string }> = [
    { signal: "formatter-enabled", pattern: /"formatter"\s*:|formatter:\s|formatter\s+enabled|biome\s+format/i, evidence: "formatter configuration or command evidence was detected." },
    { signal: "format-command", pattern: /\bbiome\s+format\b|@biomejs\/biome\s+format|"(format|fmt)"\s*:\s*"[^"]*(biome|prettier)/i, evidence: "format command evidence was detected." },
    { signal: "write-mode", pattern: /--write|--fix|check\s+--write|lint\s+--write|format\s+--write/i, evidence: "write/fix mode evidence was detected." },
    { signal: "language-support", pattern: /JavaScript|TypeScript|JSX|JSON|CSS|GraphQL|javascript|typescript|json|css|graphql/i, evidence: "supported language coverage evidence was detected." },
    { signal: "line-width", pattern: /lineWidth|printWidth|max_line_length/i, evidence: "line width formatting policy evidence was detected." },
    { signal: "indent-style", pattern: /indentStyle|indent_size|indent_style|tabWidth/i, evidence: "indent formatting policy evidence was detected." },
    { signal: "prettier-compat", pattern: /prettier|Prettier/i, evidence: "Prettier compatibility or coexistence evidence was detected." }
  ];
  return codeQualitySignalFromSpecs(sourceFiles, specs, "formatter");
}

function codeQualityLinterSignals(sourceFiles: CodeQualitySourceFile[]): CodeQualityReport["linterSignals"] {
  const specs: Array<{ signal: CodeQualityReport["linterSignals"][number]["signal"]; pattern: RegExp; evidence: string }> = [
    { signal: "linter-enabled", pattern: /"linter"\s*:|linter:\s|biome\s+lint|biome\s+check/i, evidence: "linter configuration or command evidence was detected." },
    { signal: "rule-groups", pattern: /"rules"\s*:|"style"\s*:|"correctness"\s*:|"suspicious"\s*:|"nursery"\s*:|"complexity"\s*:/i, evidence: "Biome-style rule group evidence was detected." },
    { signal: "custom-rules", pattern: /plugins?|\.grit|rules\s*:/i, evidence: "custom rule or plugin evidence was detected." },
    { signal: "recommended-rules", pattern: /recommended\s*:\s*(true|\"on\")|recommended/i, evidence: "recommended rule mode evidence was detected." },
    { signal: "safe-fixes", pattern: /safe fix|safe fixes|lint\s+--write|check\s+--write/i, evidence: "safe fix workflow evidence was detected." },
    { signal: "unsafe-fixes", pattern: /--unsafe|unsafe/i, evidence: "unsafe fix workflow evidence was detected." },
    { signal: "dependency-rule", pattern: /noUndeclaredDependencies|no-undeclared-dependencies/i, evidence: "dependency declaration lint evidence was detected." },
    { signal: "import-cycle-rule", pattern: /noImportCycles|import cycle|no-import-cycles/i, evidence: "import cycle lint evidence was detected." },
    { signal: "promise-rule", pattern: /noFloatingPromises|floating promises|no-floating-promises/i, evidence: "promise lint evidence was detected." }
  ];
  return codeQualitySignalFromSpecs(sourceFiles, specs, "linter");
}

function codeQualityAssistSignals(sourceFiles: CodeQualitySourceFile[]): CodeQualityReport["assistSignals"] {
  const specs: Array<{ signal: CodeQualityReport["assistSignals"][number]["signal"]; pattern: RegExp; evidence: string }> = [
    { signal: "assist-enabled", pattern: /"assist"\s*:|assist:\s|source action|sourceAction/i, evidence: "assist/source-action configuration evidence was detected." },
    { signal: "organize-imports", pattern: /organizeImports|organize imports|source\.organizeImports/i, evidence: "organize imports evidence was detected." },
    { signal: "sorted-keys", pattern: /useSortedKeys|sorted keys|sort(ed)? keys/i, evidence: "sorted key assist evidence was detected." },
    { signal: "plugins", pattern: /"plugins"\s*:|\.grit|plugin/i, evidence: "Biome plugin evidence was detected." },
    { signal: "vcs-ignore", pattern: /"vcs"\s*:|useIgnoreFile|clientKind|\.gitignore/i, evidence: "VCS ignore integration evidence was detected." }
  ];
  return codeQualitySignalFromSpecs(sourceFiles, specs, "assist");
}

function codeQualityCiSignals(sourceFiles: CodeQualitySourceFile[]): CodeQualityReport["ciSignals"] {
  const specs: Array<{ signal: CodeQualityReport["ciSignals"][number]["signal"]; pattern: RegExp; evidence: string }> = [
    { signal: "biome-ci", pattern: /\bbiome\s+ci\b|@biomejs\/biome\s+ci/i, evidence: "biome ci evidence was detected." },
    { signal: "biome-check", pattern: /\bbiome\s+check\b|@biomejs\/biome\s+check/i, evidence: "biome check evidence was detected." },
    { signal: "github-action", pattern: /\.github\/workflows|github actions|actions\/checkout|setup-node|biomejs\/setup-biome/i, evidence: "GitHub Actions quality gate evidence was detected." },
    { signal: "gitlab-ci", pattern: /\.gitlab-ci|gitlab/i, evidence: "GitLab CI quality gate evidence was detected." },
    { signal: "pre-commit", pattern: /pre-commit|repos:\s*\n|biome.*pre-commit/i, evidence: "pre-commit quality gate evidence was detected." },
    { signal: "package-script", pattern: /"(lint|format|fmt|check|ci)"\s*:\s*"[^"]*(biome|eslint|prettier)/i, evidence: "package script quality gate evidence was detected." },
    { signal: "editor-lsp", pattern: /biomejs\.biome|language server|LSP|editor\.defaultFormatter|\.vscode/i, evidence: "editor or LSP integration evidence was detected." },
    { signal: "reporter", pattern: /--reporter|reporter|diagnostic|junit|github|json|summary/i, evidence: "reporter or diagnostic output evidence was detected." }
  ];
  return codeQualitySignalFromSpecs(sourceFiles, specs, "CI/editor");
}

function codeQualitySignalFromSpecs<T extends { signal: string; pattern: RegExp; evidence: string }>(
  sourceFiles: CodeQualitySourceFile[],
  specs: T[],
  label: string
): Array<{ signal: T["signal"]; readiness: "ready" | "missing"; evidence: string; relatedHref: string }> {
  return specs.map((spec) => {
    const match = sourceFiles.find((source) => spec.pattern.test(source.text) || spec.pattern.test(source.filePath));
    spec.pattern.lastIndex = 0;
    return {
      signal: spec.signal,
      readiness: match ? "ready" : "missing",
      evidence: match ? `${match.filePath} ${spec.evidence}` : `${label} ${spec.signal} evidence was not detected.`,
      relatedHref: match?.sourceHref ?? "html/code-quality.html"
    };
  });
}

function codeQualityLanguageCoverage(walk: WalkResult, toolConfigs: CodeQualityReport["toolConfigs"]): CodeQualityReport["languageCoverage"] {
  const hasQualityTool = toolConfigs.some((item) => ["biome-config", "package-script", "eslint-config", "prettier-config"].includes(item.tool));
  const specs: Array<{ language: CodeQualityReport["languageCoverage"][number]["language"]; pattern: RegExp }> = [
    { language: "javascript", pattern: /\.(mjs|cjs|js)$/i },
    { language: "typescript", pattern: /\.ts$/i },
    { language: "jsx", pattern: /\.(jsx|tsx)$/i },
    { language: "json", pattern: /\.jsonc?$/i },
    { language: "css", pattern: /\.css$/i },
    { language: "graphql", pattern: /\.(graphql|gql)$/i },
    { language: "html", pattern: /\.html$/i },
    { language: "markdown", pattern: /\.mdx?$/i }
  ];
  return specs.map((spec) => {
    const count = walk.files.filter((file) => spec.pattern.test(file.relPath)).length;
    const readiness = count === 0 ? "missing" : hasQualityTool ? "ready" : "external";
    return {
      language: spec.language,
      fileCount: count,
      readiness,
      evidence: count === 0 ? `${spec.language} files were not detected.` : hasQualityTool ? `${count} ${spec.language} file(s) can be reviewed against detected quality tooling.` : `${count} ${spec.language} file(s) exist but no code-quality tool config was detected.`,
      relatedHref: "html/code-quality.html"
    };
  });
}

async function buildDocumentationReport(walk: WalkResult): Promise<DocumentationReport> {
  const sourceFiles = await documentationSourceFiles(walk);
  const siteConfigs = documentationSiteConfigs(sourceFiles);
  const contentSurfaces = documentationContentSurfaces(walk, siteConfigs);
  const navigationSignals = documentationNavigationSignals(sourceFiles);
  const qualitySignals = documentationQualitySignals(sourceFiles);
  const localizationSignals = documentationLocalizationSignals(sourceFiles);
  const releaseSignals = documentationReleaseSignals(sourceFiles);
  const hasDocContent = contentSurfaces.some((item) => item.count > 0 && ["docs", "blog", "pages", "mdx", "versioned-docs"].includes(item.surface));
  const hasDocusaurusConfig = siteConfigs.some((item) => item.configType === "docusaurus-config");
  const hasNavigation = navigationSignals.some((item) => ["sidebar", "navbar", "footer"].includes(item.signal) && item.readiness === "ready");
  const hasBuild = releaseSignals.some((item) => item.signal === "build-script" && item.readiness === "ready");
  const hasDeploy = releaseSignals.some((item) => ["deploy-script", "github-pages", "netlify", "vercel", "ci-preview"].includes(item.signal) && item.readiness === "ready");
  const hasSearch = qualitySignals.some((item) => item.signal === "search" && item.readiness === "ready");
  const hasSeo = qualitySignals.some((item) => ["seo", "sitemap"].includes(item.signal) && item.readiness === "ready");
  const hasLocalization = localizationSignals.some((item) => item.readiness === "ready");
  const hasVersioning = contentSurfaces.some((item) => item.surface === "versioned-docs" && item.count > 0);

  const riskQueue: DocumentationReport["riskQueue"] = [];
  if (hasDocContent && !hasDocusaurusConfig) {
    riskQueue.push({
      priority: "high",
      action: "Add or identify docusaurus.config when this repository is meant to publish a documentation website.",
      why: "Docusaurus keeps docs, blog, pages, navbar, footer, i18n, and plugin behavior reproducible through a committed site config.",
      relatedHref: "html/documentation.html"
    });
  }
  if (hasDocContent && !hasNavigation) {
    riskQueue.push({
      priority: "medium",
      action: "Define sidebar, navbar, or footer navigation for the main documentation paths.",
      why: "Docusaurus documentation is easier to learn when source folders map to visible navigation instead of isolated markdown files.",
      relatedHref: "html/documentation.html"
    });
  }
  if (hasDocContent && !hasBuild) {
    riskQueue.push({
      priority: "high",
      action: "Add a documented build command such as docusaurus build or an equivalent docs build script.",
      why: "A static documentation report cannot prove the site compiles; learners need a repeatable command for broken links, MDX, and generated routes.",
      relatedHref: "html/documentation.html"
    });
  }
  if (hasDocContent && !hasDeploy) {
    riskQueue.push({
      priority: "medium",
      action: "Record how the documentation site is previewed or deployed.",
      why: "Docusaurus sites often rely on GitHub Pages, Netlify, Vercel, or CI previews, and that path should be visible before publication.",
      relatedHref: "html/documentation.html"
    });
  }
  if (hasDocContent && !hasSearch) {
    riskQueue.push({
      priority: "medium",
      action: "Decide whether the docs need search and record the chosen search integration.",
      why: "Public documentation sites usually need a durable search path such as Algolia or local search as content grows.",
      relatedHref: "html/documentation.html"
    });
  }
  if (hasDocContent && !hasSeo) {
    riskQueue.push({
      priority: "low",
      action: "Check sitemap and SEO metadata before treating the docs site as publication-ready.",
      why: "A docs site can render locally while still being hard to discover or inspect in search/social previews.",
      relatedHref: "html/documentation.html"
    });
  }
  if (hasDocContent && !hasLocalization) {
    riskQueue.push({
      priority: "low",
      action: "Mark i18n as intentionally out of scope or add locale configuration when the docs serve multiple languages.",
      why: "Docusaurus has first-class i18n surfaces; RepoTutor should show whether localization is absent by design or simply missing.",
      relatedHref: "html/documentation.html"
    });
  }
  if (hasDocContent && !hasVersioning) {
    riskQueue.push({
      priority: "low",
      action: "Decide whether versioned docs are needed for released APIs or product versions.",
      why: "Docusaurus docs versioning is important when learners must match documentation to a specific release line.",
      relatedHref: "html/documentation.html"
    });
  }
  riskQueue.push({
    priority: "low",
    action: "Run Docusaurus against the original source tree before treating this report as documentation approval.",
    why: "RepoTutor records static documentation readiness only; it does not run MDX compilation, route generation, link checking, search indexing, or deployment.",
    relatedHref: "html/documentation.html"
  });

  return {
    summary: `Docusaurus식 documentation report: site config ${siteConfigs.length}개, content surface ${contentSurfaces.length}개, navigation signal ${navigationSignals.length}개, release signal ${releaseSignals.length}개를 정적 분석으로 정리했습니다.`,
    sourcePattern: "Docusaurus docs blog pages sidebars docusaurus.config themeConfig navbar footer i18n versioning search build deploy",
    siteConfigs,
    contentSurfaces,
    navigationSignals,
    qualitySignals,
    localizationSignals,
    releaseSignals,
    riskQueue: riskQueue.sort((a, b) => ({ high: 0, medium: 1, low: 2 }[a.priority] - { high: 0, medium: 1, low: 2 }[b.priority])),
    recommendedCommands: [
      { command: "npm run build", purpose: "Build the documentation site and catch MDX, routing, and broken-link failures through the project script." },
      { command: "npm run serve", purpose: "Serve the built documentation locally before sharing the output." },
      { command: "npm run docusaurus docs:version 1.0", purpose: "Create a versioned docs snapshot when the project publishes version-specific documentation." },
      { command: "npm run start -- --locale fr", purpose: "Preview a localized documentation build when i18n is enabled." },
      { command: "npx docusaurus build", purpose: "Run the Docusaurus build directly when no package script wraps it yet." }
    ],
    learnerNextSteps: [
      "Check whether docs, blog, and custom pages are visible through sidebars, navbar, or footer navigation.",
      "Use build and serve commands on the original source tree before claiming documentation pass/fail status.",
      "If the repo uses another docs stack, treat Docusaurus signals as a comparison checklist rather than a required dependency.",
      "Record why i18n, versioning, search, or deploy previews are intentionally omitted when they are out of scope."
    ]
  };
}

type DocumentationSourceFile = {
  filePath: string;
  text: string;
  sourceHref: string;
};

async function documentationSourceFiles(walk: WalkResult): Promise<DocumentationSourceFile[]> {
  const files: DocumentationSourceFile[] = [];
  for (const file of walk.files) {
    if (!file.isTextCandidate || !documentationInspectablePath(file.relPath)) continue;
    const text = await readTextIfSafe(file.absPath, 180_000);
    if (!text) continue;
    if (!documentationPathSignal(file.relPath) && !documentationContentSignal(text)) continue;
    files.push({ filePath: file.relPath, text, sourceHref: `source/${encodedPath(file.relPath)}` });
    if (files.length >= 260) break;
  }
  return files;
}

function documentationInspectablePath(filePath: string): boolean {
  const base = path.basename(filePath);
  return /^(package\.json|docusaurus\.config\.[cm]?[jt]s|sidebars\.[cm]?[jt]s|sidebars\.json|README\.md|crowdin\.ya?ml|netlify\.toml|vercel\.json)$/i.test(base)
    || /^\.github\/workflows\/.+\.ya?ml$/i.test(filePath)
    || /(^|\/)(docs|blog|src\/pages|pages|static|public|i18n|versioned_docs|versioned_sidebars)\//i.test(filePath)
    || /\.(mdx?|[cm]?[jt]sx?|json|ya?ml|toml)$/i.test(filePath);
}

function documentationPathSignal(filePath: string): boolean {
  return /(docusaurus|sidebars?|docs\/|blog\/|src\/pages|\/pages\/|i18n\/|versioned_docs|versioned_sidebars|netlify|vercel|deploy|readme)/i.test(filePath);
}

function documentationContentSignal(text: string): boolean {
  return /@docusaurus|docusaurus\s+(build|serve|start|deploy|docs:version)|sidebars?|themeConfig|navbar|footer|i18n|locales|algolia|sitemap|MDX|\.mdx|docsVersion|editUrl|GitHub Pages|Netlify|Vercel/i.test(text);
}

function documentationSiteConfigs(sourceFiles: DocumentationSourceFile[]): DocumentationReport["siteConfigs"] {
  const rows: DocumentationReport["siteConfigs"] = [];
  for (const source of sourceFiles) {
    const base = path.basename(source.filePath).toLowerCase();
    const push = (configType: DocumentationReport["siteConfigs"][number]["configType"], readiness: DocumentationReport["siteConfigs"][number]["readiness"], evidence: string) => {
      rows.push({ filePath: source.filePath, configType, readiness, evidence, sourceHref: source.sourceHref });
    };
    if (/^docusaurus\.config\.[cm]?[jt]s$/.test(base)) push("docusaurus-config", "ready", `${source.filePath} is a Docusaurus site configuration file.`);
    if (/^package\.json$/.test(base) && /@docusaurus|docusaurus\s+(start|build|serve|deploy|docs:version)/i.test(source.text)) push("package-script", "ready", `${source.filePath} references Docusaurus dependencies or commands.`);
    if (/^sidebars(\.[cm]?[jt]s|\.json)$/.test(base)) push("sidebar", "ready", `${source.filePath} defines documentation sidebar navigation.`);
    if (/themeConfig|navbar|footer|colorMode|prism/i.test(source.text) && /^docusaurus\.config\./i.test(base)) push("theme-config", "ready", `${source.filePath} contains themeConfig navigation or theme settings.`);
    if (rows.length < 140 && /@docusaurus|themeConfig|sidebars?/i.test(source.text) && !rows.some((item) => item.filePath === source.filePath)) push("unknown", "partial", `${source.filePath} contains Docusaurus-related text.`);
  }
  return rows.slice(0, 140);
}

function documentationContentSurfaces(walk: WalkResult, siteConfigs: DocumentationReport["siteConfigs"]): DocumentationReport["contentSurfaces"] {
  const hasConfig = siteConfigs.some((item) => ["docusaurus-config", "package-script"].includes(item.configType));
  const specs: Array<{ surface: DocumentationReport["contentSurfaces"][number]["surface"]; pattern: RegExp; evidence: string }> = [
    { surface: "docs", pattern: /(^|\/)docs\/.+\.mdx?$/i, evidence: "docs markdown/MDX files were detected." },
    { surface: "blog", pattern: /(^|\/)blog\/.+\.mdx?$/i, evidence: "blog markdown/MDX files were detected." },
    { surface: "pages", pattern: /(^|\/)(src\/pages|pages)\/.+\.(mdx?|[jt]sx?)$/i, evidence: "custom pages were detected." },
    { surface: "mdx", pattern: /\.mdx$/i, evidence: "MDX authoring files were detected." },
    { surface: "static-assets", pattern: /(^|\/)(static|public)\/.+/i, evidence: "static assets for documentation were detected." },
    { surface: "versioned-docs", pattern: /(^|\/)(versioned_docs|versioned_sidebars)\//i, evidence: "versioned docs or sidebars were detected." },
    { surface: "i18n", pattern: /(^|\/)i18n\//i, evidence: "i18n translation folders were detected." }
  ];
  return specs.map((spec) => {
    const count = walk.files.filter((file) => spec.pattern.test(file.relPath)).length;
    const readiness = count > 0 ? "ready" : hasConfig ? "external" : "missing";
    return {
      surface: spec.surface,
      count,
      readiness,
      evidence: count > 0 ? `${count} file(s): ${spec.evidence}` : `${spec.surface} content was not detected.`,
      relatedHref: "html/documentation.html"
    };
  });
}

function documentationNavigationSignals(sourceFiles: DocumentationSourceFile[]): DocumentationReport["navigationSignals"] {
  const specs: Array<{ signal: DocumentationReport["navigationSignals"][number]["signal"]; pattern: RegExp; evidence: string }> = [
    { signal: "sidebar", pattern: /sidebars?|sidebarPath|docs:\s*\{[\s\S]*sidebar/i, evidence: "sidebar navigation evidence was detected." },
    { signal: "navbar", pattern: /navbar|Navbar/i, evidence: "navbar evidence was detected." },
    { signal: "footer", pattern: /footer/i, evidence: "footer evidence was detected." },
    { signal: "breadcrumbs", pattern: /breadcrumbs|hideBreadcrumbs/i, evidence: "breadcrumb control evidence was detected." },
    { signal: "toc", pattern: /tableOfContents|hide_table_of_contents|\btoc\b/i, evidence: "table-of-contents evidence was detected." },
    { signal: "edit-url", pattern: /editUrl|editCurrentVersion|editLocalizedFiles/i, evidence: "edit URL evidence was detected." }
  ];
  return documentationSignalFromSpecs(sourceFiles, specs, "navigation");
}

function documentationQualitySignals(sourceFiles: DocumentationSourceFile[]): DocumentationReport["qualitySignals"] {
  const specs: Array<{ signal: DocumentationReport["qualitySignals"][number]["signal"]; pattern: RegExp; evidence: string }> = [
    { signal: "search", pattern: /algolia|localSearch|@easyops-cn\/docusaurus-search-local|search/i, evidence: "search integration evidence was detected." },
    { signal: "seo", pattern: /title:|tagline|metadata|headTags|onBrokenLinks|favicon/i, evidence: "SEO or site metadata evidence was detected." },
    { signal: "sitemap", pattern: /sitemap|@docusaurus\/plugin-sitemap/i, evidence: "sitemap evidence was detected." },
    { signal: "pwa", pattern: /pwa|@docusaurus\/plugin-pwa/i, evidence: "PWA plugin evidence was detected." },
    { signal: "analytics", pattern: /googleAnalytics|gtag|gtm|analytics|tag-manager/i, evidence: "analytics evidence was detected." },
    { signal: "theme", pattern: /themeConfig|@docusaurus\/theme|prism|colorMode/i, evidence: "theme customization evidence was detected." },
    { signal: "mdx", pattern: /MDX|\.mdx|@mdx/i, evidence: "MDX evidence was detected." },
    { signal: "typescript", pattern: /docusaurus\.config\.ts|sidebars\.ts|tsconfig|typescript/i, evidence: "TypeScript config evidence was detected." }
  ];
  return documentationSignalFromSpecs(sourceFiles, specs, "quality");
}

function documentationLocalizationSignals(sourceFiles: DocumentationSourceFile[]): DocumentationReport["localizationSignals"] {
  const specs: Array<{ signal: DocumentationReport["localizationSignals"][number]["signal"]; pattern: RegExp; evidence: string }> = [
    { signal: "i18n-config", pattern: /i18n\s*:|locales|defaultLocale/i, evidence: "i18n config evidence was detected." },
    { signal: "locale-dropdown", pattern: /localeDropdown|type:\s*['"]localeDropdown/i, evidence: "locale dropdown evidence was detected." },
    { signal: "translation-folder", pattern: /(^|\/)i18n\/|translations|code\.json/i, evidence: "translation folder evidence was detected." },
    { signal: "crowdin", pattern: /crowdin/i, evidence: "Crowdin localization workflow evidence was detected." },
    { signal: "localized-config", pattern: /currentLocale|@docusaurus\/Translate|\btranslate\(/i, evidence: "localized config or translation helper evidence was detected." }
  ];
  return documentationSignalFromSpecs(sourceFiles, specs, "localization");
}

function documentationReleaseSignals(sourceFiles: DocumentationSourceFile[]): DocumentationReport["releaseSignals"] {
  const specs: Array<{ signal: DocumentationReport["releaseSignals"][number]["signal"]; pattern: RegExp; evidence: string }> = [
    { signal: "build-script", pattern: /"build"\s*:\s*"[^"]*docusaurus\s+build|docusaurus\s+build/i, evidence: "Docusaurus build script evidence was detected." },
    { signal: "serve-script", pattern: /"serve"\s*:\s*"[^"]*docusaurus\s+serve|docusaurus\s+serve|docusaurus\s+start/i, evidence: "serve/start script evidence was detected." },
    { signal: "deploy-script", pattern: /"deploy"\s*:\s*"[^"]*docusaurus\s+deploy|docusaurus\s+deploy/i, evidence: "deploy script evidence was detected." },
    { signal: "github-pages", pattern: /gh-pages|GitHub Pages|GITHUB_TOKEN|peaceiris|actions\/deploy-pages/i, evidence: "GitHub Pages deploy evidence was detected." },
    { signal: "netlify", pattern: /netlify|deploy-preview/i, evidence: "Netlify deploy or preview evidence was detected." },
    { signal: "vercel", pattern: /vercel/i, evidence: "Vercel deploy evidence was detected." },
    { signal: "ci-preview", pattern: /pull_request|preview|artifact|pages:|upload-pages-artifact/i, evidence: "CI preview or artifact evidence was detected." }
  ];
  return documentationSignalFromSpecs(sourceFiles, specs, "release");
}

function documentationSignalFromSpecs<T extends { signal: string; pattern: RegExp; evidence: string }>(
  sourceFiles: DocumentationSourceFile[],
  specs: T[],
  label: string
): Array<{ signal: T["signal"]; readiness: "ready" | "missing" | "external"; evidence: string; relatedHref: string }> {
  return specs.map((spec) => {
    const match = sourceFiles.find((source) => spec.pattern.test(source.text) || spec.pattern.test(source.filePath));
    return {
      signal: spec.signal,
      readiness: match ? "ready" : sourceFiles.length > 0 ? "external" : "missing",
      evidence: match ? `${match.filePath} ${spec.evidence}` : `${label} ${spec.signal} evidence was not detected.`,
      relatedHref: match?.sourceHref ?? "html/documentation.html"
    };
  });
}

async function buildDatabaseReadinessReport(walk: WalkResult): Promise<DatabaseReadinessReport> {
  const sourceFiles = await databaseSourceFiles(walk);
  const schemaFiles = databaseSchemaFiles(sourceFiles);
  const datasourceSignals = databaseDatasourceSignals(schemaFiles, sourceFiles);
  const migrationSignals = databaseMigrationSignals(sourceFiles);
  const clientSignals = databaseClientSignals(sourceFiles);
  const configSignals = databaseConfigSignals(sourceFiles);
  const modelSignals = databaseModelSignals(sourceFiles);
  const hasPrismaText = sourceFiles.length > 0;
  const hasSchema = schemaFiles.length > 0;
  const hasPrismaPackage = configSignals.some((item) => item.signal === "package-script" && item.readiness === "ready");
  const hasMigration = migrationSignals.some((item) => ["migrations-folder", "migration-sql", "migrate-dev", "migrate-deploy"].includes(item.signal) && item.readiness === "ready");
  const hasGenerate = clientSignals.some((item) => item.signal === "client-generation" && item.readiness === "ready");
  const hasDatabaseUrl = configSignals.some((item) => item.signal === "database-url" && item.readiness === "ready");
  const hasSeed = configSignals.some((item) => item.signal === "seed" && item.readiness === "ready");
  const hasClientUse = clientSignals.some((item) => item.signal === "prisma-client" && item.readiness === "ready");

  const riskQueue: DatabaseReadinessReport["riskQueue"] = [];
  if (hasPrismaPackage && !hasSchema) {
    riskQueue.push({
      priority: "high",
      action: "Add or locate a Prisma schema file before treating the database layer as documented.",
      why: "Prisma readiness starts with schema.prisma or an explicit schema path; package scripts alone do not show datasource, generator, or model shape.",
      relatedHref: "html/database-readiness.html"
    });
  }
  if (hasSchema && !hasDatabaseUrl) {
    riskQueue.push({
      priority: "high",
      action: "Document the datasource URL boundary through prisma.config, DATABASE_URL, or an env example.",
      why: "Prisma CLI commands and generated clients need a reproducible datasource configuration before learners can run validate, generate, or migrate safely.",
      relatedHref: "html/database-readiness.html"
    });
  }
  if (hasSchema && !hasGenerate) {
    riskQueue.push({
      priority: "high",
      action: "Add a Prisma Client generation command or explain how generation is triggered.",
      why: "The schema is not enough for application code; Prisma Client generation connects models to type-safe query code.",
      relatedHref: "html/database-readiness.html"
    });
  }
  if (hasSchema && !hasMigration) {
    riskQueue.push({
      priority: "medium",
      action: "Choose a migration path such as migrate dev/deploy or document intentional db push usage.",
      why: "Prisma distinguishes declarative migrations from db push prototyping; RepoTutor should show which path protects database drift.",
      relatedHref: "html/database-readiness.html"
    });
  }
  if (hasSchema && !hasClientUse) {
    riskQueue.push({
      priority: "medium",
      action: "Point learners to the runtime code that imports PrismaClient or a generated client output.",
      why: "Schema and migrations explain structure, but application learning needs to see where queries enter the runtime.",
      relatedHref: "html/database-readiness.html"
    });
  }
  if (hasSchema && !hasSeed) {
    riskQueue.push({
      priority: "low",
      action: "Add a seed command or sample data note when local learning depends on database content.",
      why: "A generated client can connect successfully while the learner still has no realistic data to inspect.",
      relatedHref: "html/database-readiness.html"
    });
  }
  riskQueue.push({
    priority: "low",
    action: hasPrismaText ? "Run Prisma commands on the original source tree before treating this report as database approval." : "If this repository later adds a database layer, rerun RepoTutor to populate Prisma readiness.",
    why: "RepoTutor records static database readiness only; it does not connect to databases, run migrations, introspect schemas, generate clients, or seed data.",
    relatedHref: "html/database-readiness.html"
  });

  return {
    summary: `Prisma식 database readiness report: schema ${schemaFiles.length}개, datasource signal ${datasourceSignals.length}개, migration signal ${migrationSignals.length}개, client signal ${clientSignals.length}개를 정적 분석으로 정리했습니다.`,
    sourcePattern: "Prisma schema datasource generator model migrate generate db push seed PrismaClient DATABASE_URL driver adapter migrations",
    schemaFiles,
    datasourceSignals,
    migrationSignals,
    clientSignals,
    configSignals,
    modelSignals,
    riskQueue: riskQueue.sort((a, b) => ({ high: 0, medium: 1, low: 2 }[a.priority] - { high: 0, medium: 1, low: 2 }[b.priority])),
    recommendedCommands: [
      { command: "npx prisma validate", purpose: "Validate Prisma schema syntax and datasource/generator configuration." },
      { command: "npx prisma format", purpose: "Format schema.prisma so models, relations, and attributes are easier to inspect." },
      { command: "npx prisma generate", purpose: "Generate Prisma Client from the schema before checking runtime query code." },
      { command: "npx prisma migrate dev", purpose: "Create and apply a development migration against a safe local database." },
      { command: "npx prisma migrate deploy", purpose: "Apply committed migrations in deployment or CI environments." },
      { command: "npx prisma db seed", purpose: "Load seed data when local learning or tests need realistic rows." },
      { command: "npx prisma studio", purpose: "Open a database GUI for manual inspection after the datasource is safe." }
    ],
    learnerNextSteps: [
      "Start with schema.prisma: confirm datasource provider, generator output, model count, IDs, relations, and indexes.",
      "Separate prototype db push workflows from committed migration workflows before changing shared databases.",
      "Trace PrismaClient imports or generated client output to see where application code begins database queries.",
      "RepoTutor does not run Prisma commands, connect to databases, or generate clients; run the recommended commands on the original source tree."
    ]
  };
}

type DatabaseSourceFile = {
  filePath: string;
  text: string;
  sourceHref: string;
};

async function databaseSourceFiles(walk: WalkResult): Promise<DatabaseSourceFile[]> {
  const files: DatabaseSourceFile[] = [];
  for (const file of walk.files) {
    if (!file.isTextCandidate || !databaseInspectablePath(file.relPath)) continue;
    const text = await readTextIfSafe(file.absPath, 180_000);
    if (!text) continue;
    if (!databasePathSignal(file.relPath) && !databaseContentSignal(text)) continue;
    files.push({ filePath: file.relPath, text, sourceHref: `source/${encodedPath(file.relPath)}` });
    if (files.length >= 260) break;
  }
  return files;
}

function databaseInspectablePath(filePath: string): boolean {
  const base = path.basename(filePath);
  return /^(schema\.prisma|prisma\.config\.[cm]?[jt]s|package\.json|docker-compose\.ya?ml|compose\.ya?ml|\.env\.example|\.env\.sample|README\.md)$/i.test(base)
    || /^\.github\/workflows\/.+\.ya?ml$/i.test(filePath)
    || /(^|\/)(prisma|migrations|db|database|seed|seeds)\//i.test(filePath)
    || /\.(prisma|sql|[cm]?[jt]sx?|json|ya?ml|md)$/i.test(filePath);
}

function databasePathSignal(filePath: string): boolean {
  return /(schema\.prisma|prisma\.config|prisma\/|migrations\/|migration\.sql|seed|database|db\/|docker-compose|compose\.ya?ml|\.env\.example|\.env\.sample)/i.test(filePath);
}

function databaseContentSignal(text: string): boolean {
  return /PrismaClient|@prisma\/client|\bprisma\s+(validate|format|generate|migrate|db|studio)\b|schema\.prisma|datasource\s+\w+|generator\s+\w+|DATABASE_URL|provider\s*=|prisma\/config|defineConfig|migrations|seed/i.test(text);
}

function databaseSchemaFiles(sourceFiles: DatabaseSourceFile[]): DatabaseReadinessReport["schemaFiles"] {
  return sourceFiles
    .filter((source) => path.basename(source.filePath).toLowerCase() === "schema.prisma")
    .slice(0, 120)
    .map((source) => {
      const datasourceCount = countMatches(source.text, /\bdatasource\s+\w+\s*\{/g);
      const generatorCount = countMatches(source.text, /\bgenerator\s+\w+\s*\{/g);
      const modelCount = countMatches(source.text, /\bmodel\s+\w+\s*\{/g);
      const provider = normalizeDatabaseProvider(firstMatch(source.text, /provider\s*=\s*"([^"]+)"/i));
      return {
        filePath: source.filePath,
        provider,
        datasourceCount,
        generatorCount,
        modelCount,
        readiness: datasourceCount > 0 && generatorCount > 0 && modelCount > 0 ? "ready" : datasourceCount > 0 || generatorCount > 0 || modelCount > 0 ? "partial" : "missing",
        evidence: `${source.filePath} has ${datasourceCount} datasource block(s), ${generatorCount} generator block(s), and ${modelCount} model block(s).`,
        sourceHref: source.sourceHref
      };
    });
}

function databaseDatasourceSignals(schemaFiles: DatabaseReadinessReport["schemaFiles"], sourceFiles: DatabaseSourceFile[]): DatabaseReadinessReport["datasourceSignals"] {
  const providers: DatabaseReadinessReport["datasourceSignals"][number]["provider"][] = ["postgresql", "mysql", "sqlite", "sqlserver", "mongodb", "cockroachdb", "mariadb"];
  return providers.map((provider) => {
    const schema = schemaFiles.find((item) => item.provider === provider);
    const source = sourceFiles.find((item) => new RegExp(`provider\\s*=\\s*[\"']${provider}[\"']|${provider}`, "i").test(item.text));
    return {
      provider,
      readiness: schema ? "ready" : source ? "partial" : sourceFiles.length > 0 ? "external" : "missing",
      evidence: schema ? `${schema.filePath} declares datasource provider ${provider}.` : source ? `${source.filePath} references ${provider}.` : `${provider} datasource evidence was not detected.`,
      relatedHref: schema?.sourceHref ?? source?.sourceHref ?? "html/database-readiness.html"
    };
  });
}

function databaseMigrationSignals(sourceFiles: DatabaseSourceFile[]): DatabaseReadinessReport["migrationSignals"] {
  const specs: Array<{ signal: DatabaseReadinessReport["migrationSignals"][number]["signal"]; pattern: RegExp; evidence: string }> = [
    { signal: "migrations-folder", pattern: /(^|\/)migrations\/|migrations\s*:/i, evidence: "migrations folder or configured migration path evidence was detected." },
    { signal: "migration-sql", pattern: /migration\.sql|CREATE TABLE|ALTER TABLE|DROP TABLE/i, evidence: "SQL migration file evidence was detected." },
    { signal: "migration-lock", pattern: /migration_lock\.toml/i, evidence: "Prisma migration lock evidence was detected." },
    { signal: "migrate-dev", pattern: /prisma\s+migrate\s+dev|migrate dev/i, evidence: "development migration command evidence was detected." },
    { signal: "migrate-deploy", pattern: /prisma\s+migrate\s+deploy|migrate deploy/i, evidence: "deployment migration command evidence was detected." },
    { signal: "db-push", pattern: /prisma\s+db\s+push|db push/i, evidence: "db push workflow evidence was detected." },
    { signal: "introspection", pattern: /prisma\s+db\s+pull|introspect|introspection/i, evidence: "database introspection evidence was detected." },
    { signal: "schema-drift", pattern: /schema drift|drift detected|database is out of sync|migrate diff/i, evidence: "schema drift detection evidence was detected." }
  ];
  return databaseSignalFromSpecs(sourceFiles, specs, "migration");
}

function databaseClientSignals(sourceFiles: DatabaseSourceFile[]): DatabaseReadinessReport["clientSignals"] {
  const specs: Array<{ signal: DatabaseReadinessReport["clientSignals"][number]["signal"]; pattern: RegExp; evidence: string }> = [
    { signal: "prisma-client", pattern: /PrismaClient|@prisma\/client|generated\/(?:prisma\/)?client/i, evidence: "PrismaClient runtime usage evidence was detected." },
    { signal: "client-generation", pattern: /prisma\s+generate|generator\s+client|generate"/i, evidence: "Prisma Client generation evidence was detected." },
    { signal: "custom-output", pattern: /output\s*=|generated\/client|generated\/prisma/i, evidence: "custom generated client output evidence was detected." },
    { signal: "prisma-client-js", pattern: /prisma-client-js|provider\s*=\s*"prisma-client-js"/i, evidence: "traditional prisma-client-js generator evidence was detected." },
    { signal: "driver-adapter", pattern: /adapter|@prisma\/adapter-|PrismaPg|driver adapter/i, evidence: "driver adapter evidence was detected." },
    { signal: "typed-query", pattern: /typedSql|typed-sql|queryRaw|executeRaw/i, evidence: "typed/raw query surface evidence was detected." },
    { signal: "studio", pattern: /prisma\s+studio|Prisma Studio|studio"/i, evidence: "Prisma Studio evidence was detected." }
  ];
  return databaseSignalFromSpecs(sourceFiles, specs, "client");
}

function databaseConfigSignals(sourceFiles: DatabaseSourceFile[]): DatabaseReadinessReport["configSignals"] {
  const specs: Array<{ signal: DatabaseReadinessReport["configSignals"][number]["signal"]; pattern: RegExp; evidence: string }> = [
    { signal: "prisma-config", pattern: /prisma\.config\.[cm]?[jt]s|defineConfig|prisma\/config/i, evidence: "prisma.config evidence was detected." },
    { signal: "database-url", pattern: /DATABASE_URL|datasource:\s*\{|env\(['"]DATABASE_URL|url\s*:\s*env/i, evidence: "database URL boundary evidence was detected." },
    { signal: "dotenv", pattern: /dotenv|@dotenvx|\.env/i, evidence: "dotenv loading or env example evidence was detected." },
    { signal: "seed", pattern: /prisma\s+db\s+seed|"seed"\s*:|seed\.([cm]?[jt]s|ts|js)|seed-data/i, evidence: "seed workflow evidence was detected." },
    { signal: "package-script", pattern: /"prisma"\s*:|"dbpush"\s*:|"generate"\s*:\s*"[^"]*prisma|@prisma\/client|\bprisma\b/i, evidence: "package Prisma dependency or script evidence was detected." },
    { signal: "docker-compose", pattern: /docker-compose|compose\.ya?ml|postgres:|mysql:|mariadb:|mongo:/i, evidence: "local database service evidence was detected." },
    { signal: "env-example", pattern: /\.env\.example|\.env\.sample|DATABASE_URL=/i, evidence: "env example evidence was detected." }
  ];
  return databaseSignalFromSpecs(sourceFiles, specs, "config");
}

function databaseModelSignals(sourceFiles: DatabaseSourceFile[]): DatabaseReadinessReport["modelSignals"] {
  const specs: Array<{ signal: DatabaseReadinessReport["modelSignals"][number]["signal"]; pattern: RegExp; evidence: string }> = [
    { signal: "model", pattern: /\bmodel\s+\w+\s*\{/i, evidence: "model block evidence was detected." },
    { signal: "relation", pattern: /@relation|\w+\s+\w+\[\]/i, evidence: "relation evidence was detected." },
    { signal: "id", pattern: /@id|@@id/i, evidence: "primary key evidence was detected." },
    { signal: "unique", pattern: /@unique|@@unique/i, evidence: "unique constraint evidence was detected." },
    { signal: "index", pattern: /@@index|@@fulltext|@@map/i, evidence: "index or mapped model evidence was detected." },
    { signal: "enum", pattern: /\benum\s+\w+\s*\{/i, evidence: "enum evidence was detected." },
    { signal: "native-type", pattern: /@db\./i, evidence: "native database type evidence was detected." },
    { signal: "default", pattern: /@default\(/i, evidence: "default value evidence was detected." },
    { signal: "map", pattern: /@map|@@map/i, evidence: "database mapping evidence was detected." }
  ];
  return databaseSignalFromSpecs(sourceFiles, specs, "model");
}

function databaseSignalFromSpecs<T extends { signal: string; pattern: RegExp; evidence: string }>(
  sourceFiles: DatabaseSourceFile[],
  specs: T[],
  label: string
): Array<{ signal: T["signal"]; readiness: "ready" | "missing" | "external"; evidence: string; relatedHref: string }> {
  return specs.map((spec) => {
    const match = sourceFiles.find((source) => spec.pattern.test(source.text) || spec.pattern.test(source.filePath));
    return {
      signal: spec.signal,
      readiness: match ? "ready" : sourceFiles.length > 0 ? "external" : "missing",
      evidence: match ? `${match.filePath} ${spec.evidence}` : `${label} ${spec.signal} evidence was not detected.`,
      relatedHref: match?.sourceHref ?? "html/database-readiness.html"
    };
  });
}

function normalizeDatabaseProvider(value: string | null): DatabaseReadinessReport["schemaFiles"][number]["provider"] {
  const normalized = value?.toLowerCase();
  if (normalized === "postgresql" || normalized === "postgres") return "postgresql";
  if (normalized === "mysql") return "mysql";
  if (normalized === "sqlite") return "sqlite";
  if (normalized === "sqlserver" || normalized === "mssql") return "sqlserver";
  if (normalized === "mongodb" || normalized === "mongo") return "mongodb";
  if (normalized === "cockroachdb") return "cockroachdb";
  if (normalized === "mariadb") return "mariadb";
  return "unknown";
}

async function buildDatabaseMigrationReadinessReport(walk: WalkResult): Promise<DatabaseMigrationReadinessReport> {
  const sourceFiles = await databaseMigrationReadinessSourceFiles(walk);
  const migrationSetups = databaseMigrationReadinessSetupRows(sourceFiles);
  const fileSignals = databaseMigrationReadinessFileSignals(sourceFiles);
  const lineageSignals = databaseMigrationReadinessLineageSignals(sourceFiles);
  const rollbackSignals = databaseMigrationReadinessRollbackSignals(sourceFiles);
  const validationSignals = databaseMigrationReadinessValidationSignals(sourceFiles);
  const configSignals = databaseMigrationReadinessConfigSignals(sourceFiles);
  const ciSignals = databaseMigrationReadinessCiSignals(sourceFiles);
  const packageSignals = databaseMigrationReadinessPackageSignals(sourceFiles);
  const hasMigration = migrationSetups.some((item) => item.readiness !== "missing") || fileSignals.some((item) => item.readiness === "ready");
  const hasLineage = lineageSignals.some((item) => item.readiness === "ready");
  const hasRollback = rollbackSignals.some((item) => item.readiness === "ready");
  const hasValidation = validationSignals.some((item) => item.readiness === "ready");
  const hasCi = ciSignals.some((item) => ["github-actions", "migration-command", "dry-run", "schema-drift"].includes(item.signal) && item.readiness === "ready");

  const riskQueue: DatabaseMigrationReadinessReport["riskQueue"] = [];
  if (!hasMigration) {
    riskQueue.push({
      priority: "medium",
      action: "Add or document a versioned migration path before treating database schema changes as reproducible.",
      why: "Flyway, Liquibase, and Alembic-style workflows start with visible migration files, changelogs, or revision scripts.",
      relatedHref: "html/database-migration-readiness.html"
    });
  }
  if (hasMigration && !hasLineage) {
    riskQueue.push({
      priority: "high",
      action: "Record migration lineage through version prefixes, down_revision, checksum tables, or schema history.",
      why: "Migration files without ordering and applied-history evidence are hard to reason about during drift or rollback reviews.",
      relatedHref: "html/database-migration-readiness.html"
    });
  }
  if (hasMigration && !hasRollback) {
    riskQueue.push({
      priority: "medium",
      action: "Document rollback or restore policy for irreversible schema changes.",
      why: "Liquibase rollback blocks, Alembic downgrade functions, Flyway undo migrations, and Rails down/change paths make failure recovery visible.",
      relatedHref: "html/database-migration-readiness.html"
    });
  }
  if (hasMigration && !hasValidation) {
    riskQueue.push({
      priority: "high",
      action: "Add static validation or dry-run commands for migration review.",
      why: "Flyway validate/info, Liquibase status/updateSQL, and Alembic current/heads/check catch drift before changing a shared database.",
      relatedHref: "html/database-migration-readiness.html"
    });
  }
  if (hasMigration && !hasCi) {
    riskQueue.push({
      priority: "medium",
      action: "Wire migration validation, dry-run SQL, or drift checks into CI with explicit database service boundaries.",
      why: "Migration safety degrades when schema changes are only tested manually on a developer machine.",
      relatedHref: "html/database-migration-readiness.html"
    });
  }
  riskQueue.push({
    priority: "low",
    action: "Run migration commands only in a trusted disposable database or reviewed CI job.",
    why: "RepoTutor records static migration readiness only; it does not connect to databases, run migrate, update, rollback, repair, or stamp commands.",
    relatedHref: "html/database-migration-readiness.html"
  });

  return {
    summary: `Database migration readiness report: setup ${migrationSetups.length}개, file signal ${fileSignals.filter((item) => item.readiness === "ready").length}개, lineage signal ${lineageSignals.filter((item) => item.readiness === "ready").length}개, validation signal ${validationSignals.filter((item) => item.readiness === "ready").length}개를 정적 분석으로 정리했습니다.`,
    sourcePattern: "Database migration readiness Flyway Liquibase Alembic versioned migrations changelog changeset revision down_revision upgrade downgrade rollback validate repair info status updateSQL current heads dry-run drift CI",
    migrationSetups,
    fileSignals,
    lineageSignals,
    rollbackSignals,
    validationSignals,
    configSignals,
    ciSignals,
    packageSignals,
    riskQueue: riskQueue.sort((a, b) => ({ high: 0, medium: 1, low: 2 }[a.priority] - { high: 0, medium: 1, low: 2 }[b.priority])),
    recommendedCommands: [
      { command: "flyway info -configFiles=flyway.conf", purpose: "Inspect Flyway migration history and pending versioned/repeatable migrations in a safe database." },
      { command: "flyway validate", purpose: "Validate Flyway resolved migrations against the schema history table before deployment." },
      { command: "liquibase status --verbose", purpose: "Review pending Liquibase changesets without applying them." },
      { command: "liquibase updateSQL", purpose: "Generate SQL for review instead of applying Liquibase changes immediately." },
      { command: "alembic current && alembic heads", purpose: "Compare applied Alembic revision state with available heads." },
      { command: "alembic revision --autogenerate -m \"check drift\" && git diff -- migrations", purpose: "Use Alembic autogenerate as a drift review against a disposable database." },
      { command: "rg \"flyway|liquibase|alembic|V[0-9]+__|databaseChangeLog|changeSet|down_revision|def downgrade|updateSQL|validate|repair\" .", purpose: "Locate static migration files, lineage, rollback, and validation evidence." }
    ],
    learnerNextSteps: [
      "먼저 migration file naming과 applied-history boundary를 분리하세요: Flyway version prefix, Liquibase DATABASECHANGELOG, Alembic down_revision/heads를 찾습니다.",
      "Rollback은 파일 존재와 별개입니다. Liquibase rollback block, Alembic downgrade, Flyway undo, Rails down/change 정책을 확인하세요.",
      "validate/info/status/updateSQL/current/heads 같은 dry-run 또는 drift review 명령이 CI에 있는지 확인하세요.",
      "이 리포트는 정적 readiness입니다. 실제 migration, rollback, repair, stamp는 disposable DB 또는 검토된 CI에서만 실행해야 합니다."
    ]
  };
}

type DatabaseMigrationReadinessSourceFile = {
  filePath: string;
  text: string;
  sourceHref: string;
};

async function databaseMigrationReadinessSourceFiles(walk: WalkResult): Promise<DatabaseMigrationReadinessSourceFile[]> {
  const files: DatabaseMigrationReadinessSourceFile[] = [];
  for (const file of walk.files) {
    if (!file.isTextCandidate || !databaseMigrationReadinessInspectablePath(file.relPath)) continue;
    const pathCandidate = databaseMigrationReadinessPathSignal(file.relPath);
    const text = await readTextIfSafe(file.absPath, 180_000);
    if (!text) continue;
    if (!pathCandidate && !databaseMigrationReadinessContentSignal(text)) continue;
    files.push({ filePath: file.relPath, text, sourceHref: `source/${encodedPath(file.relPath)}` });
    if (files.length >= 220) break;
  }
  return files;
}

function databaseMigrationReadinessInspectablePath(filePath: string): boolean {
  const base = path.basename(filePath);
  return /^(flyway\.conf|flyway\.toml|liquibase\.properties|liquibase\.yaml|liquibase\.yml|liquibase\.json|liquibase\.xml|alembic\.ini|env\.py|package\.json|Gemfile|pyproject\.toml|requirements.*\.txt|README\.md)$/i.test(base)
    || /^\.github\/workflows\/.+\.ya?ml$/i.test(filePath)
    || /(^|\/)(db\/migrate|migrations?|versions|database\/changelog|changelogs?|liquibase|flyway|alembic|drizzle|prisma)(\/|\.|$)/i.test(filePath)
    || /\.(sql|xml|ya?ml|json|toml|ini|py|rb|[cm]?[jt]sx?|md)$/i.test(filePath);
}

function databaseMigrationReadinessPathSignal(filePath: string): boolean {
  return /(^|\/)(db\/migrate|migrations?|versions|database\/changelog|changelogs?|liquibase|flyway|alembic|drizzle|prisma)(\/|\.|$)|(^|\/)(V[0-9][^/]*__.*\.sql|R__.*\.sql|U[0-9][^/]*__.*\.sql)|alembic\.ini|flyway\.(conf|toml)|liquibase\.properties/i.test(filePath);
}

function databaseMigrationReadinessContentSignal(text: string): boolean {
  return /(flyway|baselineOnMigrate|validateOnMigrate|cleanDisabled|outOfOrder|databaseChangeLog|changeSet|--liquibase formatted sql|preConditions|rollback|runOnChange|runAlways|tagDatabase|liquibase status|updateSQL|DATABASECHANGELOG|alembic|script_location|version_locations|down_revision|def upgrade|def downgrade|autogenerate|run_migrations_online|run_migrations_offline|drizzle-kit|rails db:migrate|ActiveRecord::Migration|prisma migrate|migrate deploy)/i.test(text);
}

function databaseMigrationReadinessSetupRows(sourceFiles: DatabaseMigrationReadinessSourceFile[]): DatabaseMigrationReadinessReport["migrationSetups"] {
  const rows: DatabaseMigrationReadinessReport["migrationSetups"] = [];
  for (const source of sourceFiles) {
    const haystack = `${source.filePath}\n${source.text}`;
    const versionedCount = countMatches(haystack, /(^|\/)V[0-9][A-Za-z0-9_.-]*__[^/\s]+\.sql|versioned migration|create_table|ActiveRecord::Migration|prisma migrate|drizzle-kit (generate|migrate)/gi);
    const repeatableCount = countMatches(haystack, /(^|\/)R__[^/\s]+\.sql|repeatable migration|repeatableSqlMigrationPrefix/gi);
    const changelogCount = countMatches(haystack, /databaseChangeLog|--liquibase formatted sql|changelogFile|includeAll|include file|liquibase\.(properties|ya?ml|xml|json)/gi);
    const changesetCount = countMatches(haystack, /changeSet|--changeset|runOnChange|runAlways|preConditions|tagDatabase/gi);
    const revisionCount = countMatches(haystack, /revision\s*=|down_revision\s*=|def upgrade|def downgrade|script_location|version_locations|alembic revision|alembic upgrade/gi);
    const rollbackCount = countMatches(haystack, /rollback|def downgrade|(^|\/)U[0-9][A-Za-z0-9_.-]*__[^/\s]+\.sql|revert|down\s+do|def down|restore point|restore-point/gi);
    const validationCount = countMatches(haystack, /flyway (validate|info|repair)|validateOnMigrate|liquibase (status|updateSQL|validate|checks)|alembic (current|heads|check|history)|drizzle-kit check|migrate diff|schema drift|drift detected/gi);
    const ciCount = countMatches(haystack, /^\.github\/workflows\/|GitHub Actions|runs-on|pull_request|workflow_dispatch|services:|postgres:|mysql:|upload-artifact|environment:|manual approval|migration/gi);
    const totalSignals = versionedCount + repeatableCount + changelogCount + changesetCount + revisionCount + rollbackCount + validationCount + ciCount;
    if (totalSignals === 0 && !databaseMigrationReadinessPathSignal(source.filePath)) continue;
    const readiness = (versionedCount > 0 || changelogCount > 0 || revisionCount > 0) && validationCount > 0 && rollbackCount > 0
      ? "ready"
      : totalSignals > 0
        ? "partial"
        : "missing";
    rows.push({
      filePath: source.filePath,
      tool: databaseMigrationReadinessTool(source.filePath, source.text),
      versionedCount,
      repeatableCount,
      changelogCount,
      changesetCount,
      revisionCount,
      rollbackCount,
      validationCount,
      ciCount,
      readiness,
      evidence: `${source.filePath} contains ${totalSignals} database migration readiness signal(s).`,
      sourceHref: source.sourceHref
    });
  }
  const order = { ready: 0, partial: 1, missing: 2 };
  return rows.sort((a, b) => order[a.readiness] - order[b.readiness] || a.filePath.localeCompare(b.filePath)).slice(0, 100);
}

function databaseMigrationReadinessTool(filePath: string, text: string): DatabaseMigrationReadinessReport["migrationSetups"][number]["tool"] {
  const haystack = `${filePath}\n${text}`;
  if (/flyway|(^|\/)V[0-9][^/]*__.*\.sql|(^|\/)R__.*\.sql|flyway\.(conf|toml)/i.test(haystack)) return "flyway";
  if (/liquibase|databaseChangeLog|changeSet|--liquibase formatted sql|DATABASECHANGELOG/i.test(haystack)) return "liquibase";
  if (/alembic|alembic\.ini|down_revision|def upgrade|def downgrade|script_location|version_locations/i.test(haystack)) return "alembic";
  if (/drizzle-kit|drizzle\/meta|_journal\.json|drizzle migrations/i.test(haystack)) return "drizzle";
  if (/ActiveRecord::Migration|rails db:migrate|db\/migrate/i.test(haystack)) return "rails";
  if (/prisma migrate|migration_lock\.toml|schema\.prisma/i.test(haystack)) return "prisma";
  if (/\.sql$|CREATE TABLE|ALTER TABLE|DROP TABLE/i.test(haystack)) return "sql";
  return databaseMigrationReadinessContentSignal(text) ? "custom" : "unknown";
}

function databaseMigrationReadinessFileSignals(sourceFiles: DatabaseMigrationReadinessSourceFile[]): DatabaseMigrationReadinessReport["fileSignals"] {
  const specs: Array<{ signal: DatabaseMigrationReadinessReport["fileSignals"][number]["signal"]; pattern: RegExp; evidence: string }> = [
    { signal: "flyway-versioned", pattern: /(^|\/)V[0-9][A-Za-z0-9_.-]*__[^/\s]+\.sql|versioned migration/i, evidence: "Flyway versioned migration evidence was detected." },
    { signal: "flyway-repeatable", pattern: /(^|\/)R__[^/\s]+\.sql|repeatable migration/i, evidence: "Flyway repeatable migration evidence was detected." },
    { signal: "flyway-undo", pattern: /(^|\/)U[0-9][A-Za-z0-9_.-]*__[^/\s]+\.sql|undo migration/i, evidence: "Flyway undo migration evidence was detected." },
    { signal: "liquibase-changelog", pattern: /databaseChangeLog|changelogFile|includeAll|liquibase\.(properties|ya?ml|xml|json)/i, evidence: "Liquibase changelog evidence was detected." },
    { signal: "liquibase-formatted-sql", pattern: /--liquibase formatted sql|--changeset/i, evidence: "Liquibase formatted SQL evidence was detected." },
    { signal: "alembic-revision", pattern: /revision\s*=|down_revision\s*=|def upgrade|def downgrade|versions\/.+\.py/i, evidence: "Alembic revision evidence was detected." },
    { signal: "drizzle-migration", pattern: /drizzle-kit|drizzle\/meta|_journal\.json|sql.*breakpoint/i, evidence: "Drizzle migration evidence was detected." },
    { signal: "rails-migration", pattern: /ActiveRecord::Migration|db\/migrate|create_table|change_table|rails db:migrate/i, evidence: "Rails migration evidence was detected." },
    { signal: "sql-migration", pattern: /CREATE TABLE|ALTER TABLE|DROP TABLE|CREATE INDEX|ALTER INDEX/i, evidence: "SQL migration evidence was detected." }
  ];
  return databaseMigrationReadinessSignalFromSpecs(sourceFiles, specs, "file", "signal");
}

