function coverageReadinessPackageSignals(sourceFiles: CoverageReadinessSourceFile[]): CoverageReadinessReport["packageSignals"] {
  const specs: Array<{ signal: CoverageReadinessReport["packageSignals"][number]["signal"]; pattern: RegExp; evidence: string }> = [
    { signal: "nyc", pattern: /"nyc"|@istanbuljs\/nyc-config|nyc\s+/i, evidence: "nyc package/command evidence was detected." },
    { signal: "c8", pattern: /"c8"|\bc8\s+/i, evidence: "c8 package/command evidence was detected." },
    { signal: "@vitest/coverage-v8", pattern: /@vitest\/coverage-v8/i, evidence: "Vitest V8 coverage package evidence was detected." },
    { signal: "@vitest/coverage-istanbul", pattern: /@vitest\/coverage-istanbul/i, evidence: "Vitest Istanbul coverage package evidence was detected." },
    { signal: "jest", pattern: /"jest"|jest\s+.*--coverage|coverageThreshold|collectCoverageFrom/i, evidence: "Jest coverage evidence was detected." },
    { signal: "babel-plugin-istanbul", pattern: /babel-plugin-istanbul/i, evidence: "Babel Istanbul package evidence was detected." },
    { signal: "coverage", pattern: /coverage\.py|coverage\s*(=|>=|~=)|"coverage"/i, evidence: "coverage.py package evidence was detected." },
    { signal: "pytest-cov", pattern: /pytest-cov|--cov\b/i, evidence: "pytest-cov package/command evidence was detected." },
    { signal: "codecov-action", pattern: /codecov\/codecov-action/i, evidence: "Codecov Action package/workflow evidence was detected." },
    { signal: "coveralls", pattern: /coveralls/i, evidence: "Coveralls package/workflow evidence was detected." }
  ];
  return coverageReadinessSignalFromSpecs(sourceFiles, specs, "package", "signal");
}

function coverageReadinessSignalFromSpecs<T extends Record<K, string> & { pattern: RegExp; evidence: string }, K extends string>(
  sourceFiles: CoverageReadinessSourceFile[],
  specs: T[],
  label: string,
  labelKey: K
): Array<Record<K, T[K]> & { readiness: "ready" | "missing" | "external"; evidence: string; relatedHref: string }> {
  return specs.map((spec) => {
    const match = sourceFiles.find((source) => spec.pattern.test(source.filePath) || spec.pattern.test(source.text));
    return {
      [labelKey]: spec[labelKey],
      readiness: match ? "ready" : sourceFiles.length > 0 ? "external" : "missing",
      evidence: match ? `${match.filePath} ${spec.evidence}` : `${label} ${spec[labelKey]} evidence was not detected.`,
      relatedHref: match?.sourceHref ?? "html/coverage-readiness.html"
    } as Record<K, T[K]> & { readiness: "ready" | "missing" | "external"; evidence: string; relatedHref: string };
  });
}

async function buildMutationTestingReadinessReport(walk: WalkResult): Promise<MutationTestingReadinessReport> {
  const sourceFiles = await mutationTestingSourceFiles(walk);
  const mutationSetups = mutationTestingSetups(sourceFiles);
  const toolSignals = mutationTestingToolSignals(sourceFiles);
  const configSignals = mutationTestingConfigSignals(sourceFiles);
  const qualitySignals = mutationTestingQualitySignals(sourceFiles);
  const reporterSignals = mutationTestingReporterSignals(sourceFiles);
  const scopeSignals = mutationTestingScopeSignals(sourceFiles);
  const packageSignals = mutationTestingPackageSignals(sourceFiles);
  const hasSetup = mutationSetups.length > 0;
  const hasPackage = packageSignals.some((item) => item.readiness === "ready");
  const hasMutate = configSignals.some((item) => item.signal === "mutate-pattern" && item.readiness === "ready")
    || scopeSignals.some((item) => ["src", "lib"].includes(item.signal) && item.readiness === "ready");
  const hasRunner = configSignals.some((item) => item.signal === "test-runner" && item.readiness === "ready");
  const hasThreshold = qualitySignals.some((item) => ["thresholds", "mutation-score", "covered-score"].includes(item.signal) && item.readiness === "ready");
  const hasReporter = reporterSignals.some((item) => ["html", "json", "dashboard", "mutation-testing-report-schema", "junit"].includes(item.signal) && item.readiness === "ready");
  const hasSafety = qualitySignals.some((item) => ["survived", "timeout", "ignored", "no-coverage"].includes(item.signal) && item.readiness === "ready")
    || scopeSignals.some((item) => ["ignore-patterns", "with-uncovered"].includes(item.signal) && item.readiness === "ready");

  const riskQueue: MutationTestingReadinessReport["riskQueue"] = [];
  if (!hasSetup) {
    riskQueue.push({
      priority: "high",
      action: "Add mutation testing configuration before claiming mutation readiness.",
      why: "Stryker and Infection both center readiness on explicit config, mutation scope, runner, reporters, and score thresholds; this scan did not find a setup.",
      relatedHref: "html/mutation-testing-readiness.html"
    });
  }
  if (hasSetup && !hasPackage) {
    riskQueue.push({
      priority: "medium",
      action: "Declare the mutation testing tool dependency or documented installer.",
      why: "A config file without an installed Stryker, Infection, mutmut, or PIT package makes the repeatable command unclear.",
      relatedHref: "html/mutation-testing-readiness.html"
    });
  }
  if (hasSetup && !hasMutate) {
    riskQueue.push({
      priority: "high",
      action: "Define the mutation scope with mutate/source patterns.",
      why: "Mutation engines need explicit source files or directories so tests are not wasted on fixtures, generated files, or test files.",
      relatedHref: "html/mutation-testing-readiness.html"
    });
  }
  if (hasSetup && !hasRunner) {
    riskQueue.push({
      priority: "medium",
      action: "Connect the mutation engine to the test runner.",
      why: "Mutation score is only meaningful when the engine can run the repository's real test framework for each mutant.",
      relatedHref: "html/mutation-testing-readiness.html"
    });
  }
  if (hasSetup && !hasThreshold) {
    riskQueue.push({
      priority: "medium",
      action: "Set mutation score thresholds before using mutation testing as a release gate.",
      why: "Thresholds such as Stryker high/low/break or Infection min-msi/min-covered-msi convert reports into enforceable quality gates.",
      relatedHref: "html/mutation-testing-readiness.html"
    });
  }
  if (hasSetup && !hasReporter) {
    riskQueue.push({
      priority: "low",
      action: "Add HTML or JSON mutation reports for learner review.",
      why: "Machine-readable and browsable reports show killed, survived, timeout, ignored, and no-coverage mutants without rerunning the engine.",
      relatedHref: "html/mutation-testing-readiness.html"
    });
  }
  if (hasSetup && !hasSafety) {
    riskQueue.push({
      priority: "low",
      action: "Document timeout, ignored mutant, or no-coverage handling.",
      why: "Mutation testing can produce slow or intentionally equivalent mutants; safety metadata helps learners separate real gaps from tool noise.",
      relatedHref: "html/mutation-testing-readiness.html"
    });
  }

  return {
    summary: `Mutation testing readiness report: setups ${mutationSetups.length}개, tool signals ${toolSignals.filter((item) => item.readiness === "ready").length}개, quality signals ${qualitySignals.filter((item) => item.readiness === "ready").length}개를 정적 분석으로 정리했습니다.`,
    sourcePattern: "Stryker mutation testing mutate patterns mutators testRunner coverageAnalysis reporters thresholds mutationScore killed survived timeout ignored incremental dashboard HTML JSON mutation-testing-report-schema Infection MSI covered MSI with-uncovered",
    mutationSetups,
    toolSignals,
    configSignals,
    qualitySignals,
    reporterSignals,
    scopeSignals,
    packageSignals,
    riskQueue: riskQueue.sort((a, b) => ({ high: 0, medium: 1, low: 2 }[a.priority] - { high: 0, medium: 1, low: 2 }[b.priority])),
    recommendedCommands: [
      { command: "npx stryker run", purpose: "Run the configured JavaScript or TypeScript mutation test suite once." },
      { command: "npx stryker run --incremental", purpose: "Reuse prior Stryker results when the repository supports incremental mutation testing." },
      { command: "npx stryker run --reporters html,json,clear-text", purpose: "Emit learner-friendly and machine-readable mutation reports." },
      { command: "npx stryker run --testRunner vitest", purpose: "Force Stryker to use the Vitest runner when the config is ambiguous." },
      { command: "vendor/bin/infection --min-msi=80 --min-covered-msi=90", purpose: "Run Infection in a trusted PHP workspace with explicit MSI gates." },
      { command: "rg \"stryker|infection|mutationScore|mutate|mutators|thresholds\" .", purpose: "Audit mutation testing configuration and report evidence statically." }
    ],
    learnerNextSteps: [
      "Open the mutation config first: identify mutate/source scope, runner, mutators, coverage analysis, timeout, reporters, and score thresholds.",
      "Compare survived mutants with existing tests and write one focused test that kills a high-value survived mutant.",
      "Use HTML/JSON mutation reports to separate killed, survived, timeout, ignored, and no-coverage mutants before changing thresholds.",
      "RepoTutor records static mutation-readiness evidence only; run Stryker or Infection in a trusted workspace before treating this as quality approval."
    ]
  };
}

type MutationTestingSourceFile = {
  filePath: string;
  text: string;
  sourceHref: string;
};

async function mutationTestingSourceFiles(walk: WalkResult): Promise<MutationTestingSourceFile[]> {
  const files: MutationTestingSourceFile[] = [];
  for (const file of walk.files) {
    if (!file.isTextCandidate || !mutationTestingInspectablePath(file.relPath)) continue;
    const text = await readTextIfSafe(file.absPath, 180_000);
    if (!text) continue;
    const base = path.basename(file.relPath);
    if (!mutationTestingPathSignal(file.relPath) && !mutationTestingContentSignal(text) && base !== "package.json") continue;
    files.push({ filePath: file.relPath, text, sourceHref: `source/${encodedPath(file.relPath)}` });
    if (files.length >= 260) break;
  }
  return files;
}

function mutationTestingInspectablePath(filePath: string): boolean {
  const base = path.basename(filePath);
  return mutationTestingPathSignal(filePath)
    || /^(package\.json|composer\.json|stryker\.conf\.[cm]?[jt]s|stryker\.conf\.json|stryker\.config\.[cm]?[jt]s|infection\.json5?|README\.md)$/i.test(base)
    || /\.(json|md|ya?ml|xml|php|[cm]?[jt]sx?)$/i.test(base);
}

function mutationTestingPathSignal(filePath: string): boolean {
  const base = path.basename(filePath);
  return /(^|\/)(stryker|infection|mutmut|pitest|mutation|mutations?|mutators?|mutation-reports?|reports\/mutation|reports\/stryker|\.stryker-tmp)(\/|$)/i.test(filePath)
    || /^stryker\.(conf|config)\./i.test(base)
    || /^infection\.json5?$/i.test(base)
    || /(mutation|mutator|stryker|infection|mutmut|pitest)/i.test(filePath);
}

function mutationTestingContentSignal(text: string): boolean {
  return /\b(@stryker-mutator|stryker\s+run|Stryker|infection\/infection|bin\/infection|mutation testing|mutationScore|mutation score|mutators?|mutants?|testRunner|coverageAnalysis|disableTypeChecks|min-msi|min-covered-msi|covered MSI|with-uncovered|NoCoverage|mutation-testing-report-schema|mutmut|pitest)\b/i.test(text);
}

function mutationTestingSetups(sourceFiles: MutationTestingSourceFile[]): MutationTestingReadinessReport["mutationSetups"] {
  return sourceFiles
    .filter((source) => mutationTestingPathSignal(source.filePath) || mutationTestingContentSignal(source.text))
    .slice(0, 160)
    .map((source) => {
      const configCount = countMatches(source.text, /stryker\.conf|stryker\.config|infection\.json|pitest|mutmut|mutation testing|@stryker-mutator\/core|infection\/infection/gim);
      const mutatePatternCount = countMatches(source.text, /mutate\s*:|mutate"\s*:|sourceDirs|src\/|lib\/|--with-uncovered|with-uncovered/gim);
      const mutatorCount = countMatches(source.text, /mutator|mutators|BooleanLiteral|StringLiteral|ArrayDeclaration|ReturnRemoval/gim);
      const runnerCount = countMatches(source.text, /testRunner|vitest|jest|mocha|jasmine|phpunit|testFramework|JUnit/gim);
      const thresholdCount = countMatches(source.text, /threshold|thresholds|min-msi|min-covered-msi|mutationScore|mutation score|msi|covered MSI|high|low|break/gim);
      const reporterCount = countMatches(source.text, /reporters?|html|json|clear-text|dashboard|badge|junit|mutation-testing-report-schema|logs/gim);
      const timeoutCount = countMatches(source.text, /timeout|timeoutMS|timeoutFactor/gim);
      const incrementalCount = countMatches(source.text, /incremental|stryker-incremental|download-incremental-reports/gim);
      const ciCount = countMatches(source.text, /\.github\/workflows|CI|pull_request|workflow|dashboard/gim) + (/\.github\/workflows/i.test(source.filePath) ? 1 : 0);
      const total = configCount + mutatePatternCount + mutatorCount + runnerCount + thresholdCount + reporterCount + timeoutCount + incrementalCount + ciCount;
      return {
        filePath: source.filePath,
        tool: mutationTestingTool(source),
        configCount,
        mutatePatternCount,
        mutatorCount,
        runnerCount,
        thresholdCount,
        reporterCount,
        timeoutCount,
        incrementalCount,
        ciCount,
        readiness: configCount > 0 && mutatePatternCount > 0 && runnerCount > 0 && (thresholdCount > 0 || reporterCount > 0) && total >= 8 ? "ready" : total > 0 ? "partial" : "missing",
        evidence: `${source.filePath} has ${total} mutation testing setup signal(s): scope ${mutatePatternCount}, runner ${runnerCount}, thresholds ${thresholdCount}, reporters ${reporterCount}.`,
        sourceHref: source.sourceHref
      };
    });
}

function mutationTestingTool(source: MutationTestingSourceFile): MutationTestingReadinessReport["mutationSetups"][number]["tool"] {
  if (/@stryker-mutator|stryker\s+run|stryker\.conf|Stryker/i.test(source.text) || /stryker/i.test(source.filePath)) return "stryker";
  if (/infection\/infection|bin\/infection|infection\.json|MSI|covered MSI|min-msi|min-covered-msi/i.test(source.text) || /infection/i.test(source.filePath)) return "infection";
  if (/mutation-testing-report-schema|mutation-testing-elements|mutation testing report/i.test(source.text) || /mutation-testing-elements/i.test(source.filePath)) return "mutation-testing-elements";
  if (/mutmut/i.test(source.text) || /mutmut/i.test(source.filePath)) return "mutmut";
  if (/pitest|\bPIT\b/i.test(source.text) || /pitest/i.test(source.filePath)) return "pitest";
  if (/mutation testing|mutator|mutants?/i.test(source.text) || /mutation|mutator/i.test(source.filePath)) return "custom";
  return "unknown";
}

function mutationTestingToolSignals(sourceFiles: MutationTestingSourceFile[]): MutationTestingReadinessReport["toolSignals"] {
  const specs: Array<{ signal: MutationTestingReadinessReport["toolSignals"][number]["signal"]; pattern: RegExp; evidence: string }> = [
    { signal: "stryker", pattern: /@stryker-mutator|stryker\s+run|stryker\.conf|Stryker/i, evidence: "Stryker mutation testing evidence was detected." },
    { signal: "infection", pattern: /infection\/infection|bin\/infection|infection\.json|min-msi|min-covered-msi|\bMSI\b|covered MSI/i, evidence: "Infection mutation testing evidence was detected." },
    { signal: "mutmut", pattern: /\bmutmut\b/i, evidence: "mutmut evidence was detected." },
    { signal: "pitest", pattern: /\bpitest\b|\bPIT\b/i, evidence: "PIT mutation testing evidence was detected." },
    { signal: "mutation-testing-elements", pattern: /mutation-testing-report-schema|mutation-testing-elements|mutation testing report/i, evidence: "Mutation Testing Elements report schema evidence was detected." },
    { signal: "custom", pattern: /mutation testing|mutator|mutants?|mutationScore|mutation score/i, evidence: "custom mutation testing terminology was detected." }
  ];
  return mutationTestingSignalFromSpecs(sourceFiles, specs, "tool");
}

function mutationTestingConfigSignals(sourceFiles: MutationTestingSourceFile[]): MutationTestingReadinessReport["configSignals"] {
  const specs: Array<{ signal: MutationTestingReadinessReport["configSignals"][number]["signal"]; pattern: RegExp; evidence: string }> = [
    { signal: "config-file", pattern: /stryker\.(conf|config)\.|infection\.json|pitest|mutmut/i, evidence: "mutation testing config file evidence was detected." },
    { signal: "package-script", pattern: /"[^"]*(mutation|stryker|infection)[^"]*"\s*:\s*"[^"]*(stryker|infection|mutmut|pitest)[^"]*"/i, evidence: "package script evidence was detected." },
    { signal: "schema", pattern: /\$schema|mutation-testing-report-schema|schemaVersion/i, evidence: "schema evidence was detected." },
    { signal: "mutate-pattern", pattern: /mutate\s*:|mutate"\s*:|sourceDirs|src\/|lib\/|include\s*:|files\s*:/i, evidence: "mutation scope pattern evidence was detected." },
    { signal: "test-runner", pattern: /testRunner|vitest|jest|mocha|jasmine|phpunit|testFramework/i, evidence: "test runner evidence was detected." },
    { signal: "coverage-analysis", pattern: /coverageAnalysis|perTest|all|coverage/i, evidence: "coverage analysis evidence was detected." },
    { signal: "disable-type-checks", pattern: /disableTypeChecks|disable type checks/i, evidence: "disableTypeChecks evidence was detected." }
  ];
  return mutationTestingSignalFromSpecs(sourceFiles, specs, "config");
}

function mutationTestingQualitySignals(sourceFiles: MutationTestingSourceFile[]): MutationTestingReadinessReport["qualitySignals"] {
  const specs: Array<{ signal: MutationTestingReadinessReport["qualitySignals"][number]["signal"]; pattern: RegExp; evidence: string }> = [
    { signal: "thresholds", pattern: /threshold|thresholds|min-msi|min-covered-msi|high\s*:|low\s*:|break\s*:/i, evidence: "mutation threshold evidence was detected." },
    { signal: "mutation-score", pattern: /mutationScore|mutation score|\bMSI\b|min-msi/i, evidence: "mutation score evidence was detected." },
    { signal: "covered-score", pattern: /coveredScore|covered score|covered MSI|min-covered-msi/i, evidence: "covered mutation score evidence was detected." },
    { signal: "survived", pattern: /survived|Survived/i, evidence: "survived mutant evidence was detected." },
    { signal: "killed", pattern: /killed|Killed/i, evidence: "killed mutant evidence was detected." },
    { signal: "timeout", pattern: /timeout|Timeout|timeoutMS|timeoutFactor/i, evidence: "timeout mutant or config evidence was detected." },
    { signal: "ignored", pattern: /ignored|Ignored|ignoreStatic|ignore-pattern/i, evidence: "ignored mutant evidence was detected." },
    { signal: "no-coverage", pattern: /NoCoverage|no coverage|no-coverage/i, evidence: "no-coverage mutant evidence was detected." }
  ];
  return mutationTestingSignalFromSpecs(sourceFiles, specs, "quality");
}

function mutationTestingReporterSignals(sourceFiles: MutationTestingSourceFile[]): MutationTestingReadinessReport["reporterSignals"] {
  const specs: Array<{ signal: MutationTestingReadinessReport["reporterSignals"][number]["signal"]; pattern: RegExp; evidence: string }> = [
    { signal: "html", pattern: /reporters?[\s\S]{0,200}html|\bhtml\b/i, evidence: "HTML reporter evidence was detected." },
    { signal: "json", pattern: /reporters?[\s\S]{0,200}json|\bjson\b/i, evidence: "JSON reporter evidence was detected." },
    { signal: "clear-text", pattern: /clear-text|clearText/i, evidence: "clear-text reporter evidence was detected." },
    { signal: "progress", pattern: /\bprogress\b/i, evidence: "progress reporter evidence was detected." },
    { signal: "dashboard", pattern: /dashboard/i, evidence: "dashboard reporter evidence was detected." },
    { signal: "badge", pattern: /\bbadge\b/i, evidence: "badge reporter evidence was detected." },
    { signal: "junit", pattern: /\bjunit\b|JUnit/i, evidence: "JUnit reporter evidence was detected." },
    { signal: "mutation-testing-report-schema", pattern: /mutation-testing-report-schema|schemaVersion/i, evidence: "mutation testing report schema evidence was detected." }
  ];
  return mutationTestingSignalFromSpecs(sourceFiles, specs, "reporter");
}

function mutationTestingScopeSignals(sourceFiles: MutationTestingSourceFile[]): MutationTestingReadinessReport["scopeSignals"] {
  const specs: Array<{ signal: MutationTestingReadinessReport["scopeSignals"][number]["signal"]; pattern: RegExp; evidence: string }> = [
    { signal: "src", pattern: /src\/|sourceDirs[\s\S]{0,120}src|["']src["']/i, evidence: "src mutation scope evidence was detected." },
    { signal: "lib", pattern: /lib\/|["']lib["']|mutate[\s\S]{0,120}lib/i, evidence: "lib mutation scope evidence was detected." },
    { signal: "test-files", pattern: /tests?\/|__tests__|\.test\.|\.spec\.|testRunner|phpunit/i, evidence: "test file or runner scope evidence was detected." },
    { signal: "ignore-patterns", pattern: /ignoreStatic|ignorePatterns|ignore-pattern|excludedMutations|exclude\s*:/i, evidence: "ignore pattern evidence was detected." },
    { signal: "with-uncovered", pattern: /--with-uncovered|with-uncovered|withUncovered/i, evidence: "with-uncovered evidence was detected." },
    { signal: "incremental", pattern: /incremental|stryker-incremental|download-incremental-reports/i, evidence: "incremental mutation testing evidence was detected." },
    { signal: "dry-run", pattern: /dryRun|dry-run|dry run/i, evidence: "dry-run evidence was detected." }
  ];
  return mutationTestingSignalFromSpecs(sourceFiles, specs, "scope");
}

function mutationTestingPackageSignals(sourceFiles: MutationTestingSourceFile[]): MutationTestingReadinessReport["packageSignals"] {
  const specs: Array<{ signal: MutationTestingReadinessReport["packageSignals"][number]["signal"]; pattern: RegExp; evidence: string }> = [
    { signal: "@stryker-mutator/core", pattern: /@stryker-mutator\/core/i, evidence: "@stryker-mutator/core dependency evidence was detected." },
    { signal: "@stryker-mutator/vitest-runner", pattern: /@stryker-mutator\/vitest-runner/i, evidence: "Stryker Vitest runner dependency evidence was detected." },
    { signal: "@stryker-mutator/jest-runner", pattern: /@stryker-mutator\/jest-runner/i, evidence: "Stryker Jest runner dependency evidence was detected." },
    { signal: "mutation-testing-report-schema", pattern: /mutation-testing-report-schema/i, evidence: "mutation testing report schema package evidence was detected." },
    { signal: "infection/infection", pattern: /infection\/infection|bin\/infection/i, evidence: "Infection package evidence was detected." },
    { signal: "mutmut", pattern: /\bmutmut\b/i, evidence: "mutmut package evidence was detected." },
    { signal: "pitest", pattern: /\bpitest\b|\bPIT\b/i, evidence: "PIT package evidence was detected." },
    { signal: "custom", pattern: /mutation testing|mutator|mutants?|mutationScore|mutation score/i, evidence: "custom mutation testing package or terminology evidence was detected." }
  ];
  return mutationTestingSignalFromSpecs(sourceFiles, specs, "package");
}

function mutationTestingSignalFromSpecs<T extends { signal: string; pattern: RegExp; evidence: string }>(
  sourceFiles: MutationTestingSourceFile[],
  specs: T[],
  label: string
): Array<{ signal: T["signal"]; readiness: "ready" | "missing" | "external"; evidence: string; relatedHref: string }> {
  return specs.map((spec) => {
    const match = sourceFiles.find((source) => spec.pattern.test(source.text) || spec.pattern.test(source.filePath));
    return {
      signal: spec.signal,
      readiness: match ? "ready" : sourceFiles.length > 0 ? "external" : "missing",
      evidence: match ? `${match.filePath} ${spec.evidence}` : `${label} ${spec.signal} evidence was not detected.`,
      relatedHref: match?.sourceHref ?? "html/mutation-testing-readiness.html"
    };
  });
}

async function buildTypecheckReadinessReport(walk: WalkResult): Promise<TypecheckReadinessReport> {
  const sourceFiles = await typecheckSourceFiles(walk);
  const tsconfigFiles = typecheckTsconfigFiles(sourceFiles);
  const compilerOptionSignals = typecheckCompilerOptionSignals(sourceFiles);
  const projectSignals = typecheckProjectSignals(sourceFiles);
  const moduleResolutionSignals = typecheckModuleResolutionSignals(sourceFiles);
  const declarationSignals = typecheckDeclarationSignals(sourceFiles);
  const scriptSignals = typecheckScriptSignals(sourceFiles);
  const hasTsconfig = tsconfigFiles.length > 0;
  const hasStrict = compilerOptionSignals.some((item) => item.signal === "strict" && item.readiness === "ready");
  const hasTypecheckCommand = scriptSignals.some((item) => ["typecheck-script", "tsc", "noEmit-command", "project-build"].includes(item.signal) && item.readiness === "ready");
  const usesProjectReferences = projectSignals.some((item) => item.signal === "references" && item.readiness === "ready");
  const hasComposite = projectSignals.some((item) => item.signal === "composite" && item.readiness === "ready");
  const hasIncremental = projectSignals.some((item) => item.signal === "incremental" && item.readiness === "ready");
  const hasModuleResolution = moduleResolutionSignals.some((item) => item.signal === "moduleResolution" && item.readiness === "ready");
  const hasPaths = moduleResolutionSignals.some((item) => ["paths", "baseUrl"].includes(item.signal) && item.readiness === "ready");
  const hasDeclaration = declarationSignals.some((item) => ["declaration", "emitDeclarationOnly"].includes(item.signal) && item.readiness === "ready");
  const hasNoEmitOnError = compilerOptionSignals.some((item) => item.signal === "noEmitOnError" && item.readiness === "ready");
  const hasSkipLibCheck = compilerOptionSignals.some((item) => item.signal === "skipLibCheck" && item.readiness === "ready");

  const riskQueue: TypecheckReadinessReport["riskQueue"] = [];
  if (!hasTsconfig) {
    riskQueue.push({
      priority: "high",
      action: "Add a tsconfig.json or jsconfig.json before claiming TypeScript typecheck readiness.",
      why: "TypeScript's project mode centers on compilerOptions, files/include/exclude, and references loaded from config files.",
      relatedHref: "html/typecheck-readiness.html"
    });
  }
  if (!hasTypecheckCommand) {
    riskQueue.push({
      priority: "high",
      action: "Add a package script or documented command that runs tsc.",
      why: "A static tsconfig is not enough; the repository needs a repeatable typecheck command such as tsc --noEmit or tsc --build.",
      relatedHref: "html/typecheck-readiness.html"
    });
  }
  if (hasTsconfig && !hasStrict) {
    riskQueue.push({
      priority: "medium",
      action: "Enable strict or document why strict type checking is intentionally disabled.",
      why: "TypeScript treats strict as the umbrella for strictNullChecks, noImplicitAny, noImplicitThis, and related strict flags.",
      relatedHref: "html/typecheck-readiness.html"
    });
  }
  if (usesProjectReferences && !hasComposite) {
    riskQueue.push({
      priority: "high",
      action: "Pair project references with composite projects.",
      why: "TypeScript's compiler options describe composite as the constraint that allows a project to participate in project references.",
      relatedHref: "html/typecheck-readiness.html"
    });
  }
  if (usesProjectReferences && !hasIncremental) {
    riskQueue.push({
      priority: "low",
      action: "Review incremental build info settings for referenced projects.",
      why: "TypeScript supports incremental and tsBuildInfoFile to persist project build state across runs.",
      relatedHref: "html/typecheck-readiness.html"
    });
  }
  if (hasPaths && !hasModuleResolution) {
    riskQueue.push({
      priority: "medium",
      action: "Make moduleResolution explicit when using paths or baseUrl.",
      why: "TypeScript's moduleResolution strategy controls how non-relative imports and path aliases are resolved.",
      relatedHref: "html/typecheck-readiness.html"
    });
  }
  if (hasDeclaration && !hasNoEmitOnError) {
    riskQueue.push({
      priority: "low",
      action: "Consider noEmitOnError for declaration-producing packages.",
      why: "Declaration outputs can become misleading if emitted while type checking errors are present.",
      relatedHref: "html/typecheck-readiness.html"
    });
  }
  if (hasSkipLibCheck) {
    riskQueue.push({
      priority: "low",
      action: "Review skipLibCheck as a tradeoff, not as proof that dependency types are healthy.",
      why: "TypeScript describes skipLibCheck as skipping type checking for declaration files, which can hide third-party type conflicts.",
      relatedHref: "html/typecheck-readiness.html"
    });
  }
  riskQueue.push({
    priority: "low",
    action: hasTypecheckCommand ? "Run the typecheck command before treating this static report as approval." : "If this repository later adds a tsc command, rerun RepoTutor to populate typecheck readiness.",
    why: "RepoTutor records static TypeScript readiness only; it does not execute tsc, resolve modules, emit declarations, or inspect real diagnostics.",
    relatedHref: "html/typecheck-readiness.html"
  });

  return {
    summary: `TypeScript typecheck readiness report: tsconfig files ${tsconfigFiles.length}개, compiler option signals ${compilerOptionSignals.length}개, project signals ${projectSignals.length}개, script signals ${scriptSignals.length}개를 정적 분석으로 정리했습니다.`,
    sourcePattern: "TypeScript compilerOptions strict noImplicitAny strictNullChecks composite references declaration noEmit moduleResolution paths types skipLibCheck tsc build",
    tsconfigFiles,
    compilerOptionSignals,
    projectSignals,
    moduleResolutionSignals,
    declarationSignals,
    scriptSignals,
    riskQueue: riskQueue.sort((a, b) => ({ high: 0, medium: 1, low: 2 }[a.priority] - { high: 0, medium: 1, low: 2 }[b.priority])),
    recommendedCommands: [
      { command: "npx tsc --noEmit", purpose: "Run a no-output semantic typecheck for the current project." },
      { command: "npx tsc --build", purpose: "Build project references using TypeScript project mode." },
      { command: "npx tsc --showConfig", purpose: "Inspect the final compilerOptions after extends resolution." },
      { command: "npx tsc --watch --noEmit", purpose: "Keep type diagnostics running during local development." },
      { command: "npx tsc --extendedDiagnostics --noEmit", purpose: "Review typecheck performance and file counts." },
      { command: "npx tsc --traceResolution --noEmit", purpose: "Debug moduleResolution, paths, typeRoots, and types lookup behavior." }
    ],
    learnerNextSteps: [
      "Start with tsconfig files: read compilerOptions, extends, include/files/exclude, and references before looking at source code.",
      "Separate strictness flags from project build flags and declaration emit flags; they answer different readiness questions.",
      "Use --showConfig when extends or base configs are involved, then run --noEmit or --build to confirm real diagnostics.",
      "RepoTutor does not execute tsc or resolve imports; treat this report as a static checklist, not typecheck approval."
    ]
  };
}

type TypecheckSourceFile = {
  filePath: string;
  text: string;
  sourceHref: string;
};

async function typecheckSourceFiles(walk: WalkResult): Promise<TypecheckSourceFile[]> {
  const files: TypecheckSourceFile[] = [];
  for (const file of walk.files) {
    if (!file.isTextCandidate || !typecheckInspectablePath(file.relPath)) continue;
    const text = await readTextIfSafe(file.absPath, 180_000);
    if (!text) continue;
    if (!typecheckPathSignal(file.relPath) && !typecheckContentSignal(text) && path.basename(file.relPath) !== "package.json") continue;
    files.push({ filePath: file.relPath, text, sourceHref: `source/${encodedPath(file.relPath)}` });
    if (files.length >= 260) break;
  }
  return files;
}

function typecheckInspectablePath(filePath: string): boolean {
  const base = path.basename(filePath);
  return /^tsconfig.*\.json$/i.test(base)
    || /^jsconfig.*\.json$/i.test(base)
    || /^(package\.json|pnpm-workspace\.yaml|README\.md)$/i.test(base)
    || /(typescript|typecheck|tsc|tsconfig|declaration|types|compilerOptions)/i.test(filePath)
    || /\.(json|md|ya?ml|[cm]?[jt]sx?)$/i.test(filePath);
}

function typecheckPathSignal(filePath: string): boolean {
  const base = path.basename(filePath);
  return /^tsconfig.*\.json$/i.test(base)
    || /^jsconfig.*\.json$/i.test(base)
    || /(typescript|typecheck|tsc|tsconfig|declaration|types|compilerOptions)/i.test(filePath);
}

function typecheckContentSignal(text: string): boolean {
  return /typescript|tsc\b|tsconfig|compilerOptions|strictNullChecks|noImplicitAny|noEmit|declaration|composite|references|moduleResolution|skipLibCheck|typecheck/i.test(text);
}

function typecheckTsconfigFiles(sourceFiles: TypecheckSourceFile[]): TypecheckReadinessReport["tsconfigFiles"] {
  return sourceFiles
    .filter((source) => /^tsconfig.*\.json$/i.test(path.basename(source.filePath)) || /^jsconfig.*\.json$/i.test(path.basename(source.filePath)))
    .slice(0, 120)
    .map((source) => {
      const compilerOptionsCount = typecheckOptionCount(source.text);
      const referencesCount = countMatches(source.text, /"references"\s*:\s*\[[\s\S]*?\]/g) > 0 ? countMatches(source.text, /"path"\s*:/g) : 0;
      const includeCount = countMatches(source.text, /"(include|files)"\s*:\s*\[[\s\S]*?\]/g);
      return {
        filePath: source.filePath,
        compilerOptionsCount,
        referencesCount,
        includeCount,
        readiness: compilerOptionsCount > 0 ? "ready" : referencesCount > 0 || includeCount > 0 ? "partial" : "missing",
        evidence: `${source.filePath} has ${compilerOptionsCount} recognized compiler option signal(s), ${referencesCount} reference path(s), and ${includeCount} include/files list signal(s).`,
        sourceHref: source.sourceHref
      };
    });
}

function typecheckOptionCount(text: string): number {
  const options = ["strict", "noImplicitAny", "strictNullChecks", "noUncheckedIndexedAccess", "exactOptionalPropertyTypes", "noEmit", "noEmitOnError", "skipLibCheck", "isolatedModules", "moduleDetection", "jsx", "target", "module", "moduleResolution", "baseUrl", "paths", "typeRoots", "types", "lib", "declaration", "declarationMap", "emitDeclarationOnly", "declarationDir", "sourceMap", "composite", "incremental", "tsBuildInfoFile"];
  return options.filter((option) => new RegExp(`"${option}"\\s*:`, "i").test(text)).length;
}

function typecheckCompilerOptionSignals(sourceFiles: TypecheckSourceFile[]): TypecheckReadinessReport["compilerOptionSignals"] {
  const specs: Array<{ signal: TypecheckReadinessReport["compilerOptionSignals"][number]["signal"]; pattern: RegExp; evidence: string }> = [
    { signal: "strict", pattern: /"strict"\s*:\s*true/i, evidence: "strict compiler option evidence was detected." },
    { signal: "noImplicitAny", pattern: /"noImplicitAny"\s*:\s*true/i, evidence: "noImplicitAny evidence was detected." },
    { signal: "strictNullChecks", pattern: /"strictNullChecks"\s*:\s*true/i, evidence: "strictNullChecks evidence was detected." },
    { signal: "noUncheckedIndexedAccess", pattern: /"noUncheckedIndexedAccess"\s*:\s*true/i, evidence: "noUncheckedIndexedAccess evidence was detected." },
    { signal: "exactOptionalPropertyTypes", pattern: /"exactOptionalPropertyTypes"\s*:\s*true/i, evidence: "exactOptionalPropertyTypes evidence was detected." },
    { signal: "noEmit", pattern: /"noEmit"\s*:\s*true|tsc[^"\n]*--noEmit/i, evidence: "noEmit evidence was detected." },
    { signal: "noEmitOnError", pattern: /"noEmitOnError"\s*:\s*true/i, evidence: "noEmitOnError evidence was detected." },
    { signal: "skipLibCheck", pattern: /"skipLibCheck"\s*:\s*true/i, evidence: "skipLibCheck evidence was detected." },
    { signal: "isolatedModules", pattern: /"isolatedModules"\s*:\s*true/i, evidence: "isolatedModules evidence was detected." },
    { signal: "moduleDetection", pattern: /"moduleDetection"\s*:/i, evidence: "moduleDetection evidence was detected." },
    { signal: "jsx", pattern: /"jsx"\s*:/i, evidence: "jsx compiler option evidence was detected." },
    { signal: "target", pattern: /"target"\s*:/i, evidence: "target compiler option evidence was detected." },
    { signal: "module", pattern: /"module"\s*:/i, evidence: "module compiler option evidence was detected." }
  ];
  return typecheckSignalFromSpecs(sourceFiles, specs, "compiler option", "signal");
}

function typecheckProjectSignals(sourceFiles: TypecheckSourceFile[]): TypecheckReadinessReport["projectSignals"] {
  const specs: Array<{ signal: TypecheckReadinessReport["projectSignals"][number]["signal"]; pattern: RegExp; evidence: string }> = [
    { signal: "references", pattern: /"references"\s*:\s*\[/i, evidence: "project references evidence was detected." },
    { signal: "composite", pattern: /"composite"\s*:\s*true/i, evidence: "composite project evidence was detected." },
    { signal: "incremental", pattern: /"incremental"\s*:\s*true/i, evidence: "incremental build evidence was detected." },
    { signal: "tsBuildInfoFile", pattern: /"tsBuildInfoFile"\s*:/i, evidence: "tsBuildInfoFile evidence was detected." },
    { signal: "include", pattern: /"include"\s*:\s*\[/i, evidence: "include list evidence was detected." },
    { signal: "exclude", pattern: /"exclude"\s*:\s*\[/i, evidence: "exclude list evidence was detected." },
    { signal: "files", pattern: /"files"\s*:\s*\[/i, evidence: "files list evidence was detected." },
    { signal: "rootDir", pattern: /"rootDir"\s*:/i, evidence: "rootDir evidence was detected." },
    { signal: "outDir", pattern: /"outDir"\s*:/i, evidence: "outDir evidence was detected." },
    { signal: "extends", pattern: /"extends"\s*:/i, evidence: "extends base config evidence was detected." }
  ];
  return typecheckSignalFromSpecs(sourceFiles, specs, "project", "signal");
}

function typecheckModuleResolutionSignals(sourceFiles: TypecheckSourceFile[]): TypecheckReadinessReport["moduleResolutionSignals"] {
  const specs: Array<{ signal: TypecheckReadinessReport["moduleResolutionSignals"][number]["signal"]; pattern: RegExp; evidence: string }> = [
    { signal: "moduleResolution", pattern: /"moduleResolution"\s*:/i, evidence: "moduleResolution evidence was detected." },
    { signal: "baseUrl", pattern: /"baseUrl"\s*:/i, evidence: "baseUrl evidence was detected." },
    { signal: "paths", pattern: /"paths"\s*:\s*\{/i, evidence: "paths mapping evidence was detected." },
    { signal: "typeRoots", pattern: /"typeRoots"\s*:\s*\[/i, evidence: "typeRoots evidence was detected." },
    { signal: "types", pattern: /"types"\s*:\s*\[/i, evidence: "types package allowlist evidence was detected." },
    { signal: "lib", pattern: /"lib"\s*:\s*\[/i, evidence: "lib declaration bundle evidence was detected." },
    { signal: "allowImportingTsExtensions", pattern: /"allowImportingTsExtensions"\s*:\s*true/i, evidence: "allowImportingTsExtensions evidence was detected." },
    { signal: "rewriteRelativeImportExtensions", pattern: /"rewriteRelativeImportExtensions"\s*:\s*true/i, evidence: "rewriteRelativeImportExtensions evidence was detected." },
    { signal: "esModuleInterop", pattern: /"esModuleInterop"\s*:\s*true/i, evidence: "esModuleInterop evidence was detected." },
    { signal: "resolveJsonModule", pattern: /"resolveJsonModule"\s*:\s*true/i, evidence: "resolveJsonModule evidence was detected." }
  ];
  return typecheckSignalFromSpecs(sourceFiles, specs, "module resolution", "signal");
}

function typecheckDeclarationSignals(sourceFiles: TypecheckSourceFile[]): TypecheckReadinessReport["declarationSignals"] {
  const specs: Array<{ signal: TypecheckReadinessReport["declarationSignals"][number]["signal"]; pattern: RegExp; evidence: string }> = [
    { signal: "declaration", pattern: /"declaration"\s*:\s*true/i, evidence: "declaration emit evidence was detected." },
    { signal: "declarationMap", pattern: /"declarationMap"\s*:\s*true/i, evidence: "declarationMap evidence was detected." },
    { signal: "emitDeclarationOnly", pattern: /"emitDeclarationOnly"\s*:\s*true/i, evidence: "emitDeclarationOnly evidence was detected." },
    { signal: "declarationDir", pattern: /"declarationDir"\s*:/i, evidence: "declarationDir evidence was detected." },
    { signal: "sourceMap", pattern: /"sourceMap"\s*:\s*true/i, evidence: "sourceMap evidence was detected." },
    { signal: "noEmit", pattern: /"noEmit"\s*:\s*true|tsc[^"\n]*--noEmit/i, evidence: "noEmit evidence was detected." },
    { signal: "composite-declaration", pattern: /"composite"\s*:\s*true[\s\S]{0,500}"declaration"\s*:\s*true|"declaration"\s*:\s*true[\s\S]{0,500}"composite"\s*:\s*true/i, evidence: "composite plus declaration evidence was detected." }
  ];
  return typecheckSignalFromSpecs(sourceFiles, specs, "declaration", "signal");
}

function typecheckScriptSignals(sourceFiles: TypecheckSourceFile[]): TypecheckReadinessReport["scriptSignals"] {
  const specs: Array<{ signal: TypecheckReadinessReport["scriptSignals"][number]["signal"]; pattern: RegExp; evidence: string }> = [
    { signal: "tsc", pattern: /"[^"]*"\s*:\s*"[^"]*\btsc\b[^"]*"|\btsc\b/i, evidence: "tsc command evidence was detected." },
    { signal: "typecheck-script", pattern: /"type(check|s)?"\s*:\s*"[^"]*\b(tsc|vue-tsc|svelte-check)\b/i, evidence: "typecheck script evidence was detected." },
    { signal: "build-script", pattern: /"build"\s*:\s*"[^"]*\b(tsc|tsc\s+-b|tsc\s+--build)\b/i, evidence: "build script typecheck evidence was detected." },
    { signal: "noEmit-command", pattern: /\btsc\b[^"\n]*--noEmit/i, evidence: "noEmit command evidence was detected." },
    { signal: "project-build", pattern: /\btsc\b[^"\n]*(--build|-b)\b/i, evidence: "project build command evidence was detected." },
    { signal: "watch", pattern: /\btsc\b[^"\n]*(--watch|-w)\b/i, evidence: "watch command evidence was detected." },
    { signal: "generated-types", pattern: /"types"\s*:|\.d\.ts|declaration/i, evidence: "generated type output evidence was detected." }
  ];
  return typecheckSignalFromSpecs(sourceFiles, specs, "script", "signal");
}

function typecheckSignalFromSpecs<T extends Record<K, string> & { pattern: RegExp; evidence: string }, K extends string>(
  sourceFiles: TypecheckSourceFile[],
  specs: T[],
  label: string,
  labelKey: K
): Array<Record<K, T[K]> & { readiness: "ready" | "missing" | "external"; evidence: string; relatedHref: string }> {
  return specs.map((spec) => {
    const match = sourceFiles.find((source) => spec.pattern.test(source.text) || spec.pattern.test(source.filePath));
    return {
      [labelKey]: spec[labelKey],
      readiness: match ? "ready" : sourceFiles.length > 0 ? "external" : "missing",
      evidence: match ? `${match.filePath} ${spec.evidence}` : `${label} ${spec[labelKey]} evidence was not detected.`,
      relatedHref: match?.sourceHref ?? "html/typecheck-readiness.html"
    } as Record<K, T[K]> & { readiness: "ready" | "missing" | "external"; evidence: string; relatedHref: string };
  });
}

async function buildPackageManagerReport(walk: WalkResult): Promise<PackageManagerReport> {
  const sourceFiles = await packageManagerSourceFiles(walk);
  const manifestFiles = packageManagerManifestFiles(sourceFiles);
  const workspaceSignals = packageManagerWorkspaceSignals(sourceFiles);
  const lockfileSignals = packageManagerLockfileSignals(sourceFiles);
  const scriptSignals = packageManagerScriptSignals(sourceFiles);
  const policySignals = packageManagerPolicySignals(sourceFiles);

  const hasManifest = manifestFiles.length > 0;
  const hasPackageManagerField = policySignals.some((item) => item.signal === "packageManager" && item.readiness === "ready");
  const hasLockfile = lockfileSignals.length > 0;
  const hasWorkspaceFile = workspaceSignals.some((item) => item.signal === "workspace-file" && item.readiness === "ready");
  const hasWorkspacePackages = workspaceSignals.some((item) => item.signal === "packages-include" && item.readiness === "ready");
  const hasFrozenLockfile = scriptSignals.some((item) => item.signal === "frozen-lockfile" && item.readiness === "ready");
  const hasBuildPolicy = policySignals.some((item) => ["onlyBuiltDependencies", "allowBuilds"].includes(item.signal) && item.readiness === "ready");
  const hasPnpmfileHook = policySignals.some((item) => item.signal === "pnpmfile-hook" && item.readiness === "ready");
  const lockfileEcosystems = new Set(lockfileSignals.map((item) => item.ecosystem).filter((ecosystem) => ecosystem !== "unknown"));

  const riskQueue: PackageManagerReport["riskQueue"] = [];
  if (!hasManifest) {
    riskQueue.push({
      priority: "high",
      action: "Add a package manifest before claiming JavaScript package-manager readiness.",
      why: "Package managers start from manifest files such as package.json, where scripts, dependencies, and packageManager policy are declared.",
      relatedHref: "html/package-manager.html"
    });
  }
  if (hasManifest && !hasPackageManagerField) {
    riskQueue.push({
      priority: "medium",
      action: "Declare the expected package manager and version in package.json.",
      why: "pnpm-style repositories use packageManager/devEngines to make install behavior repeatable across machines.",
      relatedHref: "html/package-manager.html"
    });
  }
  if (hasManifest && !hasLockfile) {
    riskQueue.push({
      priority: "high",
      action: "Commit the matching package-manager lockfile.",
      why: "pnpm documents deterministic installs through pnpm-lock.yaml; npm, Yarn, and Bun have equivalent lockfiles for resolved dependency state.",
      relatedHref: "html/package-manager.html"
    });
  }
  if (lockfileEcosystems.size > 1) {
    riskQueue.push({
      priority: "medium",
      action: "Choose one package-manager lockfile family for this repository.",
      why: "Multiple lockfile ecosystems make it unclear whether contributors should install with pnpm, npm, Yarn, or Bun.",
      relatedHref: "html/package-manager.html"
    });
  }
  if (hasWorkspacePackages && !hasWorkspaceFile) {
    riskQueue.push({
      priority: "medium",
      action: "Move workspace package globs into an explicit workspace file or root workspace declaration.",
      why: "Monorepos need a readable workspace package list so beginners can see which folders are linked together.",
      relatedHref: "html/package-manager.html"
    });
  }
  if (hasWorkspaceFile && !hasFrozenLockfile) {
    riskQueue.push({
      priority: "low",
      action: "Document a frozen-lockfile CI install command for workspace repos.",
      why: "Workspace lockfiles are useful only if CI refuses accidental lockfile drift during install.",
      relatedHref: "html/package-manager.html"
    });
  }
  if (hasWorkspaceFile && !hasBuildPolicy) {
    riskQueue.push({
      priority: "low",
      action: "Review dependency build-script policy for packages that run install-time builds.",
      why: "pnpm workspace files can declare allowBuilds or related controls so install-time build scripts are explicit.",
      relatedHref: "html/package-manager.html"
    });
  }
  if (hasPnpmfileHook) {
    riskQueue.push({
      priority: "low",
      action: "Review .pnpmfile hooks before trusting install-time dependency rewrites.",
      why: "pnpm hooks can mutate package manifests during resolution, so they deserve a separate learning and security review.",
      relatedHref: "html/package-manager.html"
    });
  }
  riskQueue.push({
    priority: "low",
    action: "Run the real package-manager commands in a trusted workspace before treating this static report as approval.",
    why: "RepoTutor records package-manager readiness statically; it does not run install, resolve registry metadata, or execute lifecycle scripts.",
    relatedHref: "html/package-manager.html"
  });

  return {
    summary: `pnpm식 package-manager readiness report: manifest ${manifestFiles.length}개, workspace signal ${workspaceSignals.length}개, lockfile ${lockfileSignals.length}개, script signal ${scriptSignals.length}개를 정적 분석으로 정리했습니다.`,
    sourcePattern: "pnpm packageManager devEngines workspace packages catalog lockfile importers allowBuilds auditConfig pnpmfile hooks recursive filter frozen-lockfile",
    manifestFiles,
    workspaceSignals,
    lockfileSignals,
    scriptSignals,
    policySignals,
    riskQueue: riskQueue.sort((a, b) => ({ high: 0, medium: 1, low: 2 }[a.priority] - { high: 0, medium: 1, low: 2 }[b.priority])),
    recommendedCommands: [
      { command: "corepack enable", purpose: "Use the packageManager field to activate the expected package-manager binary." },
      { command: "pnpm install --frozen-lockfile", purpose: "Verify the lockfile is reproducible without modifying it." },
      { command: "pnpm -r build", purpose: "Run build scripts across workspace packages recursively." },
      { command: "pnpm -r test", purpose: "Run test scripts across workspace packages recursively." },
      { command: "pnpm audit", purpose: "Review advisory data for the current lockfile in a trusted workspace." },
      { command: "pnpm list -r --depth 0", purpose: "Inspect workspace package boundaries and direct dependencies." }
    ],
    learnerNextSteps: [
      "Start with package.json: identify packageManager, scripts, dependency groups, and whether the root is private.",
      "Then read the workspace file and lockfile together; workspace globs define projects, while the lockfile records resolved dependency state.",
      "Treat lifecycle hooks, .pnpmfile, and build-script allowlists as policy, not ordinary metadata.",
      "RepoTutor does not execute install commands; use this page as a static map before running package-manager commands yourself."
    ]
  };
}

type PackageManagerSourceFile = {
  filePath: string;
  text: string;
  sourceHref: string;
};

async function packageManagerSourceFiles(walk: WalkResult): Promise<PackageManagerSourceFile[]> {
  const files: PackageManagerSourceFile[] = [];
  for (const file of walk.files) {
    if (!file.isTextCandidate || !packageManagerInspectablePath(file.relPath)) continue;
    const text = await readTextIfSafe(file.absPath, 220_000);
    if (!text) continue;
    if (!packageManagerPathSignal(file.relPath) && !packageManagerContentSignal(text)) continue;
    files.push({ filePath: file.relPath, text, sourceHref: `source/${encodedPath(file.relPath)}` });
    if (files.length >= 240) break;
  }
  return files;
}

function packageManagerInspectablePath(filePath: string): boolean {
  const base = path.basename(filePath);
  return /^(package\.json|package-lock\.json|pnpm-lock\.yaml|pnpm-workspace\.yaml|yarn\.lock|bun\.lockb?|bun\.lock|\.npmrc|\.yarnrc\.ya?ml|\.pnpmfile\.cjs|README\.md)$/i.test(base)
    || /(package-manager|packageManager|workspace|lockfile|pnpm|npm|yarn|bun|dependencies|devEngines)/i.test(filePath)
    || /\.(json|md|ya?ml|cjs|mjs|toml)$/i.test(filePath);
}

function packageManagerPathSignal(filePath: string): boolean {
  const base = path.basename(filePath);
  return /^(package\.json|package-lock\.json|pnpm-lock\.yaml|pnpm-workspace\.yaml|yarn\.lock|bun\.lockb?|bun\.lock|\.npmrc|\.yarnrc\.ya?ml|\.pnpmfile\.cjs)$/i.test(base)
    || /(package-manager|packageManager|workspace|lockfile|pnpm|npm|yarn|bun|dependencies|devEngines)/i.test(filePath);
}

function packageManagerContentSignal(text: string): boolean {
  return /packageManager|devEngines|workspaces?|pnpm|npm|yarn|bun|lockfileVersion|dependencies|devDependencies|catalog:|allowBuilds|auditConfig|frozen-lockfile|\.pnpmfile|readPackage|beforePacking/i.test(text);
}

function packageManagerManifestFiles(sourceFiles: PackageManagerSourceFile[]): PackageManagerReport["manifestFiles"] {
  return sourceFiles
    .filter((source) => path.basename(source.filePath) === "package.json")
    .slice(0, 120)
    .map((source) => {
      let packageManager: string | null = null;
      let scriptCount = 0;
      let dependencyCount = 0;
      try {
        const json = JSON.parse(source.text) as {
          packageManager?: unknown;
          scripts?: Record<string, unknown>;
          dependencies?: Record<string, unknown>;
          devDependencies?: Record<string, unknown>;
          peerDependencies?: Record<string, unknown>;
          optionalDependencies?: Record<string, unknown>;
        };
        packageManager = typeof json.packageManager === "string" ? json.packageManager : null;
        scriptCount = Object.keys(json.scripts ?? {}).length;
        dependencyCount = Object.keys({
          ...(json.dependencies ?? {}),
          ...(json.devDependencies ?? {}),
          ...(json.peerDependencies ?? {}),
          ...(json.optionalDependencies ?? {})
        }).length;
      } catch {
        // Keep the manifest visible even when JSON parsing fails.
      }
      return {
        filePath: source.filePath,
        packageManager,
        scriptCount,
        dependencyCount,
        readiness: packageManager || dependencyCount > 0 || scriptCount > 0 ? "ready" : "partial",
        evidence: `${source.filePath} has packageManager ${packageManager ?? "not declared"}, ${scriptCount} script(s), and ${dependencyCount} dependency declaration(s).`,
        sourceHref: source.sourceHref
      };
    });
}

function packageManagerWorkspaceSignals(sourceFiles: PackageManagerSourceFile[]): PackageManagerReport["workspaceSignals"] {
  const specs: Array<{ signal: PackageManagerReport["workspaceSignals"][number]["signal"]; pattern: RegExp; evidence: string }> = [
    { signal: "workspace-file", pattern: /pnpm-workspace\.ya?ml|workspaces?\s*:/i, evidence: "workspace file or root workspace declaration evidence was detected." },
    { signal: "packages-include", pattern: /packages\s*:\s*\n\s*-\s+|workspaces?\s*:\s*\[/i, evidence: "workspace package include glob evidence was detected." },
    { signal: "packages-exclude", pattern: /^\s*-\s*['"]?!|!\*\*\/|exclude/i, evidence: "workspace package exclude glob evidence was detected." },
    { signal: "workspace-protocol", pattern: /workspace:\*|workspace:\^|workspace:~/i, evidence: "workspace protocol dependency evidence was detected." },
    { signal: "catalog", pattern: /\bcatalogs?\s*:|catalog:/i, evidence: "catalog dependency version evidence was detected." },
    { signal: "overrides", pattern: /\boverrides\s*:|"overrides"\s*:/i, evidence: "dependency override evidence was detected." },
    { signal: "patched-dependencies", pattern: /patchedDependencies|patches?:|\.patch\b/i, evidence: "patched dependency evidence was detected." },
    { signal: "shared-workspace-lockfile", pattern: /shared-workspace-lockfile|sharedWorkspaceLockfile/i, evidence: "shared workspace lockfile policy evidence was detected." }
  ];
  return packageManagerSignalFromSpecs(sourceFiles, specs, "workspace", "signal");
}

function packageManagerLockfileSignals(sourceFiles: PackageManagerSourceFile[]): PackageManagerReport["lockfileSignals"] {
  return sourceFiles
    .filter((source) => packageManagerLockfileEcosystem(source.filePath) !== null)
    .slice(0, 20)
    .map((source) => {
      const ecosystem = packageManagerLockfileEcosystem(source.filePath) ?? "unknown";
      const version = ecosystem === "npm" ? firstJsonNumber(source.text, "lockfileVersion") : firstMatch(source.text, /lockfileVersion:\s*['"]?([^'"\n]+)['"]?/i);
      const importerCount = ecosystem === "pnpm" ? packageManagerPnpmImporterCount(source.text) : packageManagerJsonObjectCount(source.text, "packages");
      const packageCount = ecosystem === "pnpm" ? packageManagerPnpmPackageCount(source.text) : packageManagerJsonObjectCount(source.text, "packages");
      return {
        filePath: source.filePath,
        ecosystem,
        version,
        importerCount,
        packageCount,
        readiness: version || packageCount > 0 || importerCount > 0 ? "ready" : "partial",
        evidence: `${source.filePath} appears to be a ${ecosystem} lockfile with version ${version ?? "unknown"}, ${importerCount} importer signal(s), and ${packageCount} package signal(s).`,
        sourceHref: source.sourceHref
      };
    });
}

function packageManagerScriptSignals(sourceFiles: PackageManagerSourceFile[]): PackageManagerReport["scriptSignals"] {
  const specs: Array<{ signal: PackageManagerReport["scriptSignals"][number]["signal"]; pattern: RegExp; evidence: string }> = [
    { signal: "install", pattern: /\b(pnpm|npm|yarn|bun)\s+(install|i|ci)\b/i, evidence: "install command evidence was detected." },
    { signal: "dev", pattern: /"dev"\s*:|\b(pnpm|npm|yarn|bun)\s+(run\s+)?dev\b/i, evidence: "dev script evidence was detected." },
    { signal: "build", pattern: /"build"\s*:|\b(pnpm|npm|yarn|bun)\s+(run\s+)?build\b/i, evidence: "build script evidence was detected." },
    { signal: "test", pattern: /"test[^"]*"\s*:|\b(pnpm|npm|yarn|bun)\s+(run\s+)?test\b/i, evidence: "test script evidence was detected." },
    { signal: "lint", pattern: /"lint[^"]*"\s*:|\b(pnpm|npm|yarn|bun)\s+(run\s+)?lint\b/i, evidence: "lint script evidence was detected." },
    { signal: "typecheck", pattern: /"type(check|s)?"\s*:|\b(pnpm|npm|yarn|bun)\s+(run\s+)?type(check|s)?\b/i, evidence: "typecheck script evidence was detected." },
    { signal: "workspace-recursive", pattern: /\b(pnpm\s+(-r|--recursive)|npm\s+.*--workspaces|yarn\s+workspaces|bun\s+.*--filter)\b/i, evidence: "workspace-recursive command evidence was detected." },
    { signal: "filter", pattern: /\b(--filter|-F=|-F\s+|--workspace|workspaces? foreach)\b/i, evidence: "workspace filter evidence was detected." },
    { signal: "frozen-lockfile", pattern: /--frozen-lockfile|npm\s+ci|yarn\s+install\s+--immutable|bun\s+install\s+--frozen-lockfile/i, evidence: "frozen lockfile install evidence was detected." },
    { signal: "prepare", pattern: /"preinstall"\s*:|"postinstall"\s*:|"prepare"\s*:/i, evidence: "lifecycle prepare/install hook evidence was detected." },
    { signal: "release", pattern: /"release"\s*:|\b(pnpm|npm|yarn|bun)\s+(run\s+)?release\b|publish\b/i, evidence: "release or publish script evidence was detected." }
  ];
  return packageManagerSignalFromSpecs(sourceFiles, specs, "script", "signal");
}

function packageManagerPolicySignals(sourceFiles: PackageManagerSourceFile[]): PackageManagerReport["policySignals"] {
  const specs: Array<{ signal: PackageManagerReport["policySignals"][number]["signal"]; pattern: RegExp; evidence: string }> = [
    { signal: "packageManager", pattern: /"packageManager"\s*:|packageManager:/i, evidence: "packageManager pin evidence was detected." },
    { signal: "devEngines", pattern: /"devEngines"\s*:|devEngines:/i, evidence: "devEngines policy evidence was detected." },
    { signal: "engines", pattern: /"engines"\s*:|engines:/i, evidence: "runtime engines policy evidence was detected." },
    { signal: "onlyBuiltDependencies", pattern: /onlyBuiltDependencies/i, evidence: "onlyBuiltDependencies policy evidence was detected." },
    { signal: "allowBuilds", pattern: /allowBuilds/i, evidence: "allowBuilds policy evidence was detected." },
    { signal: "auditConfig", pattern: /auditConfig|ignoreGhsas|audit-level/i, evidence: "audit configuration evidence was detected." },
    { signal: "minimumReleaseAge", pattern: /minimumReleaseAge|minimum-release-age/i, evidence: "minimum release age policy evidence was detected." },
    { signal: "nodeLinker", pattern: /nodeLinker|node-linker/i, evidence: "node linker policy evidence was detected." },
    { signal: "configDependencies", pattern: /configDependencies/i, evidence: "config dependency evidence was detected." },
    { signal: "pnpmfile-hook", pattern: /\.pnpmfile|readPackage|afterAllResolved|beforePacking/i, evidence: "pnpmfile hook evidence was detected." }
  ];
  return packageManagerSignalFromSpecs(sourceFiles, specs, "policy", "signal");
}

function packageManagerSignalFromSpecs<T extends Record<K, string> & { pattern: RegExp; evidence: string }, K extends string>(
  sourceFiles: PackageManagerSourceFile[],
  specs: T[],
  label: string,
  labelKey: K
): Array<Record<K, T[K]> & { readiness: "ready" | "missing" | "external"; evidence: string; relatedHref: string }> {
  return specs.map((spec) => {
    const match = sourceFiles.find((source) => spec.pattern.test(source.text) || spec.pattern.test(source.filePath));
    return {
      [labelKey]: spec[labelKey],
      readiness: match ? "ready" : sourceFiles.length > 0 ? "external" : "missing",
      evidence: match ? `${match.filePath} ${spec.evidence}` : `${label} ${spec[labelKey]} evidence was not detected.`,
      relatedHref: match?.sourceHref ?? "html/package-manager.html"
    } as Record<K, T[K]> & { readiness: "ready" | "missing" | "external"; evidence: string; relatedHref: string };
  });
}

async function buildGitHooksReport(walk: WalkResult): Promise<GitHooksReport> {
  const sourceFiles = await gitHooksSourceFiles(walk);
  const hookFiles = gitHooksHookFiles(sourceFiles);
  const installSignals = gitHooksInstallSignals(sourceFiles);
  const commandSignals = gitHooksCommandSignals(sourceFiles);
  const policySignals = gitHooksPolicySignals(sourceFiles);
  const toolConfigFiles = gitHooksToolConfigFiles(sourceFiles);

  const hasHuskyDependency = gitHooksPackageHasDependency(sourceFiles, "husky");
  const hasHookFiles = hookFiles.length > 0;
  const hasInstallSignal = installSignals.some((item) => ["prepare-script", "postinstall-script", "husky-init", "core-hooks-path"].includes(item.signal) && item.readiness === "ready");
  const hasPreCommit = policySignals.some((item) => item.signal === "pre-commit" && item.readiness === "ready");
  const hasPrePush = policySignals.some((item) => item.signal === "pre-push" && item.readiness === "ready");
  const hasCommitMsg = policySignals.some((item) => item.signal === "commit-msg" && item.readiness === "ready");
  const hasBypassPolicy = policySignals.some((item) => ["skip-env", "no-verify"].includes(item.signal) && item.readiness === "ready");
  const hasLintStaged = commandSignals.some((item) => item.signal === "lint-staged" && item.readiness === "ready") || toolConfigFiles.some((item) => item.tool === "lint-staged");
  const hasDeprecatedHuskyShim = policySignals.some((item) => item.signal === "deprecated-husky-sh" && item.readiness === "ready");

  const riskQueue: GitHooksReport["riskQueue"] = [];
  if (!hasHookFiles && toolConfigFiles.length === 0 && !hasHuskyDependency) {
    riskQueue.push({
      priority: "medium",
      action: "Decide whether local Git hooks should be part of the learner-facing quality path.",
      why: "Husky-style projects make local checks visible through .husky hook files and install scripts, while this source has no hook evidence.",
      relatedHref: "html/git-hooks.html"
    });
  }
  if (hasHuskyDependency && !hasHookFiles) {
    riskQueue.push({
      priority: "high",
      action: "Add or recover the .husky hook files that use the declared Husky dependency.",
      why: "A Husky dependency without hook files leaves contributors unable to see what will run before commit or push.",
      relatedHref: "html/git-hooks.html"
    });
  }
  if (hasHookFiles && !hasInstallSignal) {
    riskQueue.push({
      priority: "medium",
      action: "Document how hooks are installed, such as a prepare script or core.hooksPath setup.",
      why: "Husky initializes Git through core.hooksPath; without an install signal, hooks may exist but never run for new contributors.",
      relatedHref: "html/git-hooks.html"
    });
  }
  if (hasHookFiles && !hasPreCommit) {
    riskQueue.push({
      priority: "medium",
      action: "Add a pre-commit hook or document why commits do not run local checks.",
      why: "pre-commit is the common hook for fast local test, lint, format, or staged-file checks.",
      relatedHref: "html/git-hooks.html"
    });
  }
  if (hasPreCommit && !hasLintStaged) {
    riskQueue.push({
      priority: "low",
      action: "Consider a staged-file command for expensive lint or format hooks.",
      why: "Husky documentation points to lint-staged when teams need staged-file filtering instead of whole-repo commands.",
      relatedHref: "html/git-hooks.html"
    });
  }
  if (hasHookFiles && !hasPrePush) {
    riskQueue.push({
      priority: "low",
      action: "Decide whether slower checks belong in pre-push instead of pre-commit.",
      why: "pre-push can protect shared branches without slowing every local commit.",
      relatedHref: "html/git-hooks.html"
    });
  }
  if (!hasCommitMsg) {
    riskQueue.push({
      priority: "low",
      action: "Add commit-msg policy only if the team relies on structured commit messages.",
      why: "commitlint-style commit-msg hooks make commit conventions explicit, but they are optional for many learning repos.",
      relatedHref: "html/git-hooks.html"
    });
  }
  if (hasHookFiles && !hasBypassPolicy) {
    riskQueue.push({
      priority: "low",
      action: "Document emergency bypass behavior for hooks.",
      why: "Husky supports HUSKY=0 and Git supports --no-verify; learners should know when bypassing is allowed.",
      relatedHref: "html/git-hooks.html"
    });
  }
  if (hasDeprecatedHuskyShim) {
    riskQueue.push({
      priority: "medium",
      action: "Remove deprecated husky.sh shim lines from hook files.",
      why: "Husky v9 warns that old husky.sh sourcing lines are deprecated and will fail in v10.",
      relatedHref: "html/git-hooks.html"
    });
  }
  riskQueue.push({
    priority: "low",
    action: "Run real hook commands in a trusted workspace before treating this static report as approval.",
    why: "RepoTutor records Git hook readiness statically; it does not run hooks, mutate Git config, or create commits.",
    relatedHref: "html/git-hooks.html"
  });

  return {
    summary: `Husky식 Git hook readiness report: hook file ${hookFiles.length}개, install signal ${installSignals.length}개, command signal ${commandSignals.length}개, tool config ${toolConfigFiles.length}개를 정적 분석으로 정리했습니다.`,
    sourcePattern: "Husky .husky hook files prepare core.hooksPath pre-commit pre-push commit-msg HUSKY=0 no-verify lint-staged POSIX shell",
    hookFiles,
    installSignals,
    commandSignals,
    policySignals,
    toolConfigFiles,
    riskQueue: riskQueue.sort((a, b) => ({ high: 0, medium: 1, low: 2 }[a.priority] - { high: 0, medium: 1, low: 2 }[b.priority])),
    recommendedCommands: [
      { command: "pnpm exec husky init", purpose: "Initialize a Husky hook directory and prepare script in a trusted JavaScript workspace." },
      { command: "pnpm run prepare", purpose: "Run the install hook that configures Git hooks for the repository." },
      { command: "git config --get core.hooksPath", purpose: "Confirm which hook directory Git will read from." },
      { command: "pnpm exec lint-staged", purpose: "Run staged-file tasks without creating a commit when lint-staged is configured." },
      { command: "pnpm exec commitlint --from HEAD~1 --to HEAD", purpose: "Check recent commit messages when commitlint policy exists." },
      { command: "HUSKY=0 git commit ...", purpose: "Understand the documented emergency bypass path; do not use it as a normal workflow." }
    ],
    learnerNextSteps: [
      "Start with .husky files: hook filenames explain when a command runs, and file contents explain what command runs.",
      "Then read package.json scripts; Husky usually installs through prepare or postinstall, and hooks often call package scripts.",
      "Separate fast pre-commit checks from slower pre-push checks so learners understand latency and safety tradeoffs.",
      "Treat HUSKY=0 and --no-verify as policy-sensitive escape hatches, not ordinary commands."
    ]
  };
}

type GitHooksSourceFile = {
  filePath: string;
  text: string;
  sourceHref: string;
};

async function gitHooksSourceFiles(walk: WalkResult): Promise<GitHooksSourceFile[]> {
  const files: GitHooksSourceFile[] = [];
  for (const file of walk.files) {
    if (!file.isTextCandidate || !gitHooksInspectablePath(file.relPath)) continue;
    const text = await readTextIfSafe(file.absPath, 180_000);
    if (!text) continue;
    if (!gitHooksPathSignal(file.relPath) && !gitHooksContentSignal(text)) continue;
    files.push({ filePath: file.relPath, text, sourceHref: `source/${encodedPath(file.relPath)}` });
    if (files.length >= 220) break;
  }
  return files;
}

function gitHooksInspectablePath(filePath: string): boolean {
  const base = path.basename(filePath);
  return filePath.startsWith(".husky/")
    || /^(\.lintstagedrc(\..+)?|lint-staged\.config\.(js|cjs|mjs|ts)|commitlint\.config\.(js|cjs|mjs|ts)|lefthook\.ya?ml|\.pre-commit-config\.ya?ml|\.simple-git-hooks\.(json|js|cjs)|package\.json|README\.md)$/i.test(base)
    || /(husky|lint-staged|commitlint|pre-commit|pre-push|commit-msg|git-hooks?|hooksPath|lefthook|simple-git-hooks)/i.test(filePath)
    || /\.(json|md|ya?ml|sh|bash|zsh|js|cjs|mjs|ts)$/i.test(filePath);
}

function gitHooksPathSignal(filePath: string): boolean {
  const base = path.basename(filePath);
  return filePath.startsWith(".husky/")
    || /^(\.lintstagedrc(\..+)?|lint-staged\.config\.(js|cjs|mjs|ts)|commitlint\.config\.(js|cjs|mjs|ts)|lefthook\.ya?ml|\.pre-commit-config\.ya?ml|\.simple-git-hooks\.(json|js|cjs)|package\.json)$/i.test(base)
    || /(husky|lint-staged|commitlint|pre-commit|pre-push|commit-msg|git-hooks?|hooksPath|lefthook|simple-git-hooks)/i.test(filePath);
}

function gitHooksContentSignal(text: string): boolean {
  return /husky|\.husky|core\.hooksPath|pre-commit|pre-push|commit-msg|prepare-commit-msg|HUSKY=0|--no-verify|lint-staged|commitlint|lefthook|pre-commit-config|simple-git-hooks|node_modules\/\.bin/i.test(text);
}

function gitHooksHookFiles(sourceFiles: GitHooksSourceFile[]): GitHooksReport["hookFiles"] {
  return sourceFiles
    .filter((source) => source.filePath.startsWith(".husky/") && !source.filePath.startsWith(".husky/_/") && !path.basename(source.filePath).includes("."))
    .slice(0, 80)
    .map((source) => {
      const commandCount = source.text.split(/\r?\n/).filter((line) => {
        const trimmed = line.trim();
        return trimmed.length > 0 && !trimmed.startsWith("#") && !trimmed.startsWith(". \"$(dirname");
      }).length;
      const hasBypassHint = /HUSKY=0|--no-verify|\b-n\b/i.test(source.text);
      const hasNodePathHint = /node_modules\/\.bin|\bPATH\b|NVM_DIR|nvm|fnm|asdf|volta|init\.sh/i.test(source.text);
      return {
        filePath: source.filePath,
        hookName: path.basename(source.filePath),
        commandCount,
        hasBypassHint,
        hasNodePathHint,
        readiness: commandCount > 0 ? "ready" : "partial",
        evidence: `${source.filePath} declares ${commandCount} executable command line(s).`,
        sourceHref: source.sourceHref
      };
    });
}

function gitHooksInstallSignals(sourceFiles: GitHooksSourceFile[]): GitHooksReport["installSignals"] {
  const specs: Array<{ signal: GitHooksReport["installSignals"][number]["signal"]; pattern: RegExp; evidence: string }> = [
    { signal: "prepare-script", pattern: /"prepare"\s*:\s*"[^"]*husky|prepare.*husky/i, evidence: "prepare script or prepare documentation for Husky was detected." },
    { signal: "postinstall-script", pattern: /"postinstall"\s*:\s*"[^"]*husky|postinstall.*husky/i, evidence: "postinstall hook setup evidence was detected." },
    { signal: "husky-init", pattern: /\b(npx|pnpm exec|bunx|yarn dlx)?\s*husky\s+init\b/i, evidence: "husky init setup evidence was detected." },
    { signal: "core-hooks-path", pattern: /core\.hooksPath|hooksPath|git config.*core\.hooksPath|\.husky\/_/i, evidence: "Git core.hooksPath setup evidence was detected." },
    { signal: "git-root-subdir", pattern: /cd\s+\.\.\s*&&\s*husky|husky\s+[^"'\n]*\/\.husky|Project Not in Git Root Directory/i, evidence: "subdirectory project hook setup evidence was detected." },
    { signal: "ci-skip", pattern: /HUSKY=0|process\.env\.CI|CI\s*={0,2}\s*['"]?true|NODE_ENV\s*={0,2}\s*['"]?production/i, evidence: "CI or production hook install skip evidence was detected." }
  ];
  return gitHooksSignalFromSpecs(sourceFiles, specs, "install", "signal");
}

function gitHooksCommandSignals(sourceFiles: GitHooksSourceFile[]): GitHooksReport["commandSignals"] {
  const specs: Array<{ signal: GitHooksReport["commandSignals"][number]["signal"]; pattern: RegExp; evidence: string }> = [
    { signal: "test", pattern: /\b(npm|pnpm|yarn|bun)\s+(run\s+)?test\b|\bvitest\b|\bjest\b/i, evidence: "test command evidence was detected." },
    { signal: "lint", pattern: /\b(npm|pnpm|yarn|bun)\s+(run\s+)?lint\b|\beslint\b|\blint\b/i, evidence: "lint command evidence was detected." },
    { signal: "format", pattern: /\bprettier\b|\bformat\b/i, evidence: "format command evidence was detected." },
    { signal: "typecheck", pattern: /\btsc\b|typecheck|type-check/i, evidence: "typecheck command evidence was detected." },
    { signal: "security", pattern: /\bgitleaks\b|\bsemgrep\b|\bsnyk\b|\baudit\b/i, evidence: "security or audit command evidence was detected." },
    { signal: "commitlint", pattern: /\bcommitlint\b|commit-msg/i, evidence: "commit message lint evidence was detected." },
    { signal: "lint-staged", pattern: /\blint-staged\b|lintstaged/i, evidence: "staged-file task evidence was detected." },
    { signal: "npm-run", pattern: /\bnpm\s+run\s+/i, evidence: "npm script invocation evidence was detected." },
    { signal: "pnpm-run", pattern: /\bpnpm\s+(run|exec)\s+/i, evidence: "pnpm script or exec invocation evidence was detected." },
    { signal: "node-entrypoint", pattern: /\bnode\s+\.husky\/[^\s]+|\bnode\s+[^"'\n]*(pre-commit|pre-push|commit-msg)[^"'\n]*\.(mjs|cjs|js)\b|\.husky\/[^\s"']+\.(mjs|cjs|js)\b/i, evidence: "Node hook entrypoint evidence was detected." },
    { signal: "posix-shell", pattern: /^#!\/(?:usr\/bin\/env\s+)?sh\b|POSIX|bash\s+<<\s*EOF|set\s+-e/im, evidence: "POSIX shell hook evidence was detected." }
  ];
  return gitHooksSignalFromSpecs(sourceFiles, specs, "command", "signal");
}

function gitHooksPolicySignals(sourceFiles: GitHooksSourceFile[]): GitHooksReport["policySignals"] {
  const specs: Array<{ signal: GitHooksReport["policySignals"][number]["signal"]; pattern: RegExp; evidence: string }> = [
    { signal: "pre-commit", pattern: /\.husky\/pre-commit|\bpre-commit\b/i, evidence: "pre-commit hook evidence was detected." },
    { signal: "pre-push", pattern: /\.husky\/pre-push|\bpre-push\b/i, evidence: "pre-push hook evidence was detected." },
    { signal: "commit-msg", pattern: /\.husky\/commit-msg|\bcommit-msg\b/i, evidence: "commit-msg hook evidence was detected." },
    { signal: "prepare-commit-msg", pattern: /\.husky\/prepare-commit-msg|\bprepare-commit-msg\b/i, evidence: "prepare-commit-msg hook evidence was detected." },
    { signal: "post-merge", pattern: /\.husky\/post-merge|\bpost-merge\b/i, evidence: "post-merge hook evidence was detected." },
    { signal: "skip-env", pattern: /HUSKY=0|export\s+HUSKY=0/i, evidence: "HUSKY=0 skip policy evidence was detected." },
    { signal: "no-verify", pattern: /--no-verify|git\s+\w+[^\n]*\s-n(\s|$)/i, evidence: "Git --no-verify bypass evidence was detected." },
    { signal: "gui-node-path", pattern: /init\.sh|node_modules\/\.bin|\bPATH\b|NVM_DIR|version manager|nvm|fnm|asdf|volta/i, evidence: "GUI or Node PATH mitigation evidence was detected." },
    { signal: "deprecated-husky-sh", pattern: /husky\.sh|_\/husky\.sh/i, evidence: "deprecated husky.sh shim evidence was detected." }
  ];
  return gitHooksSignalFromSpecs(sourceFiles, specs, "policy", "signal");
}

function gitHooksToolConfigFiles(sourceFiles: GitHooksSourceFile[]): GitHooksReport["toolConfigFiles"] {
  return sourceFiles
    .filter((source) => gitHooksToolForPath(source.filePath, source.text) !== null)
    .slice(0, 80)
    .map((source) => {
      const tool = gitHooksToolForPath(source.filePath, source.text) ?? "unknown";
      return {
        filePath: source.filePath,
        tool,
        readiness: tool === "unknown" ? "partial" : "ready",
        evidence: `${source.filePath} contains ${tool} hook-tool configuration evidence.`,
        sourceHref: source.sourceHref
      };
    });
}

function gitHooksToolForPath(filePath: string, text: string): GitHooksReport["toolConfigFiles"][number]["tool"] | null {
  const base = path.basename(filePath).toLowerCase();
  if (filePath.startsWith(".husky/") || /\bhusky\b/i.test(text)) return "husky";
  if (/^\.lintstagedrc|lint-staged\.config\./i.test(base) || /\blint-staged\b|lintstaged/i.test(text)) return "lint-staged";
  if (/^commitlint\.config\./i.test(base) || /\bcommitlint\b/i.test(text)) return "commitlint";
  if (/^lefthook\.ya?ml$/i.test(base) || /\blefthook\b/i.test(text)) return "lefthook";
  if (/^\.pre-commit-config\.ya?ml$/i.test(base) || /\brepos:\s*\n[\s\S]*hooks:/i.test(text)) return "pre-commit";
  if (/^\.simple-git-hooks\./i.test(base) || /simple-git-hooks/i.test(text)) return "simple-git-hooks";
  return null;
}

function gitHooksPackageHasDependency(sourceFiles: GitHooksSourceFile[], dependencyName: string): boolean {
  return sourceFiles.some((source) => {
    if (path.basename(source.filePath) !== "package.json") return false;
    try {
      const json = JSON.parse(source.text) as {
        dependencies?: Record<string, unknown>;
        devDependencies?: Record<string, unknown>;
        optionalDependencies?: Record<string, unknown>;
      };
      return Boolean(json.dependencies?.[dependencyName] ?? json.devDependencies?.[dependencyName] ?? json.optionalDependencies?.[dependencyName]);
    } catch {
      return source.text.includes(`"${dependencyName}"`);
    }
  });
}

function gitHooksSignalFromSpecs<T extends Record<K, string> & { pattern: RegExp; evidence: string }, K extends string>(
  sourceFiles: GitHooksSourceFile[],
  specs: T[],
  label: string,
  labelKey: K
): Array<Record<K, T[K]> & { readiness: "ready" | "missing" | "external"; evidence: string; relatedHref: string }> {
  return specs.map((spec) => {
    const match = sourceFiles.find((source) => spec.pattern.test(source.text) || spec.pattern.test(source.filePath));
    return {
      [labelKey]: spec[labelKey],
      readiness: match ? "ready" : sourceFiles.length > 0 ? "external" : "missing",
      evidence: match ? `${match.filePath} ${spec.evidence}` : `${label} ${spec[labelKey]} evidence was not detected.`,
      relatedHref: match?.sourceHref ?? "html/git-hooks.html"
    } as Record<K, T[K]> & { readiness: "ready" | "missing" | "external"; evidence: string; relatedHref: string };
  });
}

async function buildTaskRunnerReport(walk: WalkResult): Promise<TaskRunnerReport> {
  const sourceFiles = await taskRunnerSourceFiles(walk);
  const configFiles = taskRunnerConfigFiles(sourceFiles);
  const taskSignals = taskRunnerTaskSignals(sourceFiles);
  const cacheSignals = taskRunnerCacheSignals(sourceFiles);
  const dependencySignals = taskRunnerDependencySignals(sourceFiles);
  const environmentSignals = taskRunnerEnvironmentSignals(sourceFiles);
  const packageScriptSignals = taskRunnerPackageScriptSignals(sourceFiles);

  const hasConfig = configFiles.length > 0;
  const hasTurboScript = packageScriptSignals.some((item) => item.signal === "turbo-run" && item.readiness === "ready");
  const hasTaskDependencies = dependencySignals.some((item) => ["depends-on", "caret-dependency"].includes(item.signal) && item.readiness === "ready");
  const hasOutputs = cacheSignals.some((item) => item.signal === "outputs" && item.readiness === "ready");
  const hasInputs = cacheSignals.some((item) => item.signal === "inputs" && item.readiness === "ready");
  const hasEnv = environmentSignals.some((item) => ["globalEnv", "globalPassThroughEnv", "passThroughEnv", "env"].includes(item.signal) && item.readiness === "ready");

  const riskQueue: TaskRunnerReport["riskQueue"] = [];
  if (!hasConfig && !hasTurboScript) {
    riskQueue.push({
      priority: "medium",
      action: "Decide whether workspace task orchestration should be documented for learners.",
      why: "Turbo-style monorepos make build/test/lint ordering and cache boundaries explicit through task-runner config and package scripts.",
      relatedHref: "html/task-runner.html"
    });
  }
  if (hasTurboScript && !hasConfig) {
    riskQueue.push({
      priority: "high",
      action: "Add the task-runner config that explains the turbo script behavior.",
      why: "A package script that calls turbo without turbo.json makes task dependencies, inputs, outputs, and cache policy hard to inspect.",
      relatedHref: "html/task-runner.html"
    });
  }
  if (hasConfig && !hasTaskDependencies) {
    riskQueue.push({
      priority: "medium",
      action: "Document task ordering with dependsOn where build/test tasks depend on upstream packages.",
      why: "Turborepo uses dependsOn such as ^build to express workspace task graph order.",
      relatedHref: "html/task-runner.html"
    });
  }
  if (hasConfig && !hasOutputs) {
    riskQueue.push({
      priority: "medium",
      action: "Declare cacheable task outputs for build-like tasks.",
      why: "Task runner caching needs output paths so learners can understand what is restored or invalidated.",
      relatedHref: "html/task-runner.html"
    });
  }
  if (hasConfig && !hasInputs) {
    riskQueue.push({
      priority: "low",
      action: "Review task inputs for expensive tasks or generated artifacts.",
      why: "Turbo-style inputs let teams narrow cache invalidation and avoid costly glob walking.",
      relatedHref: "html/task-runner.html"
    });
  }
  if (hasConfig && !hasEnv) {
    riskQueue.push({
      priority: "low",
      action: "Document environment variables that affect cached task results.",
      why: "Turbo separates env, globalEnv, and pass-through env so cache keys and runtime-only variables are explicit.",
      relatedHref: "html/task-runner.html"
    });
  }
  riskQueue.push({
    priority: "low",
    action: "Run task-runner commands in a trusted workspace before treating this static report as approval.",
    why: "RepoTutor records task-runner readiness statically; it does not run builds, restore cache, or contact remote cache services.",
    relatedHref: "html/task-runner.html"
  });

  return {
    summary: `Turborepo식 task-runner readiness report: config file ${configFiles.length}개, task signal ${taskSignals.length}개, cache signal ${cacheSignals.length}개, dependency signal ${dependencySignals.length}개를 정적 분석으로 정리했습니다.`,
    sourcePattern: "Turborepo turbo.json tasks dependsOn outputs inputs cache env globalEnv passThroughEnv persistent turbo run filter remote cache",
    configFiles,
    taskSignals,
    cacheSignals,
    dependencySignals,
    environmentSignals,
    packageScriptSignals,
    riskQueue: riskQueue.sort((a, b) => ({ high: 0, medium: 1, low: 2 }[a.priority] - { high: 0, medium: 1, low: 2 }[b.priority])),
    recommendedCommands: [
      { command: "pnpm turbo run build --dry=json", purpose: "Inspect the task graph and package selection without running build work." },
      { command: "pnpm turbo run test --filter <package>", purpose: "Run a scoped task for one package when the workspace is trusted." },
      { command: "pnpm turbo run build --summarize", purpose: "Review cache inputs, outputs, and task summaries after a real run." },
      { command: "pnpm turbo daemon status", purpose: "Check local Turbo daemon state when task discovery feels stale." },
      { command: "pnpm turbo prune <package>", purpose: "Understand which files a package needs for isolated builds." },
      { command: "pnpm turbo run lint --cache=local:rw", purpose: "Keep cache behavior local while validating a lint task." }
    ],
    learnerNextSteps: [
      "Start with turbo.json: task names explain what can be orchestrated, dependsOn explains ordering, and outputs explain cache artifacts.",
      "Then read package.json scripts to see which commands call the task runner and which remain direct package-manager scripts.",
      "Separate cache-key inputs from runtime-only pass-through environment variables before trusting task results.",
      "RepoTutor does not run task-runner commands; use this page as a static map before executing workspace tasks yourself."
    ]
  };
}

type TaskRunnerSourceFile = {
  filePath: string;
  text: string;
  sourceHref: string;
};

async function taskRunnerSourceFiles(walk: WalkResult): Promise<TaskRunnerSourceFile[]> {
  const files: TaskRunnerSourceFile[] = [];
  for (const file of walk.files) {
    if (!file.isTextCandidate || !taskRunnerInspectablePath(file.relPath)) continue;
    const text = await readTextIfSafe(file.absPath, 200_000);
    if (!text) continue;
    if (!taskRunnerPathSignal(file.relPath) && !taskRunnerContentSignal(text)) continue;
    files.push({ filePath: file.relPath, text, sourceHref: `source/${encodedPath(file.relPath)}` });
    if (files.length >= 220) break;
  }
  return files;
}

function taskRunnerInspectablePath(filePath: string): boolean {
  const base = path.basename(filePath);
  return /^(turbo\.json|nx\.json|workspace\.json|project\.json|Taskfile\.ya?ml|moon\.ya?ml|package\.json|README\.md)$/i.test(base)
    || filePath.startsWith(".moon/")
    || /(turbo|turborepo|task-runner|taskfile|moonrepo|nx|monorepo|workspace)/i.test(filePath)
    || /\.(json|md|ya?ml|toml)$/i.test(filePath);
}

function taskRunnerPathSignal(filePath: string): boolean {
  const base = path.basename(filePath);
  return /^(turbo\.json|nx\.json|workspace\.json|project\.json|Taskfile\.ya?ml|moon\.ya?ml|package\.json)$/i.test(base)
    || filePath.startsWith(".moon/")
    || /(turbo|turborepo|task-runner|taskfile|moonrepo|nx)/i.test(filePath);
}

function taskRunnerContentSignal(text: string): boolean {
  return /\bturbo\b|turborepo|\"tasks\"\s*:|\"pipeline\"\s*:|dependsOn|outputs|inputs|globalEnv|globalPassThroughEnv|passThroughEnv|remoteCache|cache\s*:\s*false|persistent|nx\s+run|moon\s+run|Taskfile/i.test(text);
}

function taskRunnerConfigFiles(sourceFiles: TaskRunnerSourceFile[]): TaskRunnerReport["configFiles"] {
  return sourceFiles
    .filter((source) => taskRunnerConfigPathSignal(source.filePath) && taskRunnerToolForPath(source.filePath, source.text) !== null)
    .slice(0, 80)
    .map((source) => {
      const tool = taskRunnerToolForPath(source.filePath, source.text) ?? "unknown";
      const taskCount = taskRunnerTaskCount(source.text);
      const dependsOnCount = countMatches(source.text, /dependsOn/g);
      const outputsCount = countMatches(source.text, /outputs/g);
      return {
        filePath: source.filePath,
        tool,
        taskCount,
        dependsOnCount,
        outputsCount,
        readiness: taskCount > 0 || dependsOnCount > 0 || outputsCount > 0 ? "ready" : "partial",
        evidence: `${source.filePath} contains ${tool} task-runner config with ${taskCount} task signal(s), ${dependsOnCount} dependency signal(s), and ${outputsCount} output signal(s).`,
        sourceHref: source.sourceHref
      };
    });
}

function taskRunnerConfigPathSignal(filePath: string): boolean {
  const base = path.basename(filePath);
  return /^(turbo\.json|nx\.json|workspace\.json|project\.json|Taskfile\.ya?ml|moon\.ya?ml|package\.json)$/i.test(base)
    || filePath.startsWith(".moon/")
    || /(turbo|task-runner|taskfile|moonrepo|nx|lage).*\.(json|ya?ml|toml)$/i.test(filePath);
}

function taskRunnerToolForPath(filePath: string, text: string): TaskRunnerReport["configFiles"][number]["tool"] | null {
  const base = path.basename(filePath).toLowerCase();
  if (base === "turbo.json" || /\bturbo\b|turborepo/i.test(text)) return "turbo";
  if (base === "nx.json" || base === "project.json" || /\bnx\s+run|\bnx\b/i.test(text)) return "nx";
  if (/^taskfile\.ya?ml$/i.test(base)) return "taskfile";
  if (base === "moon.yml" || base === "moon.yaml" || filePath.startsWith(".moon/") || /\bmoon\s+run\b/i.test(text)) return "moon";
  if (/\blage\b/i.test(text)) return "lage";
  return null;
}

function taskRunnerTaskCount(text: string): number {
  try {
    const cleaned = stripJsonComments(text);
    const json = JSON.parse(cleaned) as { tasks?: Record<string, unknown>; pipeline?: Record<string, unknown> };
    return Object.keys(json.tasks ?? json.pipeline ?? {}).length;
  } catch {
    const section = text.match(/"?(tasks|pipeline)"?\s*:\s*\{([\s\S]*?)\n\s*\}/)?.[2] ?? "";
    return Math.max(countMatches(section, /"[^"]+"\s*:/g), 0);
  }
}

function taskRunnerTaskSignals(sourceFiles: TaskRunnerSourceFile[]): TaskRunnerReport["taskSignals"] {
  const specs: Array<{ signal: TaskRunnerReport["taskSignals"][number]["signal"]; pattern: RegExp; evidence: string }> = [
    { signal: "build", pattern: /"build[^"]*"\s*:|\bturbo\s+run\s+build\b|\bnx\s+run\s+\S+:build\b/i, evidence: "build task evidence was detected." },
    { signal: "test", pattern: /"test[^"]*"\s*:|\bturbo\s+run\s+test\b|\bnx\s+run\s+\S+:test\b/i, evidence: "test task evidence was detected." },
    { signal: "lint", pattern: /"lint[^"]*"\s*:|\bturbo\s+run\s+lint\b|\bnx\s+run\s+\S+:lint\b/i, evidence: "lint task evidence was detected." },
    { signal: "dev", pattern: /"dev[^"]*"\s*:|\bturbo\s+run\s+dev\b/i, evidence: "dev task evidence was detected." },
    { signal: "typecheck", pattern: /typecheck|check-types|tsc\s+-b/i, evidence: "typecheck task evidence was detected." },
    { signal: "format", pattern: /"format[^"]*"\s*:|\bturbo\s+run\s+format\b|prettier|oxfmt/i, evidence: "format task evidence was detected." },
    { signal: "quality", pattern: /quality|check|verify/i, evidence: "quality or check task evidence was detected." },
    { signal: "release", pattern: /release|publish|deploy/i, evidence: "release or deploy task evidence was detected." }
  ];
  return taskRunnerSignalFromSpecs(sourceFiles, specs, "task", "signal");
}

function taskRunnerCacheSignals(sourceFiles: TaskRunnerSourceFile[]): TaskRunnerReport["cacheSignals"] {
  const specs: Array<{ signal: TaskRunnerReport["cacheSignals"][number]["signal"]; pattern: RegExp; evidence: string }> = [
    { signal: "outputs", pattern: /"outputs"\s*:|outputs:/i, evidence: "cache output declaration evidence was detected." },
    { signal: "inputs", pattern: /"inputs"\s*:|inputs:/i, evidence: "cache input declaration evidence was detected." },
    { signal: "cache-false", pattern: /"cache"\s*:\s*false|cache:\s*false/i, evidence: "cache disabled task evidence was detected." },
    { signal: "remote-cache", pattern: /remoteCache|remote cache|TURBO_TOKEN|TURBO_TEAM/i, evidence: "remote cache evidence was detected." },
    { signal: "global-env", pattern: /globalEnv|globalDependencies/i, evidence: "global cache environment evidence was detected." },
    { signal: "pass-through-env", pattern: /globalPassThroughEnv|passThroughEnv/i, evidence: "pass-through environment evidence was detected." },
    { signal: "persistent", pattern: /"persistent"\s*:\s*true|persistent:\s*true/i, evidence: "persistent task evidence was detected." }
  ];
  return taskRunnerSignalFromSpecs(sourceFiles, specs, "cache", "signal");
}

function taskRunnerDependencySignals(sourceFiles: TaskRunnerSourceFile[]): TaskRunnerReport["dependencySignals"] {
  const specs: Array<{ signal: TaskRunnerReport["dependencySignals"][number]["signal"]; pattern: RegExp; evidence: string }> = [
    { signal: "depends-on", pattern: /dependsOn/i, evidence: "task dependsOn evidence was detected." },
    { signal: "caret-dependency", pattern: /"\^[^"]+"|\^build|\^topo/i, evidence: "upstream workspace dependency task evidence was detected." },
    { signal: "root-task", pattern: /"\/\/#|\/\/#/i, evidence: "root task evidence was detected." },
    { signal: "package-task", pattern: /[A-Za-z0-9_-]+#[A-Za-z0-9:_-]+/i, evidence: "package-scoped task evidence was detected." },
    { signal: "filter", pattern: /--filter|-F\s+|--affected|affected:/i, evidence: "task filter evidence was detected." },
    { signal: "workspace-script", pattern: /workspace|workspaces|pnpm\s+-r|pnpm\s+--filter|turbo\s+run/i, evidence: "workspace script orchestration evidence was detected." }
  ];
  return taskRunnerSignalFromSpecs(sourceFiles, specs, "dependency", "signal");
}

function taskRunnerEnvironmentSignals(sourceFiles: TaskRunnerSourceFile[]): TaskRunnerReport["environmentSignals"] {
  const specs: Array<{ signal: TaskRunnerReport["environmentSignals"][number]["signal"]; pattern: RegExp; evidence: string }> = [
    { signal: "globalEnv", pattern: /globalEnv/i, evidence: "globalEnv evidence was detected." },
    { signal: "globalPassThroughEnv", pattern: /globalPassThroughEnv/i, evidence: "globalPassThroughEnv evidence was detected." },
    { signal: "passThroughEnv", pattern: /passThroughEnv/i, evidence: "passThroughEnv evidence was detected." },
    { signal: "env", pattern: /"env"\s*:|env:/i, evidence: "task env evidence was detected." },
    { signal: "dot-env", pattern: /\.env|dotenv/i, evidence: "dot-env file evidence was detected." },
    { signal: "ci", pattern: /RUNNER_OS|GITHUB_ACTIONS|CI\b|ACTIONS_/i, evidence: "CI environment evidence was detected." }
  ];
  return taskRunnerSignalFromSpecs(sourceFiles, specs, "environment", "signal");
}

function taskRunnerPackageScriptSignals(sourceFiles: TaskRunnerSourceFile[]): TaskRunnerReport["packageScriptSignals"] {
  const specs: Array<{ signal: TaskRunnerReport["packageScriptSignals"][number]["signal"]; pattern: RegExp; evidence: string }> = [
    { signal: "turbo-run", pattern: /\bturbo\s+run\b|\bpnpm\s+--\s+turbo\b|\bnpx\s+turbo\b/i, evidence: "turbo run package script evidence was detected." },
    { signal: "nx-run", pattern: /\bnx\s+run\b|\bnx\s+affected\b/i, evidence: "Nx run package script evidence was detected." },
    { signal: "task-run", pattern: /\btask\s+[A-Za-z0-9:_-]+|Taskfile\.ya?ml/i, evidence: "Taskfile task script evidence was detected." },
    { signal: "moon-run", pattern: /\bmoon\s+run\b/i, evidence: "Moon task script evidence was detected." },
    { signal: "recursive-run", pattern: /\bpnpm\s+-r\b|\bnpm\s+.*--workspaces\b|yarn\s+workspaces/i, evidence: "recursive workspace package script evidence was detected." },
    { signal: "filter-run", pattern: /--filter|-F\s+|--affected/i, evidence: "filtered task run evidence was detected." }
  ];
  return taskRunnerSignalFromSpecs(sourceFiles, specs, "package script", "signal");
}

function taskRunnerSignalFromSpecs<T extends Record<K, string> & { pattern: RegExp; evidence: string }, K extends string>(
  sourceFiles: TaskRunnerSourceFile[],
  specs: T[],
  label: string,
  labelKey: K
): Array<Record<K, T[K]> & { readiness: "ready" | "missing" | "external"; evidence: string; relatedHref: string }> {
  return specs.map((spec) => {
    const match = sourceFiles.find((source) => spec.pattern.test(source.text) || spec.pattern.test(source.filePath));
    return {
      [labelKey]: spec[labelKey],
      readiness: match ? "ready" : sourceFiles.length > 0 ? "external" : "missing",
      evidence: match ? `${match.filePath} ${spec.evidence}` : `${label} ${spec[labelKey]} evidence was not detected.`,
      relatedHref: match?.sourceHref ?? "html/task-runner.html"
    } as Record<K, T[K]> & { readiness: "ready" | "missing" | "external"; evidence: string; relatedHref: string };
  });
}

function stripJsonComments(text: string): string {
  return text.replace(/\/\/.*$/gm, "").replace(/\/\*[\s\S]*?\*\//g, "");
}

async function buildDependencyUpdateReport(walk: WalkResult): Promise<DependencyUpdateReport> {
  const sourceFiles = await dependencyUpdateSourceFiles(walk);
  const configFiles = dependencyUpdateConfigFiles(sourceFiles);
  const managerSignals = dependencyUpdateManagerSignals(sourceFiles);
  const policySignals = dependencyUpdatePolicySignals(sourceFiles);
  const workflowSignals = dependencyUpdateWorkflowSignals(sourceFiles);
  const registrySignals = dependencyUpdateRegistrySignals(sourceFiles);
  const packageFileSignals = dependencyUpdatePackageFileSignals(sourceFiles);

  const hasConfig = configFiles.length > 0;
  const hasPackageFiles = packageFileSignals.some((item) => item.readiness === "ready");
  const hasPackageRules = policySignals.some((item) => item.signal === "package-rules" && item.readiness === "ready");
  const hasDashboard = policySignals.some((item) => item.signal === "dependency-dashboard" && item.readiness === "ready");
  const hasRateLimits = policySignals.some((item) => item.signal === "rate-limits" && item.readiness === "ready");
  const hasRegistryRules = registrySignals.some((item) => ["host-rules", "registry-url", "private-packages"].includes(item.signal) && item.readiness === "ready");
  const hasAutomerge = policySignals.some((item) => item.signal === "automerge" && item.readiness === "ready");
  const hasSchedule = policySignals.some((item) => item.signal === "schedule" && item.readiness === "ready");

  const riskQueue: DependencyUpdateReport["riskQueue"] = [];
  if (hasPackageFiles && !hasConfig) {
    riskQueue.push({
      priority: "high",
      action: "Add a dependency update configuration before relying on automated update PRs.",
      why: "Renovate-style automation needs repository policy for presets, grouping, schedules, and review boundaries.",
      relatedHref: "html/dependency-updates.html"
    });
  }
  if (hasConfig && !hasPackageRules) {
    riskQueue.push({
      priority: "medium",
      action: "Review packageRules for grouping, major-update handling, and ecosystem-specific policy.",
      why: "Renovate packageRules make selective automerge, labels, schedules, grouping, and manager-specific rules inspectable.",
      relatedHref: "html/dependency-updates.html"
    });
  }
  if (hasConfig && !hasDashboard) {
    riskQueue.push({
      priority: "medium",
      action: "Consider a dependency dashboard or approval workflow for high-risk updates.",
      why: "Dependency dashboards give maintainers a single queue for approvals, blocked updates, and manual decisions.",
      relatedHref: "html/dependency-updates.html"
    });
  }
  if (hasConfig && !hasRateLimits) {
    riskQueue.push({
      priority: "low",
      action: "Set PR or branch concurrency limits when the repository has many dependency files.",
      why: "Automated update tools can create noisy PR bursts unless concurrency and hourly limits are explicit.",
      relatedHref: "html/dependency-updates.html"
    });
  }
  if (hasRegistryRules) {
    riskQueue.push({
      priority: "medium",
      action: "Verify private registry credentials outside static RepoTutor analysis.",
      why: "RepoTutor can detect hostRules and registry URLs, but it does not validate tokens, access, or registry reachability.",
      relatedHref: "html/dependency-updates.html"
    });
  }
  if (hasAutomerge && !hasSchedule) {
    riskQueue.push({
      priority: "medium",
      action: "Pair automerge with schedule, status-check, and branch-protection review.",
      why: "Renovate warns that automerge behavior depends on checks, platform automerge mode, and schedule semantics.",
      relatedHref: "html/dependency-updates.html"
    });
  }
  riskQueue.push({
    priority: "low",
    action: "Run the config validator and dry-run in a trusted workspace before enabling update PRs.",
    why: "RepoTutor records dependency-update readiness statically; it does not query registries, create branches, or open pull requests.",
    relatedHref: "html/dependency-updates.html"
  });

  return {
    summary: `Renovate식 dependency-update readiness report: config file ${configFiles.length}개, manager signal ${managerSignals.length}개, policy signal ${policySignals.length}개, package file signal ${packageFileSignals.length}개를 정적 분석으로 정리했습니다.`,
    sourcePattern: "Renovate config presets packageRules automerge schedule dependencyDashboard enabledManagers hostRules rangeStrategy prConcurrentLimit configMigration",
    configFiles,
    managerSignals,
    policySignals,
    workflowSignals,
    registrySignals,
    packageFileSignals,
    riskQueue: riskQueue.sort((a, b) => ({ high: 0, medium: 1, low: 2 }[a.priority] - { high: 0, medium: 1, low: 2 }[b.priority])),
    recommendedCommands: [
      { command: "npx renovate-config-validator", purpose: "Validate Renovate config syntax and schema in a trusted workspace." },
      { command: "npx renovate --dry-run=full", purpose: "Preview discovered dependencies, branches, and PR decisions without writing changes." },
      { command: "npx renovate --print-config", purpose: "Inspect the resolved config after presets and inherited settings are applied." },
      { command: "npx renovate --platform=github --autodiscover=false <owner/repo>", purpose: "Run a scoped repository check instead of broad autodiscovery." },
      { command: "npx renovate --dry-run=lookup", purpose: "Check lookup behavior before creating branches or pull requests." },
      { command: "gh workflow run renovate.yml --ref <branch>", purpose: "Trigger a dedicated Renovate workflow only after reviewing workflow permissions." }
    ],
    learnerNextSteps: [
      "Start with renovate.json, .renovaterc, or dependabot.yml to find the automation policy before reading package manifests.",
      "Check packageRules and schedules before trusting automerge or grouped dependency PRs.",
      "Separate public package-file discovery from private registry credentials such as hostRules and token environment variables.",
      "RepoTutor does not call registries or create branches; use this page as a static review map before enabling automation."
    ]
  };
}

type DependencyUpdateSourceFile = {
  filePath: string;
  text: string;
  sourceHref: string;
};

async function dependencyUpdateSourceFiles(walk: WalkResult): Promise<DependencyUpdateSourceFile[]> {
  const files: DependencyUpdateSourceFile[] = [];
  for (const file of walk.files) {
    if (!file.isTextCandidate || !dependencyUpdateInspectablePath(file.relPath)) continue;
    const text = await readTextIfSafe(file.absPath, 200_000);
    if (!text) continue;
    if (!dependencyUpdatePathSignal(file.relPath) && !dependencyUpdatePackageFilePathSignal(file.relPath) && !dependencyUpdateContentSignal(text)) continue;
    files.push({ filePath: file.relPath, text, sourceHref: `source/${encodedPath(file.relPath)}` });
    if (files.length >= 240) break;
  }
  return files;
}

function dependencyUpdateInspectablePath(filePath: string): boolean {
  const base = path.basename(filePath);
  return dependencyUpdatePathSignal(filePath)
    || /^(package\.json|package-lock\.json|pnpm-lock\.yaml|yarn\.lock|bun\.lockb?|Dockerfile|go\.mod|pyproject\.toml|requirements.*\.txt|Gemfile|versions\.tf)$/i.test(base)
    || filePath.startsWith(".github/workflows/")
    || /\.(json|json5|ya?ml|toml|md)$/i.test(filePath);
}

function dependencyUpdatePathSignal(filePath: string): boolean {
  const base = path.basename(filePath);
  return /^(renovate\.json|renovate\.json5|\.renovaterc|\.renovaterc\.json|\.renovaterc\.json5|\.renovaterc\.ya?ml|renovate\.config\.[cm]?[jt]s|dependabot\.ya?ml)$/i.test(base)
    || filePath === ".github/dependabot.yml"
    || filePath === ".github/dependabot.yaml"
    || /renovate|dependabot|dependency-update|dependency-updates/i.test(filePath);
}

function dependencyUpdatePackageFilePathSignal(filePath: string): boolean {
  const base = path.basename(filePath);
  return /^(package\.json|package-lock\.json|pnpm-lock\.yaml|yarn\.lock|bun\.lockb?|Dockerfile|go\.mod|pyproject\.toml|requirements.*\.txt|Gemfile|versions\.tf)$/i.test(base)
    || filePath.startsWith(".github/workflows/")
    || /\.tf$/i.test(filePath);
}

function dependencyUpdateContentSignal(text: string): boolean {
  return /renovate|dependabot|packageRules|dependencyDashboard|automerge|hostRules|enabledManagers|rangeStrategy|prConcurrentLimit|branchConcurrentLimit|lockFileMaintenance/i.test(text);
}

function dependencyUpdateConfigFiles(sourceFiles: DependencyUpdateSourceFile[]): DependencyUpdateReport["configFiles"] {
  return sourceFiles
    .filter((source) => dependencyUpdateConfigPathSignal(source.filePath, source.text))
    .slice(0, 80)
    .map((source) => {
      const configType = dependencyUpdateConfigType(source.filePath, source.text);
      const extendsCount = countMatches(source.text, /"extends"\s*:|extends:/g);
      const packageRuleCount = dependencyUpdatePackageRuleCount(source.text);
      const scheduleCount = countMatches(source.text, /schedule|automergeSchedule/g);
      const automergeSignal = dependencyUpdateAutomergeSignal(source.text);
      return {
        filePath: source.filePath,
        configType,
        extendsCount,
        packageRuleCount,
        scheduleCount,
        automergeSignal,
        readiness: extendsCount > 0 || packageRuleCount > 0 || scheduleCount > 0 || automergeSignal !== "missing" ? "ready" : "partial",
        evidence: `${source.filePath} contains ${configType} dependency-update config with ${extendsCount} preset signal(s), ${packageRuleCount} package rule signal(s), and ${scheduleCount} schedule signal(s).`,
        sourceHref: source.sourceHref
      };
    });
}

function dependencyUpdateConfigPathSignal(filePath: string, text: string): boolean {
  const base = path.basename(filePath);
  return dependencyUpdatePathSignal(filePath)
    || (base === "package.json" && /"renovate"\s*:/.test(text))
    || (filePath.startsWith(".github/workflows/") && /\brenovate\b|dependabot/i.test(text));
}

function dependencyUpdateConfigType(filePath: string, text: string): DependencyUpdateReport["configFiles"][number]["configType"] {
  const base = path.basename(filePath).toLowerCase();
  if (filePath === ".github/dependabot.yml" || filePath === ".github/dependabot.yaml" || /dependabot/i.test(filePath)) return "dependabot";
  if (base === "package.json") return "package-json";
  if (filePath.startsWith(".github/workflows/")) return "github-action";
  if (/renovate|packageRules|dependencyDashboard|hostRules|enabledManagers/i.test(filePath) || /renovate|packageRules|dependencyDashboard|hostRules|enabledManagers/i.test(text)) return "renovate";
  return "unknown";
}

function dependencyUpdatePackageRuleCount(text: string): number {
  try {
    const cleaned = stripJsonComments(text);
    const json = JSON.parse(cleaned) as { packageRules?: unknown[]; renovate?: { packageRules?: unknown[] } };
    return Array.isArray(json.packageRules) ? json.packageRules.length : Array.isArray(json.renovate?.packageRules) ? json.renovate.packageRules.length : 0;
  } catch {
    const section = text.match(/packageRules["']?\s*:\s*\[([\s\S]*?)\n\s*\]/)?.[1] ?? "";
    return Math.max(countMatches(section, /\{[\s\S]*?\}/g), countMatches(text, /packageRules/g));
  }
}

function dependencyUpdateAutomergeSignal(text: string): DependencyUpdateReport["configFiles"][number]["automergeSignal"] {
  if (/automerge[^:\n]*["']?\s*:\s*true|platformAutomerge[^:\n]*["']?\s*:\s*true/i.test(text)) return /packageRules|matchPackage|matchDep|matchUpdateTypes/i.test(text) ? "conditional" : "enabled";
  if (/automerge[^:\n]*["']?\s*:\s*false|platformAutomerge[^:\n]*["']?\s*:\s*false/i.test(text)) return "disabled";
  if (/automergeType|automergeSchedule|automergeStrategy/i.test(text)) return "conditional";
  return "missing";
}

function dependencyUpdateManagerSignals(sourceFiles: DependencyUpdateSourceFile[]): DependencyUpdateReport["managerSignals"] {
  const specs: Array<{ signal: DependencyUpdateReport["managerSignals"][number]["signal"]; pattern: RegExp; evidence: string }> = [
    { signal: "npm", pattern: /package\.json|package-lock\.json|pnpm-lock\.yaml|yarn\.lock|bun\.lockb?|npm|pnpm|yarn|bun/i, evidence: "npm-family dependency manager evidence was detected." },
    { signal: "docker", pattern: /Dockerfile|dockerfile|containerbase|docker-compose|docker/i, evidence: "Docker dependency manager evidence was detected." },
    { signal: "github-actions", pattern: /\.github\/workflows|github-actions|github action/i, evidence: "GitHub Actions dependency manager evidence was detected." },
    { signal: "python", pattern: /pyproject\.toml|requirements.*\.txt|poetry|pipenv|pip-compile/i, evidence: "Python dependency manager evidence was detected." },
    { signal: "go", pattern: /go\.mod|go\.sum|gomod|golang/i, evidence: "Go module manager evidence was detected." },
    { signal: "ruby", pattern: /Gemfile|bundler|rubygems/i, evidence: "Ruby dependency manager evidence was detected." },
    { signal: "terraform", pattern: /\.tf\b|terraform|terragrunt/i, evidence: "Terraform dependency manager evidence was detected." },
    { signal: "maven", pattern: /pom\.xml|maven/i, evidence: "Maven dependency manager evidence was detected." },
    { signal: "gradle", pattern: /build\.gradle|gradle/i, evidence: "Gradle dependency manager evidence was detected." }
  ];
  return dependencyUpdateSignalFromSpecs(sourceFiles, specs, "manager", "signal");
}

function dependencyUpdatePolicySignals(sourceFiles: DependencyUpdateSourceFile[]): DependencyUpdateReport["policySignals"] {
  const specs: Array<{ signal: DependencyUpdateReport["policySignals"][number]["signal"]; pattern: RegExp; evidence: string }> = [
    { signal: "extends", pattern: /"extends"\s*:|extends:/i, evidence: "preset extends evidence was detected." },
    { signal: "package-rules", pattern: /packageRules|package-rules/i, evidence: "packageRules evidence was detected." },
    { signal: "schedule", pattern: /schedule|automergeSchedule/i, evidence: "schedule evidence was detected." },
    { signal: "automerge", pattern: /automerge|platformAutomerge/i, evidence: "automerge policy evidence was detected." },
    { signal: "dependency-dashboard", pattern: /dependencyDashboard|dependency dashboard|dependencyDashboardApproval/i, evidence: "dependency dashboard evidence was detected." },
    { signal: "labels-reviewers", pattern: /labels|addLabels|reviewers|assignees/i, evidence: "labels, reviewers, or assignees evidence was detected." },
    { signal: "rate-limits", pattern: /prConcurrentLimit|branchConcurrentLimit|prHourlyLimit|prCreation/i, evidence: "PR or branch rate-limit evidence was detected." },
    { signal: "range-strategy", pattern: /rangeStrategy|range strategy|pinDigests|separateMajor/i, evidence: "version range strategy evidence was detected." },
    { signal: "config-migration", pattern: /configMigration|config migration/i, evidence: "config migration evidence was detected." },
    { signal: "host-rules", pattern: /hostRules|hostType|matchHost/i, evidence: "hostRules evidence was detected." },
    { signal: "vulnerability-alerts", pattern: /vulnerabilityAlerts|osv|security|dependency-review/i, evidence: "vulnerability update evidence was detected." }
  ];
  return dependencyUpdateSignalFromSpecs(sourceFiles, specs, "policy", "signal");
}

function dependencyUpdateWorkflowSignals(sourceFiles: DependencyUpdateSourceFile[]): DependencyUpdateReport["workflowSignals"] {
  const specs: Array<{ signal: DependencyUpdateReport["workflowSignals"][number]["signal"]; pattern: RegExp; evidence: string }> = [
    { signal: "branch-pr", pattern: /prCreation|branchName|branchPrefix|pull request|update PR/i, evidence: "branch or PR creation evidence was detected." },
    { signal: "dashboard-approval", pattern: /dependencyDashboardApproval|dashboard approval/i, evidence: "dashboard approval evidence was detected." },
    { signal: "grouping", pattern: /groupName|minimumGroupSize|groupSlug/i, evidence: "dependency grouping evidence was detected." },
    { signal: "separate-major", pattern: /separateMajor|separateMultipleMajor|matchUpdateTypes.*major/i, evidence: "major-update separation evidence was detected." },
    { signal: "semantic-commits", pattern: /semanticCommit|commitMessagePrefix|commitMessageTopic/i, evidence: "semantic commit evidence was detected." },
    { signal: "lockfile-maintenance", pattern: /lockFileMaintenance|lockfile maintenance/i, evidence: "lockfile maintenance evidence was detected." },
    { signal: "rebase", pattern: /rebaseWhen|automerge.*rebase|conflicted/i, evidence: "rebase policy evidence was detected." },
    { signal: "ignore-paths", pattern: /ignorePaths|ignoreDeps|ignorePresets|ignoreUnstable/i, evidence: "ignore path or ignore preset evidence was detected." }
  ];
  return dependencyUpdateSignalFromSpecs(sourceFiles, specs, "workflow", "signal");
}

function dependencyUpdateRegistrySignals(sourceFiles: DependencyUpdateSourceFile[]): DependencyUpdateReport["registrySignals"] {
  const specs: Array<{ signal: DependencyUpdateReport["registrySignals"][number]["signal"]; pattern: RegExp; evidence: string }> = [
    { signal: "host-rules", pattern: /hostRules|matchHost|hostType/i, evidence: "hostRules evidence was detected." },
    { signal: "encrypted-secrets", pattern: /encrypted|encryptedSecrets|secrets/i, evidence: "encrypted secret evidence was detected." },
    { signal: "registry-url", pattern: /registryUrls|registryUrl|npmrc|index-url|docker-registry/i, evidence: "registry URL evidence was detected." },
    { signal: "token-env", pattern: /RENOVATE_TOKEN|GITHUB_TOKEN|NPM_TOKEN|DOCKER_PASSWORD|token/i, evidence: "token environment evidence was detected." },
    { signal: "private-packages", pattern: /private package|private repositor|private registr|internal package|hostRules/i, evidence: "private package evidence was detected." }
  ];
  return dependencyUpdateSignalFromSpecs(sourceFiles, specs, "registry", "signal");
}

function dependencyUpdatePackageFileSignals(sourceFiles: DependencyUpdateSourceFile[]): DependencyUpdateReport["packageFileSignals"] {
  const specs: Array<{ signal: DependencyUpdateReport["packageFileSignals"][number]["signal"]; pattern: RegExp; evidence: string }> = [
    { signal: "package-json", pattern: /(^|\/)package\.json$/i, evidence: "package.json evidence was detected." },
    { signal: "package-lock", pattern: /(^|\/)package-lock\.json$/i, evidence: "package-lock.json evidence was detected." },
    { signal: "pnpm-lock", pattern: /(^|\/)pnpm-lock\.yaml$/i, evidence: "pnpm-lock.yaml evidence was detected." },
    { signal: "yarn-lock", pattern: /(^|\/)yarn\.lock$/i, evidence: "yarn.lock evidence was detected." },
    { signal: "bun-lock", pattern: /(^|\/)bun\.lockb?$/i, evidence: "bun lockfile evidence was detected." },
    { signal: "dockerfile", pattern: /(^|\/)Dockerfile$/i, evidence: "Dockerfile evidence was detected." },
    { signal: "github-actions", pattern: /^\.github\/workflows\/.+\.ya?ml$/i, evidence: "GitHub Actions workflow evidence was detected." },
    { signal: "go-mod", pattern: /(^|\/)go\.mod$/i, evidence: "go.mod evidence was detected." },
    { signal: "pyproject", pattern: /(^|\/)pyproject\.toml$/i, evidence: "pyproject.toml evidence was detected." },
    { signal: "requirements", pattern: /(^|\/)requirements.*\.txt$/i, evidence: "Python requirements evidence was detected." },
    { signal: "gemfile", pattern: /(^|\/)Gemfile$/i, evidence: "Gemfile evidence was detected." },
    { signal: "terraform", pattern: /\.tf$/i, evidence: "Terraform file evidence was detected." }
  ];
  return dependencyUpdateSignalFromSpecs(sourceFiles, specs, "package file", "signal");
}

function dependencyUpdateSignalFromSpecs<T extends Record<K, string> & { pattern: RegExp; evidence: string }, K extends string>(
  sourceFiles: DependencyUpdateSourceFile[],
  specs: T[],
  label: string,
  labelKey: K
): Array<Record<K, T[K]> & { readiness: "ready" | "missing" | "external"; evidence: string; relatedHref: string }> {
  return specs.map((spec) => {
    const match = sourceFiles.find((source) => spec.pattern.test(source.filePath) || spec.pattern.test(source.text));
    return {
      [labelKey]: spec[labelKey],
      readiness: match ? "ready" : sourceFiles.length > 0 ? "external" : "missing",
      evidence: match ? `${match.filePath} ${spec.evidence}` : `${label} ${spec[labelKey]} evidence was not detected.`,
      relatedHref: match?.sourceHref ?? "html/dependency-updates.html"
    } as Record<K, T[K]> & { readiness: "ready" | "missing" | "external"; evidence: string; relatedHref: string };
  });
}

async function buildDependencyReviewReadinessReport(walk: WalkResult): Promise<DependencyReviewReadinessReport> {
  const sourceFiles = await dependencyReviewSourceFiles(walk);
  const dependencyReviewSetups = dependencyReviewSetupsFromSources(sourceFiles);
  const reviewSignals = dependencyReviewReviewSignals(sourceFiles);
  const vulnerabilitySignals = dependencyReviewVulnerabilitySignals(sourceFiles);
  const licenseSignals = dependencyReviewLicenseSignals(sourceFiles);
  const packagePolicySignals = dependencyReviewPackagePolicySignals(sourceFiles);
  const ciSignals = dependencyReviewCiSignals(sourceFiles);
  const scorecardSignals = dependencyReviewScorecardSignals(sourceFiles);
  const outputSignals = dependencyReviewOutputSignals(sourceFiles);
  const packageSignals = dependencyReviewPackageSignals(sourceFiles);

  const hasReviewGate = reviewSignals.some((item) => item.readiness === "ready")
    || dependencyReviewSetups.some((item) => item.reviewCount > 0 || item.diffCount > 0);
  const hasSeverityGate = vulnerabilitySignals.some((item) => ["fail-on-severity", "min-severity", "vulnerability-check"].includes(item.signal) && item.readiness === "ready")
    || dependencyReviewSetups.some((item) => item.vulnerabilityCount > 0);
  const hasLicensePolicy = licenseSignals.some((item) => item.readiness === "ready")
    || dependencyReviewSetups.some((item) => item.licenseCount > 0);
  const hasPrDiff = reviewSignals.some((item) => ["base-head-compare", "pull-request", "snapshot-warning"].includes(item.signal) && item.readiness === "ready")
    || dependencyReviewSetups.some((item) => item.diffCount > 0 || item.snapshotCount > 0 || item.ciCount > 0);
  const hasPackagePolicy = packagePolicySignals.some((item) => item.readiness === "ready")
    || dependencyReviewSetups.some((item) => item.packagePolicyCount > 0);
  const hasOutput = outputSignals.some((item) => item.readiness === "ready")
    || dependencyReviewSetups.some((item) => item.outputCount > 0);

  const riskQueue: DependencyReviewReadinessReport["riskQueue"] = [];
  if (!hasReviewGate) {
    riskQueue.push({
      priority: "high",
      action: "Add a PR dependency review gate before treating dependency changes as reviewed.",
      why: "Dependency-review readiness needs an inspectable pull-request diff gate such as actions/dependency-review-action, dependency graph review, or OSV review workflow evidence.",
      relatedHref: "html/dependency-review-readiness.html"
    });
  }
  if (hasReviewGate && !hasSeverityGate) {
    riskQueue.push({
      priority: "high",
      action: "Set a vulnerability severity threshold for dependency review failures.",
      why: "Review gates without fail-on-severity, vulnerability-check, OSV minimum severity, or equivalent policy can surface findings without blocking risky dependency changes.",
      relatedHref: "html/dependency-review-readiness.html"
    });
  }
  if (hasReviewGate && !hasLicensePolicy) {
    riskQueue.push({
      priority: "medium",
      action: "Add license allow or deny policy to the dependency review workflow.",
      why: "License policy makes dependency review useful for both security and rights review before a dependency enters the project.",
      relatedHref: "html/dependency-review-readiness.html"
    });
  }
  if (hasReviewGate && !hasPrDiff) {
    riskQueue.push({
      priority: "medium",
      action: "Tie dependency review to pull-request base/head comparison and snapshot warning handling.",
      why: "Dependency-review-action and OSV review are most useful when the reviewed dependency diff is explicit and snapshot warning behavior is visible.",
      relatedHref: "html/dependency-review-readiness.html"
    });
  }
  if (hasReviewGate && !hasPackagePolicy) {
    riskQueue.push({
      priority: "medium",
      action: "Document package deny, allow, ignore, group, registry, or ecosystem-directory policy.",
      why: "Package policy helps reviewers separate intentional exceptions from unreviewed dependency additions.",
      relatedHref: "html/dependency-review-readiness.html"
    });
  }
  if (hasReviewGate && !hasOutput) {
    riskQueue.push({
      priority: "low",
      action: "Persist dependency review summaries, PR comments, SARIF, JSON, HTML, Markdown, or artifacts.",
      why: "Dependency review output should remain inspectable after CI finishes so learners can trace why a dependency change passed or failed.",
      relatedHref: "html/dependency-review-readiness.html"
    });
  }
  riskQueue.push({
    priority: "low",
    action: "Run Dependency Review, Dependabot, OSV Scanner, GitHub API, registry, deps.dev, and remediation commands only in an authorized local or CI environment.",
    why: "RepoTutor records static dependency-review readiness only and never calls GitHub APIs, OSV.dev, deps.dev, registries, creates pull requests, or runs actions.",
    relatedHref: "html/dependency-review-readiness.html"
  });

  return {
    summary: `Dependency review readiness report: setup ${dependencyReviewSetups.length}개, review signal ${reviewSignals.length}개, vulnerability signal ${vulnerabilitySignals.length}개, license signal ${licenseSignals.length}개, package policy signal ${packagePolicySignals.length}개를 정적 분석으로 정리했습니다.`,
    sourcePattern: "Dependency Review readiness actions/dependency-review-action fail-on-severity vulnerability-check license-check allow-licenses deny-licenses allow-dependencies-licenses deny-packages base-ref head-ref snapshot warnings OpenSSF scorecard Dependabot OSV Scanner lockfile license offline remediation PR summary artifact SARIF JSON HTML",
    dependencyReviewSetups,
    reviewSignals,
    vulnerabilitySignals,
    licenseSignals,
    packagePolicySignals,
    ciSignals,
    scorecardSignals,
    outputSignals,
    packageSignals,
    riskQueue: riskQueue.sort((a, b) => ({ high: 0, medium: 1, low: 2 }[a.priority] - { high: 0, medium: 1, low: 2 }[b.priority])),
    recommendedCommands: [
      { command: "rg \"actions/dependency-review-action|fail-on-severity|license-check|vulnerability-check|base-ref|head-ref|comment-summary-in-pr|retry-on-snapshot-warnings\" .github .", purpose: "Find Dependency Review Action gate, PR diff, vulnerability, license, summary, and snapshot-warning policy." },
      { command: "rg \"allow-licenses|deny-licenses|allow-dependencies-licenses|deny-packages|SPDX|purl\" .github .", purpose: "Find license and package policy evidence used during dependency review." },
      { command: "rg \"osv-scanner|--licenses|--offline|--download-offline-databases|--allow-no-lockfiles|--format|--json|--sarif|--min-severity|--ignore-dev\" .", purpose: "Find OSV Scanner vulnerability, license, offline, output, and guided-remediation readiness." },
      { command: "rg \"dependabot.yml|package-ecosystem|directory|schedule|groups|ignore|allow|registries|open-pull-requests-limit|security-updates\" .github .", purpose: "Find Dependabot ecosystem, directory, grouping, ignore, registry, and security-update policy." },
      { command: "rg \"permissions:|contents: read|pull-requests: write|security-events: write|upload-artifact|summary\" .github .", purpose: "Find CI permissions, PR comment/summary, SARIF, and artifact retention evidence." }
    ],
    learnerNextSteps: [
      "Open Dependency Review Readiness and verify the PR dependency diff gate before reading broader update automation.",
      "Check vulnerability severity, license allow/deny, and package policy together; one gate without the others leaves review gaps.",
      "Use OSV Scanner and Dependabot signals as complementary evidence, not proof that external databases or registries were queried.",
      "Treat all GitHub API, registry, dependency review, OSV, and remediation commands as external execution; RepoTutor only records static readiness."
    ]
  };
}

type DependencyReviewSourceFile = {
  filePath: string;
  text: string;
  sourceHref: string;
};

async function dependencyReviewSourceFiles(walk: WalkResult): Promise<DependencyReviewSourceFile[]> {
  const files: DependencyReviewSourceFile[] = [];
  for (const file of walk.files) {
    if (!file.isTextCandidate || !dependencyReviewInspectablePath(file.relPath)) continue;
    const text = await readTextIfSafe(file.absPath, 200_000);
    if (!text) continue;
    if (!dependencyReviewPathSignal(file.relPath) && !dependencyReviewContentSignal(text)) continue;
    files.push({ filePath: file.relPath, text, sourceHref: `source/${encodedPath(file.relPath)}` });
    if (files.length >= 240) break;
  }
  return files;
}

function dependencyReviewInspectablePath(filePath: string): boolean {
  const base = path.basename(filePath);
  return dependencyReviewPathSignal(filePath)
    || /(^|\/)(README|docs?|security|polic(y|ies)|compliance|risk|scripts?|workflows?)(\/|\.|-|_|$)/i.test(filePath)
    || /^(package\.json|osv-scanner\.toml|dependabot\.ya?ml|Makefile|Taskfile\.ya?ml|justfile)$/i.test(base)
    || filePath.startsWith(".github/workflows/")
    || /\.(json|json5|ya?ml|toml|md)$/i.test(filePath);
}

function dependencyReviewPathSignal(filePath: string): boolean {
  const base = path.basename(filePath);
  return filePath.startsWith(".github/workflows/")
    || filePath === ".github/dependabot.yml"
    || filePath === ".github/dependabot.yaml"
    || /dependency[-_ ]?review|dependabot|osv[-_ ]?scanner|osv-scanner|dependency[-_ ]?graph|dependency[-_ ]?submission|license[-_ ]?policy|security[-_ ]?update/i.test(filePath)
    || /^(osv-scanner\.toml|dependabot\.ya?ml)$/i.test(base);
}

function dependencyReviewContentSignal(text: string): boolean {
  return /(actions\/dependency-review-action|dependency review|Dependency Review|fail-on-severity|vulnerability-check|license-check|allow-licenses|deny-licenses|allow-dependencies-licenses|deny-packages|base-ref|head-ref|comment-summary-in-pr|retry-on-snapshot-warnings|show-openssf-scorecard|warn-on-openssf-scorecard-level|dependency graph|dependency submission|osv-scanner|OSV Scanner|--licenses|--offline|--download-offline-databases|--allow-no-lockfiles|--min-severity|--ignore-dev|package-ecosystem|open-pull-requests-limit|security-updates)/i.test(text);
}

function dependencyReviewSetupsFromSources(sourceFiles: DependencyReviewSourceFile[]): DependencyReviewReadinessReport["dependencyReviewSetups"] {
  const rows: DependencyReviewReadinessReport["dependencyReviewSetups"] = [];
  for (const source of sourceFiles) {
    const reviewCount = countMatches(source.text, /(actions\/dependency-review-action|dependency review|Dependency Review|dependency graph|dependency submission|comment-summary-in-pr|pull_request)/gi);
    const vulnerabilityCount = countMatches(source.text, /(fail-on-severity|vulnerability-check|osv-scanner|--min-severity|--ignore-dev|security advisory|vulnerabilit|GHSA|CVE)/gi);
    const licenseCount = countMatches(source.text, /(license-check|allow-licenses|deny-licenses|allow-dependencies-licenses|--licenses|SPDX|license scan|license policy)/gi);
    const packagePolicyCount = countMatches(source.text, /(deny-packages|allowlist|allow:|ignore:|groups:|security-updates|package-ecosystem|directory:|registries:|open-pull-requests-limit|purl)/gi);
    const diffCount = countMatches(source.text, /(base-ref|head-ref|base sha|head sha|base\/head|compare|pull_request|dependency diff)/gi);
    const snapshotCount = countMatches(source.text, /(snapshot warning|snapshot warnings|retry-on-snapshot-warnings|retry-on-snapshot-warnings-timeout|dependency graph snapshot)/gi);
    const scorecardCount = countMatches(source.text, /(show-openssf-scorecard|warn-on-openssf-scorecard-level|OpenSSF Scorecard|scorecard)/gi);
    const outputCount = countMatches(source.text, /(summary|GITHUB_STEP_SUMMARY|comment-summary-in-pr|pr comment|sarif|json|html|markdown|upload-artifact|artifact)/gi);
    const ciCount = countMatches(source.text, /(github actions|\.github\/workflows|pull_request|schedule:|cron:|permissions:|contents: read|pull-requests: write|security-events: write|actions\/checkout|upload-artifact)/gi);
    const totalSignals = reviewCount + vulnerabilityCount + licenseCount + packagePolicyCount + diffCount + snapshotCount + scorecardCount + outputCount + ciCount;
    if (totalSignals === 0 && !dependencyReviewPathSignal(source.filePath)) continue;
    rows.push({
      filePath: source.filePath,
      tool: dependencyReviewTool(source),
      reviewCount,
      vulnerabilityCount,
      licenseCount,
      packagePolicyCount,
      diffCount,
      snapshotCount,
      scorecardCount,
      outputCount,
      ciCount,
      readiness: totalSignals >= 6 ? "ready" : totalSignals > 0 ? "partial" : "missing",
      evidence: `${totalSignals} dependency-review readiness signal(s) detected in this file.`,
      sourceHref: source.sourceHref
    });
  }
  return rows.sort((a, b) => {
    const bScore = b.reviewCount + b.vulnerabilityCount + b.licenseCount + b.packagePolicyCount + b.diffCount + b.snapshotCount + b.outputCount + b.ciCount;
    const aScore = a.reviewCount + a.vulnerabilityCount + a.licenseCount + a.packagePolicyCount + a.diffCount + a.snapshotCount + a.outputCount + a.ciCount;
    return bScore - aScore || a.filePath.localeCompare(b.filePath);
  }).slice(0, 60);
}

function dependencyReviewTool(source: DependencyReviewSourceFile): DependencyReviewReadinessReport["dependencyReviewSetups"][number]["tool"] {
  if (/package\.json$/i.test(source.filePath) || /scripts?["']?\s*:/.test(source.text)) return "package-script";
  if (/\.github\/dependabot\.ya?ml$/i.test(source.filePath) || /dependabot/i.test(source.filePath) || /package-ecosystem|open-pull-requests-limit|security-updates/i.test(source.text)) return "dependabot";
  if (/osv[-_ ]?scanner|osv-scanner/i.test(source.filePath) || /osv-scanner|--download-offline-databases|--allow-no-lockfiles/i.test(source.text)) return "osv-scanner";
  if (/actions\/dependency-review-action|dependency-review-action/i.test(source.text) || /dependency[-_ ]?review/i.test(source.filePath)) return "dependency-review-action";
  if (/\.github\/workflows/i.test(source.filePath)) return "github-actions";
  if (/README|docs?/i.test(source.filePath)) return "readme";
  return "unknown";
}

function dependencyReviewReviewSignals(sourceFiles: DependencyReviewSourceFile[]): DependencyReviewReadinessReport["reviewSignals"] {
  return dependencyReviewSignalFromSpecs(sourceFiles, [
    { signal: "dependency-review-action", pattern: /actions\/dependency-review-action|dependency-review-action/i, evidence: "Dependency Review Action evidence was detected." },
    { signal: "dependency-graph", pattern: /dependency graph|dependency-graph|graph\/snapshots|dependencyGraph/i, evidence: "Dependency graph evidence was detected." },
    { signal: "dependency-submission", pattern: /dependency submission|dependency-submission|dependency-submission-action/i, evidence: "Dependency submission evidence was detected." },
    { signal: "base-head-compare", pattern: /base-ref|head-ref|base sha|head sha|base\/head|compare/i, evidence: "base/head comparison evidence was detected." },
    { signal: "snapshot-warning", pattern: /snapshot warning|snapshot warnings|retry-on-snapshot-warnings|dependency graph snapshot/i, evidence: "snapshot warning evidence was detected." },
    { signal: "pr-summary", pattern: /comment-summary-in-pr|pull request summary|PR summary|GITHUB_STEP_SUMMARY/i, evidence: "PR summary evidence was detected." },
    { signal: "pull-request", pattern: /pull_request|pull request|merge_request/i, evidence: "pull-request trigger evidence was detected." }
  ], "review");
}

function dependencyReviewVulnerabilitySignals(sourceFiles: DependencyReviewSourceFile[]): DependencyReviewReadinessReport["vulnerabilitySignals"] {
  return dependencyReviewSignalFromSpecs(sourceFiles, [
    { signal: "fail-on-severity", pattern: /fail-on-severity/i, evidence: "fail-on-severity evidence was detected." },
    { signal: "vulnerability-check", pattern: /vulnerability-check|vulnerability check/i, evidence: "vulnerability-check evidence was detected." },
    { signal: "osv-scanner", pattern: /osv-scanner|OSV Scanner/i, evidence: "OSV Scanner evidence was detected." },
    { signal: "lockfile-scan", pattern: /lockfile|package-lock|pnpm-lock|yarn\.lock|go\.sum|Gemfile\.lock|scan source/i, evidence: "lockfile scan evidence was detected." },
    { signal: "min-severity", pattern: /--min-severity|min_severity|min-severity/i, evidence: "minimum severity evidence was detected." },
    { signal: "ignore-dev", pattern: /--ignore-dev|ignore dev|dev dependency/i, evidence: "dev dependency filtering evidence was detected." },
    { signal: "offline-db", pattern: /--offline|--offline-vulnerabilities|--download-offline-databases|offline database/i, evidence: "offline vulnerability database evidence was detected." }
  ], "vulnerability");
}

function dependencyReviewLicenseSignals(sourceFiles: DependencyReviewSourceFile[]): DependencyReviewReadinessReport["licenseSignals"] {
  return dependencyReviewSignalFromSpecs(sourceFiles, [
    { signal: "license-check", pattern: /license-check|license check/i, evidence: "license-check evidence was detected." },
    { signal: "allow-licenses", pattern: /allow-licenses|allowed licenses/i, evidence: "allowed license evidence was detected." },
    { signal: "deny-licenses", pattern: /deny-licenses|denied licenses/i, evidence: "denied license evidence was detected." },
    { signal: "allow-dependencies-licenses", pattern: /allow-dependencies-licenses/i, evidence: "dependency-specific license exception evidence was detected." },
    { signal: "license-scan", pattern: /--licenses|license scan|license scanning/i, evidence: "license scan evidence was detected." },
    { signal: "spdx", pattern: /SPDX|spdx|Apache-2\.0|MIT|GPL|LGPL|AGPL/i, evidence: "SPDX/license identifier evidence was detected." }
  ], "license");
}

function dependencyReviewPackagePolicySignals(sourceFiles: DependencyReviewSourceFile[]): DependencyReviewReadinessReport["packagePolicySignals"] {
  return dependencyReviewSignalFromSpecs(sourceFiles, [
    { signal: "deny-packages", pattern: /deny-packages|denied packages|blocked packages/i, evidence: "denied package evidence was detected." },
    { signal: "allowlist", pattern: /allowlist|allow-list|allow:\s|allowed dependencies|allow-dependencies/i, evidence: "allowlist evidence was detected." },
    { signal: "ignore", pattern: /ignore:|ignored-vulns|ignored vulnerabilities|ignore conditions|ignoredUpdates/i, evidence: "ignore policy evidence was detected." },
    { signal: "groups", pattern: /groups:|dependency group|groupName|grouped dependencies/i, evidence: "dependency grouping evidence was detected." },
    { signal: "security-updates", pattern: /security-updates|security updates|security update/i, evidence: "security update evidence was detected." },
    { signal: "ecosystem-directory", pattern: /package-ecosystem|directory:|directories:/i, evidence: "ecosystem directory evidence was detected." },
    { signal: "registries", pattern: /registries:|registry-url|registry url|private registry|npmrc|index-url/i, evidence: "registry policy evidence was detected." }
  ], "package policy");
}

function dependencyReviewCiSignals(sourceFiles: DependencyReviewSourceFile[]): DependencyReviewReadinessReport["ciSignals"] {
  return dependencyReviewSignalFromSpecs(sourceFiles, [
    { signal: "github-actions", pattern: /\.github\/workflows|github actions|actions\/checkout/i, evidence: "GitHub Actions evidence was detected." },
    { signal: "pull-request", pattern: /pull_request|merge_request|pull request/i, evidence: "pull-request evidence was detected." },
    { signal: "permissions", pattern: /permissions:|contents: read|pull-requests: write|security-events: write|actions: read/i, evidence: "workflow permissions evidence was detected." },
    { signal: "artifact-upload", pattern: /upload-artifact|actions\/upload-artifact|artifact upload/i, evidence: "artifact upload evidence was detected." },
    { signal: "summary-comment", pattern: /GITHUB_STEP_SUMMARY|comment-summary-in-pr|pull-requests: write|pr comment/i, evidence: "summary or comment evidence was detected." },
    { signal: "scheduled-run", pattern: /schedule:|cron:|scheduled/i, evidence: "scheduled run evidence was detected." }
  ], "CI");
}

function dependencyReviewScorecardSignals(sourceFiles: DependencyReviewSourceFile[]): DependencyReviewReadinessReport["scorecardSignals"] {
  return dependencyReviewSignalFromSpecs(sourceFiles, [
    { signal: "show-openssf-scorecard", pattern: /show-openssf-scorecard/i, evidence: "show-openssf-scorecard evidence was detected." },
    { signal: "warn-on-openssf-scorecard-level", pattern: /warn-on-openssf-scorecard-level/i, evidence: "OpenSSF warning-level evidence was detected." },
    { signal: "scorecard-api", pattern: /scorecard api|OpenSSF Scorecard|openssf scorecard|scorecard/i, evidence: "OpenSSF Scorecard evidence was detected." }
  ], "scorecard");
}

function dependencyReviewOutputSignals(sourceFiles: DependencyReviewSourceFile[]): DependencyReviewReadinessReport["outputSignals"] {
  return dependencyReviewSignalFromSpecs(sourceFiles, [
    { signal: "summary", pattern: /summary|GITHUB_STEP_SUMMARY|Dependency Review summary/i, evidence: "summary output evidence was detected." },
    { signal: "pr-comment", pattern: /comment-summary-in-pr|pr comment|pull request comment|pull-requests: write/i, evidence: "PR comment evidence was detected." },
    { signal: "sarif", pattern: /sarif|security-events: write|upload-sarif/i, evidence: "SARIF output evidence was detected." },
    { signal: "json", pattern: /\.json\b|--json|format=json|json report/i, evidence: "JSON output evidence was detected." },
    { signal: "html", pattern: /\.html\b|--format=html|format html|html report/i, evidence: "HTML output evidence was detected." },
    { signal: "markdown", pattern: /markdown|\.md\b|format markdown/i, evidence: "Markdown output evidence was detected." },
    { signal: "artifact-upload", pattern: /upload-artifact|actions\/upload-artifact|artifact/i, evidence: "artifact output evidence was detected." }
  ], "output");
}

function dependencyReviewPackageSignals(sourceFiles: DependencyReviewSourceFile[]): DependencyReviewReadinessReport["packageSignals"] {
  return dependencyReviewSignalFromSpecs(sourceFiles, [
    { signal: "dependency-review-action", pattern: /actions\/dependency-review-action|@actions\/dependency-review-action/i, evidence: "Dependency Review Action package/tool evidence was detected." },
    { signal: "dependabot", pattern: /dependabot|package-ecosystem|open-pull-requests-limit/i, evidence: "Dependabot evidence was detected." },
    { signal: "osv-scanner", pattern: /osv-scanner|OSV Scanner/i, evidence: "OSV Scanner package/tool evidence was detected." },
    { signal: "github-action", pattern: /uses:\s*actions\/|github action|\.github\/workflows/i, evidence: "GitHub Action evidence was detected." }
  ], "package");
}

function dependencyReviewSignalFromSpecs<const T extends readonly { signal: string; pattern: RegExp; evidence: string }[]>(
  sourceFiles: DependencyReviewSourceFile[],
  specs: T,
  label: string
): Array<{ signal: T[number]["signal"]; readiness: "ready" | "missing" | "external"; evidence: string; relatedHref: string }> {
  return specs.map((spec) => {
    const match = sourceFiles.find((source) => spec.pattern.test(source.filePath) || spec.pattern.test(source.text));
    return {
      signal: spec.signal,
      readiness: match ? "ready" : sourceFiles.length > 0 ? "external" : "missing",
      evidence: match ? `${match.filePath} ${spec.evidence}` : `${label} ${spec.signal} evidence was not detected.`,
      relatedHref: match?.sourceHref ?? "html/dependency-review-readiness.html"
    };
  });
}

async function buildLintReadinessReport(walk: WalkResult): Promise<LintReadinessReport> {
  const sourceFiles = await lintReadinessSourceFiles(walk);
  const configFiles = lintReadinessConfigFiles(sourceFiles);
  const ruleSignals = lintReadinessRuleSignals(sourceFiles);
  const scriptSignals = lintReadinessScriptSignals(sourceFiles);
  const scopeSignals = lintReadinessScopeSignals(sourceFiles);
  const outputSignals = lintReadinessOutputSignals(sourceFiles);
  const packageSignals = lintReadinessPackageSignals(sourceFiles);

  const hasConfig = configFiles.length > 0;
  const hasLintScript = scriptSignals.some((item) => item.signal === "lint" && item.readiness === "ready");
  const hasRules = ruleSignals.some((item) => item.signal === "rules" && item.readiness === "ready");
  const hasIgnores = ruleSignals.some((item) => item.signal === "ignores" && item.readiness === "ready");
  const hasTypeScript = scopeSignals.some((item) => item.signal === "typescript" && item.readiness === "ready")
    || packageSignals.some((item) => item.signal === "typescript-eslint" && item.readiness === "ready");
  const hasParser = ruleSignals.some((item) => item.signal === "parser" && item.readiness === "ready");
  const hasMaxWarnings = scriptSignals.some((item) => item.signal === "max-warnings" && item.readiness === "ready");
  const hasUnusedDisable = outputSignals.some((item) => item.signal === "report-unused-disable" && item.readiness === "ready");

  const riskQueue: LintReadinessReport["riskQueue"] = [];
  if (!hasConfig && !hasLintScript) {
    riskQueue.push({
      priority: "medium",
      action: "Add a lint config or package script so learners can find the lint boundary.",
      why: "ESLint-style readiness starts from eslint.config.*, package scripts, and ignore rules that define what is checked.",
      relatedHref: "html/lint-readiness.html"
    });
  }
  if (hasLintScript && !hasConfig) {
    riskQueue.push({
      priority: "high",
      action: "Add the lint configuration referenced by the lint script.",
      why: "A lint script without an inspectable config hides rule severity, parser, plugin, globals, and ignore policy.",
      relatedHref: "html/lint-readiness.html"
    });
  }
  if (hasConfig && !hasRules) {
    riskQueue.push({
      priority: "medium",
      action: "Document explicit rules or an extends/recommended preset.",
      why: "ESLint rule severity is the learner-facing contract for which patterns fail CI.",
      relatedHref: "html/lint-readiness.html"
    });
  }
  if (hasConfig && !hasIgnores) {
    riskQueue.push({
      priority: "low",
      action: "Review ignore patterns for generated files, build output, and vendored code.",
      why: "Flat config and ignore files decide whether lint output is meaningful or noisy.",
      relatedHref: "html/lint-readiness.html"
    });
  }
  if (hasTypeScript && !hasParser) {
    riskQueue.push({
      priority: "medium",
      action: "Confirm TypeScript parser and typed linting boundaries.",
      why: "TypeScript linting often needs parser/plugin configuration and may need separate type-aware commands.",
      relatedHref: "html/lint-readiness.html"
    });
  }
  if (hasLintScript && !hasMaxWarnings) {
    riskQueue.push({
      priority: "low",
      action: "Consider --max-warnings=0 for CI lint scripts.",
      why: "Warnings otherwise may hide policy drift while still passing automation.",
      relatedHref: "html/lint-readiness.html"
    });
  }
  if (hasConfig && !hasUnusedDisable) {
    riskQueue.push({
      priority: "low",
      action: "Consider reporting unused eslint-disable directives.",
      why: "Unused suppression comments can keep stale exceptions alive after code changes.",
      relatedHref: "html/lint-readiness.html"
    });
  }
  riskQueue.push({
    priority: "low",
    action: "Run lint commands in a trusted workspace before treating this static report as approval.",
    why: "RepoTutor records lint readiness statically; it does not execute ESLint, autofix files, or resolve parser/plugin packages.",
    relatedHref: "html/lint-readiness.html"
  });

  return {
    summary: `ESLint식 lint readiness report: config file ${configFiles.length}개, rule signal ${ruleSignals.length}개, script signal ${scriptSignals.length}개, package signal ${packageSignals.length}개를 정적 분석으로 정리했습니다.`,
    sourcePattern: "ESLint flat config rules plugins parser ignores fix cache max-warnings report-unused-disable-directives print-config inspect-config",
    configFiles,
    ruleSignals,
    scriptSignals,
    scopeSignals,
    outputSignals,
    packageSignals,
    riskQueue: riskQueue.sort((a, b) => ({ high: 0, medium: 1, low: 2 }[a.priority] - { high: 0, medium: 1, low: 2 }[b.priority])),
    recommendedCommands: [
      { command: "npx eslint .", purpose: "Run the configured lint check in a trusted workspace." },
      { command: "npx eslint . --fix-dry-run", purpose: "Preview autofixable problems without writing files." },
      { command: "npx eslint . --max-warnings=0", purpose: "Make warning drift fail CI during readiness checks." },
      { command: "npx eslint --print-config <file>", purpose: "Inspect the resolved config for one representative file." },
      { command: "npx eslint --inspect-config", purpose: "Open ESLint's config inspector when flat config resolution is unclear." },
      { command: "npx eslint . --cache --cache-location .eslintcache", purpose: "Validate cache behavior while keeping cache files explicit." }
    ],
    learnerNextSteps: [
      "Start with eslint.config.* or package.json scripts to learn which files are checked and which command CI should run.",
      "Then inspect rules, extends, plugins, parser, globals, and ignores to understand the actual lint contract.",
      "Check TypeScript and JSX scopes separately because parser/plugin setup can differ from plain JavaScript linting.",
      "RepoTutor does not run ESLint or apply fixes; use this page as a static map before executing lint commands yourself."
    ]
  };
}

type LintReadinessSourceFile = {
  filePath: string;
  text: string;
  sourceHref: string;
};

async function lintReadinessSourceFiles(walk: WalkResult): Promise<LintReadinessSourceFile[]> {
  const files: LintReadinessSourceFile[] = [];
  for (const file of walk.files) {
    if (!file.isTextCandidate || !lintReadinessInspectablePath(file.relPath)) continue;
    const text = await readTextIfSafe(file.absPath, 200_000);
    if (!text) continue;
    if (!lintReadinessPathSignal(file.relPath) && !lintReadinessContentSignal(text)) continue;
    files.push({ filePath: file.relPath, text, sourceHref: `source/${encodedPath(file.relPath)}` });
    if (files.length >= 240) break;
  }
  return files;
}

function lintReadinessInspectablePath(filePath: string): boolean {
  const base = path.basename(filePath);
  return lintReadinessPathSignal(filePath)
    || /^(package\.json|tsconfig\.json|jsconfig\.json|\.eslintignore|\.gitignore)$/i.test(base)
    || filePath.startsWith(".github/workflows/")
    || /\.(js|cjs|mjs|ts|tsx|jsx|json|ya?ml|toml|md)$/i.test(filePath);
}

function lintReadinessPathSignal(filePath: string): boolean {
  const base = path.basename(filePath);
  return /^(eslint\.config\.[cm]?[jt]s|\.eslintrc|\.eslintrc\.(json|ya?ml|js|cjs)|biome\.json|biome\.jsonc|\.oxlintrc\.json|standard\.json|package\.json)$/i.test(base)
    || /eslint|lint|biome|oxlint|standard/i.test(filePath);
}

function lintReadinessContentSignal(text: string): boolean {
  return /eslint|biome|oxlint|standard|defineConfig|rules\s*:|plugins\s*:|parser\s*:|languageOptions|globalIgnores|includeIgnoreFile|max-warnings|fix-dry-run|report-unused-disable/i.test(text);
}

function lintReadinessConfigFiles(sourceFiles: LintReadinessSourceFile[]): LintReadinessReport["configFiles"] {
  return sourceFiles
    .filter((source) => lintReadinessConfigPathSignal(source.filePath, source.text))
    .slice(0, 80)
    .map((source) => {
      const configType = lintReadinessConfigType(source.filePath, source.text);
      const flatConfig = /eslint\.config\.[cm]?[jt]s$/i.test(source.filePath) || /defineConfig|globalIgnores|languageOptions/i.test(source.text);
      const ruleCount = countMatches(source.text, /rules\s*:|["'][A-Za-z0-9@/_-]+\/?[A-Za-z0-9_-]+["']\s*:/g);
      const pluginCount = countMatches(source.text, /plugins\s*:|eslint-plugin|@typescript-eslint|plugin:/g);
      const ignoreCount = countMatches(source.text, /ignores\s*:|ignorePatterns|globalIgnores|includeIgnoreFile|\.eslintignore|ignore-pattern/g);
      const parserSignal = lintReadinessParserSignal(source.text);
      return {
        filePath: source.filePath,
        configType,
        flatConfig,
        ruleCount,
        pluginCount,
        ignoreCount,
        parserSignal,
        readiness: ruleCount > 0 || pluginCount > 0 || ignoreCount > 0 || parserSignal !== "missing" ? "ready" : "partial",
        evidence: `${source.filePath} contains ${configType} lint config with ${ruleCount} rule signal(s), ${pluginCount} plugin signal(s), and ${ignoreCount} ignore signal(s).`,
        sourceHref: source.sourceHref
      };
    });
}

function lintReadinessConfigPathSignal(filePath: string, text: string): boolean {
  const base = path.basename(filePath);
  return /^(eslint\.config\.[cm]?[jt]s|\.eslintrc|\.eslintrc\.(json|ya?ml|js|cjs)|biome\.json|biome\.jsonc|\.oxlintrc\.json|standard\.json)$/i.test(base)
    || (base === "package.json" && /"eslintConfig"\s*:|"standard"\s*:|"scripts"\s*:[\s\S]*"lint"/i.test(text));
}

function lintReadinessConfigType(filePath: string, text: string): LintReadinessReport["configFiles"][number]["configType"] {
  const base = path.basename(filePath).toLowerCase();
  if (/eslint|\.eslintrc/.test(base) || /eslintConfig|eslint-plugin|defineConfig/i.test(text)) return "eslint";
  if (/biome/.test(base) || /biome\s+check/i.test(text)) return "biome";
  if (/oxlint|\.oxlintrc/.test(base) || /oxlint/i.test(text)) return "oxlint";
  if (/standard/.test(base) || /standard/i.test(text)) return "standard";
  if (base === "package.json") return "package-json";
  return "unknown";
}

function lintReadinessParserSignal(text: string): LintReadinessReport["configFiles"][number]["parserSignal"] {
  if (/@typescript-eslint\/parser|typescript-eslint|tsParser/i.test(text)) return "typescript";
  if (/@babel\/eslint-parser|babel-eslint/i.test(text)) return "babel";
  if (/parser\s*:|languageOptions\s*:[\s\S]*parser/i.test(text)) return "custom";
  if (/eslint|defineConfig|rules\s*:/i.test(text)) return "default";
  return "missing";
}

function lintReadinessRuleSignals(sourceFiles: LintReadinessSourceFile[]): LintReadinessReport["ruleSignals"] {
  const specs: Array<{ signal: LintReadinessReport["ruleSignals"][number]["signal"]; pattern: RegExp; evidence: string }> = [
    { signal: "rules", pattern: /rules\s*:/i, evidence: "rule map evidence was detected." },
    { signal: "extends", pattern: /extends\s*:|eslint:recommended|plugin:|recommended/i, evidence: "extends or recommended preset evidence was detected." },
    { signal: "recommended", pattern: /recommended|eslint:recommended|configs\.recommended/i, evidence: "recommended preset evidence was detected." },
    { signal: "severity", pattern: /"error"|"warn"|"off"|:\s*[012]\b/i, evidence: "rule severity evidence was detected." },
    { signal: "files-overrides", pattern: /files\s*:|overrides\s*:/i, evidence: "file scope or overrides evidence was detected." },
    { signal: "globals", pattern: /globals\s*:|languageOptions|env\s*:/i, evidence: "global variable or language options evidence was detected." },
    { signal: "parser", pattern: /parser\s*:|@typescript-eslint\/parser|@babel\/eslint-parser|languageOptions[\s\S]*parser/i, evidence: "parser evidence was detected." },
    { signal: "plugins", pattern: /plugins\s*:|eslint-plugin|@typescript-eslint/i, evidence: "plugin evidence was detected." },
    { signal: "ignores", pattern: /ignores\s*:|ignorePatterns|globalIgnores|includeIgnoreFile|\.eslintignore/i, evidence: "ignore policy evidence was detected." },
    { signal: "inline-disable", pattern: /eslint-disable|noInlineConfig|inlineConfig/i, evidence: "inline disable policy evidence was detected." },
    { signal: "unused-disable", pattern: /reportUnusedDisableDirectives|unused eslint-disable|report-unused-disable/i, evidence: "unused-disable reporting evidence was detected." }
  ];
  return lintReadinessSignalFromSpecs(sourceFiles, specs, "rule", "signal");
}

function lintReadinessScriptSignals(sourceFiles: LintReadinessSourceFile[]): LintReadinessReport["scriptSignals"] {
  const specs: Array<{ signal: LintReadinessReport["scriptSignals"][number]["signal"]; pattern: RegExp; evidence: string }> = [
    { signal: "lint", pattern: /"lint[^"]*"\s*:|\beslint\b|\bbiome\s+check\b|\boxlint\b|\bstandard\b/i, evidence: "lint script evidence was detected." },
    { signal: "lint-fix", pattern: /lint:fix|--fix\b|fix-dry-run|biome.*--write|oxlint.*--fix/i, evidence: "lint fix script evidence was detected." },
    { signal: "cache", pattern: /--cache\b|cache-location|cache-strategy/i, evidence: "lint cache evidence was detected." },
    { signal: "max-warnings", pattern: /max-warnings|--max-warnings/i, evidence: "max warnings gate evidence was detected." },
    { signal: "format", pattern: /prettier|fmt:|format|biome.*format/i, evidence: "format integration evidence was detected." },
    { signal: "type-aware", pattern: /typescript-eslint|parserOptions|projectService|tsconfig/i, evidence: "type-aware lint evidence was detected." },
    { signal: "ci", pattern: /\.github\/workflows|CI\b|--format|junit|github/i, evidence: "CI lint evidence was detected." },
    { signal: "stdin", pattern: /--stdin|stdin-filename|Lint code provided on <STDIN>/i, evidence: "stdin lint evidence was detected." },
    { signal: "report", pattern: /--format|--output-file|formatter|json|sarif/i, evidence: "lint report output evidence was detected." }
  ];
  return lintReadinessSignalFromSpecs(sourceFiles, specs, "script", "signal");
}

function lintReadinessScopeSignals(sourceFiles: LintReadinessSourceFile[]): LintReadinessReport["scopeSignals"] {
  const specs: Array<{ signal: LintReadinessReport["scopeSignals"][number]["signal"]; pattern: RegExp; evidence: string }> = [
    { signal: "javascript", pattern: /\.m?js\b|\.cjs\b|\*\*\/\*\.js|ECMAScript|JavaScript/i, evidence: "JavaScript lint scope evidence was detected." },
    { signal: "typescript", pattern: /\.tsx?\b|typescript-eslint|tsconfig|TypeScript/i, evidence: "TypeScript lint scope evidence was detected." },
    { signal: "jsx", pattern: /\.jsx\b|\.tsx\b|JSX|react/i, evidence: "JSX lint scope evidence was detected." },
    { signal: "tests", pattern: /tests?\/|\.spec\.|\.test\.|mocha|vitest|jest/i, evidence: "test file lint scope evidence was detected." },
    { signal: "docs", pattern: /docs\/|markdown|lintDocs|mdx/i, evidence: "docs lint scope evidence was detected." },
    { signal: "config-files", pattern: /config|\.ya?ml|\.json|toml/i, evidence: "config-file lint scope evidence was detected." },
    { signal: "generated", pattern: /generated|dist\/|build\/|coverage\/|templates\/|fixtures\//i, evidence: "generated or ignored file scope evidence was detected." }
  ];
  return lintReadinessSignalFromSpecs(sourceFiles, specs, "scope", "signal");
}

function lintReadinessOutputSignals(sourceFiles: LintReadinessSourceFile[]): LintReadinessReport["outputSignals"] {
  const specs: Array<{ signal: LintReadinessReport["outputSignals"][number]["signal"]; pattern: RegExp; evidence: string }> = [
    { signal: "formatter", pattern: /--format|formatter|stylish|json|sarif|junit/i, evidence: "formatter evidence was detected." },
    { signal: "output-file", pattern: /--output-file|outputFile/i, evidence: "output file evidence was detected." },
    { signal: "stats", pattern: /--stats|stats/i, evidence: "stats evidence was detected." },
    { signal: "quiet", pattern: /--quiet|quiet/i, evidence: "quiet mode evidence was detected." },
    { signal: "debug", pattern: /--debug|debug/i, evidence: "debug output evidence was detected." },
    { signal: "report-unused-disable", pattern: /reportUnusedDisableDirectives|report-unused-disable/i, evidence: "unused-disable output evidence was detected." },
    { signal: "suppressions", pattern: /suppressions|suppressAll|suppressRule|pruneSuppressions/i, evidence: "suppression output evidence was detected." }
  ];
  return lintReadinessSignalFromSpecs(sourceFiles, specs, "output", "signal");
}

function lintReadinessPackageSignals(sourceFiles: LintReadinessSourceFile[]): LintReadinessReport["packageSignals"] {
  const specs: Array<{ signal: LintReadinessReport["packageSignals"][number]["signal"]; pattern: RegExp; evidence: string }> = [
    { signal: "eslint", pattern: /"eslint"\s*:|eslint\b/i, evidence: "ESLint package evidence was detected." },
    { signal: "typescript-eslint", pattern: /@typescript-eslint|typescript-eslint/i, evidence: "typescript-eslint package evidence was detected." },
    { signal: "eslint-plugin", pattern: /eslint-plugin|plugins\s*:/i, evidence: "ESLint plugin evidence was detected." },
    { signal: "eslint-config", pattern: /eslint-config|extends\s*:/i, evidence: "ESLint shareable config evidence was detected." },
    { signal: "parser", pattern: /eslint-parser|parser\s*:/i, evidence: "parser package evidence was detected." },
    { signal: "prettier-integration", pattern: /prettier|eslint-config-prettier|eslint-plugin-prettier/i, evidence: "Prettier integration evidence was detected." },
    { signal: "globals", pattern: /"globals"\s*:|globals\b/i, evidence: "globals package or config evidence was detected." }
  ];
  return lintReadinessSignalFromSpecs(sourceFiles, specs, "package", "signal");
}

function lintReadinessSignalFromSpecs<T extends Record<K, string> & { pattern: RegExp; evidence: string }, K extends string>(
  sourceFiles: LintReadinessSourceFile[],
  specs: T[],
  label: string,
  labelKey: K
): Array<Record<K, T[K]> & { readiness: "ready" | "missing" | "external"; evidence: string; relatedHref: string }> {
  return specs.map((spec) => {
    const match = sourceFiles.find((source) => spec.pattern.test(source.filePath) || spec.pattern.test(source.text));
    return {
      [labelKey]: spec[labelKey],
      readiness: match ? "ready" : sourceFiles.length > 0 ? "external" : "missing",
      evidence: match ? `${match.filePath} ${spec.evidence}` : `${label} ${spec[labelKey]} evidence was not detected.`,
      relatedHref: match?.sourceHref ?? "html/lint-readiness.html"
    } as Record<K, T[K]> & { readiness: "ready" | "missing" | "external"; evidence: string; relatedHref: string };
  });
}

async function buildFormatReadinessReport(walk: WalkResult): Promise<FormatReadinessReport> {
  const sourceFiles = await formatReadinessSourceFiles(walk);
  const configFiles = formatReadinessConfigFiles(sourceFiles);
  const ignoreFiles = formatReadinessIgnoreFiles(sourceFiles);
  const optionSignals = formatReadinessOptionSignals(sourceFiles);
  const scriptSignals = formatReadinessScriptSignals(sourceFiles);
  const scopeSignals = formatReadinessScopeSignals(sourceFiles);
  const packageSignals = formatReadinessPackageSignals(sourceFiles);

  const hasConfig = configFiles.length > 0;
  const hasIgnore = ignoreFiles.length > 0;
  const hasFormatScript = scriptSignals.some((item) => item.signal === "format" && item.readiness === "ready");
  const hasCheck = scriptSignals.some((item) => item.signal === "format-check" && item.readiness === "ready");
  const hasWrite = scriptSignals.some((item) => item.signal === "format-write" && item.readiness === "ready");
  const hasPackage = packageSignals.some((item) => item.signal === "prettier" && item.readiness === "ready");
  const hasPlugin = packageSignals.some((item) => item.signal === "prettier-plugin" && item.readiness === "ready")
    || configFiles.some((item) => item.pluginCount > 0);

  const riskQueue: FormatReadinessReport["riskQueue"] = [];
  if (!hasConfig && !hasFormatScript) {
    riskQueue.push({
      priority: "medium",
      action: "Add a Prettier config or package script so learners can find the formatting boundary.",
      why: "Prettier-style readiness starts from .prettierrc, prettier.config.*, package scripts, and ignore rules that define what can be rewritten.",
      relatedHref: "html/format-readiness.html"
    });
  }
  if (hasWrite && !hasIgnore) {
    riskQueue.push({
      priority: "high",
      action: "Add or review .prettierignore before using write-mode formatting.",
      why: "Prettier --write rewrites files in place; ignore files protect generated output, build artifacts, and vendored code.",
      relatedHref: "html/format-readiness.html"
    });
  }
  if ((hasConfig || hasFormatScript) && !hasCheck) {
    riskQueue.push({
      priority: "medium",
      action: "Add a non-writing format check command for CI and learner verification.",
      why: "Prettier --check or --list-different provides a safe readiness gate before any --write workflow.",
      relatedHref: "html/format-readiness.html"
    });
  }
  if ((hasConfig || hasFormatScript) && !hasPackage) {
    riskQueue.push({
      priority: "medium",
      action: "Confirm the formatter package is installed where the script runs.",
      why: "A script or config without package metadata can depend on global tooling or editor-only behavior that RepoTutor cannot verify statically.",
      relatedHref: "html/format-readiness.html"
    });
  }
  if (hasPlugin) {
    riskQueue.push({
      priority: "low",
      action: "Clear or scope the Prettier cache when formatter plugins change.",
      why: "Prettier warns that plugin versions and implementations are not cache keys.",
      relatedHref: "html/format-readiness.html"
    });
  }
  riskQueue.push({
    priority: "low",
    action: "Run format commands in a trusted workspace before treating this static report as approval.",
    why: "RepoTutor records formatter readiness statically; it does not execute Prettier, rewrite files, load plugins, or create cache files.",
    relatedHref: "html/format-readiness.html"
  });

  return {
    summary: `Prettier식 format readiness report: config file ${configFiles.length}개, ignore file ${ignoreFiles.length}개, option signal ${optionSignals.length}개, script signal ${scriptSignals.length}개를 정적 분석으로 정리했습니다.`,
    sourcePattern: "Prettier config ignore options plugins parser check write list-different cache editorconfig file-info find-config-path",
    configFiles,
    ignoreFiles,
    optionSignals,
    scriptSignals,
    scopeSignals,
    packageSignals,
    riskQueue: riskQueue.sort((a, b) => ({ high: 0, medium: 1, low: 2 }[a.priority] - { high: 0, medium: 1, low: 2 }[b.priority])),
    recommendedCommands: [
      { command: "npx prettier . --check", purpose: "Check formatting in a trusted workspace without writing files." },
      { command: "npx prettier . --list-different", purpose: "Print only files that differ from Prettier output for CI handoff." },
      { command: "npx prettier . --write", purpose: "Rewrite supported files only after reviewing config and ignore boundaries." },
      { command: "npx prettier --find-config-path <file>", purpose: "Find the config Prettier would resolve for one representative file." },
      { command: "npx prettier --file-info <file> --ignore-path .prettierignore", purpose: "Check parser inference and ignore handling for one file." },
      { command: "npx prettier . --check --cache --cache-strategy content", purpose: "Validate cached checking while making cache behavior explicit." }
    ],
    learnerNextSteps: [
      "Start with .prettierrc, prettier.config.*, package.json, and .editorconfig to learn which options are shared across CLI and editors.",
      "Then inspect .prettierignore and .gitignore before any write-mode command so generated files are not reformatted.",
      "Use --check or --list-different as the safe CI gate, and keep --write as a deliberate trusted-workspace action.",
      "RepoTutor does not run Prettier or load plugins; use this page as a static map before executing formatter commands yourself."
    ]
  };
}

type FormatReadinessSourceFile = {
  filePath: string;
  text: string;
  sourceHref: string;
};

async function formatReadinessSourceFiles(walk: WalkResult): Promise<FormatReadinessSourceFile[]> {
  const files: FormatReadinessSourceFile[] = [];
  for (const file of walk.files) {
    if (!file.isTextCandidate || !formatReadinessInspectablePath(file.relPath)) continue;
    const text = await readTextIfSafe(file.absPath, 200_000);
    if (!text) continue;
    if (!formatReadinessPathSignal(file.relPath) && !formatReadinessContentSignal(text)) continue;
    files.push({ filePath: file.relPath, text, sourceHref: `source/${encodedPath(file.relPath)}` });
    if (files.length >= 240) break;
  }
  return files;
}

function formatReadinessInspectablePath(filePath: string): boolean {
  const base = path.basename(filePath);
  return formatReadinessPathSignal(filePath)
    || /^(package\.json|\.gitignore|\.editorconfig)$/i.test(base)
    || filePath.startsWith(".github/workflows/")
    || /\.(js|cjs|mjs|ts|tsx|jsx|json|json5|ya?ml|toml|md|css|scss|html|graphql)$/i.test(filePath);
}

function formatReadinessPathSignal(filePath: string): boolean {
  const base = path.basename(filePath);
  return /^(\.prettierrc|\.prettierrc\.(json|json5|ya?ml|toml|js|cjs|mjs|ts|cts|mts)|prettier\.config\.[cm]?[jt]s|\.prettierignore|\.editorconfig|dprint\.json|biome\.json|biome\.jsonc|package\.json)$/i.test(base)
    || /prettier|format|dprint|biome/i.test(filePath);
}

function formatReadinessContentSignal(text: string): boolean {
  return /prettier|\.prettierignore|printWidth|tabWidth|singleQuote|trailingComma|bracketSpacing|endOfLine|list-different|find-config-path|ignore-path|cache-strategy|editorconfig/i.test(text);
}

function formatReadinessConfigFiles(sourceFiles: FormatReadinessSourceFile[]): FormatReadinessReport["configFiles"] {
  return sourceFiles
    .filter((source) => formatReadinessConfigPathSignal(source.filePath, source.text))
    .slice(0, 80)
    .map((source) => {
      const configType = formatReadinessConfigType(source.filePath, source.text);
      const optionCount = countMatches(source.text, /printWidth|tabWidth|useTabs|singleQuote|jsxSingleQuote|trailingComma|semi|bracketSpacing|bracketSameLine|arrowParens|endOfLine|quoteProps|htmlWhitespaceSensitivity/g);
      const overrideCount = countMatches(source.text, /overrides\s*:|files\s*:|excludeFiles/g);
      const pluginCount = countMatches(source.text, /plugins\s*:|prettier-plugin|@prettier\/plugin/g);
      const parserSignal = formatReadinessParserSignal(source.text);
      return {
        filePath: source.filePath,
        configType,
        optionCount,
        overrideCount,
        pluginCount,
        parserSignal,
        readiness: optionCount > 0 || overrideCount > 0 || pluginCount > 0 || parserSignal !== "missing" ? "ready" : "partial",
        evidence: `${source.filePath} contains ${configType} formatter config with ${optionCount} option signal(s), ${overrideCount} override signal(s), and ${pluginCount} plugin signal(s).`,
        sourceHref: source.sourceHref
      };
    });
}

function formatReadinessIgnoreFiles(sourceFiles: FormatReadinessSourceFile[]): FormatReadinessReport["ignoreFiles"] {
  return sourceFiles
    .filter((source) => /^(\.prettierignore|\.gitignore)$/i.test(path.basename(source.filePath)) || /--ignore-path|ignorePath/i.test(source.text))
    .slice(0, 80)
    .map((source) => {
      const patternCount = source.text.split(/\r?\n/).filter((line) => line.trim() && !line.trim().startsWith("#")).length;
      const generatedSignal = /dist|build|coverage|generated|node_modules|vendor|\.cache/i.test(source.text);
      return {
        filePath: source.filePath,
        patternCount,
        generatedSignal,
        readiness: patternCount > 0 ? "ready" : "partial",
        evidence: `${source.filePath} contains ${patternCount} ignore pattern(s)${generatedSignal ? " including generated/build output signals" : ""}.`,
        sourceHref: source.sourceHref
      };
    });
}

function formatReadinessConfigPathSignal(filePath: string, text: string): boolean {
  const base = path.basename(filePath);
  return /^(\.prettierrc|\.prettierrc\.(json|json5|ya?ml|toml|js|cjs|mjs|ts|cts|mts)|prettier\.config\.[cm]?[jt]s|\.editorconfig|dprint\.json|biome\.json|biome\.jsonc)$/i.test(base)
    || (base === "package.json" && /"prettier"\s*:|"scripts"\s*:[\s\S]*("format"|"fmt"|prettier)/i.test(text));
}

function formatReadinessConfigType(filePath: string, text: string): FormatReadinessReport["configFiles"][number]["configType"] {
  const base = path.basename(filePath).toLowerCase();
  if (/prettier|\.prettierrc/.test(base) || /"prettier"\s*:|prettier-plugin|printWidth|tabWidth/i.test(text)) return "prettier";
  if (base === ".editorconfig") return "editorconfig";
  if (/biome/.test(base) || /biome\s+format/i.test(text)) return "biome";
  if (/dprint/.test(base) || /dprint/i.test(text)) return "dprint";
  if (base === "package.json") return "package-json";
  return "unknown";
}

function formatReadinessParserSignal(text: string): FormatReadinessReport["configFiles"][number]["parserSignal"] {
  if (/plugins\s*:|prettier-plugin|@prettier\/plugin/i.test(text)) return "plugin";
  if (/parser\s*:|overrides\s*:[\s\S]*parser/i.test(text)) return "override";
  if (/prettier|printWidth|tabWidth|trailingComma|editorconfig/i.test(text)) return "inferred";
  return "missing";
}

function formatReadinessOptionSignals(sourceFiles: FormatReadinessSourceFile[]): FormatReadinessReport["optionSignals"] {
  const specs: Array<{ signal: FormatReadinessReport["optionSignals"][number]["signal"]; pattern: RegExp; evidence: string }> = [
    { signal: "print-width", pattern: /printWidth|print-width|max_line_length/i, evidence: "print width evidence was detected." },
    { signal: "tab-width", pattern: /tabWidth|tab-width|tab_width|indent_size/i, evidence: "tab width evidence was detected." },
    { signal: "single-quote", pattern: /singleQuote|single-quote|jsxSingleQuote/i, evidence: "quote style evidence was detected." },
    { signal: "trailing-comma", pattern: /trailingComma|trailing-comma/i, evidence: "trailing comma evidence was detected." },
    { signal: "semi", pattern: /\bsemi\b|--no-semi/i, evidence: "semicolon option evidence was detected." },
    { signal: "bracket-spacing", pattern: /bracketSpacing|bracket-spacing|bracketSameLine/i, evidence: "bracket spacing evidence was detected." },
    { signal: "end-of-line", pattern: /endOfLine|end-of-line|end_of_line/i, evidence: "end-of-line evidence was detected." },
    { signal: "parser", pattern: /parser\s*:|--parser|stdin-filepath|file-info/i, evidence: "parser inference or override evidence was detected." },
    { signal: "overrides", pattern: /overrides\s*:|excludeFiles|files\s*:/i, evidence: "override evidence was detected." },
    { signal: "editorconfig", pattern: /\.editorconfig|editorconfig|no-editorconfig/i, evidence: "EditorConfig evidence was detected." }
  ];
  return formatReadinessSignalFromSpecs(sourceFiles, specs, "option", "signal");
}

function formatReadinessScriptSignals(sourceFiles: FormatReadinessSourceFile[]): FormatReadinessReport["scriptSignals"] {
  const specs: Array<{ signal: FormatReadinessReport["scriptSignals"][number]["signal"]; pattern: RegExp; evidence: string }> = [
    { signal: "format", pattern: /"format[^"]*"\s*:|"fmt"\s*:|\bprettier\b|\bdprint\b|\bbiome\s+format\b/i, evidence: "format script evidence was detected." },
    { signal: "format-check", pattern: /--check\b|list-different|biome\s+format[^\n"]*--write\s+false|dprint\s+check/i, evidence: "non-writing format check evidence was detected." },
    { signal: "format-write", pattern: /--write\b|\b-w\b|dprint\s+fmt|biome\s+format[^\n"]*--write/i, evidence: "write-mode format evidence was detected." },
    { signal: "list-different", pattern: /list-different|-l\b/i, evidence: "list-different evidence was detected." },
    { signal: "cache", pattern: /--cache\b|cache-location|cache-strategy|\.prettier-cache/i, evidence: "formatter cache evidence was detected." },
    { signal: "config-path", pattern: /find-config-path|--config\b|--no-config|config-precedence/i, evidence: "config path evidence was detected." },
    { signal: "ignore-path", pattern: /ignore-path|\.prettierignore|ignorePath/i, evidence: "ignore path evidence was detected." },
    { signal: "stdin", pattern: /stdin-filepath|--stdin|file-info/i, evidence: "stdin/file-info evidence was detected." },
    { signal: "ci", pattern: /\.github\/workflows|CI\b|--check|list-different/i, evidence: "CI formatter evidence was detected." }
  ];
  return formatReadinessSignalFromSpecs(sourceFiles, specs, "script", "signal");
}

function formatReadinessScopeSignals(sourceFiles: FormatReadinessSourceFile[]): FormatReadinessReport["scopeSignals"] {
  const specs: Array<{ signal: FormatReadinessReport["scopeSignals"][number]["signal"]; pattern: RegExp; evidence: string }> = [
    { signal: "javascript", pattern: /\.m?js\b|\.cjs\b|JavaScript|babel|estree/i, evidence: "JavaScript format scope evidence was detected." },
    { signal: "typescript", pattern: /\.tsx?\b|TypeScript|typescript-estree|tsconfig/i, evidence: "TypeScript format scope evidence was detected." },
    { signal: "json", pattern: /\.json\b|json5|package\.json/i, evidence: "JSON format scope evidence was detected." },
    { signal: "css", pattern: /\.s?css\b|postcss|css/i, evidence: "CSS format scope evidence was detected." },
    { signal: "html", pattern: /\.html\b|html|angular|vue/i, evidence: "HTML format scope evidence was detected." },
    { signal: "markdown", pattern: /\.md\b|markdown|mdx|remark/i, evidence: "Markdown format scope evidence was detected." },
    { signal: "yaml", pattern: /\.ya?ml\b|yaml/i, evidence: "YAML format scope evidence was detected." },
    { signal: "graphql", pattern: /\.graphql\b|graphql/i, evidence: "GraphQL format scope evidence was detected." }
  ];
  return formatReadinessSignalFromSpecs(sourceFiles, specs, "scope", "signal");
}

function formatReadinessPackageSignals(sourceFiles: FormatReadinessSourceFile[]): FormatReadinessReport["packageSignals"] {
  const specs: Array<{ signal: FormatReadinessReport["packageSignals"][number]["signal"]; pattern: RegExp; evidence: string }> = [
    { signal: "prettier", pattern: /"prettier"\s*:|prettier\b/i, evidence: "Prettier package evidence was detected." },
    { signal: "prettier-plugin", pattern: /prettier-plugin|@prettier\/plugin|plugins\s*:/i, evidence: "Prettier plugin evidence was detected." },
    { signal: "eslint-config-prettier", pattern: /eslint-config-prettier/i, evidence: "ESLint/Prettier conflict-prevention package evidence was detected." },
    { signal: "dprint", pattern: /"dprint"\s*:|dprint\b/i, evidence: "dprint package evidence was detected." },
    { signal: "biome", pattern: /"@biomejs\/biome"\s*:|biome\b/i, evidence: "Biome package evidence was detected." },
    { signal: "editorconfig", pattern: /editorconfig|\.editorconfig/i, evidence: "EditorConfig package or config evidence was detected." }
  ];
  return formatReadinessSignalFromSpecs(sourceFiles, specs, "package", "signal");
}

function formatReadinessSignalFromSpecs<T extends Record<K, string> & { pattern: RegExp; evidence: string }, K extends string>(
  sourceFiles: FormatReadinessSourceFile[],
  specs: T[],
  label: string,
  labelKey: K
): Array<Record<K, T[K]> & { readiness: "ready" | "missing" | "external"; evidence: string; relatedHref: string }> {
  return specs.map((spec) => {
    const match = sourceFiles.find((source) => spec.pattern.test(source.filePath) || spec.pattern.test(source.text));
    return {
      [labelKey]: spec[labelKey],
      readiness: match ? "ready" : sourceFiles.length > 0 ? "external" : "missing",
      evidence: match ? `${match.filePath} ${spec.evidence}` : `${label} ${spec[labelKey]} evidence was not detected.`,
      relatedHref: match?.sourceHref ?? "html/format-readiness.html"
    } as Record<K, T[K]> & { readiness: "ready" | "missing" | "external"; evidence: string; relatedHref: string };
  });
}

async function buildCommitConventionReport(walk: WalkResult): Promise<CommitConventionReport> {
  const sourceFiles = await commitConventionSourceFiles(walk);
  const configFiles = commitConventionConfigFiles(sourceFiles);
  const ruleSignals = commitConventionRuleSignals(sourceFiles);
  const hookSignals = commitConventionHookSignals(sourceFiles);
  const commandSignals = commitConventionCommandSignals(sourceFiles);
  const packageSignals = commitConventionPackageSignals(sourceFiles);

  const hasConfig = configFiles.length > 0;
  const hasHook = hookSignals.some((item) => item.signal === "commit-msg" && item.readiness === "ready");
  const hasCiRange = hookSignals.some((item) => item.signal === "ci-range" && item.readiness === "ready");
  const hasTypeEnum = ruleSignals.some((item) => item.signal === "type-enum" && item.readiness === "ready");
  const hasCli = packageSignals.some((item) => item.signal === "commitlint-cli" && item.readiness === "ready");
  const hasConventional = packageSignals.some((item) => item.signal === "config-conventional" && item.readiness === "ready")
    || configFiles.some((item) => item.parserPreset === "conventional");

  const riskQueue: CommitConventionReport["riskQueue"] = [];
  if (!hasConfig && !hasHook && !hasCiRange) {
    riskQueue.push({
      priority: "medium",
      action: "Add commitlint config, a commit-msg hook, or CI range check so learners can find the commit convention boundary.",
      why: "Commitlint readiness starts from config discovery, rules, and the command surface that checks messages before merge.",
      relatedHref: "html/commit-conventions.html"
    });
  }
  if ((hasHook || hasCiRange) && !hasConfig) {
    riskQueue.push({
      priority: "high",
      action: "Add the commitlint configuration referenced by hooks or CI.",
      why: "A commit-msg hook without visible rules hides type, scope, subject, body, footer, and parser policy.",
      relatedHref: "html/commit-conventions.html"
    });
  }
  if (hasConfig && !hasTypeEnum && !hasConventional) {
    riskQueue.push({
      priority: "medium",
      action: "Define a type-enum rule or extend a conventional commit preset.",
      why: "Commit types are the learner-facing contract for release notes, changelog grouping, and review triage.",
      relatedHref: "html/commit-conventions.html"
    });
  }
  if ((hasConfig || hasHook || hasCiRange) && !hasCli) {
    riskQueue.push({
      priority: "medium",
      action: "Confirm @commitlint/cli is installed where the hook or CI command runs.",
      why: "Global commitlint installs and editor-only integrations are not reproducible from the repository alone.",
      relatedHref: "html/commit-conventions.html"
    });
  }
  if (hasHook && !hasCiRange) {
    riskQueue.push({
      priority: "low",
      action: "Add a CI range check for pull request commits.",
      why: "Local hooks can be bypassed; commitlint --from/--to protects commits that arrive through remote workflows.",
      relatedHref: "html/commit-conventions.html"
    });
  }
  riskQueue.push({
    priority: "low",
    action: "Run commitlint in a trusted workspace before treating this static report as approval.",
    why: "RepoTutor records commit convention readiness statically; it does not inspect private commit history or execute hooks.",
    relatedHref: "html/commit-conventions.html"
  });

  return {
    summary: `commitlint식 commit convention report: config file ${configFiles.length}개, rule signal ${ruleSignals.length}개, hook signal ${hookSignals.length}개, package signal ${packageSignals.length}개를 정적 분석으로 정리했습니다.`,
    sourcePattern: "commitlint config conventional commits rules parserPreset commit-msg husky from to last edit strict verbose prompt",
    configFiles,
    ruleSignals,
    hookSignals,
    commandSignals,
    packageSignals,
    riskQueue: riskQueue.sort((a, b) => ({ high: 0, medium: 1, low: 2 }[a.priority] - { high: 0, medium: 1, low: 2 }[b.priority])),
    recommendedCommands: [
      { command: "npx commitlint --last --verbose", purpose: "Check the latest commit message in a trusted workspace." },
      { command: "npx commitlint --from <base-sha> --to <head-sha> --verbose", purpose: "Check a pull request commit range in CI." },
      { command: "npx commitlint --edit .git/COMMIT_EDITMSG", purpose: "Check the current commit message file from a commit-msg hook." },
      { command: "npx commitlint --print-config", purpose: "Inspect resolved config, extends, parserPreset, and rules." },
      { command: "npx commitlint --strict --last", purpose: "Fail on warnings as well as errors when the policy requires it." },
      { command: "npx commit", purpose: "Use the prompt flow when @commitlint/prompt-cli or commitizen is configured." }
    ],
    learnerNextSteps: [
      "Start with commitlint.config.* or package.json commitlint fields to learn the rules and presets.",
      "Then inspect commit-msg hooks and CI range commands because local hooks can be bypassed.",
      "Check type-enum, scope-enum, subject, body, footer, and breaking-change rules as the actual commit contract.",
      "RepoTutor does not run commitlint or inspect private history; use this page as a static map before executing commit checks yourself."
    ]
  };
}

type CommitConventionSourceFile = {
  filePath: string;
  text: string;
  sourceHref: string;
};

async function commitConventionSourceFiles(walk: WalkResult): Promise<CommitConventionSourceFile[]> {
  const files: CommitConventionSourceFile[] = [];
  for (const file of walk.files) {
    if (!file.isTextCandidate || !commitConventionInspectablePath(file.relPath)) continue;
    const text = await readTextIfSafe(file.absPath, 200_000);
    if (!text) continue;
    if (!commitConventionPathSignal(file.relPath) && !commitConventionContentSignal(text)) continue;
    files.push({ filePath: file.relPath, text, sourceHref: `source/${encodedPath(file.relPath)}` });
    if (files.length >= 240) break;
  }
  return files;
}

function commitConventionInspectablePath(filePath: string): boolean {
  const base = path.basename(filePath);
  return commitConventionPathSignal(filePath)
    || /^(package\.json|\.gitmessage|COMMIT_EDITMSG)$/i.test(base)
    || filePath.startsWith(".github/workflows/")
    || filePath.startsWith(".husky/")
    || /\.(js|cjs|mjs|ts|json|json5|ya?ml|md|sh)$/i.test(filePath);
}

function commitConventionPathSignal(filePath: string): boolean {
  const base = path.basename(filePath);
  return /^(commitlint\.config\.[cm]?[jt]s|\.commitlintrc|\.commitlintrc\.(json|ya?ml|js|cjs|mjs|ts|cts|mts)|package\.json)$/i.test(base)
    || /commitlint|commit-msg|conventional-commit|commitizen|cz-commitlint/i.test(filePath);
}

function commitConventionContentSignal(text: string): boolean {
  return /commitlint|conventional commits?|parserPreset|type-enum|scope-enum|commit-msg|COMMIT_EDITMSG|--from|--to|--last|--edit|@commitlint|commitizen|cz-commitlint/i.test(text);
}

function commitConventionConfigFiles(sourceFiles: CommitConventionSourceFile[]): CommitConventionReport["configFiles"] {
  return sourceFiles
    .filter((source) => commitConventionConfigPathSignal(source.filePath, source.text))
    .slice(0, 80)
    .map((source) => {
      const configType = commitConventionConfigType(source.filePath, source.text);
      const extendsCount = countMatches(source.text, /extends\s*:|@commitlint\/config-|commitlint-config-|config-conventional/g);
      const ruleCount = countMatches(source.text, /rules\s*:|type-enum|scope-enum|subject-|body-|footer-|header-|breaking-/g);
      const parserPreset = commitConventionParserPreset(source.text);
      const promptSignal = /prompt|commitizen|cz-commitlint|@commitlint\/prompt/i.test(source.text);
      return {
        filePath: source.filePath,
        configType,
        extendsCount,
        ruleCount,
        parserPreset,
        promptSignal,
        readiness: extendsCount > 0 || ruleCount > 0 || parserPreset !== "missing" ? "ready" : "partial",
        evidence: `${source.filePath} contains ${configType} commit convention config with ${extendsCount} extends signal(s), ${ruleCount} rule signal(s), and parserPreset ${parserPreset}.`,
        sourceHref: source.sourceHref
      };
    });
}

function commitConventionConfigPathSignal(filePath: string, text: string): boolean {
  const base = path.basename(filePath);
  return /^(commitlint\.config\.[cm]?[jt]s|\.commitlintrc|\.commitlintrc\.(json|ya?ml|js|cjs|mjs|ts|cts|mts))$/i.test(base)
    || (base === "package.json" && /"commitlint"\s*:|"scripts"\s*:[\s\S]*(commitlint|"commit")/i.test(text))
    || (filePath.startsWith(".husky/") && /commitlint/i.test(text));
}

function commitConventionConfigType(filePath: string, text: string): CommitConventionReport["configFiles"][number]["configType"] {
  const base = path.basename(filePath).toLowerCase();
  if (base === "package.json") return "package-json";
  if (filePath.startsWith(".husky/")) return "husky";
  if (/commitlint|\.commitlintrc/.test(base) || /commitlint|parserPreset|type-enum/i.test(text)) return "commitlint";
  return "unknown";
}

function commitConventionParserPreset(text: string): CommitConventionReport["configFiles"][number]["parserPreset"] {
  if (/conventional-changelog-conventionalcommits|config-conventional|conventionalcommits/i.test(text)) return "conventional";
  if (/parserPreset\s*:/i.test(text)) return "custom";
  return "missing";
}

function commitConventionRuleSignals(sourceFiles: CommitConventionSourceFile[]): CommitConventionReport["ruleSignals"] {
  const specs: Array<{ signal: CommitConventionReport["ruleSignals"][number]["signal"]; pattern: RegExp; evidence: string }> = [
    { signal: "type-enum", pattern: /type-enum|@commitlint\/config-conventional|config-conventional|conventional commits?/i, evidence: "type-enum or conventional preset evidence was detected." },
    { signal: "scope-enum", pattern: /scope-enum|scope-case|scope-empty/i, evidence: "scope rule evidence was detected." },
    { signal: "subject-case", pattern: /subject-case|sentence-case|start-case|pascal-case|upper-case/i, evidence: "subject-case evidence was detected." },
    { signal: "subject-empty", pattern: /subject-empty/i, evidence: "subject-empty evidence was detected." },
    { signal: "subject-full-stop", pattern: /subject-full-stop/i, evidence: "subject-full-stop evidence was detected." },
    { signal: "header-max-length", pattern: /header-max-length|header-max/i, evidence: "header length evidence was detected." },
    { signal: "body-leading-blank", pattern: /body-leading-blank/i, evidence: "body leading blank evidence was detected." },
    { signal: "body-max-line-length", pattern: /body-max-line-length/i, evidence: "body max line length evidence was detected." },
    { signal: "footer-leading-blank", pattern: /footer-leading-blank/i, evidence: "footer leading blank evidence was detected." },
    { signal: "footer-max-line-length", pattern: /footer-max-line-length/i, evidence: "footer max line length evidence was detected." },
    { signal: "breaking-change", pattern: /BREAKING CHANGE|breaking-change|breakingBody|breaking/i, evidence: "breaking-change evidence was detected." }
  ];
  return commitConventionSignalFromSpecs(sourceFiles, specs, "rule", "signal");
}

function commitConventionHookSignals(sourceFiles: CommitConventionSourceFile[]): CommitConventionReport["hookSignals"] {
  const specs: Array<{ signal: CommitConventionReport["hookSignals"][number]["signal"]; pattern: RegExp; evidence: string }> = [
    { signal: "commit-msg", pattern: /\.husky\/commit-msg|commit-msg|COMMIT_EDITMSG|--edit/i, evidence: "commit-msg hook evidence was detected." },
    { signal: "husky", pattern: /\.husky|husky|prepare.*husky/i, evidence: "Husky hook install evidence was detected." },
    { signal: "ci-range", pattern: /--from|--to|pull_request|base\.sha|head\.sha/i, evidence: "CI commit range evidence was detected." },
    { signal: "last-commit", pattern: /--last|last commit/i, evidence: "last commit command evidence was detected." },
    { signal: "edit-message", pattern: /--edit|COMMIT_EDITMSG|edit/i, evidence: "commit message file evidence was detected." },
    { signal: "prompt", pattern: /@commitlint\/prompt|prompt-cli|commitizen|cz-commitlint|npm run commit/i, evidence: "commit prompt evidence was detected." },
    { signal: "bypass", pattern: /--no-verify|HUSKY=0|bypass/i, evidence: "hook bypass policy evidence was detected." }
  ];
  return commitConventionSignalFromSpecs(sourceFiles, specs, "hook", "signal");
}

function commitConventionCommandSignals(sourceFiles: CommitConventionSourceFile[]): CommitConventionReport["commandSignals"] {
  const specs: Array<{ signal: CommitConventionReport["commandSignals"][number]["signal"]; pattern: RegExp; evidence: string }> = [
    { signal: "from-to", pattern: /--from|--to/i, evidence: "from/to range command evidence was detected." },
    { signal: "last", pattern: /--last/i, evidence: "last command evidence was detected." },
    { signal: "edit", pattern: /--edit|COMMIT_EDITMSG/i, evidence: "edit command evidence was detected." },
    { signal: "verbose", pattern: /--verbose|verbose/i, evidence: "verbose command evidence was detected." },
    { signal: "strict", pattern: /--strict|strict/i, evidence: "strict command evidence was detected." },
    { signal: "format", pattern: /--format|@commitlint\/format|formatter/i, evidence: "formatter command evidence was detected." },
    { signal: "config", pattern: /--config|print-config|commitlint\.config|\.commitlintrc/i, evidence: "config command evidence was detected." },
    { signal: "help-url", pattern: /help-url|helpUrl/i, evidence: "help URL evidence was detected." }
  ];
  return commitConventionSignalFromSpecs(sourceFiles, specs, "command", "signal");
}

function commitConventionPackageSignals(sourceFiles: CommitConventionSourceFile[]): CommitConventionReport["packageSignals"] {
  const specs: Array<{ signal: CommitConventionReport["packageSignals"][number]["signal"]; pattern: RegExp; evidence: string }> = [
    { signal: "commitlint-cli", pattern: /@commitlint\/cli|commitlint\b/i, evidence: "@commitlint/cli evidence was detected." },
    { signal: "config-conventional", pattern: /@commitlint\/config-conventional|config-conventional|conventional-changelog-conventionalcommits/i, evidence: "conventional config evidence was detected." },
    { signal: "commitizen", pattern: /commitizen|cz-cli/i, evidence: "Commitizen evidence was detected." },
    { signal: "cz-commitlint", pattern: /cz-commitlint|@commitlint\/cz-commitlint/i, evidence: "cz-commitlint evidence was detected." },
    { signal: "husky", pattern: /"husky"\s*:|husky\b|\.husky/i, evidence: "Husky package evidence was detected." },
    { signal: "conventional-changelog", pattern: /conventional-changelog|semantic-release|changesets/i, evidence: "release/changelog integration evidence was detected." }
  ];
  return commitConventionSignalFromSpecs(sourceFiles, specs, "package", "signal");
}

function commitConventionSignalFromSpecs<T extends Record<K, string> & { pattern: RegExp; evidence: string }, K extends string>(
  sourceFiles: CommitConventionSourceFile[],
  specs: T[],
  label: string,
  labelKey: K
): Array<Record<K, T[K]> & { readiness: "ready" | "missing" | "external"; evidence: string; relatedHref: string }> {
  return specs.map((spec) => {
    const match = sourceFiles.find((source) => spec.pattern.test(source.filePath) || spec.pattern.test(source.text));
    return {
      [labelKey]: spec[labelKey],
      readiness: match ? "ready" : sourceFiles.length > 0 ? "external" : "missing",
      evidence: match ? `${match.filePath} ${spec.evidence}` : `${label} ${spec[labelKey]} evidence was not detected.`,
      relatedHref: match?.sourceHref ?? "html/commit-conventions.html"
    } as Record<K, T[K]> & { readiness: "ready" | "missing" | "external"; evidence: string; relatedHref: string };
  });
}

async function buildChangelogReadinessReport(walk: WalkResult): Promise<ChangelogReadinessReport> {
  const sourceFiles = await changelogReadinessSourceFiles(walk);
  const configFiles = changelogReadinessConfigFiles(sourceFiles);
  const changesetFiles = changelogReadinessChangesetFiles(sourceFiles);
  const workflowSignals = changelogReadinessWorkflowSignals(sourceFiles);
  const commandSignals = changelogReadinessCommandSignals(sourceFiles);
  const packageSignals = changelogReadinessPackageSignals(sourceFiles);
  const policySignals = changelogReadinessPolicySignals(sourceFiles);

  const hasConfig = configFiles.some((item) => item.configType === "changeset-config" || item.configType === "package-json");
  const hasChangesets = changesetFiles.length > 0;
  const hasStatus = commandSignals.some((item) => item.signal === "status" && item.readiness === "ready")
    || workflowSignals.some((item) => item.signal === "status-check" && item.readiness === "ready");
  const hasAction = workflowSignals.some((item) => item.signal === "changesets-action" && item.readiness === "ready");
  const hasPublish = commandSignals.some((item) => item.signal === "publish" && item.readiness === "ready")
    || workflowSignals.some((item) => item.signal === "publish" && item.readiness === "ready");
  const hasChangelog = configFiles.some((item) => item.changelogMode !== "missing" && item.changelogMode !== "disabled");
  const hasBaseBranch = configFiles.some((item) => item.baseBranch);
  const hasFollowTags = workflowSignals.some((item) => item.signal === "follow-tags" && item.readiness === "ready");

  const riskQueue: ChangelogReadinessReport["riskQueue"] = [];
  if (!hasConfig && !hasChangesets && !hasStatus && !hasAction) {
    riskQueue.push({
      priority: "medium",
      action: "Add Changesets config, changeset files, or a status/action workflow before treating changelog readiness as present.",
      why: "Changesets readiness starts from explicit release intent files plus the workflow that turns them into versions and changelogs.",
      relatedHref: "html/changelog-readiness.html"
    });
  }
  if (hasChangesets && !hasConfig) {
    riskQueue.push({
      priority: "medium",
      action: "Run changeset init or add `.changeset/config.json` so changeset files have visible release policy.",
      why: "Without config, learners cannot see baseBranch, changelog mode, fixed/linked groups, access, and private package policy.",
      relatedHref: "html/changelog-readiness.html"
    });
  }
  if ((hasConfig || hasChangesets) && !hasStatus && !hasAction) {
    riskQueue.push({
      priority: "medium",
      action: "Add a Changesets bot/action or `changeset status --since=main` CI check for pull requests.",
      why: "Reviewers can miss absent changeset files; a status surface makes release-note intent visible before merge.",
      relatedHref: "html/changelog-readiness.html"
    });
  }
  if (hasPublish && !hasConfig) {
    riskQueue.push({
      priority: "high",
      action: "Do not publish from Changesets automation until config and package access policy are visible.",
      why: "`changeset publish` can create npm releases and git tags; static readiness should show the publishing boundary first.",
      relatedHref: "html/changelog-readiness.html"
    });
  }
  if (hasConfig && !hasChangelog) {
    riskQueue.push({
      priority: "medium",
      action: "Confirm whether changelog generation is intentionally disabled or customize the changelog generator.",
      why: "The report is about release notes; disabled changelog output should be a deliberate product decision.",
      relatedHref: "html/changelog-readiness.html"
    });
  }
  if (hasConfig && !hasBaseBranch) {
    riskQueue.push({
      priority: "low",
      action: "Set or document the Changesets baseBranch used for status and changed-package detection.",
      why: "Wrong base branches make `status --since` and contributor prompts harder to trust.",
      relatedHref: "html/changelog-readiness.html"
    });
  }
  if (hasPublish && !hasFollowTags) {
    riskQueue.push({
      priority: "low",
      action: "Document `git push --follow-tags` or equivalent tag publishing after releases.",
      why: "Changesets publish/tag workflows create git tags that must be pushed if consumers rely on source tags.",
      relatedHref: "html/changelog-readiness.html"
    });
  }
  riskQueue.push({
    priority: "low",
    action: "Run Changesets commands only in a trusted workspace after reviewing this static map.",
    why: "RepoTutor does not create changesets, version packages, publish to npm, create tags, or push release commits.",
    relatedHref: "html/changelog-readiness.html"
  });

  return {
    summary: `Changesets식 changelog readiness report: config file ${configFiles.length}개, changeset file ${changesetFiles.length}개, workflow signal ${workflowSignals.length}개, command signal ${commandSignals.length}개를 정적 분석으로 정리했습니다.`,
    sourcePattern: "Changesets config changeset files changelog version publish status pre snapshot fixed linked private packages",
    configFiles,
    changesetFiles,
    workflowSignals,
    commandSignals,
    packageSignals,
    policySignals,
    riskQueue: riskQueue.sort((a, b) => ({ high: 0, medium: 1, low: 2 }[a.priority] - { high: 0, medium: 1, low: 2 }[b.priority])),
    recommendedCommands: [
      { command: "npx changeset", purpose: "Create a release-intent markdown file with package bump metadata." },
      { command: "npx changeset status --verbose", purpose: "Inspect pending changesets and planned package versions." },
      { command: "npx changeset status --since=main --output=changeset-status.json", purpose: "Write CI-readable status output for pull request checks." },
      { command: "npx changeset version", purpose: "Apply pending changesets to package versions and changelogs in a release PR." },
      { command: "npx changeset publish --tag latest", purpose: "Publish packages only after reviewing the release commit and npm access policy." },
      { command: "git push --follow-tags", purpose: "Publish git tags created by the release process." }
    ],
    learnerNextSteps: [
      "Start with `.changeset/config.json` to learn changelog mode, baseBranch, access, private package, fixed, and linked package policy.",
      "Then inspect `.changeset/*.md` files because those are the human-written release-note and semver bump intent.",
      "Check CI for changeset status, bot comments, or Changesets action version PRs before trusting release automation.",
      "RepoTutor never runs `changeset version`, `publish`, or tag commands; use this page as a static map before executing release tooling yourself."
    ]
  };
}

type ChangelogReadinessSourceFile = {
  filePath: string;
  text: string;
  sourceHref: string;
};

async function changelogReadinessSourceFiles(walk: WalkResult): Promise<ChangelogReadinessSourceFile[]> {
  const files: ChangelogReadinessSourceFile[] = [];
  for (const file of walk.files) {
    if (!file.isTextCandidate || !changelogReadinessInspectablePath(file.relPath)) continue;
    const text = await readTextIfSafe(file.absPath, 220_000);
    if (!text) continue;
    if (!changelogReadinessPathSignal(file.relPath) && !changelogReadinessContentSignal(text)) continue;
    files.push({ filePath: file.relPath, text, sourceHref: `source/${encodedPath(file.relPath)}` });
    if (files.length >= 260) break;
  }
  return files;
}

function changelogReadinessInspectablePath(filePath: string): boolean {
  const base = path.basename(filePath);
  return changelogReadinessPathSignal(filePath)
    || /^(package\.json|CHANGELOG\.md|RELEASES?\.md)$/i.test(base)
    || filePath.startsWith(".github/workflows/")
    || /\.(json|ya?ml|md|js|cjs|mjs|ts|sh)$/i.test(filePath);
}

function changelogReadinessPathSignal(filePath: string): boolean {
  const base = path.basename(filePath);
  return filePath.startsWith(".changeset/")
    || /changeset|CHANGELOG|release-notes|release-notes|versioning|publishing/i.test(filePath)
    || /^(CHANGELOG\.md|RELEASES?\.md)$/i.test(base);
}

function changelogReadinessContentSignal(text: string): boolean {
  return /@changesets\/cli|changeset (status|version|publish|pre|tag)|changesets\/action|changeset-bot|\.changeset|baseBranch|updateInternalDependencies|fixed|linked|privatePackages|changelog|snapshot|follow-tags/i.test(text);
}

function changelogReadinessConfigFiles(sourceFiles: ChangelogReadinessSourceFile[]): ChangelogReadinessReport["configFiles"] {
  return sourceFiles
    .filter((source) => changelogReadinessConfigPathSignal(source.filePath, source.text))
    .slice(0, 80)
    .map((source) => {
      const configType = changelogReadinessConfigType(source.filePath, source.text);
      const changelogMode = changelogReadinessChangelogMode(source.text);
      const baseBranch = firstMatch(source.text, /"baseBranch"\s*:\s*"([^"]+)"/) ?? firstMatch(source.text, /baseBranch:\s*["']?([^"'\n]+)/);
      const fixedCount = changelogReadinessArrayCount(source.text, "fixed");
      const linkedCount = changelogReadinessArrayCount(source.text, "linked");
      const ignoredCount = changelogReadinessArrayCount(source.text, "ignore");
      const privatePackagePolicy = changelogReadinessPrivatePolicy(source.text);
      const readiness = changelogMode !== "missing" || baseBranch || fixedCount > 0 || linkedCount > 0 || /@changesets\/cli|changesets\/action|changeset status/i.test(source.text) ? "ready" : "partial";
      return {
        filePath: source.filePath,
        configType,
        changelogMode,
        baseBranch,
        fixedCount,
        linkedCount,
        ignoredCount,
        privatePackagePolicy,
        readiness,
        evidence: `${source.filePath} contains ${configType} Changesets signal with changelog ${changelogMode}, baseBranch ${baseBranch ?? "missing"}, fixed ${fixedCount}, linked ${linkedCount}, ignored ${ignoredCount}, private policy ${privatePackagePolicy}.`,
        sourceHref: source.sourceHref
      };
    });
}

function changelogReadinessConfigPathSignal(filePath: string, text: string): boolean {
  const base = path.basename(filePath);
  return filePath === ".changeset/config.json"
    || (base === "package.json" && /@changesets\/cli|changeset (status|version|publish)|"changeset"\s*:/i.test(text))
    || (filePath.startsWith(".github/workflows/") && /changesets\/action|changeset (status|version|publish)|@changesets\/cli/i.test(text));
}

function changelogReadinessConfigType(filePath: string, text: string): ChangelogReadinessReport["configFiles"][number]["configType"] {
  const base = path.basename(filePath).toLowerCase();
  if (filePath === ".changeset/config.json") return "changeset-config";
  if (base === "package.json") return "package-json";
  if (filePath.startsWith(".github/workflows/")) return "workflow";
  if (/\.changeset|@changesets\/cli|changesets\/action/i.test(text)) return "changeset-config";
  return "unknown";
}

function changelogReadinessChangelogMode(text: string): ChangelogReadinessReport["configFiles"][number]["changelogMode"] {
  if (/"changelog"\s*:\s*false|changelog:\s*false/i.test(text)) return "disabled";
  if (/@changesets\/changelog-github/i.test(text)) return "github";
  if (/"changelog"\s*:\s*"@changesets\/cli\/changelog"|@changesets\/cli\/changelog/i.test(text)) return "default";
  if (/"changelog"\s*:\s*(\[|"[^"]+")|changelog:\s*(\[|['"][^'"]+['"])/i.test(text)) return "custom";
  return "missing";
}

function changelogReadinessPrivatePolicy(text: string): ChangelogReadinessReport["configFiles"][number]["privatePackagePolicy"] {
  if (/"privatePackages"\s*:\s*false|privatePackages:\s*false/i.test(text)) return "disabled";
  if (/"privatePackages"[\s\S]*"tag"\s*:\s*true|privatePackages[\s\S]*tag:\s*true/i.test(text)) return "tagged";
  if (/"privatePackages"[\s\S]*"version"\s*:\s*true|privatePackages[\s\S]*version:\s*true/i.test(text)) return "version-only";
  return "missing";
}

function changelogReadinessArrayCount(text: string, field: string): number {
  try {
    const json = JSON.parse(text) as Record<string, unknown>;
    const value = json[field];
    return Array.isArray(value) ? value.length : 0;
  } catch {
    return countMatches(text, new RegExp(`${field}\\s*:`, "gi"));
  }
}

function changelogReadinessChangesetFiles(sourceFiles: ChangelogReadinessSourceFile[]): ChangelogReadinessReport["changesetFiles"] {
  return sourceFiles
    .filter((source) => /^\.changeset\/(?!config\.json|README\.md)[^/]+\.md$/i.test(source.filePath))
    .slice(0, 120)
    .map((source) => {
      const parsed = changelogReadinessChangesetFrontmatter(source.text);
      const bumpTypes = changelogReadinessBumpTypes(parsed.frontmatter, parsed.summary);
      const packageCount = countMatches(parsed.frontmatter, /["']?[^"'\n:]+["']?\s*:\s*(major|minor|patch)\b/g);
      const summaryLines = parsed.summary.split(/\r?\n/).map((line) => line.trim()).filter(Boolean).length;
      const empty = packageCount === 0 && summaryLines === 0;
      const readiness = empty || (packageCount > 0 && summaryLines > 0) ? "ready" : packageCount > 0 || summaryLines > 0 ? "partial" : "missing";
      return {
        filePath: source.filePath,
        packageCount,
        bumpTypes,
        summaryLines,
        empty,
        readiness,
        evidence: `${source.filePath} declares ${packageCount} package bump(s), ${bumpTypes.join(", ")} bump type(s), and ${summaryLines} summary line(s).`,
        sourceHref: source.sourceHref
      };
    });
}

function changelogReadinessChangesetFrontmatter(text: string): { frontmatter: string; summary: string } {
  const match = text.match(/^---\r?\n([\s\S]*?)\r?\n---\r?\n?([\s\S]*)$/);
  return { frontmatter: match?.[1] ?? "", summary: match?.[2] ?? text };
}

function changelogReadinessBumpTypes(frontmatter: string, summary: string): Array<ChangelogReadinessReport["changesetFiles"][number]["bumpTypes"][number]> {
  const bumps = [...frontmatter.matchAll(/:\s*(major|minor|patch)\b/g)].map((match) => match[1] as "major" | "minor" | "patch");
  if (bumps.length > 0) return Array.from(new Set(bumps));
  if (!frontmatter.trim() && !summary.trim()) return ["none"];
  return ["unknown"];
}

function changelogReadinessWorkflowSignals(sourceFiles: ChangelogReadinessSourceFile[]): ChangelogReadinessReport["workflowSignals"] {
  const specs: Array<{ signal: ChangelogReadinessReport["workflowSignals"][number]["signal"]; pattern: RegExp; evidence: string }> = [
    { signal: "status-check", pattern: /changeset status|@changesets\/cli status|status --since/i, evidence: "changeset status check evidence was detected." },
    { signal: "changeset-bot", pattern: /changeset-bot|github\.com\/apps\/changeset-bot/i, evidence: "Changeset bot evidence was detected." },
    { signal: "changesets-action", pattern: /changesets\/action|@changesets\/action/i, evidence: "Changesets GitHub action evidence was detected." },
    { signal: "version-pr", pattern: /version.?pr|changeset version|versioning pull request/i, evidence: "version PR or version command evidence was detected." },
    { signal: "publish", pattern: /changeset publish|publish:\s|NPM_TOKEN|npm publish/i, evidence: "publish workflow evidence was detected." },
    { signal: "follow-tags", pattern: /push --follow-tags|follow-tags|git push.*tags/i, evidence: "tag push evidence was detected." },
    { signal: "manual-release", pattern: /release coordinator|manual release|stop any merging|release PR/i, evidence: "manual release coordination evidence was detected." }
  ];
  return changelogReadinessSignalFromSpecs(sourceFiles, specs, "workflow", "signal");
}

function changelogReadinessCommandSignals(sourceFiles: ChangelogReadinessSourceFile[]): ChangelogReadinessReport["commandSignals"] {
  const specs: Array<{ signal: ChangelogReadinessReport["commandSignals"][number]["signal"]; pattern: RegExp; evidence: string }> = [
    { signal: "add", pattern: /changeset add|npx changeset\b|changeset --empty|changeset --open|changeset -m/i, evidence: "changeset add evidence was detected." },
    { signal: "status", pattern: /changeset status|status --verbose/i, evidence: "changeset status evidence was detected." },
    { signal: "version", pattern: /changeset version|version packages|update package versions/i, evidence: "changeset version evidence was detected." },
    { signal: "publish", pattern: /changeset publish|publish --tag|publish --otp/i, evidence: "changeset publish evidence was detected." },
    { signal: "pre", pattern: /changeset pre|pre enter|pre exit|prerelease/i, evidence: "pre-release command evidence was detected." },
    { signal: "tag", pattern: /changeset tag|push --follow-tags|git tags/i, evidence: "tag command evidence was detected." },
    { signal: "snapshot", pattern: /--snapshot|snapshot release|snapshot/i, evidence: "snapshot release evidence was detected." },
    { signal: "since", pattern: /--since|baseBranch/i, evidence: "since/baseBranch command evidence was detected." },
    { signal: "output", pattern: /--output|changeset-status\.json/i, evidence: "status output evidence was detected." },
    { signal: "otp", pattern: /--otp|one-time password|NPM_CONFIG_OTP/i, evidence: "npm OTP evidence was detected." }
  ];
  return changelogReadinessSignalFromSpecs(sourceFiles, specs, "command", "signal");
}

function changelogReadinessPackageSignals(sourceFiles: ChangelogReadinessSourceFile[]): ChangelogReadinessReport["packageSignals"] {
  const specs: Array<{ signal: ChangelogReadinessReport["packageSignals"][number]["signal"]; pattern: RegExp; evidence: string }> = [
    { signal: "changesets-cli", pattern: /@changesets\/cli|changeset\b/i, evidence: "@changesets/cli evidence was detected." },
    { signal: "changesets-action", pattern: /changesets\/action|@changesets\/action/i, evidence: "Changesets action evidence was detected." },
    { signal: "changelog-github", pattern: /@changesets\/changelog-github|changelog-github/i, evidence: "GitHub changelog generator evidence was detected." },
    { signal: "workspace", pattern: /workspaces|pnpm-workspace|workspace:\*|workspace:/i, evidence: "workspace package evidence was detected." },
    { signal: "package-manager", pattern: /pnpm|yarn|npm|bun|packageManager/i, evidence: "package manager evidence was detected." },
    { signal: "npm-publish", pattern: /npm publish|pnpm publish|NPM_TOKEN|registry\.npmjs/i, evidence: "npm publish evidence was detected." }
  ];
  return changelogReadinessSignalFromSpecs(sourceFiles, specs, "package", "signal");
}

function changelogReadinessPolicySignals(sourceFiles: ChangelogReadinessSourceFile[]): ChangelogReadinessReport["policySignals"] {
  const specs: Array<{ signal: ChangelogReadinessReport["policySignals"][number]["signal"]; pattern: RegExp; evidence: string }> = [
    { signal: "fixed", pattern: /"fixed"\s*:|fixed packages|fixedPackages/i, evidence: "fixed package policy evidence was detected." },
    { signal: "linked", pattern: /"linked"\s*:|linked packages|linkedPackages/i, evidence: "linked package policy evidence was detected." },
    { signal: "base-branch", pattern: /baseBranch|--since/i, evidence: "base branch policy evidence was detected." },
    { signal: "internal-deps", pattern: /updateInternalDependencies|bumpVersionsWithWorkspaceProtocolOnly|internal dependencies/i, evidence: "internal dependency update policy evidence was detected." },
    { signal: "access", pattern: /"access"\s*:|access:\s*(public|restricted)|restricted|public registry/i, evidence: "npm access policy evidence was detected." },
    { signal: "ignore", pattern: /"ignore"\s*:|--ignore|ignored packages/i, evidence: "ignore package policy evidence was detected." },
    { signal: "private-packages", pattern: /privatePackages|private packages|private:\s*true/i, evidence: "private package policy evidence was detected." },
    { signal: "pre-mode", pattern: /changeset pre|pre\.json|pre mode|prerelease/i, evidence: "pre-release mode evidence was detected." },
    { signal: "snapshot", pattern: /snapshot|--snapshot|prereleaseTemplate/i, evidence: "snapshot policy evidence was detected." }
  ];
  return changelogReadinessSignalFromSpecs(sourceFiles, specs, "policy", "signal");
}

function changelogReadinessSignalFromSpecs<T extends Record<K, string> & { pattern: RegExp; evidence: string }, K extends string>(
  sourceFiles: ChangelogReadinessSourceFile[],
  specs: T[],
  label: string,
  labelKey: K
): Array<Record<K, T[K]> & { readiness: "ready" | "missing" | "external"; evidence: string; relatedHref: string }> {
  return specs.map((spec) => {
    const match = sourceFiles.find((source) => spec.pattern.test(source.filePath) || spec.pattern.test(source.text));
    return {
      [labelKey]: spec[labelKey],
      readiness: match ? "ready" : sourceFiles.length > 0 ? "external" : "missing",
      evidence: match ? `${match.filePath} ${spec.evidence}` : `${label} ${spec[labelKey]} evidence was not detected.`,
      relatedHref: match?.sourceHref ?? "html/changelog-readiness.html"
    } as Record<K, T[K]> & { readiness: "ready" | "missing" | "external"; evidence: string; relatedHref: string };
  });
}

async function buildBundleAnalysisReport(walk: WalkResult): Promise<BundleAnalysisReport> {
  const sourceFiles = await bundleAnalysisSourceFiles(walk);
  const configFiles = bundleAnalysisConfigFiles(sourceFiles);
  const bundleArtifacts = bundleAnalysisArtifacts(walk.files, sourceFiles);
  const sizeSignals = bundleAnalysisSizeSignals(sourceFiles);
  const scriptSignals = bundleAnalysisScriptSignals(sourceFiles);
  const packageSignals = bundleAnalysisPackageSignals(sourceFiles);

  const hasAnalyzer = packageSignals.some((item) => item.readiness === "ready")
    || configFiles.some((item) => item.analyzerMode !== "missing");
  const hasStats = configFiles.some((item) => item.statsFileSignal)
    || bundleArtifacts.some((item) => item.artifactType === "stats-json");
  const hasArtifacts = bundleArtifacts.length > 0;
  const hasSourceMaps = configFiles.some((item) => item.sourceMapSignal)
    || bundleArtifacts.some((item) => item.artifactType === "source-map");
  const hasBudget = configFiles.some((item) => item.budgetSignal)
    || sizeSignals.some((item) => item.signal === "budget" && item.readiness === "ready");
  const serverMode = configFiles.some((item) => item.analyzerMode === "server");

  const riskQueue: BundleAnalysisReport["riskQueue"] = [];
  if (!hasAnalyzer && !hasStats && !hasArtifacts) {
    riskQueue.push({
      priority: "medium",
      action: "Add a bundle analyzer, stats JSON workflow, or committed size artifact before claiming bundle visibility.",
      why: "Webpack Bundle Analyzer starts from an explicit stats/report surface that explains which modules and chunks make up the output.",
      relatedHref: "html/bundle-analysis.html"
    });
  }
  if (hasAnalyzer && !hasStats && !hasArtifacts) {
    riskQueue.push({
      priority: "medium",
      action: "Generate or document a stats JSON/report output for CI review.",
      why: "A package dependency alone does not prove learners can inspect emitted chunks, parsed size, gzip, Brotli, or Zstandard size.",
      relatedHref: "html/bundle-analysis.html"
    });
  }
  if (serverMode) {
    riskQueue.push({
      priority: "low",
      action: "Prefer static or JSON analyzer output for repeatable CI artifacts.",
      why: "Server mode is useful locally, but static reports and JSON files are easier to archive and inspect after a build.",
      relatedHref: "html/bundle-analysis.html"
    });
  }
  if ((hasAnalyzer || hasArtifacts) && !hasSourceMaps) {
    riskQueue.push({
      priority: "low",
      action: "Confirm source maps are available when debugging unexpected bundle weight.",
      why: "Source-map based tools and analyzer reports are easier to teach when minified output maps back to source modules.",
      relatedHref: "html/bundle-analysis.html"
    });
  }
  if ((hasAnalyzer || hasArtifacts || hasStats) && !hasBudget) {
    riskQueue.push({
      priority: "medium",
      action: "Add size budgets or review thresholds for bundle growth.",
      why: "Bundle analysis is more actionable when growth has a threshold, owner, and review path.",
      relatedHref: "html/bundle-analysis.html"
    });
  }
  riskQueue.push({
    priority: "low",
    action: "Run build and analyzer commands only in a trusted workspace after reviewing this static map.",
    why: "RepoTutor does not build the analyzed project, start analyzer servers, parse arbitrary bundles, or open generated reports.",
    relatedHref: "html/bundle-analysis.html"
  });

  return {
    summary: `Webpack Bundle Analyzer식 bundle analysis report: config file ${configFiles.length}개, artifact ${bundleArtifacts.length}개, size signal ${sizeSignals.length}개, package signal ${packageSignals.length}개를 정적 분석으로 정리했습니다.`,
    sourcePattern: "Webpack Bundle Analyzer stats json analyzerMode reportFilename defaultSizes gzip parsed stat source maps chunks assets",
    configFiles,
    bundleArtifacts,
    sizeSignals,
    scriptSignals,
    packageSignals,
    riskQueue: riskQueue.sort((a, b) => ({ high: 0, medium: 1, low: 2 }[a.priority] - { high: 0, medium: 1, low: 2 }[b.priority])),
    recommendedCommands: [
      { command: "npx webpack --profile --json > stats.json", purpose: "Generate webpack stats JSON for offline bundle analysis." },
      { command: "npx webpack-bundle-analyzer stats.json dist --mode static --report bundle-report.html --no-open", purpose: "Create an archived static treemap report without opening a browser." },
      { command: "npx webpack-bundle-analyzer stats.json dist --mode json --default-sizes gzip", purpose: "Create machine-readable analyzer output with gzip size focus." },
      { command: "npx vite build --sourcemap", purpose: "Build Vite output with source maps before inspecting bundle ownership." },
      { command: "npx rollup -c --bundleConfigAsCjs", purpose: "Run Rollup build only in a trusted workspace before visualizer review." },
      { command: "find dist -name '*.map' -o -name '*.js' -o -name '*.css'", purpose: "Inventory emitted JS/CSS/source-map artifacts before opening analyzer output." }
    ],
    learnerNextSteps: [
      "Start with package scripts and bundler config to see whether bundle analysis is wired into the normal build workflow.",
      "Look for stats JSON, static HTML reports, source maps, chunks, vendor bundles, and compression-size signals.",
      "Treat server-mode analyzers as local-only unless static or JSON reports are archived for review.",
      "RepoTutor never runs build or analyzer commands automatically; use this page as a static readiness map before executing bundle tooling yourself."
    ]
  };
}

type BundleAnalysisSourceFile = {
  filePath: string;
  text: string;
  sourceHref: string;
};

async function bundleAnalysisSourceFiles(walk: WalkResult): Promise<BundleAnalysisSourceFile[]> {
  const files: BundleAnalysisSourceFile[] = [];
  for (const file of walk.files) {
    if (!file.isTextCandidate || !bundleAnalysisInspectablePath(file.relPath)) continue;
    const text = await readTextIfSafe(file.absPath, 220_000);
    if (!text) continue;
    if (!bundleAnalysisPathSignal(file.relPath) && !bundleAnalysisContentSignal(text)) continue;
    files.push({ filePath: file.relPath, text, sourceHref: `source/${encodedPath(file.relPath)}` });
    if (files.length >= 260) break;
  }
  return files;
}

function bundleAnalysisInspectablePath(filePath: string): boolean {
  const base = path.basename(filePath);
  return bundleAnalysisPathSignal(filePath)
    || /^(package\.json|stats\.json|asset-manifest\.json|manifest\.json)$/i.test(base)
    || /\.(json|ya?ml|md|js|cjs|mjs|ts|tsx|jsx|css|map|html)$/i.test(filePath);
}

function bundleAnalysisPathSignal(filePath: string): boolean {
  const base = path.basename(filePath);
  return /webpack\.config|vite\.config|rollup\.config|esbuild|next\.config|bundle-analy[sz]er|bundle-report|source-map-explorer|visualizer|stats\.json|asset-manifest\.json/i.test(filePath)
    || /^(report\.html|bundle-report\.html|stats\.json)$/i.test(base)
    || /(^|\/)(dist|build|public\/assets|static\/js|static\/css)\//i.test(filePath);
}

function bundleAnalysisContentSignal(text: string): boolean {
  return /webpack-bundle-analyzer|BundleAnalyzerPlugin|analyzerMode|generateStatsFile|statsFilename|defaultSizes|reportFilename|webpack --profile --json|rollup-plugin-visualizer|source-map-explorer|sourceMappingURL|sourcemap|bundle size|gzip|brotli|zstd|chunks?|assets?/i.test(text);
}

function bundleAnalysisConfigFiles(sourceFiles: BundleAnalysisSourceFile[]): BundleAnalysisReport["configFiles"] {
  return sourceFiles
    .filter((source) => bundleAnalysisConfigPathSignal(source.filePath, source.text))
    .slice(0, 80)
    .map((source) => {
      const configType = bundleAnalysisConfigType(source.filePath, source.text);
      const analyzerMode = bundleAnalysisAnalyzerMode(source.text);
      const defaultSizeMode = bundleAnalysisDefaultSizeMode(source.text);
      const statsFileSignal = /generateStatsFile|statsFilename|stats\.json|--profile\s+--json|--json\s*>\s*stats/i.test(source.text);
      const sourceMapSignal = /sourceMap|sourcemap|sourceMappingURL|\.map\b/i.test(source.text);
      const budgetSignal = /budget|budgets|maxAssetSize|maxEntrypointSize|performance\s*:|size-limit|bundlesize/i.test(source.text);
      const readiness = analyzerMode !== "missing" || statsFileSignal || /webpack-bundle-analyzer|rollup-plugin-visualizer|source-map-explorer|visualizer/i.test(source.text) ? "ready" : "partial";
      return {
        filePath: source.filePath,
        configType,
        analyzerMode,
        defaultSizeMode,
        statsFileSignal,
        sourceMapSignal,
        budgetSignal,
        readiness,
        evidence: `${source.filePath} contains ${configType} bundle-analysis signal with analyzer mode ${analyzerMode}, default size ${defaultSizeMode}, stats ${statsFileSignal ? "yes" : "no"}, source maps ${sourceMapSignal ? "yes" : "no"}, budget ${budgetSignal ? "yes" : "no"}.`,
        sourceHref: source.sourceHref
      };
    });
}

function bundleAnalysisConfigPathSignal(filePath: string, text: string): boolean {
  const base = path.basename(filePath);
  return /webpack\.config|vite\.config|rollup\.config|esbuild|next\.config/i.test(filePath)
    || (base === "package.json" && /webpack-bundle-analyzer|rollup-plugin-visualizer|source-map-explorer|bundle-analy[sz]e|stats\.json|size-limit|bundlesize/i.test(text))
    || (filePath.startsWith(".github/workflows/") && /webpack-bundle-analyzer|source-map-explorer|rollup-plugin-visualizer|stats\.json|bundle-report/i.test(text));
}

function bundleAnalysisConfigType(filePath: string, text: string): BundleAnalysisReport["configFiles"][number]["configType"] {
  const base = path.basename(filePath).toLowerCase();
  if (base === "package.json") return "package-json";
  if (/webpack\.config/i.test(filePath) || /webpack-bundle-analyzer|BundleAnalyzerPlugin/i.test(text)) return "webpack";
  if (/vite\.config/i.test(filePath) || /vite\b/i.test(text)) return "vite";
  if (/rollup\.config/i.test(filePath) || /rollup-plugin-visualizer/i.test(text)) return "rollup";
  if (/esbuild/i.test(filePath) || /esbuild/i.test(text)) return "esbuild";
  if (/next\.config/i.test(filePath) || /next-bundle-analyzer/i.test(text)) return "next";
  return "unknown";
}

function bundleAnalysisAnalyzerMode(text: string): BundleAnalysisReport["configFiles"][number]["analyzerMode"] {
  const match = firstMatch(text, /analyzerMode\s*:\s*["'](server|static|json|disabled)["']/i)
    ?? firstMatch(text, /--mode\s+(server|static|json|disabled)\b/i)
    ?? firstMatch(text, /mode\s*:\s*["'](server|static|json|disabled)["']/i);
  return (match as BundleAnalysisReport["configFiles"][number]["analyzerMode"] | null) ?? "missing";
}

function bundleAnalysisDefaultSizeMode(text: string): BundleAnalysisReport["configFiles"][number]["defaultSizeMode"] {
  const match = firstMatch(text, /defaultSizes\s*:\s*["'](stat|parsed|gzip|brotli|zstd)["']/i)
    ?? firstMatch(text, /--default-sizes\s+(stat|parsed|gzip|brotli|zstd)\b/i);
  return (match as BundleAnalysisReport["configFiles"][number]["defaultSizeMode"] | null) ?? "missing";
}

function bundleAnalysisArtifacts(files: WalkResult["files"], sourceFiles: BundleAnalysisSourceFile[]): BundleAnalysisReport["bundleArtifacts"] {
  const textByPath = new Map(sourceFiles.map((source) => [source.filePath, source]));
  return files
    .filter((file) => bundleAnalysisArtifactType(file.relPath) !== "unknown")
    .slice(0, 120)
    .map((file) => {
      const artifactType = bundleAnalysisArtifactType(file.relPath);
      const source = textByPath.get(file.relPath);
      const referencedChunks = source ? countMatches(source.text, /chunks?|assets?|modules?|sourceMappingURL|import\(/gi) : 0;
      return {
        filePath: file.relPath,
        artifactType,
        sizeBytes: file.size,
        referencedChunks,
        readiness: artifactType === "unknown" ? "missing" : source || artifactType === "dist-file" ? "ready" : "partial",
        evidence: `${file.relPath} looks like ${artifactType} bundle-analysis artifact with ${file.size} bytes and ${referencedChunks} chunk/module reference(s).`,
        sourceHref: source?.sourceHref ?? null
      };
    });
}

function bundleAnalysisArtifactType(filePath: string): BundleAnalysisReport["bundleArtifacts"][number]["artifactType"] {
  const base = path.basename(filePath).toLowerCase();
  if (/stats.*\.json$|^stats\.json$/.test(base)) return "stats-json";
  if (base.endsWith(".map")) return "source-map";
  if (/asset-manifest\.json|manifest\.json/.test(base)) return "asset-manifest";
  if (/bundle-report|report\.html|analy[sz]er.*\.html/i.test(filePath)) return "bundle-report";
  if (/(^|\/)(dist|build|public\/assets|static\/js|static\/css)\/.+\.(js|mjs|cjs|css)$/i.test(filePath)) return "dist-file";
  return "unknown";
}

function bundleAnalysisSizeSignals(sourceFiles: BundleAnalysisSourceFile[]): BundleAnalysisReport["sizeSignals"] {
  const specs: Array<{ signal: BundleAnalysisReport["sizeSignals"][number]["signal"]; pattern: RegExp; evidence: string }> = [
    { signal: "js-bundle", pattern: /(^|\/)(dist|build|static\/js|assets)\/.*\.(js|mjs|cjs)|bundle\.js|main\.[a-f0-9]+\.js/i, evidence: "JavaScript bundle evidence was detected." },
    { signal: "css-bundle", pattern: /(^|\/)(dist|build|static\/css|assets)\/.*\.css|main\.[a-f0-9]+\.css/i, evidence: "CSS bundle evidence was detected." },
    { signal: "asset", pattern: /assets?|asset-manifest|public\/assets|static\/media/i, evidence: "asset output evidence was detected." },
    { signal: "chunk", pattern: /chunks?|chunkFilename|splitChunks|manualChunks|dynamic import|import\(/i, evidence: "chunk splitting evidence was detected." },
    { signal: "vendor", pattern: /vendor|node_modules|splitChunks|common-vendor/i, evidence: "vendor chunk evidence was detected." },
    { signal: "sourcemap", pattern: /sourceMappingURL|sourceMap|sourcemap|\.map\b/i, evidence: "source map evidence was detected." },
    { signal: "gzip", pattern: /gzip|defaultSizes.*gzip|--default-sizes gzip/i, evidence: "gzip size evidence was detected." },
    { signal: "brotli", pattern: /brotli|defaultSizes.*brotli|--default-sizes brotli/i, evidence: "Brotli size evidence was detected." },
    { signal: "zstd", pattern: /zstd|defaultSizes.*zstd|compressionAlgorithm.*zstd/i, evidence: "Zstandard size evidence was detected." },
    { signal: "budget", pattern: /budget|budgets|maxAssetSize|maxEntrypointSize|size-limit|bundlesize/i, evidence: "bundle budget evidence was detected." }
  ];
  return bundleAnalysisSignalFromSpecs(sourceFiles, specs, "size", "signal");
}

function bundleAnalysisScriptSignals(sourceFiles: BundleAnalysisSourceFile[]): BundleAnalysisReport["scriptSignals"] {
  const specs: Array<{ signal: BundleAnalysisReport["scriptSignals"][number]["signal"]; pattern: RegExp; evidence: string }> = [
    { signal: "analyze", pattern: /"[^"]*analy[sz]e[^"]*"\s*:|npm run analy[sz]e|pnpm analy[sz]e|yarn analy[sz]e/i, evidence: "analyze script evidence was detected." },
    { signal: "build", pattern: /"build"\s*:|npm run build|pnpm build|vite build|webpack\b|next build/i, evidence: "build script evidence was detected." },
    { signal: "stats", pattern: /stats\.json|--profile\s+--json|generateStatsFile|statsFilename/i, evidence: "stats generation evidence was detected." },
    { signal: "visualizer", pattern: /rollup-plugin-visualizer|visualizer\(|vite-bundle-visualizer/i, evidence: "visualizer script evidence was detected." },
    { signal: "bundle-analyzer", pattern: /webpack-bundle-analyzer|BundleAnalyzerPlugin/i, evidence: "webpack-bundle-analyzer evidence was detected." },
    { signal: "source-map-explorer", pattern: /source-map-explorer/i, evidence: "source-map-explorer evidence was detected." },
    { signal: "webpack-profile", pattern: /webpack --profile|--profile --json|profile:\s*true/i, evidence: "webpack profile evidence was detected." }
  ];
  return bundleAnalysisSignalFromSpecs(sourceFiles, specs, "script", "signal");
}

function bundleAnalysisPackageSignals(sourceFiles: BundleAnalysisSourceFile[]): BundleAnalysisReport["packageSignals"] {
  const specs: Array<{ signal: BundleAnalysisReport["packageSignals"][number]["signal"]; pattern: RegExp; evidence: string }> = [
    { signal: "webpack-bundle-analyzer", pattern: /webpack-bundle-analyzer|BundleAnalyzerPlugin/i, evidence: "webpack-bundle-analyzer package evidence was detected." },
    { signal: "rollup-plugin-visualizer", pattern: /rollup-plugin-visualizer|vite-bundle-visualizer/i, evidence: "Rollup/Vite visualizer package evidence was detected." },
    { signal: "source-map-explorer", pattern: /source-map-explorer/i, evidence: "source-map-explorer package evidence was detected." },
    { signal: "vite", pattern: /"vite"\s*:|vite build|vite\.config/i, evidence: "Vite package or config evidence was detected." },
    { signal: "webpack", pattern: /"webpack"\s*:|webpack\.config|webpack\b/i, evidence: "webpack package or config evidence was detected." },
    { signal: "next-bundle-analyzer", pattern: /@next\/bundle-analyzer|next-bundle-analyzer/i, evidence: "Next bundle analyzer evidence was detected." }
  ];
  return bundleAnalysisSignalFromSpecs(sourceFiles, specs, "package", "signal");
}

function bundleAnalysisSignalFromSpecs<T extends Record<K, string> & { pattern: RegExp; evidence: string }, K extends string>(
  sourceFiles: BundleAnalysisSourceFile[],
  specs: T[],
  label: string,
  labelKey: K
): Array<Record<K, T[K]> & { readiness: "ready" | "missing" | "external"; evidence: string; relatedHref: string }> {
  return specs.map((spec) => {
    const match = sourceFiles.find((source) => spec.pattern.test(source.filePath) || spec.pattern.test(source.text));
    return {
      [labelKey]: spec[labelKey],
      readiness: match ? "ready" : sourceFiles.length > 0 ? "external" : "missing",
      evidence: match ? `${match.filePath} ${spec.evidence}` : `${label} ${spec[labelKey]} evidence was not detected.`,
      relatedHref: match?.sourceHref ?? "html/bundle-analysis.html"
    } as Record<K, T[K]> & { readiness: "ready" | "missing" | "external"; evidence: string; relatedHref: string };
  });
}

async function buildMockingReadinessReport(walk: WalkResult): Promise<MockingReadinessReport> {
  const sourceFiles = await mockingReadinessSourceFiles(walk);
  const handlerFiles = mockingReadinessHandlerFiles(sourceFiles);
  const serverSetups = mockingReadinessServerSetups(sourceFiles);
  const protocolSignals = mockingReadinessProtocolSignals(sourceFiles);
  const lifecycleSignals = mockingReadinessLifecycleSignals(sourceFiles);
  const packageSignals = mockingReadinessPackageSignals(sourceFiles);

  const hasHandlers = handlerFiles.some((item) => item.readiness === "ready");
  const hasSetup = serverSetups.some((item) => item.readiness === "ready");
  const hasLifecycle = serverSetups.some((item) => item.lifecycleSignal)
    || lifecycleSignals.some((item) => ["resetHandlers", "restoreHandlers", "close"].includes(item.signal) && item.readiness === "ready");
  const hasUnhandledPolicy = serverSetups.some((item) => item.unhandledPolicy !== "missing")
    || lifecycleSignals.some((item) => item.signal === "onUnhandledRequest" && item.readiness === "ready");
  const hasPackage = packageSignals.some((item) => item.readiness === "ready");

  const riskQueue: MockingReadinessReport["riskQueue"] = [];
  if (!hasHandlers && !hasSetup && !hasPackage) {
    riskQueue.push({
      priority: "medium",
      action: "Add request handlers and a test or development mock setup before claiming API mocking coverage.",
      why: "MSW-style mocking starts from explicit handlers that describe network behavior without changing application code.",
      relatedHref: "html/mocking-readiness.html"
    });
  }
  if (hasPackage && !hasHandlers) {
    riskQueue.push({
      priority: "medium",
      action: "Create reusable HTTP, GraphQL, or WebSocket handlers next to the tests or app mock layer.",
      why: "A mocking package dependency alone does not prove learners can see what network behavior is replaced.",
      relatedHref: "html/mocking-readiness.html"
    });
  }
  if (hasHandlers && !hasSetup) {
    riskQueue.push({
      priority: "medium",
      action: "Wire handlers into setupWorker for browser/dev flows or setupServer for Node test flows.",
      why: "Handlers need an interception boundary before tests or local development can rely on them.",
      relatedHref: "html/mocking-readiness.html"
    });
  }
  if (hasSetup && !hasLifecycle) {
    riskQueue.push({
      priority: "medium",
      action: "Add lifecycle cleanup such as resetHandlers, restoreHandlers, and close in test hooks.",
      why: "Mock handlers can leak between tests unless runtime overrides are reset after each case.",
      relatedHref: "html/unit-tests.html"
    });
  }
  if (hasSetup && !hasUnhandledPolicy) {
    riskQueue.push({
      priority: "low",
      action: "Set an explicit onUnhandledRequest policy for unexpected live network calls.",
      why: "Beginners can trust mock coverage more when unhandled requests fail or warn intentionally.",
      relatedHref: "html/mocking-readiness.html"
    });
  }
  riskQueue.push({
    priority: "low",
    action: "Run mock-enabled tests only in a trusted workspace after reviewing this static map.",
    why: "RepoTutor does not start service workers, open network servers, execute handlers, or run the analyzed project's tests.",
    relatedHref: "html/mocking-readiness.html"
  });

  return {
    summary: `MSW식 mocking readiness report: handler file ${handlerFiles.length}개, setup surface ${serverSetups.length}개, protocol signal ${protocolSignals.length}개, package signal ${packageSignals.length}개를 정적 분석으로 정리했습니다.`,
    sourcePattern: "Mock Service Worker setupWorker setupServer http graphql ws HttpResponse handlers onUnhandledRequest resetHandlers passthrough bypass",
    handlerFiles,
    serverSetups,
    protocolSignals,
    lifecycleSignals,
    packageSignals,
    riskQueue: riskQueue.sort((a, b) => ({ high: 0, medium: 1, low: 2 }[a.priority] - { high: 0, medium: 1, low: 2 }[b.priority])),
    recommendedCommands: [
      { command: "npx msw init public/ --save", purpose: "Create a browser service-worker file for MSW development flows." },
      { command: "rg \"setupWorker|setupServer|http\\.|graphql\\.|ws\\.\" src test", purpose: "Inventory mock setup and handler definitions before running tests." },
      { command: "npx vitest run", purpose: "Run Node/jsdom tests that may use setupServer or shared handlers." },
      { command: "npx playwright test", purpose: "Run browser tests that may depend on setupWorker or route-level mocking." },
      { command: "MSW_UNHANDLED_REQUEST=error pnpm test", purpose: "Use a strict local test policy when the project supports it." },
      { command: "rg \"resetHandlers|restoreHandlers|server.close|worker.stop|onUnhandledRequest\" src test", purpose: "Check mock lifecycle cleanup and unexpected-request policy." }
    ],
    learnerNextSteps: [
      "먼저 handlers 파일에서 어떤 API 경로와 응답이 가짜로 정의되어 있는지 확인하세요.",
      "브라우저 개발 흐름은 setupWorker, Node 테스트 흐름은 setupServer 연결을 찾으세요.",
      "테스트마다 resetHandlers나 restoreHandlers가 있는지 확인해 mock 상태가 새지 않게 하세요.",
      "이 리포트는 mock 실행 결과가 아닙니다. 실제 API 대체 동작은 원본 프로젝트의 테스트나 브라우저에서 별도 확인하세요."
    ]
  };
}

type MockingReadinessSourceFile = {
  filePath: string;
  text: string;
  sourceHref: string;
};

async function mockingReadinessSourceFiles(walk: WalkResult): Promise<MockingReadinessSourceFile[]> {
  const files: MockingReadinessSourceFile[] = [];
  for (const file of walk.files) {
    if (!file.isTextCandidate || !mockingReadinessInspectablePath(file.relPath)) continue;
    const text = await readTextIfSafe(file.absPath, 180_000);
    if (!text) continue;
    if (!mockingReadinessPathSignal(file.relPath) && !mockingReadinessContentSignal(text)) continue;
    files.push({ filePath: file.relPath, text, sourceHref: `source/${encodedPath(file.relPath)}` });
    if (files.length >= 220) break;
  }
  return files;
}

function mockingReadinessInspectablePath(filePath: string): boolean {
  const base = path.basename(filePath);
  return mockingReadinessPathSignal(filePath)
    || /^(package\.json|vitest\.config\.[cm]?[jt]s|jest\.config\.[cm]?[jt]s|playwright\.config\.[cm]?[jt]s|setupTests\.[cm]?[jt]sx?)$/i.test(base)
    || /\.(js|cjs|mjs|ts|tsx|jsx|json|md|ya?ml)$/i.test(filePath);
}

function mockingReadinessPathSignal(filePath: string): boolean {
  return /(^|\/)(__mocks__|mocks?|mock[-_]?server|mock[-_]?worker|handlers?|fixtures?|test|tests|spec|e2e|msw)(\/|\.|-|_)/i.test(filePath)
    || /setup[-_.]?(tests?|server|worker|msw)|mockServiceWorker\.js/i.test(filePath);
}

function mockingReadinessContentSignal(text: string): boolean {
  return /\b(msw|setupWorker|setupServer|http\.(get|post|put|patch|delete|all)|graphql\.(query|mutation|operation|link)|ws\.link|HttpResponse|server\.listen|worker\.start|resetHandlers|restoreHandlers|onUnhandledRequest|passthrough|bypass|nock\(|pact|wiremock|fetch-mock|axios-mock-adapter)\b/i.test(text);
}

function mockingReadinessHandlerFiles(sourceFiles: MockingReadinessSourceFile[]): MockingReadinessReport["handlerFiles"] {
  const rows: MockingReadinessReport["handlerFiles"] = [];
  for (const source of sourceFiles) {
    const usesHttp = /\b(http\.(get|post|put|patch|delete|head|options|all)|rest\.(get|post|put|patch|delete|all))\b/i.test(source.text);
    const usesGraphql = /\bgraphql\.(query|mutation|operation|link)\b/i.test(source.text);
    const usesWebSocket = /\b(ws\.link|WebSocketHandler|webSocket|WebSocket)\b/i.test(source.text);
    const handlerCount = countMatches(source.text, /\b(http|rest)\.(get|post|put|patch|delete|head|options|all)\b|\bgraphql\.(query|mutation|operation|link)\b|\bws\.link\b/gi);
    const responseSignals = countMatches(source.text, /\b(HttpResponse|Response\.json|ctx\.|res\(|delay\(|passthrough\(|bypass\(|status\s*:|status\()/gi);
    if (handlerCount === 0 && responseSignals === 0) continue;
    rows.push({
      filePath: source.filePath,
      environment: mockingReadinessEnvironment(source),
      handlerCount,
      usesHttp,
      usesGraphql,
      usesWebSocket,
      responseSignals,
      readiness: handlerCount > 0 && responseSignals > 0 ? "ready" : "partial",
      evidence: `${source.filePath} contains ${handlerCount} handler definition(s), HTTP ${usesHttp ? "yes" : "no"}, GraphQL ${usesGraphql ? "yes" : "no"}, WebSocket ${usesWebSocket ? "yes" : "no"}, response signal ${responseSignals}.`,
      sourceHref: source.sourceHref
    });
  }
  return rows.slice(0, 80);
}

function mockingReadinessEnvironment(source: MockingReadinessSourceFile): MockingReadinessReport["handlerFiles"][number]["environment"] {
  if (/setupWorker|msw\/browser|mockServiceWorker|service worker/i.test(source.text) || /browser|worker/i.test(source.filePath)) return "browser";
  if (/setupServer|msw\/node|server\.listen|node/i.test(source.text) || /node|server/i.test(source.filePath)) return "node";
  if (/test|spec|vitest|jest|playwright/i.test(source.filePath)) return "test";
  if (/handlers?/i.test(source.filePath)) return "shared";
  return "unknown";
}

function mockingReadinessServerSetups(sourceFiles: MockingReadinessSourceFile[]): MockingReadinessReport["serverSetups"] {
  const rows: MockingReadinessReport["serverSetups"] = [];
  for (const source of sourceFiles) {
    const setupType = mockingReadinessSetupType(source.text);
    const startSignal = /\b(worker\.start|server\.listen|setupWorker\(|setupServer\()/i.test(source.text);
    const lifecycleSignal = /\b(resetHandlers|restoreHandlers|server\.close|worker\.stop|afterEach|afterAll|beforeAll|beforeEach|server\.use|worker\.use)\b/i.test(source.text);
    const unhandledPolicy = mockingReadinessUnhandledPolicy(source.text);
    if (setupType === "unknown" && !startSignal && !lifecycleSignal && unhandledPolicy === "missing") continue;
    rows.push({
      filePath: source.filePath,
      setupType,
      startSignal,
      lifecycleSignal,
      unhandledPolicy,
      readiness: setupType !== "unknown" && startSignal ? "ready" : "partial",
      evidence: `${source.filePath} contains ${setupType} setup with start ${startSignal ? "yes" : "no"}, lifecycle ${lifecycleSignal ? "yes" : "no"}, unhandled policy ${unhandledPolicy}.`,
      sourceHref: source.sourceHref
    });
  }
  return rows.slice(0, 80);
}

function mockingReadinessSetupType(text: string): MockingReadinessReport["serverSetups"][number]["setupType"] {
  if (/setupWorker|msw\/browser/i.test(text)) return "setupWorker";
  if (/setupServer|msw\/node/i.test(text)) return "setupServer";
  if (/msw\/native/i.test(text)) return "native";
  return "unknown";
}

function mockingReadinessUnhandledPolicy(text: string): MockingReadinessReport["serverSetups"][number]["unhandledPolicy"] {
  const match = firstMatch(text, /onUnhandledRequest\s*:\s*["'](error|warn|bypass)["']/i);
  if (match === "error" || match === "warn" || match === "bypass") return match;
  if (/onUnhandledRequest\s*:/i.test(text)) return "custom";
  return "missing";
}

function mockingReadinessProtocolSignals(sourceFiles: MockingReadinessSourceFile[]): MockingReadinessReport["protocolSignals"] {
  const specs: Array<{ signal: MockingReadinessReport["protocolSignals"][number]["signal"]; pattern: RegExp; evidence: string }> = [
    { signal: "rest", pattern: /\b(http|rest)\.(get|post|put|patch|delete|head|options|all)\b/i, evidence: "REST/HTTP handler evidence was detected." },
    { signal: "graphql", pattern: /\bgraphql\.(query|mutation|operation|link)\b/i, evidence: "GraphQL handler evidence was detected." },
    { signal: "websocket", pattern: /\b(ws\.link|WebSocketHandler|webSocket|WebSocket)\b/i, evidence: "WebSocket mock evidence was detected." },
    { signal: "http-response", pattern: /\bHttpResponse|Response\.json|ctx\.json|res\(/i, evidence: "mock response builder evidence was detected." },
    { signal: "delay", pattern: /\bdelay\(/i, evidence: "mock latency/delay evidence was detected." },
    { signal: "passthrough", pattern: /\bpassthrough\(|x-msw-bypass/i, evidence: "passthrough evidence was detected." },
    { signal: "bypass", pattern: /\bbypass\(/i, evidence: "bypass request evidence was detected." },
    { signal: "cookies", pattern: /\bcookies\b|cookieStore|Set-Cookie/i, evidence: "cookie-aware mock evidence was detected." },
    { signal: "params", pattern: /\bparams\b|path-to-regexp|:id\b|:slug\b/i, evidence: "route parameter evidence was detected." }
  ];
  return mockingReadinessSignalFromSpecs(sourceFiles, specs, "protocol", "signal");
}

function mockingReadinessLifecycleSignals(sourceFiles: MockingReadinessSourceFile[]): MockingReadinessReport["lifecycleSignals"] {
  const specs: Array<{ signal: MockingReadinessReport["lifecycleSignals"][number]["signal"]; pattern: RegExp; evidence: string }> = [
    { signal: "setupWorker", pattern: /\bsetupWorker\b|msw\/browser/i, evidence: "browser worker setup evidence was detected." },
    { signal: "setupServer", pattern: /\bsetupServer\b|msw\/node/i, evidence: "Node server setup evidence was detected." },
    { signal: "listen", pattern: /\bserver\.listen\b/i, evidence: "server listen lifecycle evidence was detected." },
    { signal: "start", pattern: /\bworker\.start\b/i, evidence: "worker start lifecycle evidence was detected." },
    { signal: "use", pattern: /\b(server|worker)\.use\b/i, evidence: "runtime handler override evidence was detected." },
    { signal: "resetHandlers", pattern: /\bresetHandlers\b/i, evidence: "handler reset evidence was detected." },
    { signal: "restoreHandlers", pattern: /\brestoreHandlers\b/i, evidence: "handler restore evidence was detected." },
    { signal: "close", pattern: /\bserver\.close\b|\bworker\.stop\b/i, evidence: "mock shutdown evidence was detected." },
    { signal: "boundary", pattern: /\bboundary\(/i, evidence: "scoped mock boundary evidence was detected." },
    { signal: "onUnhandledRequest", pattern: /\bonUnhandledRequest\b/i, evidence: "unhandled request policy evidence was detected." }
  ];
  return mockingReadinessSignalFromSpecs(sourceFiles, specs, "lifecycle", "signal");
}

function mockingReadinessPackageSignals(sourceFiles: MockingReadinessSourceFile[]): MockingReadinessReport["packageSignals"] {
  const specs: Array<{ signal: MockingReadinessReport["packageSignals"][number]["signal"]; pattern: RegExp; evidence: string }> = [
    { signal: "msw", pattern: /["']msw["']|msw\/browser|msw\/node|Mock Service Worker/i, evidence: "MSW package evidence was detected." },
    { signal: "nock", pattern: /["']nock["']|\bnock\(/i, evidence: "Nock package evidence was detected." },
    { signal: "pact", pattern: /@pact-foundation\/pact|pact-js|\bPact\b/i, evidence: "Pact package evidence was detected." },
    { signal: "wiremock", pattern: /wiremock/i, evidence: "WireMock package evidence was detected." },
    { signal: "fetch-mock", pattern: /fetch-mock/i, evidence: "fetch-mock package evidence was detected." },
    { signal: "axios-mock-adapter", pattern: /axios-mock-adapter/i, evidence: "axios-mock-adapter package evidence was detected." }
  ];
  return mockingReadinessSignalFromSpecs(sourceFiles, specs, "package", "signal");
}

function mockingReadinessSignalFromSpecs<T extends Record<K, string> & { pattern: RegExp; evidence: string }, K extends string>(
  sourceFiles: MockingReadinessSourceFile[],
  specs: T[],
  label: string,
  labelKey: K
): Array<Record<K, T[K]> & { readiness: "ready" | "missing" | "external"; evidence: string; relatedHref: string }> {
  return specs.map((spec) => {
    const match = sourceFiles.find((source) => spec.pattern.test(source.filePath) || spec.pattern.test(source.text));
    return {
      [labelKey]: spec[labelKey],
      readiness: match ? "ready" : sourceFiles.length > 0 ? "external" : "missing",
      evidence: match ? `${match.filePath} ${spec.evidence}` : `${label} ${spec[labelKey]} evidence was not detected.`,
      relatedHref: match?.sourceHref ?? "html/mocking-readiness.html"
    } as Record<K, T[K]> & { readiness: "ready" | "missing" | "external"; evidence: string; relatedHref: string };
  });
}

async function buildDataFetchingReadinessReport(walk: WalkResult): Promise<DataFetchingReadinessReport> {
  const sourceFiles = await dataFetchingSourceFiles(walk);
  const clientSetups = dataFetchingClientSetups(sourceFiles);
  const queryUsages = dataFetchingQueryUsages(sourceFiles);
  const cacheSignals = dataFetchingCacheSignals(sourceFiles);
  const dataFlowSignals = dataFetchingDataFlowSignals(sourceFiles);
  const packageSignals = dataFetchingPackageSignals(sourceFiles);

  const hasPackage = packageSignals.some((item) => item.readiness === "ready");
  const hasClient = clientSetups.some((item) => item.hasClient);
  const hasProvider = clientSetups.some((item) => item.hasProvider);
  const hasQueries = queryUsages.some((item) => item.queryCount > 0 || item.infiniteQueryCount > 0);
  const hasMutations = queryUsages.some((item) => item.mutationCount > 0);
  const hasInvalidation = dataFlowSignals.some((item) => item.signal === "invalidateQueries" && item.readiness === "ready");
  const hasCachePolicy = cacheSignals.some((item) => ["staleTime", "gcTime", "retry", "enabled"].includes(item.signal) && item.readiness === "ready");

  const riskQueue: DataFetchingReadinessReport["riskQueue"] = [];
  if (!hasPackage && !hasClient && !hasQueries) {
    riskQueue.push({
      priority: "medium",
      action: "Add or document the data-fetching library before claiming server-state readiness.",
      why: "TanStack Query-style readiness starts with an explicit client/cache layer or hook usage surface.",
      relatedHref: "html/data-fetching-readiness.html"
    });
  }
  if (hasPackage && !hasProvider && !hasClient) {
    riskQueue.push({
      priority: "medium",
      action: "Create a QueryClient and provider boundary near the app root.",
      why: "Query hooks need a stable client/cache owner so learners can trace where server state is stored.",
      relatedHref: "html/data-fetching-readiness.html"
    });
  }
  if (hasQueries && !hasCachePolicy) {
    riskQueue.push({
      priority: "low",
      action: "Document cache timing and retry controls for important queries.",
      why: "staleTime, gcTime, retry, and enabled explain why data refetches or stays cached.",
      relatedHref: "html/data-fetching-readiness.html"
    });
  }
  if (hasMutations && !hasInvalidation) {
    riskQueue.push({
      priority: "medium",
      action: "Connect mutations to invalidateQueries or setQueryData where data changes.",
      why: "Mutation success paths should explain how stale cached data becomes fresh again.",
      relatedHref: "html/data-fetching-readiness.html"
    });
  }
  riskQueue.push({
    priority: "low",
    action: "Run data-fetching tests only in a trusted workspace after reviewing this static map.",
    why: "RepoTutor does not fetch remote APIs, instantiate app providers, hydrate caches, or execute the analyzed project's tests.",
    relatedHref: "html/data-fetching-readiness.html"
  });

  return {
    summary: `TanStack Query식 data fetching readiness report: client setup ${clientSetups.length}개, query usage ${queryUsages.length}개, cache signal ${cacheSignals.length}개, package signal ${packageSignals.length}개를 정적 분석으로 정리했습니다.`,
    sourcePattern: "TanStack Query QueryClient QueryClientProvider useQuery useMutation queryKey queryFn invalidateQueries staleTime gcTime hydrate persist devtools",
    clientSetups,
    queryUsages,
    cacheSignals,
    dataFlowSignals,
    packageSignals,
    riskQueue: riskQueue.sort((a, b) => ({ high: 0, medium: 1, low: 2 }[a.priority] - { high: 0, medium: 1, low: 2 }[b.priority])),
    recommendedCommands: [
      { command: "rg \"QueryClient|QueryClientProvider|useQuery|useMutation\" src app pages test", purpose: "Inventory query client setup and hook usage." },
      { command: "rg \"queryKey|queryFn|invalidateQueries|setQueryData\" src app pages test", purpose: "Check whether query keys, fetch functions, and cache update paths are explicit." },
      { command: "rg \"staleTime|gcTime|retry|enabled|refetchOnWindowFocus\" src app pages test", purpose: "Review cache timing and refetch policy controls." },
      { command: "rg \"dehydrate|HydrationBoundary|persistQueryClient|ReactQueryDevtools\" src app pages test", purpose: "Find SSR hydration, persistence, and devtools surfaces." },
      { command: "npx eslint . --rule '@tanstack/query/stable-query-client:error'", purpose: "Run TanStack Query lint checks when the plugin is installed." },
      { command: "npx vitest run", purpose: "Run local tests that exercise hooks, cache invalidation, or data-fetching boundaries." }
    ],
    learnerNextSteps: [
      "먼저 app root 근처에서 QueryClient와 Provider가 어디서 만들어지는지 확인하세요.",
      "각 useQuery는 queryKey와 queryFn을 함께 읽어 어떤 서버 데이터를 어떤 이름으로 캐시하는지 파악하세요.",
      "useMutation이 있다면 성공 후 invalidateQueries나 setQueryData로 캐시를 갱신하는지 확인하세요.",
      "이 리포트는 실제 API 호출 결과가 아닙니다. 네트워크 동작은 원본 프로젝트 테스트나 브라우저에서 별도로 확인하세요."
    ]
  };
}

type DataFetchingSourceFile = {
  filePath: string;
  text: string;
  sourceHref: string;
};

async function dataFetchingSourceFiles(walk: WalkResult): Promise<DataFetchingSourceFile[]> {
  const files: DataFetchingSourceFile[] = [];
  for (const file of walk.files) {
    if (!file.isTextCandidate || !dataFetchingInspectablePath(file.relPath)) continue;
    const text = await readTextIfSafe(file.absPath, 200_000);
    if (!text) continue;
    if (!dataFetchingPathSignal(file.relPath) && !dataFetchingContentSignal(text)) continue;
    files.push({ filePath: file.relPath, text, sourceHref: `source/${encodedPath(file.relPath)}` });
    if (files.length >= 240) break;
  }
  return files;
}

function dataFetchingInspectablePath(filePath: string): boolean {
  const base = path.basename(filePath);
  return dataFetchingPathSignal(filePath)
    || /^(package\.json|tsconfig\.json|vite\.config\.[cm]?[jt]s|next\.config\.[cm]?[jt]s)$/i.test(base)
    || /\.(js|cjs|mjs|ts|tsx|jsx|vue|svelte|json|md|ya?ml)$/i.test(filePath);
}

function dataFetchingPathSignal(filePath: string): boolean {
  return /(query|queries|mutation|mutations|api|client|fetch|hooks?|loaders?|server[-_]?state|tanstack|react-query|swr|axios|ky)/i.test(filePath);
}

function dataFetchingContentSignal(text: string): boolean {
  return /\b(QueryClient|QueryClientProvider|useQuery|useSuspenseQuery|useQueries|useMutation|useInfiniteQuery|queryKey|queryFn|invalidateQueries|prefetchQuery|setQueryData|getQueryData|dehydrate|hydrate|HydrationBoundary|persistQueryClient|ReactQueryDevtools|onlineManager|focusManager|useSWR|axios\.|ky\(|graphql-request)\b/i.test(text);
}

function dataFetchingClientSetups(sourceFiles: DataFetchingSourceFile[]): DataFetchingReadinessReport["clientSetups"] {
  const rows: DataFetchingReadinessReport["clientSetups"] = [];
  for (const source of sourceFiles) {
    const hasClient = /\bnew\s+QueryClient\b|\bQueryClient\(/i.test(source.text);
    const hasProvider = /\bQueryClientProvider\b|VueQueryPlugin|provideTanStackQuery|QueryClientProvider/i.test(source.text);
    const devtoolsSignal = /\bReactQueryDevtools|TanStackQueryDevtools|VueQueryDevtools|devtools/i.test(source.text);
    if (!hasClient && !hasProvider && !devtoolsSignal) continue;
    rows.push({
      filePath: source.filePath,
      framework: dataFetchingFramework(source),
      hasClient,
      hasProvider,
      devtoolsSignal,
      readiness: hasClient && hasProvider ? "ready" : "partial",
      evidence: `${source.filePath} contains QueryClient ${hasClient ? "yes" : "no"}, provider ${hasProvider ? "yes" : "no"}, devtools ${devtoolsSignal ? "yes" : "no"}.`,
      sourceHref: source.sourceHref
    });
  }
  return rows.slice(0, 80);
}

function dataFetchingFramework(source: DataFetchingSourceFile): DataFetchingReadinessReport["clientSetups"][number]["framework"] {
  if (/react-query|@tanstack\/react-query|ReactQuery/i.test(source.text) || /\.(tsx|jsx)$/i.test(source.filePath)) return "react";
  if (/vue-query|@tanstack\/vue-query|VueQuery/i.test(source.text) || /\.vue$/i.test(source.filePath)) return "vue";
  if (/svelte-query|@tanstack\/svelte-query/i.test(source.text) || /\.svelte$/i.test(source.filePath)) return "svelte";
  if (/solid-query|@tanstack\/solid-query/i.test(source.text)) return "solid";
  if (/angular-query|@tanstack\/angular-query/i.test(source.text)) return "angular";
  if (/query-core|@tanstack\/query-core/i.test(source.text)) return "core";
  return "unknown";
}

function dataFetchingQueryUsages(sourceFiles: DataFetchingSourceFile[]): DataFetchingReadinessReport["queryUsages"] {
  const rows: DataFetchingReadinessReport["queryUsages"] = [];
  for (const source of sourceFiles) {
    const queryCount = countMatches(source.text, /\b(useQuery|useSuspenseQuery|useQueries)\b/gi);
    const mutationCount = countMatches(source.text, /\b(useMutation|mutationFn|mutateAsync|mutate\()/gi);
    const infiniteQueryCount = countMatches(source.text, /\b(useInfiniteQuery|useSuspenseInfiniteQuery|fetchInfiniteQuery|prefetchInfiniteQuery)\b/gi);
    const queryKeySignals = countMatches(source.text, /\b(queryKey|mutationKey)\s*:/gi);
    const queryFnSignals = countMatches(source.text, /\b(queryFn|mutationFn)\s*:/gi);
    if (queryCount + mutationCount + infiniteQueryCount + queryKeySignals + queryFnSignals === 0) continue;
    rows.push({
      filePath: source.filePath,
      queryCount,
      mutationCount,
      infiniteQueryCount,
      queryKeySignals,
      queryFnSignals,
      readiness: (queryCount + infiniteQueryCount > 0 && queryKeySignals > 0 && queryFnSignals > 0) || (mutationCount > 0 && queryFnSignals > 0) ? "ready" : "partial",
      evidence: `${source.filePath} contains queries ${queryCount}, mutations ${mutationCount}, infinite queries ${infiniteQueryCount}, query keys ${queryKeySignals}, query functions ${queryFnSignals}.`,
      sourceHref: source.sourceHref
    });
  }
  return rows.slice(0, 100);
}

function dataFetchingCacheSignals(sourceFiles: DataFetchingSourceFile[]): DataFetchingReadinessReport["cacheSignals"] {
  const specs: Array<{ signal: DataFetchingReadinessReport["cacheSignals"][number]["signal"]; pattern: RegExp; evidence: string }> = [
    { signal: "staleTime", pattern: /\bstaleTime\s*:/i, evidence: "staleTime cache freshness evidence was detected." },
    { signal: "gcTime", pattern: /\bgcTime\s*:/i, evidence: "gcTime cache retention evidence was detected." },
    { signal: "retry", pattern: /\bretry\s*:/i, evidence: "retry policy evidence was detected." },
    { signal: "enabled", pattern: /\benabled\s*:/i, evidence: "dependent query enabled flag evidence was detected." },
    { signal: "placeholderData", pattern: /\bplaceholderData\s*:/i, evidence: "placeholder data evidence was detected." },
    { signal: "initialData", pattern: /\binitialData\s*:/i, evidence: "initial data evidence was detected." },
    { signal: "select", pattern: /\bselect\s*:/i, evidence: "data selection evidence was detected." },
    { signal: "suspense", pattern: /\b(useSuspenseQuery|suspense\s*:)/i, evidence: "Suspense query evidence was detected." },
    { signal: "refetchOnWindowFocus", pattern: /\brefetchOnWindowFocus\s*:/i, evidence: "window focus refetch policy evidence was detected." },
    { signal: "refetchOnReconnect", pattern: /\brefetchOnReconnect\s*:/i, evidence: "reconnect refetch policy evidence was detected." }
  ];
  return dataFetchingSignalFromSpecs(sourceFiles, specs, "cache", "signal");
}

function dataFetchingDataFlowSignals(sourceFiles: DataFetchingSourceFile[]): DataFetchingReadinessReport["dataFlowSignals"] {
  const specs: Array<{ signal: DataFetchingReadinessReport["dataFlowSignals"][number]["signal"]; pattern: RegExp; evidence: string }> = [
    { signal: "invalidateQueries", pattern: /\binvalidateQueries\b/i, evidence: "cache invalidation evidence was detected." },
    { signal: "prefetchQuery", pattern: /\b(prefetchQuery|fetchQuery|ensureQueryData)\b/i, evidence: "prefetch/fetch query evidence was detected." },
    { signal: "setQueryData", pattern: /\bsetQueryData\b/i, evidence: "manual cache write evidence was detected." },
    { signal: "getQueryData", pattern: /\bgetQueryData\b/i, evidence: "manual cache read evidence was detected." },
    { signal: "dehydrate", pattern: /\bdehydrate\b/i, evidence: "SSR dehydrate evidence was detected." },
    { signal: "hydrate", pattern: /\b(hydrate|HydrationBoundary)\b/i, evidence: "SSR/client hydration evidence was detected." },
    { signal: "persistQueryClient", pattern: /\bpersistQueryClient\b|createSyncStoragePersister|createAsyncStoragePersister/i, evidence: "query persistence evidence was detected." },
    { signal: "onlineManager", pattern: /\bonlineManager\b/i, evidence: "online manager evidence was detected." },
    { signal: "focusManager", pattern: /\bfocusManager\b/i, evidence: "focus manager evidence was detected." },
    { signal: "devtools", pattern: /\bReactQueryDevtools|TanStackQueryDevtools|devtools/i, evidence: "query devtools evidence was detected." }
  ];
  return dataFetchingSignalFromSpecs(sourceFiles, specs, "data-flow", "signal");
}

function dataFetchingPackageSignals(sourceFiles: DataFetchingSourceFile[]): DataFetchingReadinessReport["packageSignals"] {
  const specs: Array<{ signal: DataFetchingReadinessReport["packageSignals"][number]["signal"]; pattern: RegExp; evidence: string }> = [
    { signal: "tanstack-react-query", pattern: /@tanstack\/react-query|react-query/i, evidence: "TanStack React Query package evidence was detected." },
    { signal: "tanstack-query-core", pattern: /@tanstack\/query-core/i, evidence: "TanStack Query core package evidence was detected." },
    { signal: "swr", pattern: /["']swr["']|\buseSWR\b/i, evidence: "SWR package evidence was detected." },
    { signal: "axios", pattern: /["']axios["']|\baxios\./i, evidence: "Axios package evidence was detected." },
    { signal: "ky", pattern: /["']ky["']|\bky\(/i, evidence: "Ky package evidence was detected." },
    { signal: "graphql-request", pattern: /graphql-request|GraphQLClient/i, evidence: "graphql-request package evidence was detected." },
    { signal: "apollo-client", pattern: /@apollo\/client|ApolloClient|useQuery\(/i, evidence: "Apollo Client package evidence was detected." }
  ];
  return dataFetchingSignalFromSpecs(sourceFiles, specs, "package", "signal");
}

function dataFetchingSignalFromSpecs<T extends Record<K, string> & { pattern: RegExp; evidence: string }, K extends string>(
  sourceFiles: DataFetchingSourceFile[],
  specs: T[],
  label: string,
  labelKey: K
): Array<Record<K, T[K]> & { readiness: "ready" | "missing" | "external"; evidence: string; relatedHref: string }> {
  return specs.map((spec) => {
    const match = sourceFiles.find((source) => spec.pattern.test(source.filePath) || spec.pattern.test(source.text));
    return {
      [labelKey]: spec[labelKey],
      readiness: match ? "ready" : sourceFiles.length > 0 ? "external" : "missing",
      evidence: match ? `${match.filePath} ${spec.evidence}` : `${label} ${spec[labelKey]} evidence was not detected.`,
      relatedHref: match?.sourceHref ?? "html/data-fetching-readiness.html"
    } as Record<K, T[K]> & { readiness: "ready" | "missing" | "external"; evidence: string; relatedHref: string };
  });
}

async function buildRoutingReadinessReport(walk: WalkResult): Promise<RoutingReadinessReport> {
  const sourceFiles = await routingSourceFiles(walk);
  const routingSetups = routingSetupsFromSources(sourceFiles);
  const routeDefinitions = routingRouteDefinitions(sourceFiles);
  const navigationSignals = routingNavigationSignals(sourceFiles);
  const dataRouteSignals = routingDataRouteSignals(sourceFiles);
  const fileRouteSignals = routingFileRouteSignals(sourceFiles);
  const packageSignals = routingPackageSignals(sourceFiles);

  const hasPackage = packageSignals.some((item) => item.readiness === "ready");
  const hasSetup = routingSetups.some((item) => item.hasRouter || item.hasProvider || item.hasConfig);
  const hasRoutes = routeDefinitions.some((item) => item.routeCount > 0 || item.indexSignal || item.layoutSignal);
  const hasNavigation = navigationSignals.some((item) => ["Link", "NavLink", "Navigate", "useNavigate"].includes(item.signal) && item.readiness === "ready");
  const hasDynamicRoutes = routeDefinitions.some((item) => item.dynamicSegmentCount > 0);
  const hasParamsRead = navigationSignals.some((item) => item.signal === "useParams" && item.readiness === "ready");
  const hasDataRoutes = dataRouteSignals.some((item) => ["loader", "action", "clientLoader", "clientAction", "useLoaderData", "useActionData"].includes(item.signal) && item.readiness === "ready");
  const hasErrorBoundary = dataRouteSignals.some((item) => ["ErrorBoundary", "useRouteError"].includes(item.signal) && item.readiness === "ready");
  const hasFileRoutes = fileRouteSignals.some((item) => ["routes-ts", "app-routes-directory", "flatRoutes"].includes(item.signal) && item.readiness === "ready");
  const hasRootRoute = fileRouteSignals.some((item) => item.signal === "root-route" && item.readiness === "ready");

  const riskQueue: RoutingReadinessReport["riskQueue"] = [];
  if (!hasPackage && !hasSetup && !hasRoutes) {
    riskQueue.push({
      priority: "high",
      action: "Add or document the routing surface before claiming navigation readiness.",
      why: "React Router-style readiness starts with an explicit router mode, route definitions, or file-route convention.",
      relatedHref: "html/routing-readiness.html"
    });
  }
  if (hasRoutes && !hasNavigation) {
    riskQueue.push({
      priority: "medium",
      action: "Connect route definitions to visible navigation with Link, NavLink, Navigate, or useNavigate.",
      why: "Learners need to trace not only which URLs exist, but how users move between them.",
      relatedHref: "html/routing-readiness.html"
    });
  }
  if (hasDataRoutes && !hasErrorBoundary) {
    riskQueue.push({
      priority: "medium",
      action: "Add route-level ErrorBoundary or useRouteError handling around data routes.",
      why: "React Router data routes can throw from loaders/actions, so the nearest route boundary explains failure UI.",
      relatedHref: "html/routing-readiness.html"
    });
  }
  if (hasDynamicRoutes && !hasParamsRead) {
    riskQueue.push({
      priority: "low",
      action: "Document where dynamic route params are read with useParams or loader/action params.",
      why: "Dynamic segments are easier to learn when the URL token is tied to the component or data loader that consumes it.",
      relatedHref: "html/routing-readiness.html"
    });
  }
  if (hasFileRoutes && !hasRootRoute) {
    riskQueue.push({
      priority: "low",
      action: "Make the root route or app shell easy to find from the file-route map.",
      why: "Framework/file-route mode usually renders child routes through a root route and Outlet boundary.",
      relatedHref: "html/routing-readiness.html"
    });
  }
  riskQueue.push({
    priority: "low",
    action: "Run routing tests only in a trusted workspace after reviewing this static map.",
    why: "RepoTutor does not execute loaders, actions, navigation transitions, dev servers, or browser route flows.",
    relatedHref: "html/routing-readiness.html"
  });

  return {
    summary: `React Router식 routing readiness report: setup ${routingSetups.length}개, route definition ${routeDefinitions.length}개, navigation signal ${navigationSignals.length}개, data-route signal ${dataRouteSignals.length}개를 정적 분석으로 정리했습니다.`,
    sourcePattern: "React Router BrowserRouter createBrowserRouter RouterProvider routes.ts route index Link NavLink Outlet loader action ErrorBoundary useNavigate useParams useSearchParams",
    routingSetups,
    routeDefinitions,
    navigationSignals,
    dataRouteSignals,
    fileRouteSignals,
    packageSignals,
    riskQueue: riskQueue.sort((a, b) => ({ high: 0, medium: 1, low: 2 }[a.priority] - { high: 0, medium: 1, low: 2 }[b.priority])),
    recommendedCommands: [
      { command: "rg \"BrowserRouter|createBrowserRouter|RouterProvider|routes.ts|flatRoutes\" src app pages", purpose: "Inventory top-level router mode and provider/config setup." },
      { command: "rg \"<Route|route\\\\(|index\\\\(|children:|Outlet\" src app pages", purpose: "Find explicit route definitions, nested routes, index routes, and outlet boundaries." },
      { command: "rg \"Link|NavLink|useNavigate|useParams|useSearchParams|useBlocker\" src app pages test", purpose: "Review visible navigation, dynamic params, search params, and blocking flows." },
      { command: "rg \"loader|action|clientLoader|ErrorBoundary|useRouteError|redirect\" src app pages", purpose: "Check data-route loading, mutation, redirect, and error-boundary surfaces." },
      { command: "npx react-router typegen", purpose: "Generate React Router framework-mode route types when the dev package is installed." },
      { command: "npx vitest run", purpose: "Run local tests that exercise route rendering, navigation, loaders, and error boundaries." }
    ],
    learnerNextSteps: [
      "먼저 BrowserRouter, RouterProvider, routes.ts 중 어떤 라우팅 모드를 쓰는지 확인하세요.",
      "route/index/children/Outlet을 함께 읽으면 URL 구조와 화면 중첩 구조를 연결할 수 있습니다.",
      "동적 경로가 있다면 params를 어디서 읽는지 component와 loader/action 양쪽에서 확인하세요.",
      "이 리포트는 정적 readiness입니다. 실제 navigation과 loader/action 동작은 원본 프로젝트 테스트나 브라우저에서 별도로 확인하세요."
    ]
  };
}

type RoutingSourceFile = {
  filePath: string;
  text: string;
  sourceHref: string;
};

async function routingSourceFiles(walk: WalkResult): Promise<RoutingSourceFile[]> {
  const files: RoutingSourceFile[] = [];
  for (const file of walk.files) {
    if (!file.isTextCandidate || !routingInspectablePath(file.relPath)) continue;
    const text = await readTextIfSafe(file.absPath, 200_000);
    if (!text) continue;
    if (!routingPathSignal(file.relPath) && !routingContentSignal(text)) continue;
    files.push({ filePath: file.relPath, text, sourceHref: `source/${encodedPath(file.relPath)}` });
    if (files.length >= 240) break;
  }
  return files;
}

function routingInspectablePath(filePath: string): boolean {
  const base = path.basename(filePath);
  return routingPathSignal(filePath)
    || /^(package\.json|react-router\.config\.[cm]?[jt]s|vite\.config\.[cm]?[jt]s|next\.config\.[cm]?[jt]s|routes\.[cm]?[jt]sx?)$/i.test(base)
    || /\.(js|cjs|mjs|ts|tsx|jsx|vue|svelte|astro|json|md|ya?ml)$/i.test(filePath);
}

function routingPathSignal(filePath: string): boolean {
  return /(^|\/)(routes?|router|navigation|nav|pages?|app)(\/|\.|-|_|$)|react-router|tanstack-router|vue-router|next\.config|route\.[jt]sx?$|\[[^\]]+\]/i.test(filePath);
}

function routingContentSignal(text: string): boolean {
  return /\b(BrowserRouter|HashRouter|MemoryRouter|RouterProvider|createBrowserRouter|createHashRouter|createMemoryRouter|createRoutesFromElements|useRoutes|Routes|RouteObject|Link|NavLink|Navigate|Outlet|useNavigate|useLocation|useParams|useSearchParams|useMatches|useBlocker|useFetcher|loader|clientLoader|action|clientAction|useLoaderData|useActionData|useRouteError|ErrorBoundary|HydrateFallback|redirect|flatRoutes|@react-router\/dev|@react-router\/fs-routes|react-router-dom|@tanstack\/react-router|vue-router)\b/i.test(text);
}

function routingSetupsFromSources(sourceFiles: RoutingSourceFile[]): RoutingReadinessReport["routingSetups"] {
  const rows: RoutingReadinessReport["routingSetups"] = [];
  for (const source of sourceFiles) {
    const hasRouter = /\b(BrowserRouter|HashRouter|MemoryRouter|createBrowserRouter|createHashRouter|createMemoryRouter|createRoutesFromElements|createRouter|createFileRoute|createRootRoute)\b/i.test(source.text);
    const hasProvider = /\b(RouterProvider|BrowserRouter|HashRouter|MemoryRouter|RouterView|<Router\b)\b/i.test(source.text);
    const hasConfig = /routes\.[cm]?[jt]sx?$|react-router\.config|@react-router\/dev\/routes|flatRoutes|defineConfig|createFileRoute|createRootRoute/i.test(source.filePath) || /@react-router\/dev\/routes|flatRoutes|route\s*\(|index\s*\(|createFileRoute|createRootRoute/i.test(source.text);
    if (!hasRouter && !hasProvider && !hasConfig) continue;
    rows.push({
      filePath: source.filePath,
      mode: routingMode(source),
      hasRouter,
      hasProvider,
      hasConfig,
      readiness: (hasRouter || hasConfig) && (hasProvider || /routes\.[cm]?[jt]sx?$|app\/routes\//i.test(source.filePath)) ? "ready" : "partial",
      evidence: `${source.filePath} contains router ${hasRouter ? "yes" : "no"}, provider ${hasProvider ? "yes" : "no"}, config ${hasConfig ? "yes" : "no"}.`,
      sourceHref: source.sourceHref
    });
  }
  return rows.slice(0, 80);
}

function routingMode(source: RoutingSourceFile): RoutingReadinessReport["routingSetups"][number]["mode"] {
  if (/flatRoutes|@react-router\/fs-routes|app\/routes\//i.test(source.text) || /app\/routes\//i.test(source.filePath)) return "file-routes";
  if (/@react-router\/dev|react-router\.config|routes\.[cm]?[jt]sx?$/i.test(source.text) || /react-router\.config|routes\.[cm]?[jt]sx?$/i.test(source.filePath)) return "framework";
  if (/createBrowserRouter|RouterProvider|loader|action|useFetcher/i.test(source.text)) return "data";
  if (/BrowserRouter|HashRouter|MemoryRouter|<Routes|<Route|useRoutes/i.test(source.text)) return "declarative";
  if (/@tanstack\/react-router|createFileRoute|createRootRoute/i.test(source.text)) return "tanstack";
  if (/vue-router|createRouter|RouterView/i.test(source.text)) return "vue";
  if (/next\/link|next\/navigation|app\/.*page\.[jt]sx?$|pages\/.*\.[jt]sx?$/i.test(source.text) || /(^|\/)(app|pages)\/.*\.[jt]sx?$/i.test(source.filePath)) return "next";
  return "unknown";
}

function routingRouteDefinitions(sourceFiles: RoutingSourceFile[]): RoutingReadinessReport["routeDefinitions"] {
  const rows: RoutingReadinessReport["routeDefinitions"] = [];
  for (const source of sourceFiles) {
    const routeCount = countMatches(source.text, /(<Route\b|\broute\s*\(|\bindex\s*\(|\bpath\s*:|\bcreateFileRoute\s*\(|\bcreateRoutesFromElements\s*\()/gi);
    const dynamicSegmentCount = countMatches(source.text, /(:[A-Za-z_$][\w$-]*|\$[A-Za-z_$][\w$-]*|\[[A-Za-z_$][\w$.-]*\])/g) + countMatches(source.filePath, /(\$[A-Za-z_$][\w$-]*|\[[A-Za-z_$][\w$.-]*\])/g);
    const nestedSignal = /\bchildren\s*:|<Outlet\b|\bOutlet\b|route\s*\([^)]*,\s*[^)]*,\s*\[/i.test(source.text) || /\w+\.\w+\.[jt]sx?$/i.test(source.filePath);
    const indexSignal = /\bindex\s*\(|\bindex\s*:\s*true|_index\.[jt]sx?$|\/index\.[jt]sx?$/i.test(source.text) || /(^|\/)_?index\.[jt]sx?$/i.test(source.filePath);
    const layoutSignal = /\b(Outlet|Layout|root\.tsx|_layout|ErrorBoundary)\b/i.test(source.text) || /(^|\/)(root|layout|_layout)\.[jt]sx?$/i.test(source.filePath);
    if (routeCount + dynamicSegmentCount === 0 && !nestedSignal && !indexSignal && !layoutSignal) continue;
    rows.push({
      filePath: source.filePath,
      routeCount,
      dynamicSegmentCount,
      nestedSignal,
      indexSignal,
      layoutSignal,
      readiness: routeCount > 0 || indexSignal || layoutSignal ? "ready" : "partial",
      evidence: `${source.filePath} contains routes ${routeCount}, dynamic segments ${dynamicSegmentCount}, nested ${nestedSignal ? "yes" : "no"}, index ${indexSignal ? "yes" : "no"}, layout ${layoutSignal ? "yes" : "no"}.`,
      sourceHref: source.sourceHref
    });
  }
  return rows.slice(0, 100);
}

function routingNavigationSignals(sourceFiles: RoutingSourceFile[]): RoutingReadinessReport["navigationSignals"] {
  const specs: Array<{ signal: RoutingReadinessReport["navigationSignals"][number]["signal"]; pattern: RegExp; evidence: string }> = [
    { signal: "Link", pattern: /\bLink\b|<Link\b/i, evidence: "visible route link evidence was detected." },
    { signal: "NavLink", pattern: /\bNavLink\b|<NavLink\b/i, evidence: "active navigation link evidence was detected." },
    { signal: "Navigate", pattern: /\bNavigate\b|<Navigate\b/i, evidence: "declarative redirect/navigation evidence was detected." },
    { signal: "useNavigate", pattern: /\buseNavigate\b/i, evidence: "imperative navigation hook evidence was detected." },
    { signal: "useLocation", pattern: /\buseLocation\b/i, evidence: "current location hook evidence was detected." },
    { signal: "useParams", pattern: /\buseParams\b|\bparams\./i, evidence: "route params reading evidence was detected." },
    { signal: "useSearchParams", pattern: /\buseSearchParams\b|URLSearchParams|searchParams/i, evidence: "query-string/search params evidence was detected." },
    { signal: "useMatches", pattern: /\buseMatches\b|\bmatchRoutes\b|\buseMatch\b/i, evidence: "route matching hook/helper evidence was detected." },
    { signal: "useBlocker", pattern: /\buseBlocker\b|\buseBeforeUnload\b|navigation blocking/i, evidence: "navigation blocking evidence was detected." },
    { signal: "useFetcher", pattern: /\buseFetcher\b|fetcher\.Form/i, evidence: "fetcher/form navigation state evidence was detected." }
  ];
  return routingSignalFromSpecs(sourceFiles, specs, "navigation", "signal");
}

function routingDataRouteSignals(sourceFiles: RoutingSourceFile[]): RoutingReadinessReport["dataRouteSignals"] {
  const specs: Array<{ signal: RoutingReadinessReport["dataRouteSignals"][number]["signal"]; pattern: RegExp; evidence: string }> = [
    { signal: "loader", pattern: /\b(loader\s*:|export\s+(async\s+)?function\s+loader|Route\.LoaderArgs)\b/i, evidence: "route loader evidence was detected." },
    { signal: "action", pattern: /\b(action\s*:|export\s+(async\s+)?function\s+action|Route\.ActionArgs)\b/i, evidence: "route action evidence was detected." },
    { signal: "clientLoader", pattern: /\bclientLoader\b|Route\.ClientLoaderArgs/i, evidence: "clientLoader evidence was detected." },
    { signal: "clientAction", pattern: /\bclientAction\b|Route\.ClientActionArgs/i, evidence: "clientAction evidence was detected." },
    { signal: "useLoaderData", pattern: /\buseLoaderData\b|\bloaderData\b/i, evidence: "loader data consumption evidence was detected." },
    { signal: "useActionData", pattern: /\buseActionData\b|\bactionData\b/i, evidence: "action data consumption evidence was detected." },
    { signal: "useRouteError", pattern: /\buseRouteError\b|\bisRouteErrorResponse\b/i, evidence: "route error hook/response evidence was detected." },
    { signal: "ErrorBoundary", pattern: /\bErrorBoundary\b|\berrorElement\b/i, evidence: "route error boundary evidence was detected." },
    { signal: "HydrateFallback", pattern: /\bHydrateFallback\b|clientLoader\.hydrate/i, evidence: "hydration fallback evidence was detected." },
    { signal: "redirect", pattern: /\bredirect(Document)?\s*\(|\breplace\s*\(/i, evidence: "route redirect evidence was detected." },
    { signal: "defer", pattern: /\bdefer\s*\(|\bAwait\b/i, evidence: "deferred data or Await evidence was detected." }
  ];
  return routingSignalFromSpecs(sourceFiles, specs, "data-route", "signal");
}

function routingFileRouteSignals(sourceFiles: RoutingSourceFile[]): RoutingReadinessReport["fileRouteSignals"] {
  const specs: Array<{ signal: RoutingReadinessReport["fileRouteSignals"][number]["signal"]; pattern: RegExp; evidence: string }> = [
    { signal: "routes-ts", pattern: /(^|\/)routes\.[cm]?[jt]sx?$|@react-router\/dev\/routes/i, evidence: "React Router framework routes.ts config evidence was detected." },
    { signal: "app-routes-directory", pattern: /(^|\/)app\/routes\/|rootDirectory\s*:/i, evidence: "app/routes file-route directory evidence was detected." },
    { signal: "flatRoutes", pattern: /\bflatRoutes\b|@react-router\/fs-routes/i, evidence: "fs-routes flatRoutes evidence was detected." },
    { signal: "index-route", pattern: /_index\.[jt]sx?$|index\s*\(|index\s*:\s*true/i, evidence: "index route evidence was detected." },
    { signal: "dynamic-segment", pattern: /\$[A-Za-z_$][\w$-]*|\[[A-Za-z_$][\w$.-]*\]|:[A-Za-z_$][\w$-]*/i, evidence: "dynamic segment evidence was detected." },
    { signal: "nested-route", pattern: /\w+\.\w+\.[jt]sx?$|children\s*:|<Outlet\b|\bOutlet\b/i, evidence: "nested route or outlet evidence was detected." },
    { signal: "pathless-route", pattern: /(^|\/)_[A-Za-z][\w.-]*\.[jt]sx?$|pathless/i, evidence: "pathless layout route evidence was detected." },
    { signal: "ignoredRouteFiles", pattern: /\bignoredRouteFiles\b/i, evidence: "ignoredRouteFiles configuration evidence was detected." },
    { signal: "root-route", pattern: /(^|\/)(root|layout)\.[jt]sx?$|\broot\.tsx\b|<Outlet\b/i, evidence: "root route or app shell evidence was detected." }
  ];
  return routingSignalFromSpecs(sourceFiles, specs, "file-route", "signal");
}

function routingPackageSignals(sourceFiles: RoutingSourceFile[]): RoutingReadinessReport["packageSignals"] {
  const specs: Array<{ signal: RoutingReadinessReport["packageSignals"][number]["signal"]; pattern: RegExp; evidence: string }> = [
    { signal: "react-router", pattern: /["']react-router["']|from\s+["']react-router["']/i, evidence: "react-router package/import evidence was detected." },
    { signal: "react-router-dom", pattern: /["']react-router-dom["']|from\s+["']react-router-dom["']/i, evidence: "react-router-dom package/import evidence was detected." },
    { signal: "@react-router/dev", pattern: /@react-router\/dev/i, evidence: "@react-router/dev package/config evidence was detected." },
    { signal: "@react-router/fs-routes", pattern: /@react-router\/fs-routes|flatRoutes/i, evidence: "@react-router/fs-routes package evidence was detected." },
    { signal: "tanstack-router", pattern: /@tanstack\/react-router|createFileRoute|createRootRoute/i, evidence: "TanStack Router package/import evidence was detected." },
    { signal: "next", pattern: /["']next["']|next\/link|next\/navigation|app\/.*page\.[jt]sx?$|pages\/.*\.[jt]sx?$/i, evidence: "Next.js route package or file-route evidence was detected." },
    { signal: "vue-router", pattern: /["']vue-router["']|createRouter|RouterView/i, evidence: "Vue Router package/import evidence was detected." }
  ];
  return routingSignalFromSpecs(sourceFiles, specs, "package", "signal");
}

function routingSignalFromSpecs<T extends Record<K, string> & { pattern: RegExp; evidence: string }, K extends string>(
  sourceFiles: RoutingSourceFile[],
  specs: T[],
  label: string,
  labelKey: K
): Array<Record<K, T[K]> & { readiness: "ready" | "missing" | "external"; evidence: string; relatedHref: string }> {
  return specs.map((spec) => {
    const match = sourceFiles.find((source) => spec.pattern.test(source.filePath) || spec.pattern.test(source.text));
    return {
      [labelKey]: spec[labelKey],
      readiness: match ? "ready" : sourceFiles.length > 0 ? "external" : "missing",
      evidence: match ? `${match.filePath} ${spec.evidence}` : `${label} ${spec[labelKey]} evidence was not detected.`,
      relatedHref: match?.sourceHref ?? "html/routing-readiness.html"
    } as Record<K, T[K]> & { readiness: "ready" | "missing" | "external"; evidence: string; relatedHref: string };
  });
}

async function buildStateManagementReadinessReport(walk: WalkResult): Promise<StateManagementReadinessReport> {
  const sourceFiles = await stateManagementSourceFiles(walk);
  const storeSetups = stateManagementStoreSetups(sourceFiles);
  const sliceDefinitions = stateManagementSliceDefinitions(sourceFiles);
  const selectorSignals = stateManagementSelectorSignals(sourceFiles);
  const sideEffectSignals = stateManagementSideEffectSignals(sourceFiles);
  const entitySignals = stateManagementEntitySignals(sourceFiles);
  const middlewareSignals = stateManagementMiddlewareSignals(sourceFiles);
  const rtkQuerySignals = stateManagementRtkQuerySignals(sourceFiles);
  const packageSignals = stateManagementPackageSignals(sourceFiles);

  const hasPackage = packageSignals.some((item) => item.readiness === "ready");
  const hasReduxToolkit = packageSignals.some((item) => item.signal === "redux-toolkit" && item.readiness === "ready");
  const hasStore = storeSetups.some((item) => item.hasConfigureStore || item.storeType !== "unknown");
  const hasProvider = storeSetups.some((item) => item.hasProvider);
  const hasTypedHooks = storeSetups.some((item) => item.hasTypedHooks) || selectorSignals.some((item) => ["useAppSelector", "RootState"].includes(item.signal) && item.readiness === "ready");
  const hasSlices = sliceDefinitions.some((item) => item.sliceCount > 0);
  const hasSelectors = sliceDefinitions.some((item) => item.selectorCount > 0) || selectorSignals.some((item) => item.readiness === "ready");
  const hasAsyncThunk = sideEffectSignals.some((item) => item.signal === "createAsyncThunk" && item.readiness === "ready");
  const hasExtraReducers = sideEffectSignals.some((item) => ["extraReducers", "builder-callback"].includes(item.signal) && item.readiness === "ready");
  const hasRtkQuery = rtkQuerySignals.some((item) => item.signal === "createApi" && item.readiness === "ready");
  const hasRtkQueryStoreWiring = rtkQuerySignals.some((item) => ["reducerPath", "api-middleware"].includes(item.signal) && item.readiness === "ready");

  const riskQueue: StateManagementReadinessReport["riskQueue"] = [];
  if (!hasPackage && !hasStore && !hasSlices) {
    riskQueue.push({
      priority: "medium",
      action: "Add or document the client-state strategy before claiming state-management readiness.",
      why: "Redux Toolkit-style readiness starts with an explicit store, slice, selector, or alternative state package surface.",
      relatedHref: "html/state-management-readiness.html"
    });
  }
  if (hasReduxToolkit && !storeSetups.some((item) => item.hasConfigureStore)) {
    riskQueue.push({
      priority: "high",
      action: "Create or expose a configureStore setup that combines reducers and middleware.",
      why: "Redux Toolkit recommends configureStore as the standard store setup with middleware, DevTools, and reducer composition defaults.",
      relatedHref: "html/state-management-readiness.html"
    });
  }
  if (hasStore && !hasProvider) {
    riskQueue.push({
      priority: "medium",
      action: "Connect the store to the UI root with a Provider or document why the store is framework-agnostic.",
      why: "Learners need to trace where global state becomes available to components.",
      relatedHref: "html/state-management-readiness.html"
    });
  }
  if ((hasStore || hasSlices) && !hasTypedHooks) {
    riskQueue.push({
      priority: "low",
      action: "Add typed useAppDispatch/useAppSelector hooks or document the RootState/AppDispatch access pattern.",
      why: "Typed hooks make Redux state reads and dispatches easier to follow in TypeScript projects.",
      relatedHref: "html/state-management-readiness.html"
    });
  }
  if (hasSlices && !hasSelectors) {
    riskQueue.push({
      priority: "low",
      action: "Expose selectors near slices or a selector module for important state reads.",
      why: "Selectors explain which state shape belongs to public UI or business logic reads.",
      relatedHref: "html/state-management-readiness.html"
    });
  }
  if (hasAsyncThunk && !hasExtraReducers) {
    riskQueue.push({
      priority: "medium",
      action: "Pair async thunks with extraReducers or builder.addCase lifecycle handling.",
      why: "createAsyncThunk emits pending, fulfilled, and rejected actions, but reducer logic must record loading/error/data state.",
      relatedHref: "html/state-management-readiness.html"
    });
  }
  if (hasRtkQuery && !hasRtkQueryStoreWiring) {
    riskQueue.push({
      priority: "medium",
      action: "Wire RTK Query reducerPath and api.middleware into the store before trusting cache behavior.",
      why: "RTK Query API slices need both reducer and middleware registration for subscriptions, invalidation, polling, and cache lifecycle behavior.",
      relatedHref: "html/state-management-readiness.html"
    });
  }
  riskQueue.push({
    priority: "low",
    action: "Run state-management tests only in a trusted workspace after reviewing this static map.",
    why: "RepoTutor does not instantiate stores, dispatch actions, mount providers, or run the analyzed project's tests.",
    relatedHref: "html/state-management-readiness.html"
  });

  return {
    summary: `Redux Toolkit식 state management readiness report: store setup ${storeSetups.length}개, slice definition ${sliceDefinitions.length}개, selector signal ${selectorSignals.length}개, side-effect signal ${sideEffectSignals.length}개를 정적 분석으로 정리했습니다.`,
    sourcePattern: "Redux Toolkit configureStore createSlice reducers actions selectors Provider useSelector useDispatch createAsyncThunk createListenerMiddleware createEntityAdapter middleware devTools RTK Query",
    storeSetups,
    sliceDefinitions,
    selectorSignals,
    sideEffectSignals,
    entitySignals,
    middlewareSignals,
    rtkQuerySignals,
    packageSignals,
    riskQueue: riskQueue.sort((a, b) => ({ high: 0, medium: 1, low: 2 }[a.priority] - { high: 0, medium: 1, low: 2 }[b.priority])),
    recommendedCommands: [
      { command: "rg \"configureStore|Provider|useSelector|useDispatch|useAppSelector|useAppDispatch\" src app packages", purpose: "Inventory store setup, UI provider boundaries, and typed hook usage." },
      { command: "rg \"createSlice|reducers:|extraReducers|createAction|createReducer\" src app packages", purpose: "Find slices, reducers, generated actions, and extra reducer lifecycle handling." },
      { command: "rg \"createAsyncThunk|createListenerMiddleware|listenerMiddleware|rejectWithValue\" src app packages", purpose: "Review async thunk and listener side-effect surfaces." },
      { command: "rg \"createEntityAdapter|selectId|sortComparer|getSelectors\" src app packages", purpose: "Check normalized entity adapter setup and selector generation." },
      { command: "rg \"createApi|fetchBaseQuery|reducerPath|tagTypes|providesTags|invalidatesTags\" src app packages", purpose: "Trace optional RTK Query API slice and cache invalidation wiring." },
      { command: "npx vitest run", purpose: "Run local tests that exercise reducers, selectors, store setup, and async state transitions." }
    ],
    learnerNextSteps: [
      "먼저 configureStore나 대체 store 생성 함수가 어디 있는지 찾고 reducer/middleware 구성을 확인하세요.",
      "createSlice 파일에서는 initialState, reducers, actions export, selectors를 함께 읽어 상태 모양과 변경 규칙을 연결하세요.",
      "createAsyncThunk나 listener middleware가 있다면 pending/fulfilled/rejected 또는 effect 흐름이 어디서 처리되는지 확인하세요.",
      "RTK Query가 있으면 createApi 파일과 store의 reducerPath/middleware 연결을 함께 확인하세요.",
      "이 리포트는 정적 readiness입니다. 실제 dispatch와 UI 반응은 원본 프로젝트 테스트나 브라우저에서 별도로 확인하세요."
    ]
  };
}

type StateManagementSourceFile = {
  filePath: string;
  text: string;
  sourceHref: string;
};

async function stateManagementSourceFiles(walk: WalkResult): Promise<StateManagementSourceFile[]> {
  const files: StateManagementSourceFile[] = [];
  for (const file of walk.files) {
    if (!file.isTextCandidate || !stateManagementInspectablePath(file.relPath)) continue;
    const text = await readTextIfSafe(file.absPath, 220_000);
    if (!text) continue;
    if (!stateManagementPathSignal(file.relPath) && !stateManagementContentSignal(text)) continue;
    files.push({ filePath: file.relPath, text, sourceHref: `source/${encodedPath(file.relPath)}` });
    if (files.length >= 260) break;
  }
  return files;
}

function stateManagementInspectablePath(filePath: string): boolean {
  const base = path.basename(filePath);
  return stateManagementPathSignal(filePath)
    || /^(package\.json|tsconfig\.json|vite\.config\.[cm]?[jt]s|next\.config\.[cm]?[jt]s)$/i.test(base)
    || /\.(js|cjs|mjs|ts|tsx|jsx|vue|svelte|json|md|ya?ml)$/i.test(filePath);
}

function stateManagementPathSignal(filePath: string): boolean {
  return /(^|\/)(store|stores|state|redux|slices?|reducers?|selectors?|hooks?|features?|entities?|services?|api)(\/|\.|-|_|$)|redux-toolkit|rtk-query|zustand|jotai|mobx|valtio/i.test(filePath);
}

function stateManagementContentSignal(text: string): boolean {
  return /\b(configureStore|createStore|createSlice|createReducer|createAction|combineSlices|Provider|useSelector|useDispatch|useAppSelector|useAppDispatch|RootState|AppDispatch|createSelector|createAsyncThunk|createListenerMiddleware|listenerMiddleware|extraReducers|builder\.addCase|rejectWithValue|createEntityAdapter|createApi|fetchBaseQuery|reducerPath|tagTypes|providesTags|invalidatesTags|serializableCheck|immutableCheck|devTools|autoBatchEnhancer|dynamicMiddleware|zustand|jotai|makeAutoObservable|observable|valtio)\b/i.test(text);
}

function stateManagementStoreSetups(sourceFiles: StateManagementSourceFile[]): StateManagementReadinessReport["storeSetups"] {
  const rows: StateManagementReadinessReport["storeSetups"] = [];
  for (const source of sourceFiles) {
    const hasConfigureStore = /\bconfigureStore\s*\(/i.test(source.text);
    const hasProvider = /\bProvider\b|<Provider\b|ApiProvider|ReduxProvider/i.test(source.text);
    const hasTypedHooks = /\b(useAppDispatch|useAppSelector|AppDispatch|RootState|TypedUseSelectorHook|\.withTypes\s*<)/i.test(source.text);
    const hasStoreSignal = hasConfigureStore || /\b(createStore|create\s*<|create\s*\(|atom\s*\(|makeAutoObservable|observable\s*\(|proxy\s*\()\b/i.test(source.text);
    if (!hasStoreSignal && !hasProvider && !hasTypedHooks) continue;
    rows.push({
      filePath: source.filePath,
      storeType: stateManagementStoreType(source),
      hasConfigureStore,
      hasProvider,
      hasTypedHooks,
      readiness: hasConfigureStore && (hasProvider || hasTypedHooks) ? "ready" : hasStoreSignal || hasProvider || hasTypedHooks ? "partial" : "missing",
      evidence: `${source.filePath} contains configureStore ${hasConfigureStore ? "yes" : "no"}, provider ${hasProvider ? "yes" : "no"}, typed hooks ${hasTypedHooks ? "yes" : "no"}.`,
      sourceHref: source.sourceHref
    });
  }
  return rows.slice(0, 90);
}

function stateManagementStoreType(source: StateManagementSourceFile): StateManagementReadinessReport["storeSetups"][number]["storeType"] {
  if (/@reduxjs\/toolkit|\bconfigureStore\b|\bcreateSlice\b/i.test(source.text)) return "redux-toolkit";
  if (/["']redux["']|react-redux|\bcreateStore\b|\bcombineReducers\b/i.test(source.text)) return "redux";
  if (/["']zustand["']|\bcreate\s*<|\bcreateStore\s*\(/i.test(source.text)) return "zustand";
  if (/["']jotai["']|\batom\s*\(|\buseAtom\b/i.test(source.text)) return "jotai";
  if (/["']mobx["']|mobx-react|\bmakeAutoObservable\b|\bobservable\s*\(/i.test(source.text)) return "mobx";
  if (/["']valtio["']|\bproxy\s*\(/i.test(source.text)) return "unknown";
  return "unknown";
}

function stateManagementSliceDefinitions(sourceFiles: StateManagementSourceFile[]): StateManagementReadinessReport["sliceDefinitions"] {
  const rows: StateManagementReadinessReport["sliceDefinitions"] = [];
  for (const source of sourceFiles) {
    const sliceCount = countMatches(source.text, /\bcreateSlice\s*\(/gi);
    const reducerCount = countMatches(source.text, /\breducers\s*:|\bcreateReducer\s*\(|\baddCase\s*\(|\bcaseReducers\b/gi);
    const actionCount = countMatches(source.text, /\bcreateAction\s*\(|\.actions\b|create\.reducer\b|create\.preparedReducer\b|create\.asyncThunk\b/gi);
    const selectorCount = countMatches(source.text, /\bselectors\s*:|\bcreateSelector\s*\(|\.getSelectors\s*\(|\bselect[A-Z][A-Za-z0-9_$]*\b|\bselectFromResult\b/gi);
    const usesImmerStyle = sliceCount > 0 && /\bstate\.[A-Za-z_$][\w$]*(\s*(=|\+=|-=|\+\+|--)|\.push\s*\(|\.splice\s*\(|\.sort\s*\()/i.test(source.text);
    if (sliceCount + reducerCount + actionCount + selectorCount === 0 && !usesImmerStyle) continue;
    rows.push({
      filePath: source.filePath,
      sliceCount,
      reducerCount,
      actionCount,
      selectorCount,
      usesImmerStyle,
      readiness: sliceCount > 0 && reducerCount > 0 ? "ready" : reducerCount + actionCount + selectorCount > 0 ? "partial" : "missing",
      evidence: `${source.filePath} contains slices ${sliceCount}, reducer signals ${reducerCount}, action signals ${actionCount}, selector signals ${selectorCount}, Immer-style updates ${usesImmerStyle ? "yes" : "no"}.`,
      sourceHref: source.sourceHref
    });
  }
  return rows.slice(0, 120);
}

function stateManagementSelectorSignals(sourceFiles: StateManagementSourceFile[]): StateManagementReadinessReport["selectorSignals"] {
  const specs: Array<{ signal: StateManagementReadinessReport["selectorSignals"][number]["signal"]; pattern: RegExp; evidence: string }> = [
    { signal: "useSelector", pattern: /\buseSelector\b/i, evidence: "React-Redux useSelector evidence was detected." },
    { signal: "useAppSelector", pattern: /\buseAppSelector\b|useSelector\.withTypes/i, evidence: "typed app selector hook evidence was detected." },
    { signal: "createSelector", pattern: /\bcreateSelector\s*\(/i, evidence: "memoized selector evidence was detected." },
    { signal: "slice-selectors", pattern: /\bselectors\s*:|\.selectors\b/i, evidence: "createSlice selector evidence was detected." },
    { signal: "RootState", pattern: /\bRootState\b|getState\s*:\s*\(\)\s*=>/i, evidence: "RootState type evidence was detected." },
    { signal: "selectFromResult", pattern: /\bselectFromResult\b/i, evidence: "RTK Query selectFromResult evidence was detected." }
  ];
  return stateManagementSignalFromSpecs(sourceFiles, specs, "selector", "signal");
}

function stateManagementSideEffectSignals(sourceFiles: StateManagementSourceFile[]): StateManagementReadinessReport["sideEffectSignals"] {
  const specs: Array<{ signal: StateManagementReadinessReport["sideEffectSignals"][number]["signal"]; pattern: RegExp; evidence: string }> = [
    { signal: "createAsyncThunk", pattern: /\bcreateAsyncThunk\s*\(/i, evidence: "createAsyncThunk evidence was detected." },
    { signal: "createListenerMiddleware", pattern: /\bcreateListenerMiddleware\s*\(/i, evidence: "listener middleware factory evidence was detected." },
    { signal: "listenerMiddleware", pattern: /\blistenerMiddleware\b|startListening\s*\(/i, evidence: "listener middleware registration evidence was detected." },
    { signal: "thunkMiddleware", pattern: /\bthunk\b|redux-thunk|extraArgument|getDefaultMiddleware\s*\(/i, evidence: "thunk middleware evidence was detected." },
    { signal: "extraReducers", pattern: /\bextraReducers\s*:/i, evidence: "extraReducers lifecycle handling evidence was detected." },
    { signal: "builder-callback", pattern: /\bbuilder\s*=>|\bbuilder\.add(Case|Matcher|DefaultCase)\b/i, evidence: "builder callback reducer evidence was detected." },
    { signal: "rejectWithValue", pattern: /\brejectWithValue\b/i, evidence: "typed rejected payload evidence was detected." },
    { signal: "abort-signal", pattern: /\bAbortSignal\b|\bsignal\b.*abort|thunkAPI\.signal/i, evidence: "async cancellation evidence was detected." }
  ];
  return stateManagementSignalFromSpecs(sourceFiles, specs, "side-effect", "signal");
}

